window.HADITH_CACHE = window.HADITH_CACHE || {};
window.HADITH_CACHE["darimi_0"] = {"1":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَ جَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَيُؤَاخَذُ الرَّجُلُ بِمَا عَمِلَ فِي الْجَاهِلِيَّةِ قَالَ مَنْ أَحْسَنَ فِي الْإِسْلَامِ لَمْ يُؤَاخَذْ بِمَا كَانَ عَمِلَ فِي الْجَاهِلِيَّةِ وَمَنْ أَسَاءَ فِي الْإِسْلَامِ أُخِذَ بِالْأَوَّلِ وَالْآخِرِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Al A'masy] dari [Abu Wa`il] dari [Abdullah], ia berkata; Datang kepada Rasulullah shallallahu 'alaihi wasallam seorang laki-laki lalu berkata: Wahai Rasulullah apakah seseorang akan dihukum atas perbuatan jelek yang dilakukannya pada masa jahiliyah? Rasul pun menjawab: Barang siapa yang berkelakuan baik pada masa Islamnya, ia tidak dihukum atas perbuatan jeleknya dimasa jahiliyah, tetapi barang siapa yang berkelakuan tidak baik (jahat) pada masa Islamnya, dia dihukum (atas dosanya) baik yang lalu ataupun yang selanjutnya. "},"2":{"ar":" أَخْبَرَنَا الْوَلِيدُ بْنُ النَّضْرِ الرَّمْلِيُّ عَنْ مَسَرَّةَ بْنِ مَعْبَدٍ مِنْ بَنِي الْحَارِثِ بْنِ أَبِي الْحَرَامِ مِنْ لَخْمٍ عَنْ الْوَضِينِ أَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّا كُنَّا أَهْلَ جَاهِلِيَّةٍ وَعِبَادَةِ أَوْثَانٍ فَكُنَّا نَقْتُلُ الْأَوْلَادَ وَكَانَتْ عِنْدِي ابْنَةٌ لِي فَلَمَّا أَجَابَتْ وَكَانَتْ مَسْرُورَةً بِدُعَائِي إِذَا دَعَوْتُهَا فَدَعَوْتُهَا يَوْمًا فَاتَّبَعَتْنِي فَمَرَرْتُ حَتَّى أَتَيْتُ بِئْرًا مِنْ أَهْلِي غَيْرَ بَعِيدٍ فَأَخَذْتُ بِيَدِهَا فَرَدَّيْتُ بِهَا فِي الْبِئْرِ وَكَانَ آخِرَ عَهْدِي بِهَا أَنْ تَقُولَ يَا أَبَتَاهُ يَا أَبَتَاهُ فَبَكَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى وَكَفَ دَمْعُ عَيْنَيْهِ فَقَالَ لَهُ رَجُلٌ مِنْ جُلَسَاءِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحْزَنْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ كُفَّ فَإِنَّهُ يَسْأَلُ عَمَّا أَهَمَّهُ ثُمَّ قَالَ لَهُ أَعِدْ عَلَيَّ حَدِيثَكَ فَأَعَادَهُ فَبَكَى حَتَّى وَكَفَ الدَّمْعُ مِنْ عَيْنَيْهِ عَلَى لِحْيَتِهِ ثُمَّ قَالَ لَهُ إِنَّ اللَّهَ قَدْ وَضَعَ عَنْ الْجَاهِلِيَّةِ مَا عَمِلُوا فَاسْتَأْنِفْ عَمَلَكَ","id":"Telah mengabarkan kepada kami [Al Walid bin An Nadlr Ar Ramli] dari [Masarrah bin Ma'bad] -dari Bani Al Harits bin Abu Al Haram dari Lakhmin- dari [Al Wadliin] Bahwa seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam lalu berkata: Hai Rasulullah, kami dahulu adalah orang-orang jahiliyah penyembah berhala dan kami membunuh anak-anak kami, ketika itu kami mempunyai anak yang senang apabila saya memanggilnya. Suatu hari saya pun memanggilnya dan dia langsung menyahut dan mengikuti saya. Ketika saya sampai di sebuah sumur keluarga, saya langsung memegang tangannya dan saya ceburkan dia ke sumur, itulah akhir kebersamaan saya dengannya. Dia memanggil 'wahai ayahku, wahai ayahku. ' Rasulullah pun menangis sampai air matanya bercucuran. Lalu seseeorang yang duduk-duduk bersama Rasulullah shallallahu 'alaihi wasallam berkata kepada laki-laki tersebut: kamu telah membuat Rasulullah shallallahu 'alaihi wasallam sedih. Rasulullah shallallahu 'alaihi wasallam berkata kepada orang tersebut: biarkan dia karena dia bertanya tentang sesuatu yang penting yang dihadapinya, kemudian Rasul berkata kepada laki-laki tersebut: Ulangi lagi cerita kamu tadi, lalu dia pun mengulangi ceritanya dan Rasul menangis lagi sampai bercucuran air matanya, membasahi jenggotnya, lalu beliau bersabda: Allah subhanahu wata'ala telah menghapus dosa-dosa yang dilakukan pada masa jahiliyah oleh karena itu mulailah perbuatan kamu dengan lembaran baru yang bersih. "},"3":{"ar":" أَخْبَرَنَا هَارُونُ بْنُ مُعَاوِيَةَ عَنْ إِبْرَاهِيمَ بْنِ سُلَيْمَانَ الْمُؤَدِّبِ عَنْ الْأَعْمَشِ عَنْ مُجَاهِدٍ قَالَ حَدَّثَنِي مَوْلَايَ أَنَّ أَهْلَهُ بَعَثُوا مَعَهُ بِقَدَحٍ فِيهِ زُبْدٌ وَلَبَنٌ إِلَى آلِهَتِهِمْ قَالَ فَمَنَعَنِي أَنْ آكُلَ الزُّبْدَ لِمَخَافَتِهَا قَالَ فَجَاءَ كَلْبٌ فَأَكَلَ الزُّبْدَ وَشَرِبَ اللَّبَنَ ثُمَّ بَالَ عَلَى الصَّنَمِ وَهُوَ إِسَافٌ وَنَائِلَةُ قَالَ هَارُونُ كَانَ الرَّجُلُ فِي الْجَاهِلِيَّةِ إِذَا سَافَرَ حَمَلَ مَعَهُ أَرْبَعَةَ أَحْجَارٍ ثَلَاثَةً لِقِدْرِهِ وَالرَّابِعَ يَعْبُدُهُ وَيُرَبِّي كَلْبَهُ وَيَقْتُلُ وَلَدَهُ","id":"Telah mengabarkan kepada kami [Harun bin Mu`awiyah] dari [Ibrahim bin sulaiman Al Mu`addib] dari [Al A'masy] dari [Mujahid], [bekas budakku] menceritakan kepadaku; bahwa keluarganya menitip sebuah wadah yang berisi keju dan susu untuk dipersembahkan kepada tuhan-tuhan mereka, ia berkata; keluargaku melarangku makan keju karena takut kepada tuhan-tuhan tersebut; lalu datanglah seekor anjing, memakan keju dan meminum susu serta kencing di atas patung-patung tersebut yaitu patung Iqaf dan nailah. Harun berkata: pada masa jahiliyah dulu apabila seorang laki-laki hendak bepergian dia akan mengikusertakan empat buah batu, tiga diantaranya untuk menopang/menegakan priuk (kuali/bejana) dan yang keempatnya untuk ia sembah, untuk melatih anjingnya, serta untuk membunuh anaknya. "},"4":{"ar":" حَدَّثَنَا مُجَاهِدُ بْنُ مُوسَى حَدَّثَنَا رَيْحَانُ هُوَ ابْنُ سَعِيدٍ السَّامِيُّ حَدَّثَنَا عَبَّادٌ هُوَ ابْنُ مَنْصُورٍ عَنْ أَبِي رَجَاءٍ قَالَ كُنَّا فِي الْجَاهِلِيَّةِ إِذَا أَصَبْنَا حَجَرًا حَسَنًا عَبَدْنَاهُ وَإِنْ لَمْ نُصِبْ حَجَرًا جَمَعْنَا كُثْبَةً مِنْ رَمْلٍ ثُمَّ جِئْنَا بِالنَّاقَةِ الصَّفِيِّ فَتَفَاجُّ عَلَيْهَا فَنَحْلُبُهَا عَلَى الْكُثْبَةِ حَتَّى نَرْوِيَهَا ثُمَّ نَعْبُدُ تِلْكَ الْكُثْبَةَ مَا أَقَمْنَا بِذَلِكَ الْمَكَانِ قَالَ أَبُو مُحَمَّد الصَّفِيُّ الْكَثِيرَةُ الْأَلْبَانِ","id":"Telah menceritakan kepada kami [Mujahid bin Musa] telah menceritakan kepada kami [Raihan Ibnu Sa'id As Sami] telah menceritakan kepada kami ['Abbad Ibnu Manshur] dari [Abu Raja`], ia berkata: kami dulu pada masa jahiliyah apabila menemukan batu yang bagus, kami pun menyembahnya dan apabila tidak mendapatkan yang bagus, kami pun mengumpulkan pasir. Kemudian kami mendatangkan onta yang shafi, ketika onta tersebut sudah mengangkanginya kamipun memeras susunya untuk menyirami tumpukan pasir yang kami kumpulkan, kemudian kami menyembah tumpukan pasir tersebut selama kami tinggal di tempat tersebut. Abu Muhammad berkata: onta shafi adalah onta yang banyak susunya. "},"5":{"ar":" أَخْبَرَنَا الْحَسَنُ بْنُ الرَّبِيعِ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ قَالَ قَالَ كَعْبٌ نَجِدُهُ مَكْتُوبًا مُحَمَّدٌ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا فَظٌّ وَلَا غَلِيظٌ وَلَا صَخَّابٌ بِالْأَسْوَاقِ وَلَا يَجْزِي بِالسَّيِّئَةِ السَّيِّئَةَ وَلَكِنْ يَعْفُو وَيَغْفِرُ وَأُمَّتُهُ الْحَمَّادُونَ يُكَبِّرُونَ اللَّهَ عَزَّ وَجَلَّ عَلَى كُلِّ نَجْدٍ وَيَحْمَدُونَهُ فِي كُلِّ مَنْزِلَةٍ وَيَتَأَزَّرُونَ عَلَى أَنْصَافِهِمْ وَيَتَوَضَّئُونَ عَلَى أَطْرَافِهِمْ مُنَادِيهِمْ يُنَادِي فِي جَوِّ السَّمَاءِ صَفُّهُمْ فِي الْقِتَالِ وَصَفُّهُمْ فِي الصَّلَاةِ سَوَاءٌ لَهُمْ بِاللَّيْلِ دَوِيٌّ كَدَوِيِّ النَّحْلِ وَمَوْلِدُهُ بِمَكَّةَ وَمُهَاجِرُهُ بِطَابَةَ وَمُلْكُهُ بِالشَّامِ","id":"Telah mengabarkan kepada kami [Al Hasan bin Ar Rabi'] telah menceritakan kepada kami [Abul Ahwash] dari [Al A'masy] dari [Abu Shalih], ia berkata; [Ka'ab] berkata; kami mendapatinya tertulis: Muhammad Rasulullah shallallahu 'alaihi wasallam, beliau tidak kasar tutur katanya, tidak keras wataknya, tidak bersuara keras ketika di pasar, tidak membalas kejelekan dengan kejelekan, tetapi membalasnya dengan memaafkan dan mengampuni, umatnya adalah orang-orang yang selalu bertahmid (memuji Allah) bertakbir (mengagungkan Allah) disetiap tempat yang tinggi /pendakian, atau peperangan, mereka memuji Allah Subhanahu wa Ta'ala di tiap-tiap rumah, mengenakan sarung pada bagian tengah mereka, berwudlu pada setiap anggota wudlu mereka, panggilan adzan mereka terdengar di langit, shaf mereka pada waktu perang seperti shaf mereka pada waktu shalat, suara mereka (ketika membaca Al Quran dan berdzikir) bagaikan gemuruh suara lebah, tempat kelahiran beliau di Makkah dan tempat hijrahnya di thaabah (Madinah) dan kerajaannya berada di Syam. "},"6":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي خَالِدٌ هُوَ ابْنُ يَزِيدَ عَنْ سَعِيدٍ هُوَ ابْنُ أَبِي هِلَالٍ عَنْ هِلَالِ بْنِ أُسَامَةَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ ابْنِ سَلَامٍ أَنَّهُ كَانَ يَقُولُ إِنَّا لَنَجِدُ صِفَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّا أَرْسَلْنَاكَ شَاهِدًا وَمُبَشِّرًا وَنَذِيرًا وَحِرْزًا لِلْأُمِّيِّينَ أَنْتَ عَبْدِي وَرَسُولِي سَمَّيْتُهُ الْمُتَوَكِّلَ لَيْسَ بِفَظٍّ وَلَا غَلِيظٍ وَلَا صَخَّابٍ بِالْأَسْوَاقِ وَلَا يَجْزِي بِالسَّيِّئَةِ مِثْلَهَا وَلَكِنْ يَعْفُو وَيَتَجَاوَزُ وَلَنْ أَقْبِضَهُ حَتَّى نُقِيمَ الْمِلَّةَ الْمُتَعَوِّجَةَ بِأَنْ تَشْهَدَ أَنْ لَا إِلَهَ إِلَّا اللَّهُ يَفْتَحُ بِهِ أَعْيُنًا عُمْيًا وَآذَانًا صُمًّا وَقُلُوبًا غُلْفًا قَالَ عَطَاءُ بْنُ يَسَارٍ وَأَخْبَرَنِي أَبُو وَاقِدٍ اللَّيْثِيُّ أَنَّهُ سَمِعَ كَعْبًا يَقُولُ مِثْلَ مَا قَالَ ابْنُ سَلَامٍ","id":"Telah menceritakan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku [Khalid Ibnu Yazid] dari [Sa'id Ibnu Abu Hilal] dari [Hilal bin Usamah] dari ['Atha' bin Yasar] dari [Ibnu Salam], bahwa ia berkata; kami mendapati sifat Rasulullah shallallahu 'alaihi wasallam 'Sesungguhnya Kami mengutus kamu sebagai saksi, pemberi kabar gembira dan sebagai pemberi peringatan', yang menolong orang ummi, engkau adalah hambaKu RasulKu, Aku menamakannya Al Mutawakkil, tutur katanya tidak kasar dan perangainya tidak keras, tidak berteriak-teriak di pasar dan tidak membalas kejelekan dengan kejelekan, akan tetapi dengan memaafkannya sehingga kami meluruskan agama yang melenceng kepada persaksian bahwa tidak ada tuhan yang berhak disembah selain Allah Subhanahu wa Ta'ala, dengan persaksian tersebut kita dapat membuka mata yang buta, telinga-telinga yang pekak dan hati-hati yang tertutup. ['Atha` bin Yasar] berkata; [Abu waqid Al Laitsi] memberitahukan kepada saya bahwa ia mendengar [Ka'ab] juga berkata seperti apa yang dikatakan Ibnu salam. "},"7":{"ar":" أَخْبَرَنَا زَيْدُ بْنُ عَوْفٍ قَالَ وَحَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ ذَكْوَانَ أَبِي صَالِحٍ عَنْ كَعْبٍ فِي السَّطْرِ الْأَوَّلِ مُحَمَّدٌ رَسُولُ اللَّهِ عَبْدِي الْمُخْتَارُ لَا فَظٌّ وَلَا غَلِيظٌ وَلَا صَخَّابٌ فِي الْأَسْوَاقِ وَلَا يَجْزِي بِالسَّيِّئَةِ السَّيِّئَةَ وَلَكِنْ يَعْفُو وَيَغْفِرُ مَوْلِدُهُ بِمَكَّةَ وَهِجْرَتُهُ بِطَيْبَةَ وَمُلْكُهُ بِالشَّامِ وَفِي السَّطْرِ الثَّانِي مُحَمَّدٌ رَسُولُ اللَّهِ أُمَّتُهُ الْحَمَّادُونَ يَحْمَدُونَ اللَّهَ فِي السَّرَّاءِ وَالضَّرَّاءِ يَحْمَدُونَ اللَّهَ فِي كُلِّ مَنْزِلَةٍ وَيُكَبِّرُونَ عَلَى كُلِّ شَرَفٍ رُعَاةُ الشَّمْسِ يُصَلُّونَ الصَّلَاةَ إِذَا جَاءَ وَقْتُهَا وَلَوْ كَانُوا عَلَى رَأْسِ كُنَاسَةٍ وَيَأْتَزِرُونَ عَلَى أَوْسَاطِهِمْ وَيُوَضِّئُونَ أَطْرَافَهُمْ وَأَصْوَاتُهُمْ بِاللَّيْلِ فِي جَوِّ السَّمَاءِ كَأَصْوَاتِ النَّحْلِ","id":"Telah mengabarkan kepada kami [Zaid bin Yusuf] telah menceritakan kepada kami [Abu 'Awanah] dari [Abdul malik bin Umair] dari [Dzakwan Abu Shalih] dari [Ka'ab] bahwa pada alinea pertama tertulis; Muhammad adalah utusan Allah Subhanahu wa Ta'ala, dan hambaKu yang terpilih, tutur katanya tidak kasar, perangainya tidak keras, tidak bersuara lantang di pasar, tidak membalas kejelekan dengan kejelekan akan tetapi membalasnya dengan pemberian maaf dan ampunan, tempat kelahirannya di Makkah dan tempat hijrahnya di Thaibah serta kerajaannya/kekuasaannya di Syam. Dan pada alenia kedua tertulis, Muhammad utusan Allah Subhanahu wa Ta'ala umatnya adalah orang-orang yang selalu memuji Allah atas segala kemuliaan, para pemantau matahari (untuk mengetahui waktu shalat) menunaikan shalat saat tiba waktunya, meskipun mereka di saat berada pada tempat yang kotor, mengenakan sarung pada bagian tengah, membasuh wudlu pada seluruh anggota wudlu, dan suara mereka di malam hari terdengar di udara bagaikan gemuruh suara lebah (karena kegigihan ibadah dan tangisnya). "},"8":{"ar":" أَخْبَرَنَا مُجَاهِدُ بْنُ مُوسَى حَدَّثَنَا مَعْنُ بْنُ عِيسَى حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ عَنْ أَبِي فَرْوَةَ عَنْ ابْنِ عَبَّاسٍ أَنَّهُ سَأَلَ كَعْبَ الْأَحْبَارِ كَيْفَ تَجِدُ نَعْتَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي التَّوْرَاةِ فَقَالَ كَعْبٌ نَجِدُهُ مُحَمَّدُ بْنُ عَبْدِ اللَّهِ يُولَدُ بِمَكَّةَ وَيُهَاجِرُ إِلَى طَابَةَ وَيَكُونُ مُلْكُهُ بِالشَّامِ وَلَيْسَ بِفَحَّاشٍ وَلَا صَخَّابٍ فِي الْأَسْوَاقِ وَلَا يُكَافِئُ بِالسَّيِّئَةِ السَّيِّئَةَ وَلَكِنْ يَعْفُو وَيَغْفِرُ أُمَّتُهُ الْحَمَّادُونَ يَحْمَدُونَ اللَّهَ فِي كُلِّ سَرَّاءَ وَضَرَّاءَ وَيُكَبِّرُونَ اللَّهَ عَلَى كُلِّ نَجْدٍ يُوَضِّئُونَ أَطْرَافَهُمْ وَيَأْتَزِرُونَ فِي أَوْسَاطِهِمْ يُصَفُّونَ فِي صَلَوَاتِهِمْ كَمَا يُصَفُّونَ فِي قِتَالِهِمْ دَوِيُّهُمْ فِي مَسَاجِدِهِمْ كَدَوِيِّ النَّحْلِ يُسْمَعُ مُنَادِيهِمْ فِي جَوِّ السَّمَاءِ","id":"Telah mengabarkan kepada kami [Mujahid biun Musa] telah menceritakan kepada kami [Ma'n ibnu 'Isa] telah menceritakan kepada kami [Mu'awiyah bin Shalih] dari [Abu Farwah] dari [Ibnu 'Abbas] Radliyallahu'anhu, bahwa ia bertanya kepada Ka'ab Al Ahbar; Bagaimana kamu dapati sifat Rasulullah shallallahu 'alaihi wasallam dalam kitab Taurat?, [Ka'ab] menjawab; kami dapati ia Muhammad bin Abdullah dilahirkan di Makkah, berhijrah ke Thaabah atau Madinah, kerajaannya akan ada di Syam, ia bukan orang keji, ia tidak bersuara keras di pasar, ia tidak membalas kejelekan dengan kejelekan tetapi memaafkan dan mengampuni, umatnya senantiasa memuji. Mereka memuji Allah Subhanahu wa Ta'ala baik dalam keadaan senang atau susah, mereka selalu mengagungkan Allah Subhanahu wa Ta'ala dalam setiap kemenangan, mereka membasuh anggota wudlu mereka, mengenakan kain sarung pada bagian tengah mereka, bereka berbaris dalam shalat seperti berbarisnya mereka dalam peperangan, suara mereka di masjid-masjid mereka seperti gemuruh suara lebah, terdengar suara mu`dzin mereka di angkasa. "},"9":{"ar":" أَخْبَرَنَا حَيْوَةُ بْنُ شُرَيْحٍ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ الْمِيثَمِيُّ حَدَّثَنَا بَحِيرُ بْنُ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ الْحَضْرَمِيِّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَقَدْ جَاءَكُمْ رَسُولٌ إِلَيْكُمْ لَيْسَ بِوَهِنٍ وَلَا كَسِلٍ لِيَخْتِنَ قُلُوبًا غُلْفًا وَيَفْتَحَ أَعْيُنًا عُمْيًا وَيُسْمِعَ آذَانًا صُمًّا وَيُقِيمَ أَلْسِنَةً عُوجًا حَتَّى يُقَالَ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ","id":"Telah mengabarkan kepada kami [Haiwah bin Syuraih] telah menceritakan kepada kami [Baqiyyah bin Al Walid Al Maitami] telah menceritakan kepada kami [Buhair bin Sa'ad] dari [Khalid bin Ma'dan] dari [Jubair bin Nufair Al Hadlrami]; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Telah datang kepada kalian seorang utusan yang tidak lemah dan juga tidak malas, (diutus untuk) menyadarkan hati-hati yang lalai, membuka mata yang tertutup, dan menjadikan telinga-telinga yang tuli mendengar, meluruskan lisan yang bengkok, sehingga dikatakan; tiada tuhan yang berhak disembah melainkan Allah Subhanahu wa Ta'ala saja. "},"10":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يَزِيدَ الْحِزَامِيُّ حَدَّثَنَا إِسْحَقُ بْنُ سُلَيْمَانَ عَنْ عَمْرِو بْنِ أَبِي قَيْسٍ عَنْ عَطَاءٍ قَالَ كَانَ رَجُلٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَهُ إِلَيْهِ حَاجَةٌ فَمَشَى مَعَهُ حَتَّى دَخَلَ قَالَ فَإِحْدَى رِجْلَيْهِ فِي الْبَيْتِ وَالْأُخْرَى خَارِجَهُ كَأَنَّهُ يُنَاجِي فَالْتَفَتَ فَقَالَ أَتَدْرِي مَنْ كُنْتُ أُكَلِّمُ إِنَّ هَذَا مَلَكٌ لَمْ أَرَهُ قَطُّ قَبْلَ يَوْمِي هَذَا اسْتَأْذَنَ رَبَّهُ أَنْ يُسَلِّمَ عَلَيَّ قَالَ إِنَّا آتَيْنَاكَ أَوْ أَنْزَلْنَا الْقُرْآنَ فَصْلًا وَالسَّكِينَةَ صَبْرًا وَالْفُرْقَانَ وَصْلًا","id":"Telah mengabarkan kepada kami [Muhammad bin Yazid Al Hizami] telah menceritakan kepada kami [Ishaq bin Sulaiman] dari ['Amr bin Abu Qais] dari ['Atha`], ia berkata; Salah seorang sahabat Nabi shallallahu 'alaihi wasallam mempunyai keperluan dengan beliau. Ia berjalan bersama beliau, sampai ketika sudah memasuki rumah dan salah satu kaki beliau berada di dalam dan yang lainnya di luar rumah, seakan-akan Rasulullah shallallahu 'alaihi wasallam bercakap-cakap dengan seorang laki-laki, setelah itu beliau menoleh dan berbicara kepada sahabat tersebut: Tahukah anda siapa yang aku ajak bicara? dia adalah malaikat yang aku belum pernah melihatnya sebelum ini, malaikat tersebut meminta izin Rabbnya agar dapat mengucapkan salam kepadaku. Allah berfirman: \"Sesungguhnya kami mendatangimu atau menurunkan Al Qur'an sebagai pemutus perkara dan As Sakinah sebagai kesabaran dan Al Furqon sebagai pedoman. "},"11":{"ar":" أَخْبَرَنَا مُجَاهِدُ بْنُ مُوسَى حَدَّثَنَا رَيْحَانُ هُوَ ابْنُ سَعِيدٍ حَدَّثَنَا عَبَّادٌ هُوَ ابْنُ مَنْصُورٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ عَطِيَّةَ أَنَّهُ سَمِعَ رَبِيعَةَ الْجُرَشِيَّ يَقُولُ أُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقِيلَ لَهُ لِتَنَمْ عَيْنُكَ وَلْتَسْمَعْ أُذُنُكَ وَلْيَعْقِلْ قَلْبُكَ قَالَ فَنَامَتْ عَيْنَايَ وَسَمِعَتْ أُذُنَايَ وَعَقَلَ قَلْبِي قَالَ فَقِيلَ لِي سَيِّدٌ بَنَى دَارًا فَصَنَعَ مَأْدُبَةً وَأَرْسَلَ دَاعِيًا فَمَنْ أَجَابَ الدَّاعِيَ دَخَلَ الدَّارَ وَأَكَلَ مِنْ الْمَأْد��بَةِ وَرَضِيَ عَنْهُ السَّيِّدُ وَمَنْ لَمْ يُجِبْ الدَّاعِيَ لَمْ يَدْخُلْ الدَّارَ وَلَمْ يَطْعَمْ مِنْ الْمَأْدُبَةِ وَسَخِطَ عَلَيْهِ السَّيِّدُ قَالَ فَاللَّهُ السَّيِّدُ وَمُحَمَّدٌ الدَّاعِي وَالدَّارُ الْإِسْلَامُ وَالْمَأْدُبَةُ الْجَنَّةُ","id":"Telah mengabarkan kepada kami [Mujahid bin Musa] telah menceritakan kepada kami [Raihan Ibnu Sa'id] telah menceritakan kepada kami ['Abbad Ibnu Mansur] dari [Ayyub] dari [Abu Qilabah] dari ['Athiyah] bahwasanya ia mendengar [Rabi'ah Al Jurasyi] berkata; Nabi shallallahu 'alaihi wasallam didatangkan lalu dikatakan kepada beliau, silahkan mata baginda tidur, telinga baginda mendengar, dan hati baginda berpikir. Beliau berkata: maka mata saya melihat, telinga saya mendengar, dan hati saya berpikir. Ia berkata; saya memperoleh informasi \"Ada seorang Tuan yang membangun rumah, lalu menyediakan jamuan, kemudian ia mengutus seorang untuk mengundang ke jamuan, barang siapa yang menyambut seruan penyeru dan memasuki rumah lalu makan hidangan maka baginda tersebut akan ridla kepadanya. Sebaliknya barang siapa yang tidak menyambut seruan penyeru dan tidak masuk ke rumah serta tidak makan hidangan, maka Tuan akan marah kepadanya. Lalu ia berkata: Tuan tersebut adalah Allah Subhanahu Wa Ta'ala, penyerunya adalah Muhammad shallallahu 'alaihi wasallam, rumahnya adalah Islam, dan hidangannya adalah surga. "},"12":{"ar":" أَخْبَرَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ جَعْفَرِ بْنِ مَيْمُونٍ التَّمِيمِيِّ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ إِلَى الْبَطْحَاءِ وَمَعَهُ ابْنُ مَسْعُودٍ فَأَقْعَدَهُ وَخَطَّ عَلَيْهِ خَطًّا ثُمَّ قَالَ لَا تَبْرَحَنَّ فَإِنَّهُ سَيَنْتَهِي إِلَيْكَ رِجَالٌ فَلَا تُكَلِّمْهُمْ فَإِنَّهُمْ لَنْ يُكَلِّمُوكَ فَمَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَيْثُ أَرَادَ ثُمَّ جَعَلُوا يَنْتَهُونَ إِلَى الْخَطِّ لَا يُجَاوِزُونَهُ ثُمَّ يَصْدُرُونَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا كَانَ مِنْ آخِرِ اللَّيْلِ جَاءَ إِلَيَّ فَتَوَسَّدَ فَخِذِي وَكَانَ إِذَا نَامَ نَفَخَ فِي النَّوْمِ نَفْخًا فَبَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَوَسِّدٌ فَخِذِي رَاقِدٌ إِذْ أَتَانِي رِجَالٌ كَأَنَّهُمْ الْجِمَالُ عَلَيْهِمْ ثِيَابٌ بِيضٌ اللَّهُ أَعْلَمُ مَا بِهِمْ مِنْ الْجَمَالِ حَتَّى قَعَدَ طَائِفَةٌ مِنْهُمْ عِنْدَ رَأْسِهِ وَطَائِفَةٌ مِنْهُمْ عِنْدَ رِجْلَيْهِ فَقَالُوا بَيْنَهُمْ مَا رَأَيْنَا عَبْدًا أُوتِيَ مِثْلَ مَا أُوتِيَ هَذَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ عَيْنَيْهِ لَتَنَامَانِ وَإِنَّ قَلْبَهُ لَيَقْظَانُ اضْرِبُوا لَهُ مَثَلًا سَيِّدٌ بَنَى قَصْرًا ثُمَّ جَعَلَ مَأْدُبَةً فَدَعَا النَّاسَ إِلَى طَعَامِهِ وَشَرَابِهِ ثُمَّ ارْتَفَعُوا وَاسْتَيْقَظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ ذَلِكَ فَقَالَ لِي أَتَدْرِي مَنْ هَؤُلَاءِ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ هُمْ الْمَلَائِكَةُ قَالَ وَهَلْ تَدْرِي مَا الْمَثَلُ الَّذِي ضَرَبُوهُ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ الرَّحْمَنُ بَنَى الْجَنَّةَ فَدَعَا إِلَيْهَا عِبَادَهُ فَمَنْ أَجَابَهُ دَخَلَ جَنَّتَهُ وَمَنْ لَمْ يُجِبْهُ عَاقَبَهُ وَعَذَّبَهُ","id":"Telah mengabarkan kepada kami [Al Hasan bin 'Ali] telah menceritakan kepada kami [Abu Usamah] dari [Ja'far bin Maimun At Tamimi] dari [Abu Utsman An Nahdi] Bahwa Rasulullah shallallahu 'alaihi wasallam keluar ke Bathha` dan bersamanya Ibnu Mas'ud Radliyallahu'anhu, lalu Rasulullah shallallahu 'alaihi wasallam pergi menuju Bathaa bersama ibnu Mas'ud, lalu beliau mengajak duduk Ibnu Mas'ud dan membuat satu garis pembatas untuknya. Lalu berkata: Jangan sekali-kali kamu tinggalkan tempat ini, karena beberapa orang laki-laki akan menemuimu yang kamu tidak berbicara kepada mereka, dan mereka pun tidak akan berbicara kepadamu. Lalu Rasulullah shallallahu 'alaihi wasallam meneruskan perjalanannya kemana saja beliau kehendaki. Kemudian sampailah orang-orang tersebut pada garis pembatas dan mereka tidak melewatinya, kemudian mereka pergi menuju Rasulullah shallallahu 'alaihi wasallam. Sampai ketika pada akhir malam beliau mendatangiku lalu tidur dengan menjadikan pahaku sebagai bantalnya, dan beliau apabila tidur terdengar hembusan nafasnya. Tatkala Rasulullah shallallahu 'alaihi wasallam sedang tidur di pahaku datanglah para lelaki seperti dengan paras yang tampan memakai pakaian yang serba putih. Huuh, alangkah indahnya mereka! sehingga segolongan dari mereka duduk di sisi kepala Rasulullah shallallahu 'alaihi wasallam dan segolongan yang lain di sisi kaminya lalu mereka saling berkata: kami belum pernah mendapatkan seorang hamba yang diberi anugerah seperti apa yang diberikan kepada Nabi shallallahu 'alaihi wasallam. Orang ini matanya tertidur tapi hatinya dalam keadaan sadar, buatlah baginya suatu perumpamaan. Baiklah, dia seperti seorang tuan yang membangun sebuah istana, kemudian membuat hidangan lalu mengundang orang-orang untuk makan dan minum, kemudian orang-orang tersebut naik ke langit. Lalu terbangunlah Rasulullah shallallahu 'alaihi wasallam ketika itu lalu beliau berkata kepadaku: tahukah kamu siapa mereka itu? lalu aku menjawab: Allah Subhanahu wa Ta'ala dan Rasul-Nya yang lebih tahu. Lalu beliau berkata: mereka adalah malaikat. Lalu beliau berkata lagi: tahukah anda apa yang diumpamakan? Aku katakan Allah Subhanahu wa Ta'ala dan Rasul-Nya yang lebih tahu beliau menjawab: Ar Rahman membangun surga, lalu menyeru (mengundang) hamba-hamba-Nya kepadanya, barang siapa yang menyambut maka dia akan masuk surga dan barang siapa yang menolak maka dia menghukum dan menyiksanya. "},"13":{"ar":" أَخْبَرَنَا نُعَيْمُ بْنُ حَمَّادٍ حَدَّثَنَا بَقِيَّةُ عَنْ بَحِيرٍ عَنْ خَالِدِ بْنِ مَعْدَانَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَمْرٍو السُّلَمِيُّ عَنْ عُتْبَةَ بْنِ عَبْدٍ السُّلَمِيِّ أَنَّهُ حَدَّثَهُمْ وَكَانَ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ رَجُلٌ كَيْفَ كَانَ أَوَّلُ شَأْنِكَ يَا رَسُولَ اللَّهِ قَالَ كَانَتْ حَاضِنَتِي مِنْ بَنِي سَعْدِ بْنِ بَكْرٍ فَانْطَلَقْتُ أَنَا وَابْنٌ لَهَا فِي بَهْمٍ لَنَا وَلَمْ نَأْخُذْ مَعَنَا زَادًا فَقُلْتُ يَا أَخِي اذْهَبْ فَأْتِنَا بِزَادٍ مِنْ عِنْدِ أُمِّنَا فَانْطَلَقَ أَخِي وَمَكَثْتُ عِنْدَ الْبَهْمِ فَأَقْبَلَ طَائِرَانِ أَبْيَضَانِ كَأَنَّهُمَا نَسْرَانِ فَقَالَ أَحَدُهُمَا لِصَاحِبِهِ أَهُوَ هُوَ قَالَ الْآخَرُ نَعَمْ فَأَقْبَلَا يَبْتَدِرَانِي فَأَخَذَانِي فَبَطَحَانِي لِلْقَفَا فَشَقَّا بَطْنِي ثُمَّ اسْتَخْرَجَا قَلْبِي فَشَقَّاهُ فَأَخْرَجَا مِنْهُ عَلَقَتَيْنِ سَوْدَاوَيْنِ فَقَالَ أَحَدُهُمَا لِصَاحِبِهِ ائْتِنِي بِمَاءِ ثَلْجٍ فَغَسَلَ بِهِ جَوْفِي ثُمَّ قَالَ ائْتِنِي بِمَاءِ بَرَدٍ فَغَسَلَ بِهِ قَلْبِي ثُمَّ قَالَ ائْتِنِي بِالسَّكِينَةِ فَذَرَّهُ فِي قَلْبِي ثُمَّ قَالَ أَحَدُهُمَا لِصَاحِبِهِ حُصْهُ فَحَاصَهُ وَخَتَمَ عَلَيْهِ بِخَاتَمِ النُّبُوَّةِ ثُمَّ قَالَ أَحَدُهُمَا لِصَاحِبِهِ اجْعَلْهُ فِي كِفَّةٍ وَاجْعَلْ أَلْفًا مِنْ أُمَّتِهِ فِي كِفَّةٍ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا أَنَا أَنْظُرُ إِلَى الْأَلْفِ فَوْقِي أُشْفِقُ أَنْ يَخِرَّ عَلَيَّ بَعْضُهُمْ فَقَالَ لَوْ أَنَّ أُمَّتَهُ وُزِنَتْ بِهِ لَمَالَ بِهِمْ ثُمَّ انْطَلَقَا وَتَرَكَانِي قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفَرِقْتُ فَرَقًا شَدِيدًا ثُمَّ انْطَلَقْتُ إِلَى أُمِّي فَأَخْبَرْتُهَا بِالَّذِي لَقِيتُ فَأَشْفَقَتْ أَنْ يَكُونَ قَدْ الْتَبَسَ بِي فَقَالَتْ أُعِيذُكَ بِاللَّهِ فَرَحَلَتْ بَعِيرًا لَهَا فَجَعَلَتْنِي عَلَى الرَّحْلِ وَرَكِبَتْ خَلْفِي حَتَّى بُلْغَتِنَا إِلَى أُمِّي فَقَالَتْ أَدَّيْتُ أَمَانَتِي وَذِمَّتِي وَحَدَّثَتْهَا بِالَّذِي لَقِيتُ فَلَمْ يَرُعْهَا ذَلِكَ وَقَالَتْ إِنِّي رَأَيْتُ حِينَ خَرَجَ مِنِّي يَعْنِي نُورًا أَضَاءَتْ مِنْهُ قُصُورُ الشَّامِ","id":"Telah mengabarkan kepada kami [Nu'aim bin Hammad] telah menceritakan kepada kami [Baqiyyah] dari [Bahir] dari [Khalid bin Ma'dan] telah menceritakan kepada kami ['Abdur Rahman bin 'Amr As Sulami] dari ['Utbah bin 'Abd As Sulami] Bahwa ia menceritakan kepada mereka, dan ia termasuk dari sahabat Rasulullah shallallahu 'alaihi wasallam, seorang laki-laki bertanya kepada Rasulullah shallallahu 'alaihi wasallam: Bagaimanakah perihal awal hidup baginda ya Rasulullah? beliau menjawab: Ibu asuhku ketika itu adalah perempuan Bani Sa'd bin Bakr ketika itu saya dan seorang anak kecil lainnya dari kabilah tersebut sedang menggembala binatang ternak. Karena kami tidak membawa bekal maka saya meminta kepada teman saya tersebut: wahai saudaraku pulanglah dan mintalah bekal kepada ibu kita. Lalu saudaraku pergi dan tinggal saya sendiri menjaga binatang ternak. Tiba-tiba datanglah dua burung yang putih seperti burung elang, salah satunya mengatakan kepada yang lain, apakah betul-betul dia? jawab yang lain; ya! lalu keduanya mengelilingi saya dan menarik saya serta menelentangkan saya, lalu mereka membelah perut saya kemudian mengeluarkan hati saya, membelahnya dan mengeluarkan dua gumpalan hitam. Kemudian berkatalah salah satu diantara keduanya kepada temannya: berikan saya air salju lalu dia pergunakan mencuci perut saya. Kemudian berkata lagi: berikan saya air sejuk\". Dan dia pergunakan mencuci hati saya. Kemudian dia berkata: berikan saya As Sakinah (ketenangan)! lalu dia menaburkannya dihati saya. Kemudian salah satunya berkata kepada temannya: jahitlah dia! lalu dijahitlah dan dia berikan tanda dengan khatam nubuwah (penutup para nabi). Kemudian berkata salah satu kepada temannya: letakkan dia pada salah satu timbangan dan letakkan seribu orang dari umatnya pada satu timbangan. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: ketika itu saya melihat seribu orang di atasku sehingga aku khawatir sebagian dari mereka jatuh menimpaku, lalu orang itu berkata lagi: seandainya umatnya ditimbang dengannya pasti akan lebih berat dia dari umatnya kemudian keduanya pergi meninggalkanku. Rasulullah shallallahu 'alaihi wasallam berkata: saya takut sekali kemudian saya berlari menuju ibu susuku dan saya beritahukan dia tentang apa yang baru saja terjadi padaku. Dia pun khawatir akan terjadi apa-apa terhadapku lalu dia berkata: aku meminta perlindungan Allah Subhanahu wa Ta'ala untukmu. Lalu dia mempersiapkan tunggangannya untuk pergi dan menempatkanku di atas onta dan dia naik di belakangku hingga kami sampai menjumpai ibuku, lalu dia berkata kepada ibuku: aku telah melaksanakan amanat dan beban yang telah dibebankan kepadaku, lalu dia menceritakan apa yang terjadi padaku. Namun hal itu tidak membuatnya gusar, bahkan ibuku menjawab: Dahulu malah saya melihatnya ketika dia baru keluar dari rahimku, yaitu cahaya yang menyinari singgasana Syam. "},"14":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ عِمْرَانَ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا جَعْفَرُ بْنُ عُثْمَانَ الْقُرَشِيُّ عَنْ عُثْمَانَ بْنِ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ أَبِيهِ عَنْ أَبِي ذَرٍّ الْغِفَارِيِّ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ كَيْفَ عَلِمْتَ أَنَّكَ نَبِيٌّ حَتَّى اسْتَيْقَنْتَ فَقَالَ يَا أَبَا ذَرٍّ أَتَانِي مَلَكَانِ وَأَنَا بِبَعْضِ بَطْحَاءِ مَكَّةَ فَوَقَعَ أَحَدُهُمَا عَلَى الْأَرْضِ وَكَانَ الْآخَرُ بَيْنَ السَّمَاءِ وَالْأَرْضِ فَقَالَ أَحَدُهُمَا لِصَاحِبِهِ أَهُوَ هُوَ قَالَ نَعَمْ قَالَ فَزِنْهُ بِرَجُلٍ فَوُزِنْتُ بِهِ فَوَزَنْتُهُ ثُمَّ قَالَ فَزِنْهُ بِعَشَرَةٍ فَوُزِنْتُ بِهِمْ فَرَجَحْتُهُمْ ثُمَّ قَالَ زِنْهُ بِمِائَةٍ فَوُزِنْتُ بِهِمْ فَرَجَحْتُهُمْ ثُمَّ قَالَ زِنْهُ بِأَلْفٍ فَوُزِنْتُ بِهِمْ فَرَجَحْتُهُمْ كَأَنِّي أَنْظُرُ إِلَيْهِمْ يَنْتَثِرُونَ عَلَيَّ مِنْ خِفَّةِ الْمِيزَانِ قَالَ فَقَالَ أَحَدُهُمَا لِصَاحِبِهِ لَوْ وَزَنْتَهُ بِأُمَّتِهِ لَرَجَحَهَا","id":"Telah mengabarkan kepada kami [Abdullah bin Imran] telah menceritakan kepada kami [Abu Daud] telah menceritakan kepada kami [Ja'far bin Utsman Al Qurasyi] dari [Utsman bin Urwah bin Az Zubair] dari [ayahnya] dari [Abu Dzar Al Ghifari] Radliyallahu'anhu, ia berkata; saya bertanya wahai Rasulullah bagaimana bisa yakin bahwa kamu adalah nabi? nabi menjawab: wahai Abu Dzar dua malaikat datang kepadaku ketika aku sedang berada di suatu lembah di Makkah. Salah satunya turun ke bumi dan yang lainnya berada diantara langit dan bumi. Salah satunya mengatakan kepada temannya: apakah benar-benar dia? lalu temannya menjawab: ya! lalu berkata lagi: kalau begitu timbanglah dia dengan seseorang, maka saya ditimbang dengan sepuluh orang dan saya lebih berat dari pada mereka. Kemudian berkata lagi: \"Timbanglah dia dengan seratus orang\", maka saya pun ditimbang dan saya lebih berat daripada mereka. Lalu berkata lagi: \"Kalau begitu timbanglah dengan seribu orang\", lalu saya pun ditimbang dan saya lebih berat dari mereka. Ketika itu saya seakan-akan melihat mereka berdesak-desakkan karena sempitnya timbangan kemudian salah satu diantara dua malaikat itu berkata kepada temannya: kalaupun dia ditimbang dengan seluruh umatnya maka dia akan tetap lebih berat dari mereka. "},"15":{"ar":" أَخْبَرَنَا إِسْمَعِيلُ بْنُ خَلِيلٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنَادِيهِمْ يَا أَيُّهَا النَّاسُ إِنَّمَا أَنَا رَحْمَةٌ مُهْدَاةٌ","id":"Telah mengabarkan kepada kami [Ismail bin Khalil] telah menceritakan kepada kami [Ali bin Mushir] telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih], ia berkata; Nabi shallallahu 'alaihi wasallam pernah memanggil mereka; wahai manusia sesungguhnya saya adalah rahmat dan mendapatkan petunjuk. "},"16":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ طَرِيفٍ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ حَدَّثَنَا أَبُو حَيَّانَ عَنْ عَطَاءٍ عَنْ ابْنِ عُمَرَ قَالَ كُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَأَقْبَلَ أَعْرَابِيٌّ فَلَمَّا دَنَا مِنْهُ قَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْنَ تُرِيدُ قَالَ إِلَى أَهْلِي قَالَ هَلْ لَكَ فِي خَيْرٍ قَالَ وَمَا هُوَ قَالَ تَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ قَالَ وَمَنْ يَشْهَدُ عَلَى مَا تَقُولُ قَالَ هَذِهِ السَّلَمَةُ فَدَعَاهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ بِشَاطِئِ الْوَادِي فَأَقْبَلَتْ تَخُدُّ الْأَرْضَ خَدًّا حَتَّى قَامَتْ بَيْنَ يَدَيْهِ فَاسْتَشْهَدَهَا ثَلَاثًا فَشَهِدَتْ ثَلَاثًا أَنَّهُ كَمَا قَالَ ثُمَّ رَجَعَتْ إِلَى مَنْبَتِهَا وَرَجَعَ الْأَعْرَابِيُّ إِلَى قَوْمِهِ وَقَالَ إِنْ اتَّبَعُونِي أَتَيْتُكَ بِهِمْ وَإِلَّا رَجَعْتُ فَكُنْتُ مَعَكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Tharif] telah menceritakan kepada kami [Muhammad bin Fudlail] telah menceritakan kepada kami [Abu Hayyan] dari ['Atha`] dari [Ibnu Umar] Radliyallahu'anhu, ia berkata; ketika kami sedang bersama Rasulullah shallallahu 'alaihi wasallam dalam sebuah perjalanan kami bertemu seorang Arab badui dan setelah kami mendekatinya Rasulullah shallallahu 'alaihi wasallam berkata kepadanya: engkau hendak kemana? Arab badui menjawab: aku hendak menemui keluargaku. Lalu Rasul berkata: apakah kamu mau sesuatu kebaikan? dia menjawab: apakah kebaikan itu? Rasulullah shallallahu 'alaihi wasallam bersabda: yaitu kamu bersaksi bahwa tiada tuhan yang berhak disembah kecuali Allah Subhanahu wa Ta'ala dan bersaksi bahwa Muhammad shallallahu 'alaihi wasallam adalah hamba dan RasulNya. Arab badui itu mengatakan: lalu siapa yang membuktikan kebenaran apa yang baginda katakan? Rasul menjawab: pohon Salamah itu, maka Rasul pun memanggilnya sementara pohon tersebut berada di tepi bukit, lalu pohon tersebut menghampiri Rasulullah shallallahu 'alaihi wasallam dengan membelah bumi sampai pohon tersebut sampai di hadapan Rasulullah shallallahu 'alaihi wasallam. Rasul memintanya untuk bersaksi tiga kali. Dia pun bersaksi tiga kali seperti apa yang dikatakan Rasulullah shallallahu 'alaihi wasallam kemudian pohon tersebut pun kembali lagi ke tempat ia tumbuh. Arab badui itu kembali ke kaumnya seraya berucap; sekiranya mereka mengikuti saya, saya akan membawa mereka menemui baginda (Rasulullah shallallahu 'alaihi wasallam), jika tidak saya akan kembali menemui baginda dan tinggal bersama baginda. "},"17":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْمَعِيلَ بْنِ عَبْدِ الْمَلِكِ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَ خَرَجْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ وَكَانَ لَا يَأْتِي الْبَرَازَ حَتَّى يَتَغَيَّبَ فَلَا يُرَى فَنَزَلْنَا بِفَلَاةٍ مِنْ الْأَرْضِ لَيْسَ فِيهَا شَجَرٌ وَلَا عَلَمٌ فَقَالَ يَا جَابِرُ اجْعَلْ فِي إِدَاوَتِكَ مَاءً ثُمَّ انْطَلِقْ بِنَا قَالَ فَانْطَلَقْنَا حَتَّى لَا نُرَى فَإِذَا هُوَ بِشَجَرَتَيْنِ بَيْنَهُمَا أَرْبَعُ أَذْرُعٍ فَقَالَ يَا جَابِرُ انْطَلِقْ إِلَى هَذِهِ الشَّجَرَةِ فَقُلْ يُقَلْ لَكِ الْحَقِي بِصَاحِبَتِكِ حَتَّى أَجْلِسَ خَلْفَكُمَا فَرَجَعَتْ إِلَيْهَا فَجَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَلْفَهُمَا ثُمَّ رَجَعَتَا إِلَى مَكَانِهِمَا فَرَكِبْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَسُولُ اللَّهِ بَيْنَنَا كَأَنَّمَا عَلَيْنَا الطَّيْرُ تُظِلُّنَا فَعَرَضَتْ لَهُ امْرَأَةٌ مَعَهَا صَبِيٌّ لَهَا فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ ابْنِي هَذَا يَأْخُذُهُ الشَّيْطَانُ كُلَّ يَوْمٍ ثَلَاثَ مِرَارٍ قَالَ فَتَنَاوَلَ الصَّبِيَّ فَجَعَلَهُ بَيْنَهُ وَبَيْنَ مُقَدَّمِ الرَّحْلِ ثُمَّ قَالَ اخْسَأْ عَدُوَّ اللَّهِ أَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اخْسَأْ عَدُوَّ اللَّهِ أَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثًا ثُمَّ دَفَعَهُ إِلَيْهَا فَلَمَّا قَضَيْنَا سَفَرَنَا مَرَرْنَا بِذَلِكَ الْمَكَانِ فَعَرَضَتْ لَنَا الْمَرْأَةُ مَعَهَا صَبِيُّهَا وَمَعَهَا كَبْشَانِ تَسُوقُهُمَا فَقَالَتْ يَا رَسُولَ اللَّهِ اقْبَلْ مِنِّي هَدِيَّتِي فَوَالَّذِي بَعَثَكَ بِالْحَقِّ مَا عَادَ إِلَيْهِ بَعْدُ فَقَالَ خُذُوا مِنْهَا وَاحِدًا وَرُدُّوا عَلَيْهَا الْآخَرَ قَالَ ثُمَّ سِرْنَا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَنَا كَأَنَّمَا عَلَيْنَا الطَّيْرُ تُظِلُّنَا فَإِذَا جَمَلٌ نَادٌّ حَتَّى إِذَا كَانَ بَيْنَ سِمَاطَيْنِ خَرَّ سَاجِدًا فَحَبَسَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ عَلَيَّ النَّاسَ مَنْ صَاحِبُ الْجَمَلِ فَإِذَا فِتْيَةٌ مِنْ الْأَنْصَارِ قَالُوا هُوَ لَنَا يَا رَسُولَ اللَّهِ قَالَ فَمَا شَأْنُهُ قَالُوا اسْتَنَيْنَا عَلَيْهِ مُنْذُ عِشْرِينَ سَنَةً وَكَانَتْ بِهِ شُحَيْمَةٌ فَأَرَدْنَا أَنْ نَنْحَرَهُ فَنَقْسِمَهُ بَيْنَ غِلْمَانِنَا فَانْفَلَتَ مِنَّا قَالَ بِيعُونِيهِ قَالُوا لَا بَلْ هُوَ لَكَ يَا رَسُولَ اللَّهِ قَالَ أَمَّا لِي فَأَحْسِنُوا إِلَيْهِ حَتَّى يَأْتِيَهُ أَجَلُهُ قَالَ الْمُسْلِمُونَ عِنْدَ ذَلِكَ يَا رَسُولَ اللَّهِ نَحْنُ أَحَقُّ بِالسُّجُودِ لَكَ مِنْ الْبَهَائِمِ قَالَ لَا يَنْبَغِي لِشَيْءٍ أَنْ يَسْجُدَ لِشَيْءٍ وَلَوْ كَانَ ذَلِكَ كَانَ النِّسَاءُ لِأَزْوَاجِهِنَّ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Musa] dari [Isa bin Abdul Malik] dari [Abu Az Zubair] dari [Jabir] Radliyallahu'anhu, ia berkata; saya keluar bersama Rasulullah shallallahu 'alaihi wasallam dalam satu perjalanan dan beliau apabila hendak buang hajat selalu bersembunyi hingga tidak kelihatan. Ketika itu kami sedang berada pada tanah lapang yang luas yang tidak ada pepohonan atau pun tanda kehidupan lalu beliau berkata: wahai Jabir ambillah air dengan bejanamu, dan marilah kita teruskan perjalanan. Kata Jabir, kami terus melanjutkan perjalanan hingga tidak terlihat. Tiba-tiba ada dua pohon yang jarak antara keduanya empat hasta. Beliau bersabda: Tolong kamu dekati pohon itu, ajaklah bicara, niscaya dia menjawab, katakanlah padanya 'temuilah pohon sebelahmu hingga aku bisa duduk di belakang kamu berdua'. Pohon itu mendekati (temannya, pohon sebelahnya) dan Rasulullah shallallahu 'alaihi wasallam duduk di belakang keduanya, kemudian kedua pohon itu kembali ke tempat masing-masing. Selanjutnya kami menaiki tunggangan kami, dan seakan-akan di atas kami ada seekor burung yang menaungi kami, lalu seorang perempuan bersama bayinya mencegat Rasulullah shallallahu 'alaihi wasallam, ia berkata; wahai Rasulullah sesungguhnya anak saya ini selalu diganggu syaitan setiap hari tiga kali. Jabir berkata; lalu Rasulullah shallallahu 'alaihi wasallam mengambil bayi tersebut dan meletakannya di depan kendaraannya lalu beliau berkata; pergilah hai musuh Allah! saya adalah Rasulullah. Rasul mengucapkannya sebanyak tiga kali. Kemudian beliau mengembalikannya kepada perempuan tersebut. Tatkala kami kembali dari perjalanan, kami melewati jalan semula, dan seorang perempuan bersama anaknya telah mencegat kami bersama dua domba yang digiringnya. Kemudian ia berkata; \"Wahai Rasulullah shallallahu 'alaihi wasallam terimalah hadiah dari saya ini, demi Dzat yang mengutus baginda dengan benar sungguh syaitan itu tidak datang lagi. \" Beliau berkata: ambilah satu dan kembalikan yang satunya kepadanya. Kemudian kami terus melanjutkan perjalanan dan burung seolah-olah memayungi kami, tiba-tiba ada unta melarikan diri, namun saat ia sampai pada dua rerimbunan pohon, ia langsung merunduk bersujud dan Rasulullah shallallahu 'alaihi wasallam menangkapnya. Rasul bertanya kepada orang-orang: \"Kemarilah hai orang-orang, siapa pemilik unta ini? Maka beberapa pemuda dari kaum Anshar menjawab; ia milik kami wahai Rasulullah, beliau bertanya: apa yang sedang dialaminya? Mereka menjawab; kami telah lelah mengurusnya selama dua puluh tahun dan ia telah mempunyai banyak lemak (sudah menjadi gemuk) maka kami ingin menyembelihnya serta ingin membagikannya diantara anak-anak kami, akan tetapi ia kabur dari kami. Beliau berkata: \"baiklah, kalau begitu jual saja kepada saya. \". Mereka menjawab; \"Ohh, nggak usah baginda, tetapi cukuplah unta itu sebagai (hadiah) untuk baginda. Nabi berujar; \"Okelah, jika ia milik saya maka berlaku baiklah kepadanya, sampai tiba ajalnya. Pada saat itu kaum muslimin berkata; Wahai Rasulullah kami lebih berhak untuk bersujud kepada baginda dari binatang, beliau bersabda: Tidaklah berhak satu (makhluk) bersujud kepada makhluk (lainnya), kalau sekiranya hal itu boleh maka para wanita diperkenankan sujud kepada suami-suami mereka. "},"18":{"ar":" حَدَّثَنَا يَعْلَى حَدَّثَنَا الْأَجْلَحُ عَنْ الذَّيَّالِ بْنِ حَرْمَلَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ أَقْبَلْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى دُفِعْنَا إِلَى حَائِطٍ فِي بَنِي النَّجَّارِ فَإِذَا فِيهِ جَمَلٌ لَا يَدْخُلُ الْحَائِطَ أَحَدٌ إِلَّا شَدَّ عَلَيْهِ فَذَكَرُوا ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَاهُ فَدَعَاهُ فَجَاءَ وَاضِعًا مِشْفَرَهُ عَلَى الْأَرْضِ حَتَّى بَرَكَ بَيْنَ يَدَيْهِ فَقَالَ هَاتُوا خِطَامًا فَخَطَمَهُ وَدَفَعَهُ إِلَى صَاحِبِهِ ثُمَّ الْتَفَتَ فَقَالَ مَا بَيْنَ السَّمَاءِ إِلَى الْأَرْضِ إِلَّا يَعْلَمُ أَنِّي رَسُولُ اللَّهِ إِلَّا عَاصِيَ الْجِنِّ وَالْإِنْسِ","id":"Telah menceritakan kepada kami [Ya'la] telah menceritakan kepada kami [Al Ajlah] dari [Adz Dzayyal bin Harmalah] dari [Jabir bin Abdullah] Radliyallahu'anhu ia berkata; kami kembali dari bepergian bersama Rasulullah shallallahu 'alaihi wasallam. Sampai kami tiba di satu perkampungan Bani Najjar, tiba-tiba ada seekor unta yang menghalangi setiap orang yang hendak memasuki perkebunan tersebut. Hal itu dilaporkan kepada Rasulullah shallallahu 'alaihi wasallam, maka beliau mendatanginya dan memanggil unta tersebut. Si unta datang dan meletakkan bibirnya di atas bumi hingga bertekuk lutut di hadapan beliau. Kemudian beliau bersabda: ambilkan seutas tali, selanjutnya beliau mengikatnya dengan tali tersebut dan mengembalikannya kepada pemiliknya. Kemudian beliau menengok ke belakang dan bersabda: Tidaklah seseorangpun diantara langit dan bumi melainkan dirinya mengetahui sesungguhnya saya adalah utusan Allah Subhanahu wa Ta'ala kecuali mereka yang durhaka; dari bangsa jin dan manusia. "},"19":{"ar":" أَخْبَرَنَا الْحَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ فَرْقَدٍ السَّبَخِيِّ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ أَنَّ امْرَأَةً جَاءَتْ بِابْنٍ لَهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ ابْنِي بِهِ جُنُونٌ وَإِنَّهُ يَأْخُذُهُ عِنْدَ غَدَائِنَا وَعَشَائِنَا فَيُخَبَّثُ عَلَيْنَا فَمَسَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدْرَهُ وَدَعَا فَثَعَّ ثَعَّةً وَخَرَجَ مِنْ جَوْفِهِ مِثْلُ الْجِرْوِ الْأَسْوَدِ فَسَعَى","id":"Telah mengabarkan kepada kami [Al Hajjaj bin Minhal] telah mencereitakan kepada kami [Hammad bin Salamah] dari [Farqad As Sabakhi] dari [Sa'id bin Jubair] dari [Ibnu Abbas] Radliyallahu'anhu, Bahwa seorang wanita datang membawa anaknya kepada Rasulullah shallallahu 'alaihi wasallam dan berkata: \"Ya Rasulullah, anak saya kemasukkan jin, jin tersebut selalu masuk pada waktu kami sedang makan siang dan makan malam kami, dan menjelek-jelekkan kami. \"Lalu Rasulullah shallallahu 'alaihi wasallam dan mendoakannya. Kemudian ia muntah dan keluar dari mulutnya sesuatu (seperti anak anjing) hitam lalu pergi. "},"20":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ سَعِيدٍ أَخْبَرَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ الْعَبْدِيُّ عَنْ إِبْرَاهِيمَ بْنِ طَهْمَانَ عَنْ سِمَاكٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَأَعْرِفُ حَجَرًا بِمَكَّةَ كَانَ يُسَلِّمُ عَلَيَّ قَبْلَ أَنْ أُبْعَثَ إِنِّي لَأَعْرِفُهُ الْآنَ","id":"Telah menceritakan kepada kami [Muhammad bin Sa'id] telah mengabarkan kepada kami [Yahya bin Abu Bakr Al 'Abdi] dari [Ibrahim bin Thahman] dari [Simak] dari [Jabir bin Samurah] Radliyallahu'anhu ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Saya benar-benar mengetahui ada sebongkah batu di Makkah yang waktu dulu dia mengucapkan salam kepadaku sebelum aku diutus. Sungguh saya benar-benar mengetahuinya sekarang\". "},"21":{"ar":" حَدَّثَنَا فَرْوَةُ حَدَّثَنَا الْوَلِيدُ بْنُ أَبِي ثَوْرٍ الْهَمْدَانِيُّ عَنْ إِسْمَعِيلَ السُّدِّيِّ عَنْ عَبَّادٍ أَبِي يَزِيدَ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَ كُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَكَّةَ فَخَرَجْنَا مَعَهُ فِي بَعْضِ نَوَاحِيهَا فَمَرَرْنَا بَيْنَ الْجِبَالِ وَالشَّجَرِ فَلَمْ نَمُرَّ بِشَجَرَةٍ وَلَا جَبَلٍ إِلَّا قَالَ السَّلَامُ عَلَيْكَ يَا رَسُولَ اللَّهِ","id":"Telah menceritakan kepada kami [Farwah] telah menceritakan kepada kami [Al Walid bin Abu Tsaur Al Hamdani] dari [Isma'il As Suddi] dari ['Abbad bin Abu Yazid] dari [Ali bin Abu Thalib] Radliyallahu'anhu ia berkata; Kami bersama Nabi shallallahu 'alaihi wasallam di Makkah. Lalu kami keluar bersamanya maka kami tidak melewati satu pohon atau bukit pun melainkan ia mengucapkan; ASSALAMU 'ALAIKA YA RASULALLAH (keselamatan senantiasa atas baginda wahai Rasulullah). "},"22":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ شِمْرِ بْنِ عَطِيَّةَ عَنْ رَجُلٍ مِنْ مُزَيْنَةَ أَوْ جُهَيْنَةَ قَالَ صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْفَجْرَ فَإِذَا هُوَ بِقَرِيبٍ مِنْ مِائَةِ ذِئْبٍ قَدْ أَقْعَيْنَ وُفُودُ الذِّئَابِ فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَرْضَخُوا لَهُمْ شَيْئًا مِنْ طَعَامِكُمْ وَتَأْمَنُونَ عَلَى مَا سِوَى ذَلِكَ فَشَكَوْا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحَاجَةَ قَالَ فَآذِنُوهُنَّ قَالَ فَآذَنُوهُنَّ فَخَرَجْنَ وَلَهُنَّ عُوَاءٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Syimr bin 'Athiyah] dari [seseorang] dari Muzainah atau Juhainah ia berkata; Rasulullah shallallahu 'alaihi wasallam shalat subuh ternyata beliau berada di dekat seratus serigala yang semuanya sudah pada jongkok. Rasulullah shallallahu 'alaihi wasallam hanya berkata kepada mereka (para sahabat) \" Tolong, lemparkanlah sedikit dari makanan kalian ke gerombolan mereka (serigala) maka makanan kalian yang lain akan aman. \" Lalu mereka mengadu kepada Rasulullah shallallahu 'alaihi wasallam untuk suatu keperluan. Rasul pun bersabda: Beritahukanlah kepada serigala-serigala itu. Maka para sahabat memberitahu gerombolan serigala bahwa mereka mempunyai keperluan sehingga harus lewat. Gerombolan serigala itu dengan sendirinya pergi dengan melolong. "},"23":{"ar":" أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي سُفْيَانَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ جَاءَ جِبْرِيلُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ جَالِسٌ حَزِينٌ وَقَدْ تَخَضَّبَ بِالدَّمِ مِنْ فِعْلِ أَهْلِ مَكَّةَ مِنْ قُرَيْشٍ فَقَالَ جِبْرِيلُ يَا رَسُولَ اللَّهِ هَلْ تُحِبُّ أَنْ أُرِيَكَ آيَةً قَالَ نَعَمْ فَنَظَرَ إِلَى شَجَرَةٍ مِنْ وَرَائِهِ فَقَالَ ادْعُ بِهَا فَدَعَا بِهَا فَجَاءَتْ وَقَامَتْ بَيْنَ يَدَيْهِ فَقَالَ مُرْهَا فَلْتَرْجِعْ فَأَمَرَهَا فَرَجَعَتْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَسْبِي حَسْبِي","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Al A'masy] dari [Abu Sufyan] dari [Anas bin Malik] ia berkata; Jibril datang kepada Rasulullah shallallahu 'alaihi wasallam ketika beliau sedang duduk sedih berlumuran darah disebabkan perlakuan orang-orang kafir Quraisy Makkah, lalu jibril berkata: wahai Rasulullah apakah baginda ingin saya perlihatkan tanda (kekuasaan Subhanahu wa Ta'ala) Rasul menjawab: 'ya': lalu beliau melihat sebuah pohon di belakangnya, jibril mengatakan: panggillah pohon tersebut, maka beliau memanggilnya dan pohon itu datang serta berdiri di hadapan beliau, kemudian Jibril berkata: \"Perintahkan untuk kembali\". Maka beliau memerintahkannya untuk kembali dan pohon itupun kembali (ke tempat asalnya) Rasulullah berkata: cukup-cukup. "},"24":{"ar":" أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا جَرِيرٌ وَأَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي ظَبْيَانَ عَنْ ابْنِ عَبَّاسٍ قَالَ أَتَى رَجُلٌ مِنْ بَنِي عَامِرٍ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا أُرِيكَ آيَةً قَالَ بَلَى قَالَ فَاذْهَبْ فَادْعُ تِلْكَ النَّخْلَةَ فَدَعَاهَا فَجَاءَتْ تَنْقُزُ بَيْنَ يَدَيْهِ قَالَ قُلْ لَهَا تَرْجِعْ قَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ارْجِعِي فَرَجَعَتْ حَتَّى عَادَتْ إِلَى مَكَانِهَا فَقَالَ يَا بَنِي عَامِرٍ مَا رَأَيْتُ رَجُلًا كَالْيَوْمِ أَسْحَرَ مِنْهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Jarir] dan [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Zhabyan] dari [Ibnu Abbas] Radliyallahu' anhu ia berkata; Seseorang dari bani 'Amir mendatangi Rasulullah shallallahu 'alaihi wasallam, lalu Rasulullah shallallahu 'alaihi wasallam mengatakan; Sudikah kamu saya perlihatkan kepada kamu satu tanda (kebesaran Allah Subhanahu wa Ta'ala) dia menjawab: ya! Rasul berkata: pergi dan panggil pohon kurma itu, lalu ia memanggilnya dan kurma itu datang dengan melompat ke hadapan beliau, kemudian orang itu berkata; katakan padanya untuk kembali, maka Rasulullah shallallahu 'alaihi wasallam berkata kepada pohon itu: kembalilah, maka pohon itu kembali sehingga sampai ke tempatnya, orang itu menyeru; wahai bani 'Amir saya tidak melihat seorang lelakipun yang lebih pandai menyihir daripada dirinya. "},"25":{"ar":" أَخْبَرَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا شُعَيْبُ بْنُ صَفْوَانَ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِي الضُّحَى عَنْ ابْنِ عَبَّاسٍ قَالَ دَعَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلَالًا فَطَلَبَ بِلَالٌ الْمَاءَ ثُمَّ جَاءَ فَقَالَ لَا وَاللَّهِ مَا وَجَدْتُ الْمَاءَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهَلْ مِنْ شَنٍّ فَأَتَاهُ بِشَنٍّ فَبَسَطَ كَفَّيْهِ فِيهِ فَانْبَعَثَتْ تَحْتَ يَدَيْهِ عَيْنٌ قَالَ فَكَانَ ابْنُ مَسْعُودٍ يَشْرَبُ وَغَيْرُهُ يَتَوَضَّأُ","id":"Telah mengabarkan kepada kami [Ismail bin Ibrahim] telah menceritakan kepada kami [Syuaib bin Shafwan] dari ['Atha` bin As Sa`ib] dari [Abu Al Dluha] dari [Ibnu Abbas] Radliyallahu'anhu ia berkata; Nabi shallallahu 'alaihi wasallam memanggil Bilal, dan Bilal mencari air kemudian datang dan berkata; tidak, demi Allah Subhanahu wa Ta'ala saya tidak mediate air, maka Nabi shallallahu 'alaihi wasallam bertanya: apakah kamu mempunyai wadah air?, lalu ia (Bilal) memberi beliau sebuah wadah air dan beliaupun membentangkan kedua tangan beliau di wadah itu, maka mengalirkan air dari kedua telapak tangan beliau, perawi berkata; Ibnu Mas'ud dan yang lainnya juga meminum dan berwudlu (dari air tersebut). "},"26":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ عَنْ نُبَيْحٍ الْعَنَزِيِّ قَالَ قَالَ جَابِرُ بْنُ عَبْدِ اللَّهِ غَزَوْنَا أَوْ سَافَرْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ يَوْمَئِذٍ بِضْعَةَ عَشَرَ وَمِائَتَانِ فَحَضَرَتْ الصَّلَاةُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ فِي الْقَوْمِ مِنْ طَهُورٍ فَجَاءَ رَجُلٌ يَسْعَى بِإِدَاوَةٍ فِيهَا شَيْءٌ مِنْ مَاءٍ لَيْسَ فِي الْقَوْمِ مَاءٌ غَيْرُهُ فَصَبَّهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قَدَحٍ ثُمَّ تَوَضَّأَ فَأَحْسَنَ الْوُضُوءَ ثُمَّ انْصَرَفَ وَتَرَكَ الْقَدَحَ فَرَكِبَ النَّاسُ ذَلِكَ الْقَدَحَ وَقَالُوا تَمَسَّحُوا تَمَسَّحُوا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رِسْلِكُمْ حِينَ سَمِعَهُمْ يَقُولُونَ ذَلِكَ فَوَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَفَّهُ فِي الْمَاءِ وَالْقَدَحِ وَقَالَ بِسْمِ اللَّهِ ثُمَّ قَالَ أَسْبِغُوا الطُّهُورَ فَوَالَّذِي هُوَ ابْتَلَانِي بِبَصَرِي لَقَدْ رَأَيْتُ الْعُيُونَ عُيُونَ الْمَاءِ تَخْرُجُ مِنْ بَيْنِ أَصَابِعِهِ فَلَمْ يَرْفَعْهَا حَتَّى تَوَضَّئُوا أَجْمَعُونَ","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Abu 'Awanah] dari [Al Aswad bin Qais] dari [Nubaih Al 'Anazi] ia berkata; [Jabir bin Abdullah] berkata; Kami pernah berperang atau mengadakan perjalanan bersama Rasulullah shallallahu 'alaihi wasallam. Pada hari itu jumlah kami sebanyak dua ratus sekian orang. Lalu tibalah waktu shalat. Rasulullah shallallahu 'alaihi wasallam bertanya: \"Apakah semua orang dalam keadaan suci?\" Kemudian datang seseorang membawa jerigen kulit berisi air, dan tidak ada air lagi kecuali air tersebut. Kemudian Rasulullah menuangkannya ke dalam bejana (yang lebih besar) kemudian beliau berwudlu dengan sebaik-baik wudlu, lalu beliau berpaling meninggalkan bejana itu. Maka orang-orang berebut mendekati bejana tersebut, seraya mereka berkata; \"Cukup kalian mengusap saja. \" Lalu Rasulullah shallallahu 'alaihi wasallam berkata: \"Maaf beri aku jalan\". Rasul ucapkan demikian ketika beliau mendengar mereka berucap di atas. Selanjutnya Rasulullah shallallahu 'alaihi wasallam meletakkan telapak tangannya di air tersebut seraya berucap: Dengan nama Allah Subhanahu wa Ta'ala, kemudian beliau berkata: Sempurnakan wudlu kalian. (Jabir Radliyallahu'anhu) berkata; Demi Dzat yang tidak mengaburkan penglihatan saya, saya melihat dengan jelas mata air yang keluar dari jari-jari beliau dan beliau tidak mengangkat tangan beliau sampai mereka semua berwudlu. "},"27":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ وَسَعِيدُ بْنُ الرَّبِيعِ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ وَحُصَيْنٍ سَمِعَا سَالِمَ بْنَ أَبِي الْجَعْدِ يَقُولُ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ قَالَ أَصَابَنَا عَطَشٌ فَجَهَشْنَا فَانْتَهَيْنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَضَعَ يَدَهُ فِي تَوْرٍ فَجَعَلَ يَفُورُ كَأَنَّهُ عُيُونٌ مِنْ خَلَلِ أَصَابِعِهِ وَقَالَ اذْكُرُوا اسْمَ اللَّهِ فَشَرِبْنَا حَتَّى وَسِعَنَا وَكَفَانَا وَفِي حَدِيثِ عَمْرِو بْنِ مُرَّةَ فَقُلْنَا لِجَابِرٍ كَمْ كُنْتُمْ قَالَ كُنَّا أَلْفًا وَخَمْسَ مِائَةٍ وَلَوْ كُنَّا مِائَةَ أَلْفٍ لَكَفَانَا","id":"Telah mengabarkan kepada kami [Abu Al Walid Al Thayalitsi] dan [Sa'id bin Ar Rabi'] keduanya berkata; telah menceritakan kepada kami [Syu'bah] dari [Amr bin Murrah] dan [Hushain] keduanya mendengar [Salim bin Abu Ja'd] berkata; saya mendengar [Jabir bin Abdullah] Radliyallahu'anhu berkata; kami merasa sangat kehausan dan kami berjalan dengan cepat sampai kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau memasukkan tangannya ke periuk kemudian air memancar dari jari-jemari beliau seperti mata air, dan beliau berkata: sebutlah nama Allah Subhanahu wa Ta'ala (maka kamipun menyebut nama Allah Subhanahu wa Ta'ala) dan kami minum sampai kami kenyang dan cukup, Dalam hadits Amru bin Murrah, kami bertanya kepada Jabir Radliyallahu'anhu; berapa jumlah kalian (waktu itu)? ia menjawab; kami berjumlah seribu lima ratus orang, kalaupun sekiranya kami (waktu itu) seratus ribu orang niscaya air itu cukup bagi kami. "},"28":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرَّقَاشِيُّ حَدَّثَنَا جَعْفَرُ بْنُ سُلَيْمَانَ حَدَّثَنَا الْجَعْدُ أَبُو عُثْمَانَ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ حَدَّثَنَا جَابِرُ بْنُ عَبْدِ اللَّهِ قَالَ شَكَا أَصْحَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَطَشَ فَدَعَا بِعُسٍّ فَصُبَّ فِيهِ مَاءٌ وَوَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ فِيهِ قَالَ فَجَعَلْتُ أَنْظُرُ إِلَى الْمَاءِ يَنْبُعُ عُيُونًا مِنْ بَيْنِ أَصَابِعِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسُ يَسْتَقُونَ حَتَّى اسْتَقَى النَّاسُ كُلُّهُمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah Ar Raqqasyi] telah menceritakan kepada kami [Ja'far bin Sulaiman] telah menceritakan kepada kami [Al Ja'du Abu Utsman] telah menceritakan kepada kami [Anas bin Malik] Radliyallahu'anhu telah menceritakan kepada kami [Jabir bin Abdullah] Radliyallahu'anhu ia berkata; Para sahabat Rasulullah shallallahu 'alaihi wasallam mengadu kepada beliau tentang rasa haus (yang mereka rasakan) lalu beliau meminta bejana yang besar dan dibagikan air ke dalamnya dan Rasulullah shallallahu 'alaihi wasallam meletakkan tangannya di bejana tersebut. Perawi berkata; aku melihat mata air yang memancar dari jari-jemari Rasulullah shallallahu 'alaihi wasallam, orang-orang mengambilnya untuk minum sehingga mereka semuanya dapat meminumnya. "},"29":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَ سَمِعَ عَبْدُ اللَّهِ بِخَسْفٍ فَقَالَ كُنَّا أَصْحَابَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعُدُّ الْآيَاتِ بَرَكَةً وَأَنْتُمْ تَعُدُّونَهَا تَخْوِيفًا إِنَّا بَيْنَمَا نَحْنُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَيْسَ مَعَنَا مَاءٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اطْلُبُوا مَنْ مَعَهُ فَضْلُ مَاءٍ فَأُتِيَ بِمَاءٍ فَصَبَّهُ فِي الْإِنَاءِ ثُمَّ وَضَعَ كَفَّهُ فِيهِ فَجَعَلَ الْمَاءُ يَخْرُجُ مِنْ بَيْنِ أَصَابِعِهِ ثُمَّ قَالَ حَيَّ عَلَى الطَّهُورِ الْمُبَارَكِ وَالْبَرَكَةُ مِنْ اللَّهِ تَعَالَى فَشَرِبْنَا و قَالَ عَبْدُ اللَّهِ كُنَّا نَسْمَعُ تَسْبِيحَ الطَّعَامِ وَهُوَ يُؤْكَلُ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Israil] dari [Mansur] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] ia berkata; Abdullah mendengar tentang gerhana bulan, lalu ia berkata; Kami para sahabat Nabi Muhammad shallallahu 'alaihi wasallam menganggap tanda-tanda (kekuasaan Allah Subhanahu wa Ta'ala) Sebagai suatu keberkahan sementara kalian menganggapnya sebagai sesuatu yang menakutkan. Sesungguhnya ketika kami berada bersama Rasulullah shallallahu 'alaihi wasallam kami tidak memiliki air. Lalu Rasulullah shallallahu 'alaihi wasallam berkata: \"Mintalah kepada yang mempunyai kelebihan air. \" Kemudian didatangkan kepada Rasulullah shallallahu 'alaihi wasallam dan beliau pun menuangkannya ke sebuah bejana, beliau meletakkan telapak tangan ke dalamnya maka terpancarlah air dari jari-jemari Rasulullah shallallahu 'alaihi wasallam dan beliau menyeru: Mari bersegera bersuci yang penuh keberkahan, dan keberkahan itu hanya milik Allah Subhanahu wa Ta'ala, lalu kami meminumnya. Abdullah berkata; Bahkan dulu kami pernah mendengar tasbih suatu makanan padahal ia sedang disantap. "},"30":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبُو الْجَوَّابِ عَنْ عَمَّارِ بْنِ رُزَيْقٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَ زُلْزِلَتْ الْأَرْضُ عَلَى عَهْدِ عَبْدِ اللَّهِ فَأُخْبِرَ بِذَلِكَ فَقَالَ إِنَّا كُنَّا أَصْحَابَ مُحَمَّدٍ نَرَى الْآيَاتِ بَرَكَاتٍ وَأَنْتُمْ تَرَوْنَهَا تَخْوِيفًا بَيْنَا نَحْنُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ إِذْ حَضَرَتْ الصَّلَاةُ وَلَيْسَ مَعَنَا مَاءٌ إِلَّا يَسِيرٌ فَدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَاءٍ فِي صَحْفَةٍ وَوَضَعَ كَفَّهُ فِيهِ فَجَعَلَ الْمَاءُ يَنْبَجِسُ مِنْ بَيْنِ أَصَابِعِهِ ثُمَّ نَادَى حَيَّ عَلَى الْوَضُوءِ وَالْبَرَكَةُ مِنْ اللَّهِ فَأَقْبَلَ النَّاسُ فَتَوَضَّئُوا وَجَعَلْتُ لَا هَمَّ لِي إِلَّا مَا أُدْخِلُهُ بَطْنِي لِقَوْلِهِ وَالْبَرَكَةُ مِنْ اللَّهِ فَحَدَّثْتُ بِهِ سَالِمَ بْنَ أَبِي الْجَعْدِ فَقَالَ كَانُوا خَمْسَ عَشْرَةَ مِائَةٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Abu Al Jawwab] dari ['Amar bin Ruzaiq] dari [Al A'masy] dari [Ibrahim] dari [Alqamah] dari [Abdullah] ia berkata; telah terjadi gempa pada masa Abdullah dan kejadian tersebut diberitahukan kepada Abdullah lalu beliau berkata: Kami para sahabat menganggap tanda-tanda (kebesaran Allah Subhanahu wa Ta'ala) sebagai suatu keberkahan, sementara kalian menganggapnya sebagai hal yang menakutkan. Pernah ketika kami sedang bersama Rasulullah shallallahu 'alaihi wasallam dalam sebuah perjalanan, tiba-tiba waktu shalat tiba, sementara kami tidak membawa air kecuali sedikit. Lalu Rasulullah shallallahu 'alaihi wasallam meminta air di bejana yang besar, dan beliau meletakkan telapak tangannya padanya. Secara mengejutkan air memancar diantara jari-jemarinya kemudian beliau menyeru: \"Hai, Kemarilah untuk mengambil air wudhu dan keberkahan dari Allah Subhanahu wa Ta'ala.\" Maka semuanya orang-orang mengambil wudhu sementara saya tidak mempunyai keinginan apa-apa kecuali saya hanya ingin meminumnya dan memasukkan air tersebut ke dalam perut saya karena beliau bersabda: keberkahan dari Allah. Aku ceritakan peristiwa itu kepada [Salim bin Abu Al Ja'd], maka ia berkata; mereka (waktu itu) berjumlah lima belas orang. "},"31":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا مُعَاذُ بْنُ الْعَلَاءِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَخْطُبُ إِلَى جِذْعٍ فَلَمَّا اتَّخَذَ الْمِنْبَرَ حَنَّ الْجِذْعُ حَتَّى أَتَاهُ فَمَسَحَهُ","id":"Telah mengabarkan kepada kami [Utsman bin Umar] telah mengabarkan kepada kami [Mu'adz bin Al 'Ala`] dari [Nafi'] dari [Ibnu Umar] Pada awal mulanya Rasulullah shallallahu 'alaihi wasallam selalu berkhutbah dengan bersandar pada sebatang kayu. Setelah beliau menggunakan mimbar (dan kayu itu tak dipakai lagi), kayu itu merintih sehingga beliau mengelusnya. "},"32":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ حُمَيْدٍ حَدَّثَنَا تَمِيمُ بْنُ عَبْدِ الْمُؤْمِنِ حَدَّثَنَا صَالِحُ بْنُ حَيَّانَ حَدَّثَنِي ابْنُ بُرَيْدَةَ عَنْ أَبِيهِ قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا خَطَبَ قَامَ فَأَطَالَ الْقِيَامَ فَكَانَ يَشُقُّ عَلَيْهِ قِيَامُهُ فَأُتِيَ بِجِذْعِ نَخْلَةٍ فَحُفِرَ لَهُ وَأُقِيمَ إِلَى جَنْبِهِ قَائِمًا لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا خَطَبَ فَطَالَ الْقِيَامُ عَلَيْهِ اسْتَنَدَ إِلَيْهِ فَاتَّكَأَ عَلَيْهِ فَبَصُرَ بِهِ رَجُلٌ كَانَ وَرَدَ الْمَدِينَةَ فَرَآهُ قَائِمًا إِلَى جَنْبِ ذَلِكَ الْجِذْعِ فَقَالَ لِمَنْ يَلِيهِ مِنْ النَّاسِ لَوْ أَعْلَمُ أَنَّ مُحَمَّدًا يَحْمَدُنِي فِي شَيْءٍ يَرْفُقُ بِهِ لَصَنَعْتُ لَهُ مَجْلِسًا يَقُومُ عَلَيْهِ فَإِنْ شَاءَ جَلَسَ مَا شَاءَ وَإِنْ شَاءَ قَامَ فَبَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ائْتُونِي بِهِ فَأَتَوْهُ بِهِ فَأُمِرَ أَنْ يَصْنَعَ لَهُ هَذِهِ الْمَرَاقِيَ الثَّلَاثَ أَوْ الْأَرْبَعَ هِيَ الْآنَ فِي مِنْبَرِ الْمَدِينَةِ فَوَجَدَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ذَلِكَ رَاحَةً فَلَمَّا فَارَقَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجِذْعَ وَعَمَدَ إِلَى هَذِهِ الَّتِي صُنِعَتْ لَهُ جَزِعَ الْجِذْعُ فَحَنَّ كَمَا تَحِنُّ النَّاقَةُ حِينَ فَارَقَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَزَعَمَ ابْنُ بُرَيْدَةَ عَنْ أَبِيهِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ سَمِعَ حَنِينَ الْجِذْعِ رَجَعَ إِلَيْهِ فَوَضَعَ يَدَهُ عَلَيْهِ وَقَالَ اخْتَرْ أَنْ أَغْرِسَكَ فِي الْمَكَانِ الَّذِي كُنْتَ فِيهِ فَتَكُونَ كَمَا كُنْتَ وَإِنْ شِئْتَ أَنْ أَغْرِسَكَ فِي الْجَنَّةِ فَتَشْرَبَ مِنْ أَنْهَارِهَا وَعُيُونِهَا فَيَحْسُنُ نَبْتُكَ وَتُثْمِرُ فَيَأْكُلَ أَوْلِيَاءُ اللَّهِ مِنْ ثَمَرَتِكَ وَنَخْلِكَ فَعَلْتُ فَزَعَمَ أَنَّهُ سَمِعَ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَقُولُ لَهُ نَعَمْ قَدْ فَعَلْتُ مَرَّتَيْنِ فَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اخْتَارَ أَنْ أَغْرِسَهُ فِي الْجَنَّةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Humaid] telah menceritakan kepada kami [Tamim bin 'Abdul Mukmin] telah menceritakan kepada kami [Shalih bin Hayyan] telah menceritakan kepadaku [Ibnu Buraidah] dari [ayahnya] ia berkata; Pada awal mulanya Nabi shallallahu 'alaihi wasallam apabila berkhutbah dengan berdiri, dan beliau lama sekali berdiri. Maka hal itu sangat memberatkan beliau. Kemudian didatangkan pelepah kurma, tanah dibuat kubangan, dan pohon kurma itu ditancapkannya di samping Nabi shallallahu 'alaihi wasallam agar beliau pergunakan saat berdiri. Jika nabi berkhutbah dan berdiri lama, beliau bersandar pada batang kurma tersebut. Seorang lelaki yang baru datang ke Madinah melihat kejadian ini, yaitu beliau sedang berdiri di samping batang kurma tersebut. Maka si lelaki itu menyampaikan uneg-unegnya kepada orang-orang di sekelilingnya; \"Kalaulah saya tahu bahwa Muhammad akan memujiku karena kulakukan suatu hal yang meringankan bebannya niscaya aku membuatkannya suatu tempat duduk yang dapat beliau pergunakan untuk berdiri, apabila dia suka maka dia dapat duduk dan apabila dia suka dia bisa berdiri di tempat tersebut. \" Lalu perihal tersebut disampaikan kepada Rasulullah shallallahu 'alaihi wasallam dan beliau pun berkata: \"Bawa orang tersebut ke hadapanku\". Lalu orang tersebut didatangkan dan diperintahkannya untuk membuatkan tangga yang memiliki tiga atau empat tangga seperti yang sekarang ada pada mimbar Madinah. Rasulullah shallallahu 'alaihi wasallam merasakan kenyamanan dengan hal itu. Tatkala beliau meninggalkan batang pohon tersebut (yang dulu pernah digunakannya) dan bersandar pada mimbar yang dibuat untuknya, Maka batang pohon kurma itu merasa sedih dan merintih sebagaimana rintihan unta tatkala Rasulullah shallallahu 'alaihi wasallam meninggalkannya. Ibnu Buraidhah berkeyakinan dari ayahnya bahwa Nabi shallallahu 'alaihi wasallam ketika mendengarkan rintihan batang kurma tersebut beliau kembali meletakkan tangannya padanya dan berkata: \"Pilihlah apakah kamu saya tanam kembali di tempat semula atau saya tanam (nanti) di surga sehingga kamu dapat menghisap dari sungai dan mata airnya yang membuat pertumbuhan kamu menjadi baik dan berbuah, dan sehingga para wali Allah Subhanahu wa Ta'ala dapat memakan buah kamu (kurma) maka saya akan melakukannya. \" Ayah Ibnu Buraidah berkeyakinan bahwa dia mendengar dari Nabi shallallahu 'alaihi wasallam, beliau berkata kepada batang kurma tersebut: \"Baik, telah kulakukan (Nabi mengulangi ucapannya dua kali. \" Lalu Nabi shallallahu 'alaihi wasallam di tanya dan beliau menjawab: batang tersebut memilih agar saya menanamnya di surga nanti. "},"33":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ سُلَيْمَانَ بْنِ كَثِيرٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ الْأَنْصَارِيِّ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُومُ إِلَى جِذْعٍ قَبْلَ أَنْ يُجْعَلَ الْمِنْبَرُ فَلَمَّا جُعِلَ الْمِنْبَرُ حَنَّ ذَلِكَ الْجِذْعُ حَتَّى سَمِعْنَا حَنِينَهُ فَوَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ عَلَيْهِ فَسَكَنَ","id":"Telah mengabarkan kepada kami [Muhammad bin Katsir] dari [Sulaiman bin Katsir] dari [Az Zuhri] dari [Sa'id bin Al Musayyib] dari [Jabir bin Abdullah] Radliyallahu'anhu berkata; Dahulu Rasulullah shallallahu 'alaihi wasallam selalu berdiri dengan bersandar ke batang kurma sebelum dibuatkan mimbar. Ketika dibuatkan mimbar, batang kurma tersebut merintih sampai kami mendengar rintihannya, lalu Rasulullah shallallahu 'alaihi wasallam meletakkan tangan beliau padanya dan ia pun diam. "},"34":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ حَدَّثَنَا سُلَيْمَانُ بْنُ كَثِيرٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ حَفْصِ بْنِ عُبَيْدِ اللَّهِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ إِلَى خَشَبَةٍ فَلَمَّا صُنِعَ الْمِنْبَرُ فَجَلَسَ عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَنَّتْ حَنِينَ الْعِشَارِ حَتَّى وَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ عَلَيْهَا فَسَكَنَتْ","id":"Telah mengabarkan kepada kami [Muhammad bin Katsir] telah menceritakan kepada kami [Sulaiman bin Katsir] dari [Yahya bin Sa'id] dari [Hafs bin Ubaidullah] dari [Jabir bin Abdullah] Radliyallahu'anhu ia berkata; Dahulu Nabi shallallahu 'alaihi wasallam berkhutbah dengan bersandar pada batang kayu, maka tatkala telah dibuatkan mimbar Rasulullah shallallahu 'alaihi wasallam duduk di atasnya, lalu batang kayu tersebut merintih seperti rintihan seekor unta betina, sehingga Rasulullah shallallahu 'alaihi wasallam meletakkan tangan beliau padanya dan ia pun diam. "},"35":{"ar":" أَخْبَرَنَا فَرْوَةُ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا عَنْ أَبِيهِ عَنْ أَبِي إِسْحَقَ عَنْ سَعِيدِ بْنِ أَبِي كَرِبٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ حَنَّتْ الْخَشَبَةُ حَنِينَ النَّاقَةِ الْخَلُوجِ","id":"Telah mengabarkan kepada kami [Farwah] telah menceritakan kepada kami [Yahya bin Zakaria] dari [ayahnya] dari [Abu Ishaq] dari [Sa'id bin Abu Karb] dari [Jabir bin Abdullah] Radliyallahu'anhu ia berkata; Batang kayu itu merintih bagaikan rintihan unta betina yang diambil anaknya. "},"36":{"ar":" أَخْبَرَنَا زَكَرِيَّا بْنُ عَدِيٍّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ الطُّفَيْلِ بْنِ أُبَيِّ بْنِ كَعْبٍ عَنْ أَبِيهِ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي إِلَى جِذْعٍ وَيَخْطُبُ إِلَيْهِ إِذْ كَانَ الْمَسْجِدُ عَرِيشًا فَقَالَ لَهُ رَجُلٌ مِنْ أَصْحَابِهِ أَلَا نَجْعَلُ لَكَ عَرِيشًا تَقُومُ عَلَيْهِ يَرَاكَ النَّاسُ يَوْمَ الْجُمُعَةِ وَتُسْمِعُ مِنْ خُطْبَتِكَ قَالَ نَعَمْ فَصَنَعَ لَهُ الثَّلَاثَ دَرَجَاتٍ هُنَّ اللَّوَاتِي عَلَى الْمِنْبَرِ فَلَمَّا صُنِعَ الْمِنْبَرُ وَوُضِعَ فِي مَوْضِعِهِ الَّذِي وَضَعَهُ فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَلَمَّا جَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرِيدُ الْمِنْبَرَ مَرَّ عَلَيْهِ فَلَمَّا جَاوَزَهُ خَارَ الْجِذْعُ حَتَّى تَصَدَّعَ وَانْشَقَّ فَرَجَعَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَسَحَهُ بِيَدِهِ حَتَّى سَكَنَ ثُمَّ رَجَعَ إِلَى الْمِنْبَرِ قَالَ فَكَانَ إِذَا صَلَّى صَلَّى إِلَيْهِ فَلَمَّا هُدِمَ الْمَسْجِدُ أَخَذَ ذَلِكَ الْجِذْعَ أُبَيُّ بْنُ كَعْبٍ فَلَمْ يَزَلْ عِنْدَهُ حَتَّى بَلِيَ وَأَكَلَتْهُ الْأَرَضَةُ وَعَادَ رُفَاتًا","id":"Telah mengabarkan kepada kami [Zakaria bin 'Adi] dari [Ubaidullah bin Amr] dari [Abdullah bin Muhammad bin 'Aqil] dari [Ath Thufail bin Ubay bin Ka'ab] dari [ayahnya] Radliyallahu'anhu ia berkata; Dahulu Rasulullah shallallahu 'alaihi wasallam shalat bersandar pada batang kurma dan begitu juga ketika berkhutbah saat masjid masih belum memiliki tempat berteduh. Lalu seorang laki-laki dari sahabat beliau berkata kepadanya; \"Sudikah baginda kami buatkan tempat berteduh (mimbar) dan diletakkanlah mimbar itu di tempat baginda bisa berdiri di atasnya dan orang-orang dapat melihat baginda pada (khutbah) hari jum`at dan mereka dapat mendengarkan kkhutbah baginda. Beliau menjawab: \"Ya, boleh\". Maka dibuatkanlah untuk beliau tiga anak tangga yang berada pada mimbar dan diletakkan di tempat Nabi shallallahu 'alaihi wasallam meletakkannya (batang kurma). Tatkala beliau datang menuju mimbar, beliau melewati batang kurma itu, maka batang kurma itu menangis hingga terbanting dan terbelah. Lalu Rasulullah shallallahu 'alaihi wasallam kembali kepadanya. Beliau mengusapnya dengan tangannya hingga pohon kurma itu tenang kembali dan nabi ke mimbar semula. Dan Nabi jika shalat, ia menghadap pohon itu. Tatkala masjid diruntuhkan Ubai bin Ka'ab mengambil batang kurma itu dan menyimpannya sampai lapuk serta dimakan rayap sampai hancur. "},"37":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ مُجَالِدٍ عَنْ أَبِي الْوَدَّاكِ عَنْ أَبِي سَعِيدٍ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ إِلَى لِزْقِ جِذْعٍ فَأَتَاهُ رَجُلٌ رُومِيٌّ فَقَالَ أَصْنَعُ لَكَ مِنْبَرًا تَخْطُبُ عَلَيْهِ فَصَنَعَ لَهُ مِنْبَرًا هَذَا الَّذِي تَرَوْنَ قَالَ فَلَمَّا قَامَ عَلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ حَنَّ الْجِذْعُ حَنِينَ النَّاقَةِ إِلَى وَلَدِهَا فَنَزَلَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَضَمَّهُ إِلَيْهِ فَسَكَنَ فَأُمِرَ بِهِ أَنْ يُحْفَرَ لَهُ وَيُدْفَنَ","id":"Telah menceritakan kepada kami [Ubaidullah bin Sa'id] telah menceritakan kepada kami [Abu Usamah] dari [Mujalid] dari [Abu Al Waddak] dari [Abu Sa'id] ia berkata; Dahulu Rasulullah shallallahu 'alaihi wasallam berkhutbah dengan bersandar pada sebatang batang kurma, lalu seorang dari Romawi mendatangi beliau dan berkata; Saya akan buatkan mimbar dan baginda dapat berkhutbah di atas, maka dia pun membuatkan mimbar sebagaimana yang kalian lihat ini. Perawi berkata; maka tatkala Nabi shallallahu 'alaihi wasallam berdiri (di mimbar) berkkhutbah, batang kurma itu merintih bagaikan unta betina yang kehilangan anaknya. lalu Rasulullah shallallahu 'alaihi wasallam turun mendekatinya serta memeluknya maka ia pun diam, lalu Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk membuat lubang dan menguburnya. "},"38":{"ar":" أَخْبَرَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا الصَّعْقُ قَالَ سَمِعْتُ الْحَسَنَ يَقُولُ لَمَّا أَنْ قَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ جَعَلَ يُسْنِدُ ظَهْرَهُ إِلَى خَشَبَةٍ وَي��حَدِّثُ النَّاسَ فَكَثُرُوا حَوْلَهُ فَأَرَادَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُسْمِعَهُمْ فَقَالَ ابْنُوا لِي شَيْئًا أَرْتَفِعُ عَلَيْهِ قَالُوا كَيْفَ يَا نَبِيَّ اللَّهِ قَالَ عَرِيشٌ كَعَرِيشِ مُوسَى فَلَمَّا أَنْ بَنَوْا لَهُ قَالَ الْحَسَنُ حَنَّتْ وَاللَّهِ الْخَشَبَةُ قَالَ الْحَسَنُ سُبْحَانَ اللَّهِ هَلْ تُبْتَغَى قُلُوبُ قَوْمٍ سَمِعُوا قَالَ أَبُو مُحَمَّد يَعْنِي هَذَا","id":"Telah mengabarkan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Ash Sh'aq] ia berkata; saya mendengar [Al Hasan] berkata; Tatkala Nabi shallallahu 'alaihi wasallam datang ke Madinah beliau menyandarkan punggungnya pada sebatang pohon sambil memberikan wejangan kepada orang-orang. Lambat laun semakin banyaklah hadirin yang berada di sekeliling beliau. Hal ini menjadikan beliau berniat agar semua -tanpa terkecuali-mendengar ucapannya. Maka beliau shallallahu 'alaihi wasallam sabdakan \"Tolong, buatkan untukku mimbar yang tinggi sebagaimana yang dimiliki Musa! \" Tatkala mereka membuatnya, Batang pohon itu demi Allah -kata Alhasan- merintih. Al Hasan berkata lagi; Maha suci Allah Subhanahu wa Ta'ala, apakah hati orang-orang yang mendengar itu masih bisa diharapkan (patuh)? Abu Muhammad berkata; maksudnya orang-orang yang mendengar (kisah) ini. "},"39":{"ar":" أَخْبَرَنَا الْحَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَمَّارِ بْنِ أَبِي عَمَّارٍ عَنْ ابْنِ عَبَّاسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَخْطُبُ إِلَى جِذْعٍ قَبْلَ أَنْ يَتَّخِذَ الْمِنْبَرَ فَلَمَّا اتَّخَذَ الْمِنْبَرَ وَتَحَوَّلَ إِلَيْهِ حَنَّ الْجِذْعُ فَاحْتَضَنَهُ فَسَكَنَ وَقَالَ لَوْ لَمْ أَحْتَضِنْهُ لَحَنَّ إِلَى يَوْمِ الْقِيَامَةِ أَخْبَرَنَا الْحَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ عَنْ أَنَسٍ بِمِثْلِهِ","id":"Telah mengabarkan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad bin Salamah] dari ['Amar bin Abu 'Amar] dari [Ibnu Abbas] Bahwa Nabi shallallahu 'alaihi wasallam dulu pernah berkhutbah bersandar pada sebatang pohon sebelum beliau dibuatkan mimbar. Tatkala beliau dibuatkan mimbar dan beralih padanya, batang pohon itu merintih, hingga beliau memeluknya dan ia diam. Beliau tambahkan: \"Kalau tidak aku peluk niscaya ia menangis sampai hari kiamat. \" Telah mengabarkan kepada kami [Al Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad] dari [Tsabit] dari [Anas bin Malik] Radliyallahu'anhu seperti hadits di atas. "},"40":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا الْمَسْعُودِيُّ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَ حَنَّتْ الْخَشَبَةُ الَّتِي كَانَ يَقُومُ عِنْدَهَا فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْهَا فَوَضَعَ يَدَهُ عَلَيْهَا فَسَكَنَتْ","id":"Telah mengabarkan kepada kami [Abdullah bin Yazid] telah menceritakan kepada kami [Al Mas'udi] dari [Abu Hazim] dari [Sahl bin Sa'id] ia berkata; Batang pohon yang dulu beliau jadikan untuk bersandar saat berdiri merintih, lalu Rasulullah shallallahu 'alaihi wasallam berdiri mendekatinya dan meletakkan tangan beliau padanya, sehingga pohon itu pun diam. "},"41":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ بْنِ أَبَانَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدٍ الْمُحَارِبِيُّ عَنْ عَبْدِ الْوَاحِدِ بْنِ أَيْمَنَ الْمَكِّيِّ عَنْ أَبِيهِ قَالَ قُلْتُ لِجَابِرِ بْنِ عَبْدِ اللَّهِ حَدِّثْنِي بِحَدِيثٍ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمِعْتَهُ مِنْهُ أَرْوِيهِ عَنْكَ فَقَالَ جَابِرٌ كُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْخَنْدَقِ نَحْفُرُهُ فَلَبِثْنَا ثَلَاثَةَ أَيَّامٍ لَا نَطْعَمُ طَعَامًا وَلَا نَقْدِرُ عَلَيْهِ فَعَرَضَتْ فِي الْخَنْدَقِ كُدْيَةٌ فَجِئْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ هَذِهِ كُدْيَةٌ قَدْ عَرَضَتْ فِي الْخَنْدَقِ فَرَشَشْنَا عَلَيْهَا الْمَاءَ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبَطْنُهُ مَعْصُوبٌ بِحَجَرٍ فَأَخَذَ الْمِعْوَلَ أَوْ الْمِسْحَاةَ ثُمَّ سَمَّى ثَلَاثًا ثُمَّ ضَرَبَ فَعَادَتْ كَثِيبًا أَهْيَلَ فَلَمَّا رَأَيْتُ ذَلِكَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ يَا رَسُولَ اللَّهِ ايْذَنْ لِي قَالَ فَأَذِنَ لِي فَجِئْتُ امْرَأَتِي فَقُلْتُ ثَكِلَتْكِ أُمُّكِ فَقُلْتُ قَدْ رَأَيْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا لَا صَبْرَ لِي عَلَيْهِ فَهَلْ عِنْدَكِ مِنْ شَيْءٍ فَقَالَتْ عِنْدِي صَاعٌ مِنْ شَعِيرٍ وَعَنَاقٌ قَالَ فَطَحَنَّا الشَّعِيرَ وَذَبَحْنَا الْعَنَاقَ وَسَلَخْتُهَا وَجَعَلْتُهَا فِي الْبُرْمَةِ وَعَجَنْتُ الشَّعِيرَ ثُمَّ رَجَعْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَبِثْتُ سَاعَةً ثُمَّ اسْتَأْذَنْتُهُ الثَّانِيَةَ فَأَذِنَ لِي فَجِئْتُ فَإِذَا الْعَجِينُ قَدْ أَمْكَنَ فَأَمَرْتُهَا بِالْخَبْزِ وَجَعَلْتُ الْقِدْرَ عَلَى الْأَثَاثِي قَالَ أَبُو عَبْدِ الرَّحْمَنِ إِنَّمَا هِيَ الْأَثَافِيُّ وَلَكِنْ هَكَذَا قَالَ ثُمَّ جِئْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنَّ عِنْدَنَا طُعَيِّمًا لَنَا فَإِنْ رَأَيْتَ أَنْ تَقُومَ مَعِي أَنْتَ وَرَجُلٌ أَوْ رَجُلَانِ مَعَكَ فَقَالَ وَكَمْ هُوَ قُلْتُ صَاعٌ مِنْ شَعِيرٍ وَعَنَاقٌ فَقَالَ ارْجِعْ إِلَى أَهْلِكَ وَقُلْ لَهَا لَا تَنْزِعْ الْقِدْرَ مِنْ الْأَثَافِيِّ وَلَا تُخْرِجْ الْخُبْزَ مِنْ التَّنُّورِ حَتَّى آتِيَ ثُمَّ قَالَ لِلنَّاسِ قُومُوا إِلَى بَيْتِ جَابِرٍ قَالَ فَاسْتَحْيَيْتُ حَيَاءً لَا يَعْلَمُهُ إِلَّا اللَّهُ فَقُلْتُ لِامْرَأَتِي ثَكِلَتْكِ أُمُّكِ قَدْ جَاءَكِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَصْحَابِهِ أَجْمَعِينَ فَقَالَتْ أَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَأَلَكَ كَمْ الطَّعَامُ فَقُلْتُ نَعَمْ فَقَالَتْ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَدْ أَخْبَرْتَهُ بِمَا كَانَ عِنْدَنَا قَالَ فَذَهَبَ عَنِّي بَعْضُ مَا كُنْتُ أَجِدُ وَقُلْتُ لَقَدْ صَدَقْتِ فَجَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَخَلَ ثُمَّ قَالَ لِأَصْحَابِهِ لَا تَضَاغَطُوا ثُمَّ بَرَّكَ عَلَى التَّنُّورِ وَعَلَى الْبُرْمَةِ قَالَ فَجَعَلْنَا نَأْخُذُ مِنْ التَّنُّورِ الْخُبْزَ وَنَأْخُذُ اللَّحْمَ مِنْ الْبُرْمَةِ فَنُثَرِّدُ وَنَغْرِفُ لَهُمْ وَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَجْلِسْ عَلَى الصَّحْفَةِ سَبْعَةٌ أَوْ ثَمَانِيَةٌ فَإِذَا أَكَلُوا كَشَفْنَا عَنْ التَّنُّورِ وَكَشَفْنَا عَنْ الْبُرْمَةِ فَإِذَا هُمَا أَمْلَأُ مَا كَانَا فَلَمْ نَزَلْ نَفْعَلُ ذَلِكَ كُلَّمَا فَتَحْنَا التَّنُّورَ وَكَشَفْنَا عَنْ الْبُرْمَةِ وَجَدْنَاهُمَا أَمْلَأَ مَا كَانَا حَتَّى شَبِعَ الْمُسْلِمُونَ كُلُّهُمْ وَبَقِيَ طَائِفَةٌ مِنْ الطَّعَامِ فَقَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ النَّاسَ قَدْ أَصَابَتْهُمْ مَخْمَصَةٌ فَكُلُوا وَأَطْعِمُوا فَلَمْ نَزَلْ يَوْمَنَا ذَلِكَ نَأْكُلُ وَنُطْعِمُ قَالَ وَأَخْبَرَنِي أَنَّهُمْ كَانُوا ثَمَانَ مِائَةٍ أَوْ قَالَ ثَلَاثَ مِائَةٍ قَالَ أَيْمَنُ لَا أَدْرِي أَيُّهُمَا قَالَ","id":"Telah mengabarkan kepada kami [Abdullah bin Umar bin Abaan] telah menceritakan kepada kami [Abdur Rahman bin Muhammad Al Muharibi] dari [Abdul Wahid bin Aiman Al Makki] dari [ayahnya] ia berkata; aku berkata kepada Jabir bin Abdullah Radliyallahu'anhu: ia berkata; Riwayatkanlah kepadaku sebuah hadits dari Rasulullah shallallahu 'alaihi wasallam yang kamu dengar dari beliau dan dapat saya riwayatkan dari kamu. Jabir berkata; Dahulu kami bersama Rasulullah shallallahu 'alaihi wasallam pada perang Khandaq dan kami sedang menggali parit. Selama tiga hari kami tidak makan dan tidak mampu untuk mendapatkan makanan. Kemudian dalam parit saya menemukan sebongkah tanah yang keras, maka saya pun mendatangi Rasulullah shallallahu 'alaihi wasallam. Saya berkata; \"Wahai Rasulullah shallallahu 'alaihi wasallam, tanah keras ini telah menghalangi penggalian parit ini, padahal sudah kami siram dengan air\". Lalu Nabi shallallahu 'alaihi wasallam berdiri dengan perut yang diikat dengan batu lalu beliau mengambil cangkul kemudian membaca Bismillah sebanyak tiga kali. Beliau memukulnya lalu menjadikannya debu yang lembut. Ketika saya melihat kondisi Rasulullah shallallahu 'alaihi wasallam yang demikian itu, saya berkata kepada beliau; \"Wahai Rasulullah izinkanlah saya pulang sebentar, lalu beliau mengizinkan saya (untuk pulang sebentar). \" Kemudian saya datangi istri, aku berkata; \"Keadaan betul-betul gawat\". Dan saya berkata kepada istriku; \"Saya telah menyaksikan keadaan Rasulullah shallallahu 'alaihi wasallam yang membuat diri saya tidak dapat menahannya apakah kamu memiliki sesuatu untuk dimakan?\" Ia menjawab; \"Ada, sekedar satu sha` tepung yang masih kasar dan seekor anak kambing betina. \" Jabir berkata: \"Lalu kami menumbuk tepung yang masih kasar itu agar layak dikunyah dan kami sembelih anak kambing, kami kuliti dan kutaruh di periuk. Saya terus mengadon tepung kemudian saya kembali menemui Rasulullah shallallahu 'alaihi wasallam dan diam beberapa saat. Kemudian saya minta izin lagi untuk pulang kedua kalinya. Beliau mengizinkan saya, maka ketika saya menemui isteri saya ternyata adonan gandum telah siap, lalu saya memerintahkan isteri saya untuk membuat roti, dan saya letakkan periuk di atas batu pemasak. Abdurrahman mengatakan; maksudnya adalah di atas tungku/dapur. Kemudian Jabir berkata; kemudian saya menemui Nabi shallallahu 'alaihi wasallam. lagi, lalu saya katakan kepada beliau: \"Saya punya makanan tak seberapa, aduhai sekiranya baginda mau ya Rasulullah, baginda bisa datang ke rumah saya bersama seseorang atau dua orang saja. \" Beliau bertanya: \"Memangnya berapa banyak makanannya?\" Saya menjawab; \"Sekedar satu sha`gandum dan seekor anak kambing. \" Lalu Rasul berkata: \"Begini saja, pulanglah kamu ke keluargamu dan katakan kepadanya agar jangan mengangkat periuk dari dapur dan jangan mengangkat roti dari panggangannya sampai saya datang. \" Kemudian beliau berkata kepada para sahabat: \"Marilah kita pergi ke rumah Jabir. \" Jabir berkata: \"Saya pun malu dengan malu sangat serius, yang tidak ada yang mengetahui kecuali Allah. \"- (karena nabi mengajak sahabatnya, padahal jumlah masakan tak seberapa banyaknya) --- Saya katakan kepada isteri saya: \"Wah,,, persoalan jadi gawat nich,,, Rasulullah datang dengan para keseluruhan sahabat-sahabatnya. \" Isteri saya berkata: \"Tadi apakah Rasul bertanya kepadamu berapa banyak makanan kita?\". Saya jawab \"Iya, telah kujelaskan \"! lalu isteriku berkata: \"Allah dan Rasul-Nya yang lebih tahu, yang jelas engkau telah melaporkan kepada beliau seberapa banyak makanan yang kita punya\". Jabir berkata; \"Perkataannya isteriku itu menjadikanku tenang dari segala yang saya khawatirkan. \" Lalu saya katakan kepadanya: \"Sungguh adinda benar. \" Nabi shallallahu 'alaihi wasallam kemudian datang dan masuk, lalu mengatakan kepada para sahabatnya \"Awas, jangan kalian berdesak-desakkan ya! \" Kemudian Rasulullah shallallahu 'alaihi wasallam memberkahi panggangan roti dan periuk. Jabir berkata: \"Lalu kami mengambil roti dari panggangan dan daging dari periuk, lalu kami aduk dan kami sendokkan untuk mereka. \" Kemudian Nabi shallallahu 'alaihi wasallam berkata \"Hendaklah masing-masing tujuh atau delapan orang duduk berkumpul pada satu piring, \" Ketika mereka sudah memakannya, kami buka lagi tutup panggangan dan periuk ternyata keduanya masih dalam keadaan penuh seperti semula. Dan keadaan tersebut berlangsung terus-menerus berlangsung sampai seluruh kaum muslimin kenyang dan makanan tersisa tinggal sebagian. Maka berkatalah Rasulullah shallallahu 'alaihi wasallam kepada kami: \"Sesungguhnya orang-orang telah kenyang semua, kini makanlah kamu dan keluargamu! \" Maka pada hari itu kami makan dengan roti dan daging tersebut berkali-kali. Jabir berkata; \"Saya diberitahu bahwa jumlah para sahabat yang makan di rumah jabir sekitar delapan ratus orang atau tiga ratus orang. \" Aiman berkata: saya tidak tahu mana yang benar dari diantara jumlah tersebut. "},"42":{"ar":" أَخْبَرَنَا زَكَرِيَّا بْنُ عَدِيٍّ حَدَّثَنَا عُبَيْدُ اللَّهِ هُوَ ابْنُ عَمْرٍو عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ أَمَرَ أَبُو طَلْحَةَ أُمَّ سُلَيْمٍ أَنْ تَجْعَلَ لِرَسُ��لِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَعَامًا يَأْكُلُ مِنْهُ قَالَ ثُمَّ بَعَثَنِي أَبُو طَلْحَةَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَيْتُهُ فَقُلْتُ بَعَثَنِي إِلَيْكَ أَبُو طَلْحَةَ فَقَالَ لِلْقَوْمِ قُومُوا فَانْطَلَقَ وَانْطَلَقَ الْقَوْمُ مَعَهُ فَقَالَ أَبُو طَلْحَةَ يَا رَسُولَ اللَّهِ إِنَّمَا صَنَعْتُ طَعَامًا لِنَفْسِكَ خَاصَّةً فَقَالَ لَا عَلَيْكَ انْطَلِقْ قَالَ فَانْطَلَقَ وَانْطَلَقَ الْقَوْمُ قَالَ فَجِيءَ بِالطَّعَامِ فَوَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ وَسَمَّى عَلَيْهِ ثُمَّ قَالَ ائْذَنْ لِعَشَرَةٍ قَالَ فَأَذِنَ لَهُمْ فَقَالَ كُلُوا بِاسْمِ اللَّهِ فَأَكَلُوا حَتَّى شَبِعُوا ثُمَّ قَامُوا ثُمَّ وَضَعَ يَدَهُ كَمَا صَنَعَ فِي الْمَرَّةِ الْأُولَى وَسَمَّى عَلَيْهِ ثُمَّ قَالَ ائْذَنْ لِعَشَرَةٍ فَأَذِنَ لَهُمْ فَقَالَ كُلُوا بِاسْمِ اللَّهِ فَأَكَلُوا حَتَّى شَبِعُوا ثُمَّ قَامُوا حَتَّى فَعَلَ ذَلِكَ بِثَمَانِينَ رَجُلًا قَالَ وَأَكَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَهْلُ الْبَيْتِ وَتَرَكُوا سُؤْرًا","id":"Telah mengabarkan kepada kami [Zakaria bin 'Adi] telah menceritakan kepada kami [Ubaidullah Ibnu 'Amr] dari [Abdul Malik bin Umair] dari [Abdur Rahman bin Abu Laila] dari [Anas bin Malik] ia berkata; Abu Thalhah memerintahkan kepada Ummu Sulaim agar ia membuatkan untuk Rasulullah shallallahu 'alaihi wasallam makanan yang bisa beliau makan. Ia berkata; kemudian Abu Thalhah mengutusku kepada Rasulullah shallallahu 'alaihi wasallam. Saya temui beliau, kemudian saya berkata; Abu Thalhah mengutus saya kepada baginda, maka beliau menyeru; \"Wahai kaum muslimin, ayo kita berangkat. \" Dan beliau berangkat, maka berangkatlah para sahabat. Perawi berkata; maka didatangkanlah makanan tersebut lalu Rasulullah shallallahu 'alaihi wasallam meletakkan tangan di atasnya dan mendoakan (keberkahan) makanan tersebut dan berkata; \" Berikan kepada sepuluh orang. \" Perawi berkata; maka makanan itu diberikan kepada mereka. Lalu beliau berkata: \"Makanlah dengan menyebut nama Allah Subhanahu wa Ta'ala\". Lalu mereka makan sampai kenyang, kemudian mereka bangkit sehingga beliau dapat melakukan hal itu terhadap delapan puluh orang. Perawi berkata; Rasulullah shallallahu 'alaihi wasallam makan bersama pemilik rumah dan masih menyisakan semangkuk besar. "},"43":{"ar":" أَخْبَرَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبَانُ هُوَ الْعَطَّارُ حَدَّثَنَا قَتَادَةُ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَبِي عُبَيْدٍ أَنَّهُ طَبَخَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِدْرًا فَقَالَ لَهُ نَاوِلْنِي الذِّرَاعَ وَكَانَ يُعْجِبُهُ الذِّرَاعُ فَنَاوَلَهُ الذِّرَاعَ ثُمَّ قَالَ نَاوِلْنِي الذِّرَاعَ فَنَاوَلَهُ ذِرَاعًا ثُمَّ قَالَ نَاوِلْنِي الذِّرَاعَ فَقُلْتُ يَا نَبِيَّ اللَّهِ وَكَمْ لِلشَّاةِ مِنْ ذِرَاعٍ فَقَالَ وَالَّذِي نَفْسِي بِيَدِهِ أَنْ لَوْ سَكَتَّ لَأُعْطِيتُ أَذْرُعًا مَا دَعَوْتُ بِهِ","id":"Telah mengabarkan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Abaan Al 'Athar] telah menceritakan kepada kami [Qatadah] dari [Syahr bin Hausyab] dari [Abu Ubaid] Bahwasanya ia memasak satu periuk untuk Nabi shallallahu 'alaihi wasallam. Lalu beliau berkata kepadanya: \"Berikan saya sampilnya\" dan kesukaan beliau adalah daging bagian sampil. Ia pun memberi baginda nabi shallallahu 'alaihi wasallam bagian tulang hasta (sampil). Kemudian beliau berkata: \"Tolong berikan saya daging tulang hasta\" maka ia memberi beliau daging tulang hasta. \" lalu beliau berkata lagi: \"Berikan saya daging tulang belakang\", maka saya berkata; \"Wahai Nabi Allah Subhanahu wa Ta'ala (memang) berapa tulang hasta yang dimiliki seekor kambing?\" beliau menjawab: \"Demi Dzat yang diriku berada dalam genggaman tangan-Nya, jika kamu diam niscaya kamu dapat menyediakan daging tulang hasta sebagaimana yang saya minta. \" "},"44":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ الْأَسْوَدِ عَنْ نُبَيْحٍ الْعَنَزِيِّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْمُشْرِكِينَ لِيُقَاتِلَهُمْ فَقَالَ أَبِي عَبْدُ اللَّهِ يَا جَابِرُ لَا عَلَيْكَ أَنْ تَكُونَ فِي نَظَّارِي أَهْلِ الْمَدِينَةِ حَتَّى تَعْلَمَ إِلَى مَا يَصِيرُ أَمْرُنَا فَإِنِّي وَاللَّهِ لَوْلَا أَنِّي أَتْرُكُ بَنَاتٍ لِي بَعْدِي لَأَحْبَبْتُ أَنْ تُقْتَلَ بَيْنَ يَدَيَّ قَالَ فَبَيْنَمَا أَنَا فِي النَّظَّارِينَ إِذْ جَاءَتْ عَمَّتِي بِأَبِي وَخَالِي لِتَدْفِنَهُمَا فِي مَقَابِرِنَا فَلَحِقَ رَجُلٌ يُنَادِي إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُكُمْ أَنْ تَرُدُّوا الْقَتْلَى فَتَدْفِنُوهَا فِي مَضَاجِعِهَا حَيْثُ قُتِلَتْ فَرَدَدْنَاهُمَا فَدَفَنَّاهُمَا فِي مَضْجَعِهِمَا حَيْثُ قُتِلَا فَبَيْنَا أَنَا فِي خِلَافَةِ مُعَاوِيَةَ بْنِ أَبِي سُفْيَانَ إِذْ جَاءَنِي رَجُلٌ فَقَالَ يَا جَابِرُ بْنَ عَبْدِ اللَّهِ لَقَدْ أَثَارَ أَبَاكَ عُمَّالُ مُعَاوِيَةَ فَبَدَا فَخَرَجَ طَائِفَةٌ مِنْهُمْ فَانْطَلَقْتُ إِلَيْهِ فَوَجَدْتُهُ عَلَى النَّحْوِ الَّذِي دَفَنْتُهُ لَمْ يَتَغَيَّرْ إِلَّا مَا لَمْ يَدَعْ الْقَتِيلَ قَالَ فَوَارَيْتُهُ وَتَرَكَ أَبِي عَلَيْهِ دَيْنًا مِنْ التَّمْرِ فَاشْتَدَّ عَلَيَّ بَعْضُ غُرَمَائِهِ فِي التَّقَاضِي فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ أَبِي أُصِيبَ يَوْمَ كَذَا وَكَذَا وَإِنَّهُ تَرَكَ عَلَيْهِ دَيْنًا مِنْ التَّمْرِ وَإِنَّهُ قَدْ اشْتَدَّ عَلَيَّ بَعْضُ غُرَمَائِهِ فِي الطَّلَبِ فَأُحِبُّ أَنْ تُعِينَنِي عَلَيْهِ لَعَلَّهُ أَنْ يُنْظِرَنِي طَائِفَةً مِنْ تَمْرِهِ إِلَى هَذَا الصِّرَامِ الْمُقْبِلِ قَالَ نَعَمْ آتِيكَ إِنْ شَاءَ اللَّهُ قَرِيبًا مِنْ وَسَطِ النَّهَارِ قَالَ فَجَاءَ وَمَعَهُ حَوَارِيُّوهُ قَالَ فَجَلَسُوا فِي الظِّلِّ وَسَلَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاسْتَأْذَنَ ثُمَّ دَخَلَ عَلَيْنَا قَالَ وَقَدْ قُلْتُ لِامْرَأَتِي إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَائِيَّ الْيَوْمَ وَسَطَ النَّهَارِ فَلَا يَرَيَنَّكِ وَلَا تُؤْذِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شَيْءٍ وَلَا تُكَلِّمِيهِ فَفَرَشَتْ فِرَاشًا وَوِسَادَةً وَوَضَعَ رَأْسَهُ فَنَامَ فَقُلْتُ لِمَوْلًى لِي اذْبَحْ هَذِهِ الْعَنَاقَ وَهِيَ دَاجِنٌ سَمِينَةٌ فَالْوَحَى وَالْعَجَلَ افْرُغْ مِنْهَا قَبْلَ أَنْ يَسْتَيْقِظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا مَعَكَ فَلَمْ نَزَلْ فِيهَا حَتَّى فَرَغْنَا مِنْهَا وَهُوَ نَائِمٌ فَقُلْتُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ يَسْتَيْقِظُ يَدْعُو بِطَهُورِهِ وَأَنَا أَخَافُ إِذَا فَرَغَ أَنْ يَقُومَ فَلَا يَفْرُغَ مِنْ طُهُورِهِ حَتَّى يُوضَعَ الْعَنَاقُ بَيْنَ يَدَيْهِ فَلَمَّا اسْتَيْقَظَ قَالَ يَا جَابِرُ ايْتِنِي بِطَهُورٍ قَالَ نَعَمْ فَلَمْ يَفْرُغْ مِنْ وُضُوئِهِ حَتَّى وُضِعَتْ الْعَنَاقُ بَيْنَ يَدَيْهِ قَالَ فَنَظَرَ إِلَيَّ فَقَالَ كَأَنَّكَ قَدْ عَلِمْتَ حُبَّنَا اللَّحْمِ ادْعُ أَبَا بَكْرٍ ثُمَّ دَعَا حَوَارِيِّيهِ قَالَ فَجِيءَ بِالطَّعَامِ فَوُضِعَ قَالَ فَوَضَعَ يَدَهُ وَقَالَ بِسْمِ اللَّهِ كُلُوا فَأَكَلُوا حَتَّى شَبِعُوا وَفَضَلَ مِنْهَا لَحْمٌ كَثِيرٌ وَقَالَ وَاللَّهِ إِنَّ مَجْلِسَ بَنِي سَلَمَةَ لَيَنْظُرُونَ إِلَيْهِمْ هُوَ أَحَبُّ إِلَيْهِمْ مِنْ أَعْيُنِهِمْ مَا يَقْرَبُونَهُ مَخَافَةَ أَنْ يُؤْذُوهُ ثُمَّ قَامَ وَقَامَ أَصْحَابُهُ فَخَرَجُوا بَيْنَ يَدَيْهِ وَكَانَ يَقُولُ خَلُّوا ظَهْرِي لِلْمَلَائِكَةِ قَالَ فَاتَّبَعْتُهُمْ حَتَّى بَلَغْتُ سَقُفَّةَ الْبَابِ فَأَخْرَجَتْ امْرَأَتِي صَدْرَهَا وَكَانَتْ سَتِيرَةً فَقَالَتْ يَا رَسُولَ اللَّهِ صَلِّ عَلَيَّ وَعَلَى زَوْجِي قَالَ صَلَّى اللَّهُ عَلَيْكِ وَعَلَى زَوْجِكِ ثُمَّ قَالَ ادْعُوا لِي فُلَانًا لِلْغَرِيمِ الَّذِي اشْتَدَّ عَلَيَّ فِي الطَّلَبِ فَقَالَ أَنْسِ جَابِرًا طَائِفَةً مِنْ دَيْنِكَ الَّذِي عَلَى أَبِيهِ إِلَى هَذَا الصِّرَامِ الْمُقْبِلِ قَالَ مَا أَنَا بِفَاعِلٍ قَالَ وَاعْتَلَّ وَقَالَ إِنَّمَا هُوَ مَالُ يَتَامَى فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْنَ جَابِرٌ قَالَ قُلْتُ أَنَا ذَا يَا رَسُولَ اللَّهِ قَالَ كِلْ لَهُ مِنْ الْعَجْوَةِ فَإِنَّ اللَّهَ تَعَالَى سَوْفَ يُوَفِّيهِ فَرَفَعَ رَأْسَهُ إِلَى السَّمَاءِ فَإِذَا الشَّمْسُ قَدْ دَلَكَتْ قَالَ الصَّلَاةُ يَا أَبَا بَكْرٍ قَالَ فَانْدَفَعُوا إِلَى الْمَسْجِدِ فَقُلْتُ لِغَرِيمِي قَرِّبْ أَوْعِيَتَكَ فَكِلْتُ لَهُ مِنْ الْعَجْوَةِ فَوَفَّاهُ اللَّهُ وَفَضَلَ لَنَا مِنْ التَّمْرِ كَذَا وَكَذَا قَالَ فَجِئْتُ أَسْعَى إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَسْجِدِهِ كَأَنِّي شَرَارَةٌ فَوَجَدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ صَلَّى فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي قَدْ كِلْتُ لِغَرِيمِي تَمْرَهُ فَوَفَّاهُ اللَّهُ وَفَضَلَ لَنَا مِنْ التَّمْرِ كَذَا وَكَذَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْنَ عُمَرُ بْنُ الْخَطَّابِ قَالَ فَجَاءَ يُهَرْوِلُ قَالَ سَلْ جَابِرَ بْنَ عَبْدِ اللَّهِ عَنْ غَرِيمِهِ وَتَمْرِهِ قَالَ مَا أَنَا بِسَائِلِهِ قَدْ عَلِمْتُ أَنَّ اللَّهَ سَوْفَ يُوَفِّيهِ إِذْ أَخْبَرْتَ أَنَّ اللَّهَ سَوْفَ يُوَفِّيهِ فَرَدَّدَ عَلَيْهِ وَرَدَّدَ عَلَيْهِ هَذِهِ الْكَلِمَةَ ثَلَاثَ مَرَّاتٍ كُلُّ ذَلِكَ يَقُولُ مَا أَنَا بِسَائِلِهِ وَكَانَ لَا يُرَاجَعُ بَعْدَ الْمَرَّةِ الثَّالِثَةِ فَقَالَ مَا فَعَلَ غَرِيمُكَ وَتَمْرُكَ قَالَ قُلْتُ وَفَّاهُ اللَّهُ وَفَضَلَ لَنَا مِنْ التَّمْرِ كَذَا وَكَذَا فَرَجَعْتُ إِلَى امْرَأَتِي فَقُلْتُ أَلَمْ أَكُنْ نَهَيْتُكِ أَنْ تُكَلِّمِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِي فَقَالَتْ تَظُنُّ أَنَّ اللَّهَ تَعَالَى يُورِدُ نَبِيَّهُ فِي بَيْتِي ثُمَّ يَخْرُجُ وَلَا أَسْأَلُهُ الصَّلَاةَ عَلَيَّ وَعَلَى زَوْجِي","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Abu 'Awanah] dari [Al Aswad] dari [Nubaih Al 'Anazi] dari [Jabir bin Abdullah] Radliyallahu'anhu ia berkata; Rasulullah shallallahu 'alaihi wasallam keluar memerangi orang-orang musyrik. Ayah saya (Abdullah) berkata; \"Jangan kamu ikut berangkat perang wahai Jabir, kamu cukup sebagai penduduk Madinah yang tugasnya memantau informasi keadaan pasukan muslimin. Sehingga kamu betul-betul mengetahui bagaimana nasib kita. Saya demi Allah Subhanahu wa Ta'ala, kalaulah bukan karena aku akan meninggalkan anak-anak perempuan sepeninggalku, niscaya saya sangat senang kalau kamu ikut terbunuh di depanku (mati syahid di medan perang). Jabir berkata; Ketika saya berada bersama orang-orang yang tugasnya memantau keadaan dan kepulangan para pasukan, Tiba-tiba bibi saya datang dengan membawa jenazah ayah dan paman saya untuk ia kuburkan keduanya di pemakaman keluarga kami. Lalu ia bertemu seseorang yang berteriak-teriak mengumandangkan; \"Sesungguhnya Nabi shallallahu 'alaihi wasallam memerintahkan kalian untuk mengembalikan orang-orang yang wafat ke tempat ia terbunuh, dan kalian kubur di lokasi ia terbunuh. \" Maka kami segera mengembalikan jenazah ayah dan pamanku di lokasi ia terbunuh. Kami kubur persis di lokasi keduanya terbantai. Kemudian hari, sewaktu saya (Jabir) berada pada masa kekhilafahan Mu'awiyah bin Abu Sufyan Radliyallahu'anhu, tiba-tiba datang seseorang utusan kepada saya. Ia berkata; \"Wahai Jabir bin Abdullah, sungguh para tukang bangunan Mu'awiyah Radliyallahu'anhu saat membongkar pekuburan menemukan (jasad) ayah kamu hingga jasadnya kelihatan. Beberapa tukang bangunan itu ada yang pergi sehingga saya berkesempatan untuk melihat jasad ayahku. Uhh,, Uhh,,,, saya mendapatkan jasad ayahku masih sama persis seperti saya menguburnya, tidak berubah kecuali bekas-bekas orang yang terbunuh. Perawi (Jabir) berkata; maka saya pun menutupinya. Aku masih ingat bahwa ayahku meninggalkan hutang berupa kurma, beberapa orang yang meminjaminya memaksa saya untuk (segera) membayarnya. Lalu saya menemui Rasulullah shallallahu 'alaihi wasallam. Dan saya ungkapkan segala uneg-unegku; \"Wahai Rasulullah shallallahu 'alaihi wasallam sesungguhnya ayah saya meninggal pada satu peperangan, dan sungguh ia telah meninggalkan hutang berupa kurma, dan sungguh para pemilik piutang itu memaksa saya untuk (segera) melunasi hutang-hutang tersebut. Saya sangat senang jika baginda bersedia membantunya siapa tahu ia bersedia menangguhkan (tagihannya) sampai musim panen depan. Beliau berkata: \"Baiklah saya akan berikan kepada kamu insya Allah Subhanahu wa Ta'ala tidak lama lagi siang nanti. \" Perawi (Jabir) berkata; \"Beliau kemudian datang bersama para sahabat setia beliau. \" Perawi (Jabir) berkata; mereka menanti di tempat berteduh dan Rasulullah shallallahu 'alaihi wasallam memberi salam serta meminta izin, kemudian masuk ke rumah kami. Perawi (Jabir) berkata; \"Saya telah mengatakan kepada isteri saya bahwa Rasulullah shallallahu 'alaihi wasallam akan mengunjungi saya pada hari ini setelah lewat pertengahan hari, maka kamu jangan menampakkan diri, jangan menyinggung perasaan Rasulullah shallallahu 'alaihi wasallam dengan sesuatu (apapun) serta jangan pula berbicara kepada beliau. \" Kemudian saya menggelar hamparan dan menyediakan bantal, lalu beliau meletakkan kepalanya dan tidur. Lalu saya memerintahkan hamba sahaya saya; \"Sembelihlah anak kambing betina ini, ia adalah anak kambing yang jinak, banyak dagingnya dan tangkas. Tolong siapkan sebelum Rasulullah shallallahu 'alaihi wasallam bangun, dan jika beliau bangun beliau pasti meminta air untuk bersuci, sedang saya merasa khawatir jika beliau bangun dan selesai bersuci sedangkan daging anak kambing belum tersedia di hadapan beliau. \" Ketika beliau bangun dari tidurnya, maka beliau berkata: \"Wahai Jabir sediakan saya air untuk bersuci, saya menjawab; \"Ya, baiklah. \" Maka sebelum beliau menyelesaikan wudlunya saya letakkan (masakan) daging anak kambing di hadapan beliau. Perawi (Jabir) berkata; \"Beliau memandang saya lalu berkata; sepertinya kamu sudah tahu daging kesukaan kami, panggillah Abu Bakar Radliyallahu'anhu. Kemudian makanan didatangkan serta dihidangkan. Perawi (Jabir) berkata; Kemudian beliau berkata: Sebutlah nama Allah Subhanahu wa Ta'ala (Bismillah) dan makanlah. maka mereka makan sampai mereka kenyang dan tersisa daging yang banyak (dari hidangan tersebut). Perawi (Jabir) berkata; \"Demi Allah Subhanahu wa Ta'ala, sesungguhnya majelis bani Salamah mempunyai penilaian terhadap diri mereka sendiri bahwa nabi shallallahu 'alaihi wasallam lebih mereka cintai daripada mata mereka sendiri yang teramat sangat dekat dengan mereka, karena mereka sangat khawatir kalaulah mereka menyakitinya. Kemudian beliau bangkit berdiri dan begitu juga para sahabatnya, lalu mereka keluar dengan melewati beliau, dan beliau berujar \"Biarkan saya serahkan kelapangan dada saya (urusan saya) pada malaikat. \" Perawi (Jabir) berkata; Lalu saya mengantar kepulangan mereka sampai di papan dekat pintu, maka isteri saya menampakkan dirinya sedikit yang sebelumnya tertutup tabir dan berkata; \"Wahai Rasulullah shallallahu 'alaihi wasallam, doakanlah untuk diri saya dan juga suami saya. \" Beliau menjawab; \"Semoga Allah Subhanahu wa Ta'ala memberikan shalawat-Nya atas dirimu dan suamimu. \" Lalu beliau berkata: \"Tolong panggilkan saya si fulan (ditujukan kepada orang yang menghutangi yang mendesak saya untuk segera melunasinya) \". Lalu beliau berkata: \"Tangguhkan untuk Jabir Radliyallahu'anhu sebagian hutang yang engkau hutangkan kepada ayahnya hingga musim panen mendatang. \" Dia berkata: \"Saya tidak bisa melakukannya ya Rasulullah! \" Beliau berkata: \"Atau anda kurangi\" dia berkata: \"Harta ini adalah milik orang yatim ya Rasulullah. \" lalu Rasul berkata: \"Mana Jabir?\" Jabir berkata: \"Aku ya Rasulullah\" Lalu Rasul berkata: \"Timbanglah untuknya kurma 'ajuwa (satu jenis kurma yang tumbuh di 'Aliyah Madinah) karena Allah Subhanahu wa Ta'ala pasti akan mencukupinya\", kemudian Rasulullah shallallahu 'alaihi wasallam mengangkat kepalanya ke atas dan ternyata matahari telah tergelincir maka beliau berkata: \"Mari kita shalat ya Abu Bakar Radliyallahu'anhu\", Jabir Radliyallahu'anhu berkata: \"Mereka pun semuanya pergi ke masjid\" lalu saya berkata kepada penghutang: \"Dekatkanlah bejanamu. \" Lalu kutimbangkan untuknya kurma 'ajuwa. Maka Allah Subhanahu wa Ta'ala mencukupkannya dan masih menyisakan kurma untuk kami sebagian. Jabir Radliyallahu'anhu berkata: \"Maka aku bergegas menemui Rasulullah shallallahu 'alaihi wasallam di masjidnya ini, seakan-akan saya orang yang hina, lalu saya dapati Rasulullah shallallahu 'alaihi wasallam selesai shalat, kemudian saya berkata kepada Rasulullah shallallahu 'alaihi wasallam; Sesungguhnya saya sudah menakar kurmanya dan Allah Subhanahu wa Ta'ala mencukupinya, dan tersisa untuk kami segini dan segini. \" Kemudian Rasulullah shallallahu 'alaihi wasallam bertanya: \"Dimana Umar bin Khaththab Radliyallahu'anhu?\" Perawi (Jabir) berkata; Umar datang sambil berlari kecil, maka beliau memerintahkan kepadanya, \"Tolong tanyakan Jabir bin Abdullah Radliyallahu'anhu tentang orang yang menghutangi (ayahnya) dan juga kurma miliknya. \" Umar menjawab; \"Saya tidak perlu menanyakannya dan saya merasa yakin bahwa Allah Subhanahu wa Ta'ala pasti akan memberikan kecukupan kepadanya, yaitu tatkala engkau memberitahukan bahwa Allah Subhanahu wa Ta'ala akan memberikan kecukupan padanya. \" Kemudian diulangi lagi pertanyaan itu kepadanya, maka Umar Radliyallahu'anhu mengulangi jawaban itu tiga kali, semua itu diucapkannya dengan kata; \"Saya tidak perlu menanyakannya. \" Rasulullah shallallahu 'alaihi wasallam tidak mengulangi lagi pertanyaannya setelah ketiga kalinya, maka beliau bertanya: \"Bagaimana keadaan orang yang menghutangi kamu dan juga kurmamu?\" Perawi berkata; Maka saya menjawab; Allah Subhanahu wa Ta'ala telah memberikan kecukupan kepadanya dan telah menyisakan kurma sebanyak begini dan begini. Kemudian saya pulang kepada isteriku dan berkata; \"Bukankah saya telah melarang kamu untuk berbicara dengan Rasulullah shallallahu 'alaihi wasallam di rumah saya?\" ia menjawab; Apakah kamu mengira bahwa Allah Subhanahu wa Ta'ala telah mendatangkan Rasul-Nya di rumah saya ini, lalu pergi tanpa saya memohon kepada beliau untuk bershalawat (mendoakan kesejahteraan) atas diri saya dan suami??. "},"45":{"ar":" أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا يَزِيدُ بْنُ أَبِي حَكِيمٍ حَدَّثَنِي الْحَكَمُ بْنُ أَبَانَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ إِنَّ اللَّهَ فَضَّلَ مُحَمَّدًا عَلَى الْأَنْبِيَاءِ وَعَلَى أَهْلِ السَّمَاءِ فَقَالُوا يَا ابْنَ عَبَّاسٍ بِمَ فَضَّلَهُ عَلَى أَهْلِ السَّمَاءِ قَالَ إِنَّ اللَّهَ قَالَ لِأَهْلِ السَّمَاءِ { وَمَنْ يَقُلْ مِنْهُمْ إِنِّي إِلَهٌ مِنْ دُونِهِ فَذَلِكَ نَجْزِيهِ جَهَنَّمَ كَذَلِكَ نَجْزِي الظَّالِمِينَ } الْآيَةَ وَقَالَ اللَّهُ لِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ { إِنَّا فَتَحْنَا لَكَ فَتْحًا مُبِينًا لِيَغْفِرَ لَكَ اللَّهُ مَا تَقَدَّمَ مِنْ ذَنْبِكَ وَمَا تَأَخَّرَ } قَالُوا فَمَا فَضْلُهُ عَلَى الْأَنْبِيَاءِ قَالَ قَالَ اللَّهُ عَزَّ وَجَلَّ { وَمَا أَرْسَلْنَا مِنْ رَسُولٍ إِلَّا بِلِسَانِ قَوْمِهِ لِيُبَيِّنَ لَهُمْ } الْآيَةَ وَقَالَ اللَّهُ عَزَّ وَجَلَّ لِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ { وَمَا أَرْسَلْنَاكَ إِلَّا كَافَّةً لِلنَّاسِ } فَأَرْسَلَهُ إِلَى الْجِنِّ وَالْإِنْسِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Yazid bin Abu Hakim] telah menceritakan kepadaku [Al Hakam bin Abaan] dari ['Ikrimah] dari [Ibnu Abbas] Radliyallahu'anhu ia berkata; \" Sesungguhnya Allah Subhanahu wa Ta'ala memberikan keutamaan kepada Nabi Muhammad shallallahu 'alaihi wasallam atas Nabi-nabi yang lainnya dan atas penghuni langit. \" lalu mereka bertanya: \"Wahai Ibnu Abbas, keutamaan apa yang diberikan kepada beliau atas penghuni langit?\" Ibnu Abbas menjawab; \"Sesungguhnya Allah Subhanahu wa Ta'ala telah berfirman kepada penghuni langit: Dari Ibnu Abbas berkata: WAMAN YAQUL MINHUM INNII ILAAHUN MIN DUNIHI FADZALIJKA NAJZIIHI JAHANNAMA KADZALIKA NAJZII AZHA-ZHALIMIIN Dan barang siapa diantara mereka mengatakan, sesungguhnya aku adalah tuhan selain dari pada Allah Subhanahu wa Ta'ala, maka orang itu kami beri balasan dengan jahannam, dengan demikian kami memberikan pembalasan kepada orang-orang zhalim. (Qs. Al Anbiya` /21: 29) Dan Allah Subhanahu wa Ta'ala terhadap dosamu yang telah lalu dan yang akan datang serta menyempurnakan nikmat-Nya atasmu dan memimpin kamu ke jalan yang lurus. ` (Qs. Al Fath /48: 1. 2) Lalu mereka bertanya, \" Apa keutamaan beliau atas semua Nabi-nabi?\" bin Abbas menjawab, \"Sesungguhnya Allah Subhanahu wa Ta'ala telah berfirman, `Kami tidak mengutus seorang Rasul pun, melainkan dengan bahasa kaumnya, supaya ia dapat memberi penjelasan dengan terang kepada mereka. ` (Qs. Ibraahiim /14: 4) dan Allah Subhanahu wa Ta'ala berfirman untuk Nabi Muhammad shallallahu 'alaihi wasallam, ` dan Kami tidak mengutus kamu melainkan kepada umat manusia seluruhnya Sebagai pembawa berita gembira dan pemberi peringatan. ` (Qs. As Saba` 34: 28), maka beliau telah diutus kepada bangsa jin dan manusia. "},"46":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا زَمْعَةُ عَنْ سَلَمَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ جَلَسَ نَاسٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْتَظِرُونَهُ فَخَرَجَ حَتَّى إِذَا دَنَا مِنْهُمْ سَمِعَهُمْ يَتَذَاكَرُونَ فَتَسَمَّعَ حَدِيثَهُمْ فَإِذَا بَعْضُهُمْ يَقُولُ عَجَبًا إِنَّ اللَّهَ اتَّخَذَ مِنْ خَلْقِهِ خَلِيلًا فَإِبْرَاهِيمُ خَلِيلُهُ وَقَالَ آخَرُ مَاذَا بِأَعْجَبَ مِنْ { وَكَلَّمَ اللَّهُ مُوسَى تَكْلِيمًا } وَقَالَ آخَرُ فَعِيسَى كَلِمَةُ اللَّهِ وَرُوحُهُ وَقَالَ آخَرُ وَآدَمُ اصْطَفَاهُ اللَّهُ فَخَرَجَ عَلَيْهِمْ فَسَلَّمَ وَقَالَ قَدْ سَمِعْتُ كَلَامَكُمْ وَعَجَبَكُمْ أَنَّ إِبْرَاهِيمَ خَلِيلُ اللَّهِ وَهُوَ كَذَلِكَ وَمُوسَى نَجِيُّهُ وَهُوَ كَذَلِكَ وَعِيسَى رُوحُهُ وَكَلِمَتُهُ وَهُوَ كَذَلِكَ وَآدَمُ اصْطَفَاهُ اللَّهُ تَعَالَى وَهُوَ كَذَلِكَ أَلَا وَأَنَا حَبِيبُ اللَّهِ وَلَا فَخْرَ وَأَنَا حَامِلُ لِوَاءِ الْحَمْدِ يَوْمَ الْقِيَامَةِ تَحْتَهُ آدَمُ فَمَنْ دُونَهُ وَلَا فَخْرَ وَأَنَا أَوَّلُ شَافِعٍ وَأَوَّلُ مُشَفَّعٍ يَوْمَ الْقِيَامَةِ وَلَا فَخْرَ وَأَنَا أَوَّلُ مَنْ يُحَرِّكُ بِحَلَقِ الْجَنَّةِ وَلَا فَخْرَ فَيَفْتَحُ اللَّهُ فَيُدْخِلُنِيهَا وَمَعِي فُقَرَاءُ الْمُؤْمِنِينَ وَلَا فَخْرَ وَأَنَا أَكْرَمُ الْأَوَّلِينَ وَالْآخِرِينَ عَلَى اللَّهِ وَلَا فَخْرَ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Zam'ah] dari [Salamah] dari ['Ikrimah] dari [Ibnu Abbas] Radliyallahu'anhu ia berkata; Orang-orang dari sahabat Nabi shallallahu 'alaihi wasallam duduk menunggu beliau. Kemudian beliau keluar dan tatkala dekat dengan mereka beliau mendengar mereka sedang menyebut-nyebut nama beliau shallallahu 'alaihi wasallam. Lalu beliau mendengarkan percakapan mereka dengan baik, maka diantara mereka ada yang berkata; \"Sungguh sangat mengherankan bahwasannya Allah Subhanahu wa Ta'ala menjadikan dari makhluk-Nya Sebagai sahabat karib-Nya, dan Ibrahim adalah sahabat karib Allah Subhanahu wa Ta'ala yang lain berkata; Mana yang lebih mengherankan dari ayat, WA KALLAMA ALLAHU MUSA TAKLIIMAA Dan Allah telah berbicara kepada Nabi Musa dengan langsung (Qs. An Nisaa`/4: 164) sementara yang lainnya lagi berkata; Sedangkan Isa adalah Kalimat Allah Subhanahu wa Ta'ala dan Ruh Nya, yang lainnya pun ikut berkata; Sementara Adam telah disucikan Allah Subhanahu wa Ta'ala. Lalu beliau keluar menemui mereka dan mengucapkan salam, lalu bersabda: \"Saya telah mendengarkan percakapan kalian dan keheranan bahwa Ibrahim adalah sahabat karib Allah Subhanahu wa Ta'ala, dan memang demikian, Musa orang yang diajak langsung berbicara dengan-Nya dan memang demikian, dan Isa adalah Ruh dan Kalimat-Nya dan memang demikian, dan Adam Allah Subhanahu wa Ta'ala telah memilihnya dan memang demikian, ketahuilah bahwa saya adalah habibullah (manusia kecintaan Allah) dan tiada kesombongan, aku adalah pembawa panji pujian di hari kiamat yang membawai Adam dan para nabi sesudahnya dan tiada kesombongan, dan aku adalah orang pertama yang memberi dan yang diberi syafa`at pada hari kiamat dan tidak ada kesombongan, dan saya adalah orang pertama yang menggerakkan tali pintu surga dan tidak ada kesombongan, kemudian Allah Subhanahu wa Ta'ala membukakan pintunya dan memasukkan saya ke dalamnya, saya masuk bersama orang-orang miskin dari kaum muslimin dan tidak ada kesombongan, serta saya adalah orang yang paling mulia dari orang-orang terdahulu dan orang-orang yang datang belakangan di sisi Allah Subhanahu wa Ta'ala dan tidak ada kesombongan\". "},"47":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ عَنْ مَنْصُورِ بْنِ أَبِي الْأَسْوَدِ عَنْ لَيْثٍ عَنْ الرَّبِيعِ بْنِ أَنَسٍ عَنْ أَنَسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا أَوَّلُهُمْ خُرُوجًا وَأَنَا قَائِدُهُمْ إِذَا وَفَدُوا وَأَنَا خَطِيبُهُمْ إِذَا أَنْصَتُوا وَأَنَا مُسْتَشْفِعُكُمْ إِذَا حُبِسُوا وَأَنَا مُبَشِّرُهُمْ إِذَا أَيِسُوا الْكَرَامَةُ وَالْمَفَاتِيحُ يَوْمَئِذٍ بِيَدِي وَأَنَا أَكْرَمُ وَلَدِ آدَمَ عَلَى رَبِّي يَطُوفُ عَلَيَّ أَلْفُ خَادِمٍ كَأَنَّهُمْ بَيْضٌ مَكْنُونٌ أَوْ لُؤْلُؤٌ مَنْثُورٌ","id":"Telah menceritakan kepada kami [Sa'id bin Sulaiman] dari [Mansur bin Abi Al Aswad] dari [Laits] dari [Ar Rabi' bin Anas] dari [Anas] Radliyallahu'anhu ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saya adalah orang pertama kali yang bangkit dari kubur di hari berbangkit, saya adalah pemimpin mereka ketika mereka datang, saya adalah juru bicara mereka ketika mereka diam, saya adalah orang yang meminta syafa`at untuk mereka ketika mereka tertahan (di padang mahsyar), saya adalah orang yang memberikan kabar kepada mereka ketika mereka putus asa. Kemuliaan dan kunci-kunci pada hari itu di tangan saya, dan saya adalah anak Adam Alaihis salam yang paling mulia di sisi Tuhanku, berkeliling di samping saya seribu pelayan, seakan-akan mereka adalah permata yang putih atau mutiara yang bertaburan\". "},"48":{"ar":" أخبرنا عبد الله بن عبد الحكم المصري حدثنا بكر بن مضر عن جعفر بن ربيعة عن صالح هو ابن عطاء بن خباب مولى بني الدئل عن عطاء بن أبي رباح عن جابر بن عبد الله أن النبي صلى الله عليه وسلم قال أنا قائد المرسلين ولا فخر وأنا خاتم النبيين ولا فخر وأنا أول شافع وأول مشفع ولا فخر","id":"Telah mengabarkan kepada kami [Abdullah bin Abdul Hakam Al Mishri] telah menceritakan kepada kami [Bakar bin Mudlar] dari [Ja'far bin Rabi'ah] dari [Shalih Ibnu 'Atha` bin Khabbab] bekas budak dari bani Al Duil dari ['Atha` bin Abi Rabbah] dari [Jabir bin Abdullah] Radliyallahu'anhu Bahwasannya Nabi shallallahu 'alaihi wasallam. bersabda: \"Saya adalah pemimpin para Rasul, dan tidak ada kesombongan, saya adalah penutup para Nabi dan tidak ada kesombongan, saya adalah orang pertama yang akan memberi syafa`at dan orang pertama yang diberi syafa`at dan tidak ada kesombongan\". "},"49":{"ar":" حدثنا محمد بن عباد حدثنا سفيان هو ابن عيينة عن ابن جدعان عن أنس أن النبي صلى الله عليه وسلم قال أنا أول من يأخذ بحلقة باب الجنة فأقعقعها قال أنس كأني أنظر إلى يد رسول الله صلى الله عليه وسلم يحركها وصف لنا سفيان كذا وجمع أبو عبد الله أصابعه وحركها قال وقال له ثابت مسست يد رسول الله صلى الله عليه وسلم بيدك قال نعم قال فأعطنيها أقبلها","id":"Telah menceritakan kepada kami [Muhammad bin 'Abbad] telah menceritakan kepada kami [Sufyan Ibnu 'Uyainah] dari [Ibnu Jud'aan] dari [Anas] Bahwasannya Nabi shallallahu 'alaihi wasallam bersabda: Dari Jabir bin Abdillah bahwa nabi shallallahu 'alaihi wasallam bersabda: Saya adalah orang pertama yang memegang tali pintu surga dan saya pun menggerak-gerakkannya. Anas berkata; Seakan-akan saya melihat tangan Rasulullah shallallahu 'alaihi wasallam menggerak-gerakkannya, dan Sufyan menyebut (kisah) demikian juga, dan Abu Abdullah menggenggamkan tangannya dan menggerakkannya, perawi berkata; Tsabit bertanya kepadanya; apakah kamu memegang tangan Rasulullah shallallahu 'alaihi wasallam dengan tangan kamu? Ia menjawab; Bahkan beliau memberikan tangannya kepada saya untuk saya cium. "},"50":{"ar":" أخبرنا أحمد بن عبد الله حدثنا حسين بن علي عن زائدة عن المختار بن فلفل عن أنس قال قال رسول الله صلى الله عليه وسلم أنا أول شافع في الجنة","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Husain bin Ali] dari [Zaidah] dari [Al Mukhtar bin Fulful] dari [Anas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Saya adalah orang pertama di surga yang memberi syafa`at. \" "},"51":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي يَزِيدُ هُوَ ابْنُ عَبْدِ اللَّهِ بْنِ الْهَادِ عَنْ عَمْرِو بْنِ أَبِي عَمْرٍو عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنِّي لَأَوَّلُ النَّاسِ تَنْشَقُّ الْأَرْضُ عَنْ جُمْجُمَتِي يَوْمَ الْقِيَامَةِ وَلَا فَخْرَ وَأُعْطَى لِوَاءَ الْحَمْدِ وَلَا فَخْرَ وَأَنَا سَيِّدُ النَّاسِ يَوْمَ الْقِيَامَةِ وَلَا فَخْرَ وَأَنَا أَوَّلُ مَنْ يَدْخُلُ الْجَنَّةَ يَوْمَ الْقِيَامَةِ وَلَا فَخْرَ وَآتِي بَابَ الْجَنَّةِ فَآخُذُ بِحَلْقَتِهَا فَيَقُولُونَ مَنْ هَذَا فَأَقُولُ أَنَا مُحَمَّدٌ فَيَفْتَحُونَ لِي فَأَدْخُلُ فَأَجِدُ الْجَبَّارَ مُسْتَقْبِلِي فَأَسْجُدُ لَهُ فَيَقُولُ ارْفَعْ رَأْسَكَ يَا مُحَمَّدُ وَتَكَلَّمْ يُسْمَعْ مِنْكَ وَقُلْ يُقْبَلْ مِنْكَ وَاشْفَعْ تُشَفَّعْ فَأَرْفَعُ رَأْسِي فَأَقُولُ أُمَّتِي أُمَّتِي يَا رَبِّ فَيَقُولُ اذْهَبْ إِلَى أُمَّتِكَ فَمَنْ وَجَدْتَ فِي قَلْبِهِ مِثْقَالَ حَبَّةٍ مِنْ شَعِيرٍ مِنْ الْإِيمَانِ فَأَدْخِلْهُ الْجَنَّةَ فَأَذْهَبُ فَمَنْ وَجَدْتُ فِي قَلْبِهِ مِثْقَالَ ذَلِكَ أَدْخَلْتُهُمْ الْجَنَّةَ فَأَجِدُ الْجَبَّارَ مُسْتَقْبِلِي فَأَسْجُدُ لَهُ فَيَقُولُ ارْفَعْ رَأْسَكَ يَا مُحَمَّدُ وَتَكَلَّمْ يُسْمَعْ مِنْكَ وَقُلْ يُقْبَلْ مِنْكَ وَاشْفَعْ تُشَفَّعْ فَأَرْفَعُ رَأْسِي فَأَقُولُ أُمَّتِي أُمَّتِي يَا رَبِّ فَيَقُولُ اذْهَبْ إِلَى أُمَّتِكَ فَمَنْ وَجَدْتَ فِي قَلْبِهِ مِثْقَالَ حَبَّةٍ مِنْ خَرْدَلٍ مِنْ الْإِيمَانِ فَأَدْخِلْهُ الْجَنَّةَ فَأَذْهَبُ فَمَنْ وَجَدْتُ فِي قَلْبِهِ مِثْقَالَ ذَلِكَ أَدْخَلْتُهُمْ الْجَنَّةَ وَفُرِغَ مِنْ حِسَابِ النَّاسِ وَأُدْخِلَ مَنْ بَقِيَ مِنْ أُمَّتِي فِي النَّارِ مَعَ أَهْلِ النَّارِ فَيَقُولُ أَهْلُ النَّارِ مَا أَغْنَى عَنْكُمْ أَنَّكُمْ كُنْتُمْ تَعْبُدُونَ اللَّهَ وَلَا تُشْرِكُونَ بِهِ شَيْئًا فَيَقُولُ الْجَبَّارُ فَبِعِزَّتِي لَأَعْتِقَنَّهُمْ مِنْ النَّارِ فَيُرْسِلُ إِلَيْهِمْ فَيَخْرُجُونَ مِنْ النَّارِ وَقَدْ امْتُحِشُوا فَيُدْخَلُونَ فِي نَهَرِ الْحَيَاةِ فَيَنْبُتُونَ فِيهِ كَمَا تَنْبُتُ الْحِبَّةُ فِي غُثَاءِ السَّيْلِ وَيُكْتَبُ بَيْنَ أَعْيُنِهِمْ هَؤُلَاءِ عُتَقَاءُ اللَّهِ فَيُذْهَبُ بِهِمْ فَيَدْخُلُونَ الْجَنَّةَ فَيَقُولُ لَهُمْ أَهْلُ الْجَنَّةِ هَؤُلَاءِ الْجَهَنَّمِيُّونَ فَيَقُولُ الْجَبَّارُ بَلْ هَؤُلَاءِ عُتَقَاءُ الْجَبَّارِ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepada kami [Al Laits] telah menceritakan kepadaku [Yazid Ibnu Abdullah bin Al Had] dari [`Amr bin Abu `Amr] dari [Anas bin Malik] Radliyallahu'anhu ia berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam: \" Sesungguhnya saya adalah orang pertama yang bumi akan terbelah karena kemuliaanku pada hari kiamat (nanti) dan tidak ada kesombongan, saya orang pertama yang masuk surga pada hari kiamat dan tidak ada kesombongan, dan saya mendekati pintu surga serta memegang talinya, mereka (penjaga surga) bertanya siapakah orang ini? saya menjawab: Saya Muhammad kemudian mereka membukanya untuk saya, lalu saya masuk dan saya mendapatkan Yang Maha Kuasa di hadapan saya maka saya bersujud kepada-Nya. Lalu Dia berfirman: Angkat kepalamu wahai Muhammad, dan bicaralah niscaya akan didengar perkataanmu, memohonlah niscaya akan dikabulkan permohonanmu, berilah syafa'at niscaya kamu dapat memberi syafa'at. Maka saya mengangkat kepala saya dan berkata: Umat saya, umat saya wahai Tuhan saya. Dia berfirman: \"Pergilah kepada umatmu dan barang siapa yang kamu dapati keimanan di hatinya sebesar biji gandum niscaya akan Kumasukkan ke dalam surga. Kemudian saya pergi dan siapa saja yang saya jumpai dalam hatinya sebesar biji tersebut, saya masukkan mereka kedalam surga. Lalu saya mendapatkan Yang Maha Kuasa di hadapan saya, maka saya sujud kepada-Nya. Dia berfirman: Angkatlah kepalamu dan berbicaralah niscaya akan didengar perkataanmu dan katakanlah niscaya akan didengar pula dan berilah syafa'at niscaya kamu dapat memberi syafa'at. Maka saya mengangkat kepala dan saya berkata umatku ya Tuhan kemudian Dia berfirman 'Pergilah kepada umatmu barang siapa yang kamu dapati di hatinya keimanan sebesar biji gandum maka masukkanlah ia ke surga kemudian saya pergi dan barang siapa yang saya dapati di hatinya keimanan sebesar biji tersebut saya masukkan mereka ke surga. ' Selesai sudah penghitungan amal perbuatan semua manusia, dan dimasukkan yang tersisa dari umat saya ke neraka bersama penghuni neraka, maka penghuni neraka berkata; Tidak berguna bagimu bahwa kamu dahulu telah menyembah Allah Subhanahu wa Ta'ala dan kamu tidak menyekutukan-Nya dengan sesuatu. Maka Yang Maha Kuasa berfirman: Dengan keagungan-Ku, Aku akan membebaskan mereka dari api neraka. Kemudian diutus kepada mereka dan dikeluarkanlah mereka dari neraka dalam keadaan terpanggang, lalu mereka dimasukkan ke dalam sungai kehidupan, maka mereka tumbuh sebagaimana tumbuhnya sebuah biji di dalam buih yang mengalir, dan dituliskan pada kening mereka; mereka adalah orang-orang yang dibebaskan Allah Subhanahu wa Ta'ala. Kemudian mereka digiring dan dimasukkan ke dalam surga. Maka penghuni surga berkata kepada mereka; \"Mereka ini adalah penghuni neraka jahannam\". Maka Yang Maha Kuasa berfirman: \"Oh Bukan, mereka itu adalah orang-orang yang dibebaskan oleh Yang Maha Kuasa. \" "},"52":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي مُعَاوِيَةُ عَنْ يُونُسَ بْنِ مَيْسَرَةَ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ عَنْ ابْنِ غَنْمٍ قَالَ نَزَلَ جِبْرِيلُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَشَقَّ بَطْنَهُ ثُمَّ قَالَ جِبْرِيلُ قَلْبٌ وَكِيعٌ فِيهِ أُذُنَانِ سَمِيعَتَانِ وَعَيْنَانِ بَصِيرَتَانِ مُحَمَّدٌ رَسُولُ اللَّهِ الْمُقَفِّي الْحَاشِرُ خُلُقُكَ قَيِّمٌ وَلِسَانُكَ صَادِقٌ وَنَفْسُكَ مُطْمَئِنَّةٌ قَالَ أَبُو مُحَمَّد وَكِيعٌ يَعْنِي شَدِيدًا","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Mu`awiyah] dari [Yunus bin Maisarah] dari [Abu Idris Al Khaulani] dari [Ibnu Ghanm] ia berkata; Jibril Alaihis salam turun kepada Rasulullah dan membelah perutnya, kemudian Jibril berkata 'Hati yang kokoh terdapat di sana dua telinga yang dapat mendengar dan dua mata yang dapat melihat, Muhammad shallallahu 'alaihi wasallam. Rasulullah Al Muqaffa (yang dimuliakan) dan Al Hasyir (yang mengumpulkan), akhlakmu mulia, lidahmu dapat dipercaya dan jiwamu tenang. Abu Muhammad berkata arti kata waki' adalah yang kuat. "},"53":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي مُعَاوِيَةُ عَنْ عُرْوَةَ بْنِ رُوَيْمٍ عَنْ عَمْرِو بْنِ قَيْسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ أَدْرَكَ بِيَ الْأَجَلَ الْمَرْحُومَ وَاخْتَصَرَ لِيَ اخْتِصَارًا فَنَحْنُ الْآخِرُونَ وَنَحْنُ السَّابِقُونَ يَوْمَ الْقِيَامَةِ وَإِنِّي قَائِلٌ قَوْلًا غَيْرَ فَخْرٍ إِبْرَاهِيمُ خَلِيلُ اللَّهِ وَمُوسَى صَفِيُّ اللَّهِ وَأَنَا حَبِيبُ اللَّهِ وَمَعِي لِوَاءُ الْحَمْدِ يَوْمَ الْقِيَامَةِ وَإِنَّ اللَّهَ عَزَّ وَجَلَّ وَعَدَنِي فِي أُمَّتِي وَأَجَارَهُمْ مِنْ ثَلَاثٍ لَا يَعُمُّهُمْ بِسَنَةٍ وَلَا يَسْتَأْصِلُهُمْ عَدُوٌّ وَلَا يَجْمَعُهُمْ عَلَى ضَلَالَةٍ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Mu`awiyah] dari ['Urwah bin Ruwaim] dari [Amr bin Qais], Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah Subhanahu wa Ta'ala telah memberitahuku ajal kematianku yang dikasihani dan Dia memperpendek umurku. \" Maka kita adalah orang-orang yang terakhir namun kita orang-orang pendahulu pada hari kiamat. Saya akan menyatakan sebuah pernyataan dan maaf ini tidak ada kesombongan, Ibrahim adalah sahabat karib Allah Subhanahu wa Ta'ala (khalilullah), Musa adalah pilihan Allah Subhanahu wa Ta'ala dan saya adalah kekasih Allah Subhanahu wa Ta'ala dan bersamaku bendera pujian pada hari kiamat. Sesungguhnya Allah Subhanahu wa Ta'ala telah menjanjikan untuk umat saya dan melindungi mereka dari tiga hal; tidak akan ditimpakan kepada mereka musim paceklik yang mahadahsyat, tidak akan dicerai-beraikan oleh musuh dan tidak akan dikumpulkan dalam kesesatan. "},"54":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ الْمُبَارَكِ حَدَّثَنَا مُعَاوِيَةُ بْنُ يَحْيَى حَدَّثَنَا أَرْطَاةُ بْنُ الْمُنْذِرِ عَنْ ضَمْرَةَ بْنِ حَبِيبٍ قَالَ سَمِعْتُ مَسْلَمَةَ السَّكُونِيَّ وَقَالَ غَيْرُ مُحَمَّدٍ سَلَمَةَ السَّكُونِيَّ قَالَ بَيْنَمَا نَحْنُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ قَالَ قَائِلٌ يَا رَسُولَ اللَّهِ هَلْ أُتِيتَ بِطَعَامٍ مِنْ السَّمَاءِ قَالَ نَعَمْ أُتِيتُ بِطَعَامٍ قَالَ يَا نَبِيَّ اللَّهِ هَلْ كَانَ فِيهِ مِنْ فَضْلٍ قَالَ نَعَمْ قَالَ فَمَا فُعِلَ بِهِ قَالِ رُفِعَ إِلَى السَّمَاءِ وَقَدْ أُوحِيَ إِلَيَّ أَنِّي غَيْرُ لَابِثٍ فِيكُمْ إِلَّا قَلِيلًا ثُمَّ تَلْبَثُونَ حَتَّى تَقُولُوا مَتَى مَتَى ثُمَّ تَأْتُونِي أَفْنَادًا يُفْنِي بَعْضُكُمْ بَعْضًا بَيْنَ يَدَيْ السَّاعَةِ مُوتَانٌ شَدِيدٌ وَبَعْدَهُ سَنَوَاتُ الزَّلَازِلِ","id":"Telah meceritakan kepada kami [Muhammad bin Al Mubarak] telah menceritakan kepada kami [Mu'awiyah bin Yahya] telah menceritakan kepada kami [Arthah bin Al Mundzir] dari [Dlamrah bin Habib] ia berkata saya mendengar Maslamah As Sakuni -menurut ucapan selain Muhammad- [Salamah As Sakuni] ia berkata; Tatkala kami bersama Rasulullah shallallahu 'alaihi wasallam, tiba-tiba seseorang berkata; \" Wahai Rasulullah shallallahu 'alaihi wasallam, apakah kamu diberikan makanan dari langit? Beliau menjawab: Ya aku diberikan makanan. Ia bertanya kembali; \"Wahai Nabi Allah Subhanahu wa Ta'ala apakah makanan itu masih tersisa?\" Beliau menjawab: \"Ya. \" Ia bertanya lagi, apa yang diperbuat padanya? Beliau menjawab: \"Telah diangkat kembali ke langit, dan telah diwahyukan kepada saya bahwa saya tidak akan lama lagi tinggal bersamamu, kemudian kamu akan terus hidup sampai kamu berkata; \"Kapan, kapan? Lalu kamu datang kepada saya berkelompok-kelompok yang satu sama lain saling menghancurkan, menjelang terjadinya kiamat akan ada kematian yang mengerikan, dan setelahnya datanglah tahun-tahun yang penuh dengan gempa. "},"55":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا سُلَيْمَانُ التَّيْمِيُّ عَنْ أَبِي الْعَلَاءِ عَنْ سَمُرَةَ بْنِ جُنْدُبٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِقَصْعَةٍ مِنْ ثَرِيدٍ فَوُضِعَتْ بَيْنَ يَدَيْ الْقَوْمِ فَتَعَاقَبُوهَا إِلَى الظُّهْرِ مِنْ غُدْوَةٍ يَقُومُ قَوْمٌ وَيَجْلِسُ آخَرُونَ فَقَالَ رَجُلٌ لِسَمُرَةَ بْنِ جُنْدُبٍ أَمَا كَانَتْ تُمَدُّ فَقَالَ سَمُرَةُ مِنْ أَيِّ شَيْءٍ تَعْجَبُ مَا كَانَتْ تُمَدُّ إِلَّا مِنْ هَا هُنَا وَأَشَارَ بِيَدِهِ إِلَى السَّمَاءِ","id":"Telah mengabarkan kepada kami [Utsman bin Muhammad] telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Sulaiman At Taimi] dari [Abu Al 'Ala`] dari [Samurah bin Jundud] bahwa Rasulullah shallallahu 'alaihi wasallam diberikan semangkuk besar yang berisi bubur daging, lalu mangkuk itu diletakkan ditengah-tengah kaum, maka mereka saling bergantian untuk melaksanakan shalat zhuhur karena makan siang, sebagian orang berdiri sebagian lagi duduk. Dan seseorang berkata kepada Samurah bin Jundab; apakah makanan ini datang begitu saja? Samurah menjawab; \"Dengan hal apa kamu terheran-heran? Tidaklah didatangkan semangkuk makanan itu kecuali dari sana, sambil ia memberi isyarat dengan tangannya ke arah langit. \" "},"56":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ سَعِيدٍ أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدٍ عَنْ أَشْعَثَ بْنِ سَوَّارٍ عَنْ أَبِي إِسْحَقَ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي لَيْلَةٍ إِضْحِيَانَ وَعَلَيْهِ حُلَّةٌ حَمْرَاءُ فَجَعَلْتُ أَنْظُرُ إِلَيْهِ وَإِلَى الْقَمَرِ قَالَ فَلَهُوَ كَانَ أَحْسَنَ فِي عَيْنِي مِنْ الْقَمَرِ","id":"Telah menceritakan kepada kami [Muhammad bin Sa'id] telah mengabarkan kepada kami [Abdur Rahman bin Muhammad] dari [Asy 'ats bin Shawwar] dari [Abu Ishaq] dari [Jabir bin Samurah] ia berkata; Saya melihat Rasulullah shallallahu 'alaihi wasallam pada malam bulan purnama dan beliau memakai pakaian merah, lalu saya (bergantian) memandang beliau dan memandang bulan. "},"57":{"ar":" أَخْبَرَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي ثَابِتٍ الزُّهْرِيُّ حَدَّثَنِي إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ ابْنُ أَخِي مُوسَى عَنْ عَمِّهِ مُوسَى بْنِ عُقْبَةَ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْلَجَ الثَّنِيَّتَيْنِ إِذَا تَكَلَّمَ رُئِيَ كَالنُّورِ يَخْرُجُ مِنْ بَيْنِ ثَنَايَاهُ","id":"Telah mengabarkan kepada kami [Ibrahim bin Al Mundzir] telah menceritakan kepada kami [Abdul Aziz bin Abu Tsabit Az Zuhri] telah menceritakan kepadaku [Ismail bin Ibrahim] -anak saudaraku, Musa- dari Pamannya [Musa bin 'Uqbah] dari [Kuraib] dari [Ibnu Abbas] Radliyallahu'anhu ia berkata; Rasulullah shallallahu 'alaihi wasallam mempunyai gigi seri yang renggang, apabila beliau berbicara terlihat seperti ada cahaya yang memancar dari antara kedua gigi seri beliau itu. "},"58":{"ar":" أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مِسْعَرٌ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ قَالَ قَالَ ابْنُ عُمَرَ مَا رَأَيْتُ أَحَدًا أَنْجَدَ وَلَا أَجْوَدَ وَلَا أَشْجَعَ وَلَا أَضْوَأَ وَأَوْضَأَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Mis'ar] dari [Abdul Malik bin 'Umair] ia berkata; [Ibnu Umar] berkata; Saya tidak pernah melihat seseorang yang lebih cepat berperang, lebih bersih, lebih berani, dan lebih bersinar dari Rasulullah shallallahu 'alaihi wasallam. "},"59":{"ar":" أَخْبَرَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى حَدَّثَنَا أُسَامَةُ بْنُ زَيْدٍ عَنْ أَبِي عُبَيْدَةَ بْنِ مُحَمَّدِ بْنِ عَمَّارِ بْنِ يَاسِرٍ قَالَ قُلْتُ لِلرُّبَيِّعِ بِنْتِ مُعَوِّذِ بْنِ عَفْرَاءَ صِفِي لَنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا بُنَيَّ لَوْ رَأَيْتَهُ رَأَيْتَ الشَّمْسَ طَالِعَةً","id":"Telah mengabarkan kepada kami [Ibrahim bin Al Mundzir Al Hizami] telah menceritakan kepada kami [Ubaidullah bin Musa] telah menceritakan kepada kami [Usamah bin Zaid] dari [Abu 'Ubaidah bin Muhammad bin 'Ammar bin Yasir] ia berkata; Aku berkata kepada [Ar Rubai' binti Mu'awwidz bin 'Afra`]; Tolong, sifatkanlah kepada saya, (bagaimana) Rasulullah shallallahu 'alaihi wasallam, maka ia berkata; Wahai anakku kalau sekiranya kamu melihat beliau maka seakan kamu melihat matahari yang sedang terbit. "},"60":{"ar":" أَخْبَرَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا ثَابِتٌ عَنْ أَنَسٍ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَزْهَرَ اللَّوْنِ كَأَنَّ عَرَقَهُ اللُّؤْلُؤُ إِذَا مَشَى تَكَفَّأَ وَمَا مَسِسْتُ حَرِيرَةً وَلَا دِيبَاجَةً أَلْيَنَ مِنْ كَفِّهِ وَلَا شَمِمْتُ رَائِحَةً قَطُّ أَطْيَبُ مِنْ رَائِحَتِهِ مِسْكَةً وَلَا غَيْرَهَا","id":"Telah mengabarkan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad bin Salamah] telah mengabarkan kepada kami [Tsabit] dari [Anas] ia berkata; Rasulullah shallallahu 'alaihi wasallam adalah seorang yang berkulit terang seakan-akan keringatnya adalah permata, jika berjalan tegak, dan tidaklah saya menyentuh kain sutera atau kain wool yang lebih halus dari telapak tangan beliau, serta saya tidak pernah sekalipun mencium semerbak wewangian dari minyak misk atau yang lainnya yang lebih wangi dari wanginya beliau. "},"61":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ أَخْبَرَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ خَدَمْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا قَالَ لِي أُفٍّ قَطُّ وَلَا قَالَ لِي لِشَيْءٍ صَنَعْتُهُ لِمَ صَنَعْتَ كَذَا وَكَذَا أَوْ هَلَّا صَنَعْتَ كَذَا وَكَذَا وَقَالَ لَا وَاللَّهِ مَا مَسِسْتُ بِيَدِي دِيبَاجًا وَلَا حَرِيرًا أَلْيَنَ مِنْ يَدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا وَجَدْتُ رِيحًا قَطُّ أَوْ عَرْفًا كَانَ أَطْيَبَ مِنْ عَرْفِ أَوْ رِيحِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Abu Nu'man] telah mengabarkan kepada kami [Hammad bin Zaid] dari [Tsabit] dari [Anas bin Malik] Radliyallahu'anhu ia bercerita; Dahulu saya membantu Rasulullah shallallahu 'alaihi wasallam dan beliau tidak pernah berkata: \"Ah (dasar, Huss, dan bentakan semisal) kepada saya, atau beliau mengatakan atas apa saja yang saya lakukan: \"Mengapa kamu kerjakan begini dan begini?\", atau \"Kamu harus mengerjakan begini dan begini?\" Dan Anas berkata; Tidak, saya tidak pernah menyentuh kain wool kain sutera yang lebih halus dari tangan Rasulullah shallallahu 'alaihi wasallam, dan saya tidak pernah mencium wewangian dan keringat yang lebih wangi dari keringat atau wanginya Rasulullah shallallahu 'alaihi wasallam. "},"62":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يَزِيدَ الرِّفَاعِيُّ حَدَّثَنَا أَبُو بَكْرٍ عَنْ حَبِيبِ بْنِ خُدْرَةَ قَالَ حَدَّثَنِي رَجُلٌ مِنْ بَنِي حُرَيْشٍ قَالَ كُنْتُ مَعَ أَبِي حِينَ رَجَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَاعِزَ بْنَ مَالِكٍ فَلَمَّا أَخَذَتْهُ الْحِجَارَةُ أُرْعِبْتُ فَضَمَّنِي إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَالَ عَلَيَّ مِنْ عَرَقِ إِبْطِهِ مِثْلُ رِيحِ الْمِسْكِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yazid Ar Rifa'i] telah menceritakan kepada kami [Abu Bakar] dari [Habib bin Khadrah] telah menceritakan kepadaku [seseorang dari Bani Huraisy] ia berkata; Dahulu saya bersama ayah saya ketika Rasulullah shallallahu 'alaihi wasallam merajam Ma'iz bin Malik, tatkala bebatuan sudah mengenainya, saya gemetar kemudian Rasulullah shallallahu 'alaihi wasallam mendekap saya, lalu meneteslah keringat dari ketiak beliau yang baunya bagaikan (minyak wangi) misk. "},"63":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ قَالَ سَأَلَهُ رَجُلٌ قَالَ أَرَأَيْتَ كَانَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَ السَّيْفِ قَالَ لَا مِثْلَ الْقَمَرِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zuhair] dari [Abu Ishaq] dari [Barra`] ia berkata; seseorang bertanya kepadanya; Apakah kamu melihat wajah Rasulullah shallallahu 'alaihi wasallam seperti sebilah pedang? Ia menjawab; \"Tidak, wajah beliau bagaikan bulan. \""},"64":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا شَرِيكٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعْرَفُ بِاللَّيْلِ بِرِيحِ الطِّيبِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Syariik] dari [Al A'masy] dari [Ibrahim] ia berkata; \" Rasulullah shallallahu 'alaihi wasallam pada malam hari dikenali dengan bau wanginya. \""},"65":{"ar":" أَخْبَرَنَا مَالِكُ بْنُ إِسْمَعِيلَ حَدَّثَنَا إِسْحَقُ بْنُ الْفَضْلِ بْنِ عَبْدِ الرَّحْمَنِ الْهَاشِمِيُّ أَخْبَرَنَا الْمُغِيرَةُ بْنُ عَطِيَّةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَسْلُكْ طَرِيقًا أَوْ لَا يَسْلُكُ طَرِيقًا فَيَتْبَعُهُ أَحَدٌ إِلَّا عَرَفَ أَنَّهُ قَدْ سَلَكَهُ مِنْ طِيبِ عَرْفِهِ أَوْ قَالَ مِنْ رِيحِ عَرَقِهِ","id":"Telah mengabarkan kepada kami [Malik bin isma'il] telah menceritakan kepada kami [Ishaq bin Al Fadl bin AbdurRahman Al Hasyimi] telah mengabarkan kepada kami [Al Mughirah bin 'Athiyah] dari [Abu Zubair] dari [Jabir] Bahwasannya Nabi shallallahu 'alaihi wasallam tidak melewati satu jalan pun atau beliau melewati jalan melainkan beliau dikenal bahwa beliau (baru saja) melewati jalan tersebut dari wangi keringatnya atau ia berkata; dari keringat beliau yang harum. "},"66":{"ar":" أَخْبَرَنَا جَعْفَرُ بْنُ عَوْنٍ أَخْبَرَنَا مُحَمَّدُ بْنُ عَمْرٍو اللَّيْثِيُّ عَنْ أَبِي سَلَمَةَ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ الْهَدِيَّةَ وَلَا يَقْبَلُ الصَّدَقَةَ فَأَهْدَتْ لَهُ امْرَأَةٌ مِنْ يَهُودِ خَيْبَرَ شَاةً مَصْلِيَّةً فَتَنَاوَلَ مِنْهَا وَتَنَاوَلَ مِنْهَا بِشْرُ بْنُ الْبَرَاءِ ثُمَّ رَفَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ ثُمَّ قَالَ إِنَّ هَذِهِ تُخْبِرُنِي أَنَّهَا مَسْمُومَةٌ فَمَاتَ بِشْرُ بْنُ الْبَرَاءِ فَأَرْسَلَ إِلَيْهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا حَمَلَكِ عَلَى مَا صَنَعْتِ فَقَالَتْ إِنْ كُنْتَ نَبِيًّا لَمْ يَضُرَّكَ شَيْءٌ وَإِنْ كُنْتَ مَلِكًا أَرَحْتُ النَّاسَ مِنْكَ فَقَالَ فِي مَرَضِهِ مَا زِلْتُ مِنْ الْأَكْلَةِ الَّتِي أَكَلْتُ بِخَيْبَرَ فَهَذَا أَوَانُ انْقِطَاعِ أَبْهَرِي","id":"Telah mengabarkan kepada kami [Ja'far bin 'Aun] telah mengabarkan kepada kami [Muhammad bin 'Amr Al Laitsi] dari [Abu Salamah] ia berkata; Dahulu Rasulullah shallallahu 'alaihi wasallam bersedia makan (menerima) hadiah dan tidak mau menerima sedekah, maka seorang wanita Yahudi Khaibar menghadiahkan kepada beliau shallallahu 'alaihi wasallam seekor kambing panggang dan beliau memakannya begitu juga Bisyr bin Barra`, kemudian Nabi shallallahu 'alaihi wasallam mengangkat tangan beliau dan berkata: Sesungguhnya kambing ini memberitahuku bahwasannya dirinya telah (dilumuri) racun. Maka Bisyr bin Al Barra` meninggal, Maka Nabi shallallahu 'alaihi wasallam mengutus seseorang untuk menangkapnya, dan beliau bertanya: Apa yang menyebabkanmu melakukan perbuatan keji ini? Perempuan itu menjawab; \"Apabila engkau benar-benar seorang Nabi niscaya tidak ada yang dapat mencelakakanmu, sebaliknya apabila engkau seorang raja niscaya saya telah membebaskan manusia darimu. \" Beliau berkata di waktu sakitnya: Saya masih merasakan efek makanan yang saya makan ketika di Khaibar, dan ini adalah saat terputusnya tulang punggungku. "},"67":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ نَافِعٍ أَخْبَرَنَا شُعَيْبُ بْنُ أَبِي حَمْزَةَ عَنْ الزُّهْرِيِّ قَالَ كَانَ جَابِرُ بْنُ عَبْدِ اللَّهِ يُحَدِّثُ أَنَّ يَهُودِيَّةً مِنْ أَهْلِ خَيْبَرَ سَمَّتْ شَاةً مَصْلِيَّةً ثُمَّ أَهْدَتْهَا لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخَذَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهَا الذِّرَاعَ فَأَكَلَ مِنْهَا وَأَكَلَ الرَّهْطُ مِنْ أَصْحَابِهِ مَعَهُ ثُمَّ قَالَ لَهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ارْفَعُوا أَيْدِيَكُمْ وَأَرْسَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْيَهُودِيَّةِ فَدَعَاهَا فَقَالَ لَهَا أَسَمَمْتِ هَذِهِ الشَّاةَ فَقَالَتْ نَعَمْ وَمَنْ أَخْبَرَكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْنِي هَذِهِ فِي يَدِيَ الذِّرَاعُ قَالَتْ نَعَمْ قَالَ فَمَاذَا أَرَدْتِ إِلَى ذَلِكَ قَالَتْ قُلْتُ إِنْ كَانَ نَبِيًّا لَمْ يَضُرَّهُ وَإِنْ لَمْ يَكُنْ نَبِيًّا اسْتَرَحْنَا مِنْهُ فَعَفَا عَنْهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يُعَاقِبْهَا وَتُوُفِّيَ بَعْضُ أَصْحَابِهِ الَّذِينَ أَكَلُوا مِنْ الشَّاةِ وَاحْتَجَمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى كَاهِلِهِ مِنْ أَجْلِ الَّذِي أَكَلَ مِنْ الشَّاةِ حَجَمَهُ أَبُو هِنْدٍ مَوْلَى بَنِي بَيَاضَةَ بِالْقَرْنِ وَالشَّفْرَةِ وَهُوَ مِنْ بَنِي ثُمَامَةَ وَهُمْ حَيٌّ مِنْ الْأَنْصَارِ","id":"Telah mengabarkan kepada kami [Al Hakam bin Nafi'] telah mengabarkan kepada kami [Syu'aib bin Abu Hamzah] dari [Az Zuhri] ia berkata; [Jabir bin Abdullah] Radliyallahu'anhu menceritakan; Seorang wanita Yahudi penduduk Khaibar membubuhi racun pada daging kambing panggang dan menghadiahkannya kepada Nabi shallallahu 'alaihi wasallam. Nabi mengambil daging tulang hastanya dan memakannya, dan sebagian sahabatnya juga ikut makan bersamanya. Nabi shallallahu 'alaihi wasallam kontan berkata kepada mereka: \" Angkatlah tangan kalian.\" Kemudian beliau mengutus seseorang untuk menangkap wanita Yahudi tadi dan menginterogasi: \"Kamu melumuri kambing tadi dengan racun?\" Ia menjawab; \"Ya, benar. \" Si wanita bertanya; \"Siapa gerangan yang memberitahukan kepada baginda?\" Nabi menjawab: \"Yang memberitahuku adalah yang ada di tanganku ini, \" -maksudnya tulang sampil--Perempuan itu berkata, \"Betul, memang kububuhi racun, \" beliau bertanya, \" Apa maksudmu melakukan hal itu?\" ia menjawab, \"Aku hanya ingin membuktikan, jika seorang Nabi niscaya tidak mencelakainya dan jikalau bukan, kami terbebas darinya. \" Maka Rasulullah shallallahu 'alaihi wasallam memaafkannya dengan tidak menghukumnya, sedang sebagian sahabat lain yang memakan daging kambing tersebut meninggal dunia. Nabi shallallahu 'alaihi wasallam berbekam pada bagian atas punggung untuk menghilangkan racun yang dimakannya dari daging kambing tersebut. Beliau dibekam oleh Abu Hind, maula Bani Bayadhah, dengan tanduk dan parang, ia dari Bani Tsumamah yaitu daerah bagian dari kaum Anshar. \" "},"68":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي سَعِيدُ بْنُ أَبِي سَعِيدٍ الْمَقْبُرِيُّ عَنْ أَبِي هُرَيْرَةَ قَالَ لَمَّا فَتَحْنَا خَيْبَرَ أُهْدِيَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَاةٌ فِيهَا سُمٌّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْمَعُوا لِي مَنْ كَانَ هَا هُنَا مِنْ الْيَهُودِ فَجُمِعُوا لَهُ فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي سَائِلُكُمْ عَنْ شَيْءٍ فَهَلْ أَنْتُمْ صَادِقِيَّ عَنْهُ قَالُوا نَعَمْ يَا أَبَا الْقَاسِمِ فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَبُوكُمْ قَالُوا أَبُونَا فُلَانٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَذَبْتُمْ بَلْ أَبُوكُمْ فُلَانٌ قَالُوا صَدَقْتَ وَبَرَرْتَ فَقَالَ لَهُمْ هَلْ أَنْتُمْ صَادِقِيَّ عَنْ شَيْءٍ إِنْ سَأَلْتُكُمْ عَنْهُ فَقَالُوا نَعَمْ وَإِنْ كَذَبْنَاكَ عَرَفْتَ كَذِبَنَا كَمَا عَرَفْتَ فِي آبَائِنَا فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَنْ أَهْلُ النَّارِ فَقَالُوا نَكُونُ فِيهَا يَسِيرًا ثُمَّ تَخْلُفُونَا فِيهَا قَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اخْسَئُوا فِيهَا وَاللَّهِ لَا نَخْلُفُكُمْ فِيهَا أَبَدًا ثُمَّ قَالَ لَهُمْ هَلْ أَنْتُمْ صَادِقِيَّ عَنْ شَيْءٍ إِنْ سَأَلْتُكُمْ عَنْهُ قَالُوا نَعَمْ قَالَ هَلْ جَعَلْتُمْ فِي هَذِهِ الشَّاةِ سُمًّا قَالُوا نَعَمْ قَالَ مَا حَمَلَكُمْ عَلَى ذَلِكَ قَالُوا أَرَدْنَا إِنْ كُنْتَ كَاذِبًا أَنْ نَسْتَرِيحَ مِنْكَ وَإِنْ كُنْتَ نَبِيًّا لَمْ يَضُرَّكَ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku [Sa'id bin Abu Sa'id Al Maqburi] dari [Abu Hurairah] Radliyallahu'anhu ia berkata; \"Ketika kami menaklukan Khaibar, Rasulullah shallallahu 'alaihi wasallam diberi hadiah seekor kambing beracun. Rasulullah shallallahu 'alaihi wasallam kontan berkata: ' Tolong kumpulkanlah orang-orang Yahudi yang ada di sini. ' Maka dikumpulkanlah mereka kepada beliau. Lalu Rasulullah shallallahu 'alaihi wasallam berkata: 'Saya akan bertanya kalian tentang sesuatu, apakah kalian akan menjawab dengan jujur? ', mereka menjawab; 'Ya, wahai Abu Qasim (Nabi Muhammad shallallahu 'alaihi wasallam). ' Lalu Rasulullah shallallahu 'alaihi wasallam bertanya: 'Siapakah ayah kalian? ' Mereka menjawab; 'Ayah kami si fulan. ' Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: 'Kalian bohong!, tetapi ayah kalian adalah si fulan. ' Mereka menjawab; 'Baginda benar. ' Lalu beliau berkata kepada mereka: 'Apakah kalian akan jujur jika saya tanya tentang sesuatu? ' Mereka menjawab; 'Ya, dan jika kami berbohong niscaya baginda mengetahuinya, sebagaimana baginda mengetahui ayah-ayah kami. ' Rasulullah shallallahu 'alaihi wasallam bertanya kepada mereka: 'Siapakah penghuni neraka? ' Mereka menjawab; 'Kami berada di dalamnya sebentar dan kemudian baginda menggantikan kami di dalamnya. ' Maka Rasulullah shallallahu 'alaihi wasallam berkata kepada mereka: Terhinalah kalian di dalamnya, demi Allah Subhanahu wa Ta'ala kami tidak akan menggantikan kalian di dalamnya selamanya. Lalu Rasulullah shallallahu 'alaihi wasallam bertanya kepada mereka: Apakah kalian akan berkata jujur terhadap pertanyaan yang akan ku tanyakan kepada kalian?, mereka menjawab; Ya. Beliau berkata: Apakah kalian membubuhi racun pada (daging) kambing tersebut? Mereka menjawab; Ya, beliau bertanya: apa yang menyebabkan kalian berbuat demikian? Mereka menjawab; Kami ingin terbebas jika baginda seorang pembohong dan jika baginda benar seorang Nabi maka (racun itu) tidak bakalan mencelakai baginda. "},"69":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ ابْنِ الْمُنْكَدِرِ عَنْ جَابِرٍ قَالَ مَا سُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا قَطُّ فَقَالَ لَا قَالَ أَبُو مُحَمَّد قَالَ ابْنُ عُيَيْنَةَ إِذَا لَمْ يَكُنْ عِنْدَهُ وَعَدَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Ibnu Al Munkadir] dari [Jabir] ia berkata; Rasulullah shallallahu 'alaihi wasallam tidak pernah diminta sesuatu, lalu beliau menjawab tidak. Abu Muhammad berkata; Ibnu 'Uyainah berkata; Jika permintaan tak dipunyainya, niscaya beliau shallallahu 'alaihi wasallam menjanjikan. "},"70":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ عِمْرَانَ حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ عَنْ زَمْعَةَ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَيِيًّا لَا يُسْأَلُ شَيْئًا إِلَّا أَعْطَاهُ","id":"Telah mengabarkan kepada kami [Abdullah bin Imran] telah menceritakan kepada kami [Abu Daud Al Thayalitsi] dari [Zam'ah] dari [Abu Hazim] dari [Sahl bin Sa'ad] Radliyallahu'anhu ia berkata; Rasulullah shallallahu 'alaihi wasallam seorang pemalu, dan tidaklah beliau diminta sesuatu melainkan akan memberinya. "},"71":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْم��دَ بْنِ أَبِي خَلَفٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي بَكْرٍ عَنْ رَجُلٍ مِنْ الْعَرَبِ قَالَ زَحَمْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ حُنَيْنٍ وَفِي رِجْلِي نَعْلٌ كَثِيفَةٌ فَوَطِئْتُ بِهَا عَلَى رِجْلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَفَحَنِي نَفْحَةً بِسَوْطٍ فِي يَدِهِ وَقَالَ بِسْمِ اللَّهِ أَوْجَعْتَنِي قَالَ فَبِتُّ لِنَفْسِي لَائِمًا أَقُولُ أَوْجَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَبِتُّ بِلَيْلَةٍ كَمَا يَعْلَمُ اللَّهُ فَلَمَّا أَصْبَحْنَا إِذَا رَجُلٌ يَقُولُ أَيْنَ فُلَانٌ قَالَ قُلْتُ هَذَا وَاللَّهِ الَّذِي كَانَ مِنِّي بِالْأَمْسِ قَالَ فَانْطَلَقْتُ وَأَنَا مُتَخَوِّفٌ فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكَ وَطِئْتَ بِنَعْلِكَ عَلَى رِجْلِي بِالْأَمْسِ فَأَوْجَعْتَنِي فَنَفَحْتُكَ نَفْحَةً بِالسَّوْطِ فَهَذِهِ ثَمَانُونَ نَعْجَةً فَخُذْهَا بِهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad bin Abu Khalaf] telah menceritakan kepada kami [Abdurrahman bin Muhammad] dari [Muhammad bin Ishaq] telah menceritakan kepadaku [Abdullah bin Abu Bakar] dari [seseorang dari Arab] ia berkata; Saya berdesakan dengan Rasulullah shallallahu 'alaihi wasallam pada peperangan Hunain dan saya mengenakan sandal besar, lalu saya menginjak kaki Rasulullah shallallahu 'alaihi wasallam. Maka beliau memukul saya dengan cemeti di tangannya sambil berkata: Bismillah kamu telah menyakiti saya. Perawi (laki-laki arab) berkata; di malam harinya saya bergumam sendiri; Saya telah menyakiti Rasulullah shallallahu 'alaihi wasallam. Kemudian saya bermalam waktu itu yang hanya Allah Subhanahu wa Ta'ala mengetahuinya. Pagi harinya, tiba-tiba seseorang bertanya; Mana si fulan?. Perawi (laki-laki arab) berkata; Saya berbisik; Demi Allah Subhanahu wa Ta'ala, orang inilah yang kemarin ada masalah dengan saya. Ia berkata; saya pergi dengan rasa takut. Lalu Rasulullah shallallahu 'alaihi wasallam berkata kepada saya: sungguh kamu kemarin yang menginjak kaki saya dan membuat saya sakit, lalu saya pukul kamu dengan cemeti, maka ini ada delapan puluh domba betina, silahkan ambillah untukmu sebagai gantinya. "},"72":{"ar":" أَخْبَرَنَا يَعْقُوبُ بْنُ حُمَيْدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ ابْنِ أَخِي الزُّهْرِيِّ عَنْ الزُّهْرِيِّ قَالَ إِنَّ جِبْرِيلَ قَالَ مَا فِي الْأَرْضِ أَهْلُ عَشَرَةِ أَبْيَاتٍ إِلَّا قَلَّبْتُهُمْ فَمَا وَجَدْتُ أَحَدًا أَشَدَّ إِنْفَاقًا لِهَذَا الْمَالِ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Ya'qub bin Humaid] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Ibnu Akhi Az Zuhri] dari [Az Zuhri] ia berkata; Jibril Aalaihissalam berkata: Tidaklah di muka bumi ini terdapat pemilik sepuluh gedung kecuali saya (Aalaihissalam) Telah membolak-balikkan mereka, maka saya tidak mendapat seorang pun yang lebih banyak berinfak selain Rasulullah shallallahu 'alaihi wasallam. "},"73":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ حُمَيْدٍ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى حَدَّثَنَا الْحُسَيْنُ بْنُ وَاقِدٍ عَنْ يَحْيَى بْنِ عُقَيْلٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكْثِرُ الذِّكْرَ وَيُقِلُّ اللَّغْوَ وَيُطِيلُ الصَّلَاةَ وَيُقْصِرُ الْخُطْبَةَ وَلَا يَأْنَفُ وَلَا يَسْتَنْكِفُ أَنْ يَمْشِيَ مَعَ الْأَرْمَلَةِ وَالْمِسْكِينِ فَيَقْضِيَ لَهُمَا حَاجَتَهُمَا","id":"Telah menceritakan kepada kami [Muhammad bin Humaid] telah menceritakan kepada kami [Al Fadl bin Musa] telah menceritakan kepada kami [Al Husain bin Waqid] dari [Yahya bin 'Uqail] dari [Abdullah bin Abi Aufa] ia berkata; Nabi shallallahu 'alaihi wasallam selalu memperbanyak dzikir, mengurangi (menghindari) hal sia-sia, memperpanjang shalat, memendekkan khutbah, tidak berbuat kasar, tidak merasa malu berbicara dengan para janda dan orang miskin untuk menyelesaikan urusan mereka. "},"74":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ أَخْبَرَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ قَالَ قَالَ الْعَبَّاسُ رَضِيَ اللَّهُ تَعَالَى عَنْهُ لَأَعْلَمَنَّ مَا بَقَاءُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِينَا فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي رَأَيْتُهُمْ قَدْ آذَوْكَ وَآذَاكَ غُبَارُهُمْ فَلَوْ اتَّخَذْتَ عَرِيشًا تُكَلِّمُهُمْ مِنْهُ فَقَالَ لَا أَزَالُ بَيْنَ أَظْهُرِهِمْ يَطَئُونَ عَقِبِي وَيُنَازِعُونِي رِدَائِي حَتَّى يَكُونَ اللَّهُ هُوَ الَّذِي يُرِيحُنِي مِنْهُمْ قَالَ فَعَلِمْتُ أَنَّ بَقَاءَهُ فِينَا قَلِيلٌ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah mengabarkan kepada kami [Hammad bin Zaid] dari [Ayyub] dari ['Ikrimah] ia berkata; [Abbas] Radliyallahu'anhu berkata; Sungguh saya sangat mengetahui lamanya Rasulullah shallallahu 'alaihi wasallam tinggal bersama kami, perawi (Ikrimah) berkata; Wahai Rasulullah, saya melihat mereka telah menyakiti baginda dan sampai debu-debu mereka juga menyakiti baginda, bagaimana jika saya buatkan tempat berteduh yang baginda gunakan untuk berbicara dengan mereka? beliau menjawab: aku akan tetap akan berada di tengah-tengah mereka, sekalipun mereka menginjak-injak kakiku ini dan menarik selendangku hingga Allah Subhanahu wa Ta'ala yang membebaskan saya dari mereka. Perawi berkata; Maka kami tahu bahwa beliau akan tinggal bersama kami hanya sebentar. "},"75":{"ar":" أَخْبَرَنَا زَكَرِيَّا بْنُ عَدِيٍّ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ أُنَيْسِ بْنِ أَبِي يَحْيَى عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ خَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَرَضِهِ الَّذِي مَاتَ فِيهِ وَنَحْنُ فِي الْمَسْجِدِ عَاصِبًا رَأْسَهُ بِخِرْقَةٍ حَتَّى أَهْوَى نَحْوَ الْمِنْبَرِ فَاسْتَوَى عَلَيْهِ وَاتَّبَعْنَاهُ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ إِنِّي لَأَنْظُرُ إِلَى الْحَوْضِ مِنْ مَقَامِي هَذَا ثُمَّ قَالَ إِنَّ عَبْدًا عُرِضَتْ عَلَيْهِ الدُّنْيَا وَزِينَتُهَا فَاخْتَارَ الْآخِرَةَ قَالَ فَلَمْ يَفْطِنْ لَهَا أَحَدٌ غَيْرُ أَبِي بَكْرٍ فَذَرَفَتْ عَيْنَاهُ فَبَكَى ثُمَّ قَالَ بَلْ نَفْدِيكَ بِآبَائِنَا وَأُمَّهَاتِنَا وَأَنْفُسِنَا وَأَمْوَالِنَا يَا رَسُولَ اللَّهِ قَالَ ثُمَّ هَبَطَ فَمَا قَامَ عَلَيْهِ حَتَّى السَّاعَةِ","id":"Telah mengabarkan kepada kami [Zakaria bin 'Adi] telah menceritakan kepada kami [Hatim bin Ismail] dari [Unais bin Abu Yahya] dari [ayahnya] dari [Abu Sa'id Al Khudri] ia berkata; Rasulullah shallallahu 'alaihi wasallam keluar menemui kami di waktu sakit beliau yang menyebabkan kematian beliau. Kami berada di masjid (masjid Nabawi) sambil membalut kepalanya dengan sobekan kain, hingga beliau mendekati mimbar, dan duduk di atasnya. Kami terus mengikuti beliau. Kemudian beliau bersabda: \"Demi Dzat yang jiwaku berada di tangan-Nya, sungguh saya melihat sebuah telaga dari tempat berdiri saya ini. \" Kemudian beliau berkata: 'Sesungguhnya ada seorang hamba diperlihatkan kepadanya dunia dan perhiasannya, kemudian ia justru memilih akhirat. ' Perawi (Abu Sa'id alkhudzri) berkata: Ketika itu tidak ada seorang pun yang bisa memahami ucapan beliau selain Abu Bakar, maka berlinanglah kedua mata Abu Bakar lalu ia menangis dan berkata; Bahkan kami akan menebusmu dengan ayah-ayah kami, ibu-ibu kami, jiwa kami, dan harta kami, wahai Rasulullah! '. Perawi bercerita; Kemudian beliau turun dari mimbar itu dan tidak pernah berdiri di mimbar itu hingga ajal meninggal. "},"76":{"ar":" أَخْبَرَنَا خَلِيفَةُ بْنُ خَيَّاطٍ حَدَّثَنَا بَكْرُ بْنُ سُلَيْمَانَ حَدَّثَنَا ابْنُ إِسْحَقَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عُمَرَ بْنِ عَلِيِّ بْنِ عَدِيٍّ عَنْ عُبَيْدٍ مَوْلَى الْحَكَمِ بْنِ أَبِي الْعَاصِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو عَنْ أَبِي مُوَيْهِبَةَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي قَدْ أُمِرْتُ أَنْ أَسْتَغْفِرَ لِأَهْلِ الْبَقِيعِ فَانْطَلِقْ مَعِي فَانْطَلَقْتُ مَعَهُ فِي جَوْفِ اللَّيْلِ فَلَمَّا وَقَفَ عَلَيْهِمْ قَالَ السَّلَامُ عَلَيْكُمْ يَا أَهْلَ الْمَقَابِرِ لِيُهْنِكُمْ مَا أَصْبَحْتُمْ فِيهِ مِمَّا أَصْبَحَ فِيهِ النَّاسُ أَقْبَلَتْ الْفِتَنُ كَقِطْعِ اللَّيْلِ الْمُظْلِمِ يَتْبَعُ آخِرُهَا أَوَّلَهَا الْآخِرَةُ أَشَدُّ مِنْ الْأُولَى ثُمَّ أَقْبَلَ عَلَيَّ فَقَالَ يَا أَبَا مُوَيْهِبَةَ إِنِّي قَدْ أُوتِيتُ بِمَفَاتِيحِ خَزَائِنِ الدُّنْيَا وَالْخُلْدِ فِيهَا ثُمَّ الْجَنَّةُ فَخُيِّرْتُ بَيْنَ ذَلِكَ وَبَيْنَ لِقَاءِ رَبِّي قُلْتُ بِأَبِي أَنْتَ وَأُمِّي خُذْ مَفَاتِيحَ خَزَائِنِ الدُّنْيَا وَالْخُلْدَ فِيهَا ثُمَّ الْجَنَّةَ قَالَ لَا وَاللَّهِ يَا أَبَا مُوَيْهِبَةَ لَقَدْ اخْتَرْتُ لِقَاءَ رَبِّي ثُمَّ اسْتَغْفَرَ لِأَهْلِ الْبَقِيعِ ثُمَّ انْصَرَفَ فَبُدِئَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي وَجَعِهِ الَّذِي مَاتَ فِيهِ","id":"Telah mengabarkan kepada kami [Khalifah bin Khayyat] telah menceritakan kepada kami [Bakar bin Suilaiman] telah menceritakan kepada kami [Ibnu Ishaq] telah menceritakan kepadaku [Abdullah bin Umar bin Ali bin 'Adi] dari ['Ubaid] -bekas budak Al Hakam bin Abu Al 'Ash- dari [Abdullah bin 'Amr] dari [Abu Muiwaihibah] -bekas budak Rasulullah shallallahu 'alaihi wasallam- ia berkata; Rasulullah shallallahu 'alaihi wasallam berkata kepadaku 'Sesungguhnya saya diperintah untuk memintakan ampun bagi penghuni pemakaman Baqi', lalu beliau berangkat bersamaku di tengah malam. Tatkala beliau sudah berdiri menghadap mereka (pemakaman) beliau mengucap: ASSALAMU 'ALAIKUM YAA AHLAL MAQAABIR (semoga kesejahteraan untuk kalian wahai penduduk pemakaman ini). Semoga keadaan kalian sekarang ini lebih selamat bagi kalian daripada keadaan yang dihadapi manusia sekarang. Kini telah menyebar fitnah bagaikan potongan malam yang gelap gulita, penghujungnya mengikuti permulaannya. Dan sungguh hari akhirat lebih sulit daripada kehidupan dunia. Lalu beliau berbalik menghadapku dan berkata: Wahai Abu Muwaihibah, telah diberikan kepadaku kunci-kunci gudang dunia dan keabadian di dalamnya. Kemudian aku diberi kebebasan memilih antara hal itu atau berjumpa dengan Tuhanku. Saya (Abu Muwaihibah) menjawab; Demi ayah serta ibuku sebagai tebusannya, wahai baginda, ambil saja kunci-kunci gudang kehidupan dunia dan keabadian di dalamnya, kemudian surga. Beliau menjawab: 'Tidak, demi Allah wahai Abu Muwaihibah, sesungguhnya saya telah memilih untuk berjumpa dengan Tuhanku. Kemudian beliau memohonkan ampunan untuk penghuni Baqi lalu pergi. "},"77":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ ابْنِ إِسْحَقَ عَنْ يَعْقُوبَ بْنِ عُتْبَةَ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ عَائِشَةَ قَالَتْ رَجَعَ إِلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ مِنْ جَنَازَةٍ مِنْ الْبَقِيعِ فَوَجَدَنِي وَأَنَا أَجِدُ صُدَاعًا وَأَنَا أَقُولُ وَا رَأْسَاهُ قَالَ بَلْ أَنَا يَا عَائِشَةُ وَا رَأْسَاهُ قَالَ وَمَا ضَرَّكِ لَوْ مُتِّ قَبْلِي فَغَسَّلْتُكِ وَكَفَّنْتُكِ وَصَلَّيْتُ عَلَيْكِ وَدَفَنْتُكِ فَقُلْتُ لَكَأَنِّي بِكَ وَاللَّهِ لَوْ فَعَلْتَ ذَلِكَ لَرَجَعْتَ إِلَى بَيْتِي فَعَرَّسْتَ فِيهِ بِبَعْضِ نِسَائِكَ قَالَتْ فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ بُدِئَ فِي وَجَعِهِ الَّذِي مَاتَ فِيهِ","id":"Telah mengabarkan kepada kami [Al Hakam bin Mubarak] telah menceritakan kepada kami [Muhammad bin Salamah] dari [Ibnu Ishaq] dari [Ya'qub bin 'Utbah] dari [Ibnu Syihab] dari [Ubaidullah bin Abdullah bin 'Utbah] dari [Aisyah] Radliyallahu'anha ia berkata; Rasulullah shallallahu 'alaihi wasallam, suatu hari pulang kepadaku dari (memakamkan) jenazah di Baqi'. lalu ia mendapati saya sedang sakit kepala dan mengaduh; 'Aduh kepalaku', Beliau berkata: ' Aduh kepalaku wahai Aisyah'. Beliau berkata lagi: 'Apa yang membuat kamu susah jika kamu wafat sebelum saya? ' Sungguh niscaya saya akan memandikanmu dan mengkafani kamu serta akan memakamkanmu. Lalu saya (Aisyah Radliyallahu'anha) berkata; sepertinya itu yang baginda harapkan, demi Allah Subhanahu wa Ta'ala jika baginda melakukan hal itu niscaya baginda akan pulang ke rumahku. Lalu baginda menggauli sebagian isteri baginda di sana. Aisyah Radliyallahu'anha berkata; Rasulullah shallallahu 'alaihi wasallam tersenyum kemudian beliau mulai terserang sakit yang menyebabkan beliau meninggal dunia. "},"78":{"ar":" أَخْبَرَنَا فَرْوَةُ بْنُ أَبِي الْمَغْرَاءِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُخْتَارٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ كَعْبٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَرَضِهِ صُبُّوا عَلَيَّ سَبْعَ قِرَبٍ مِنْ سَبْعِ آبَارٍ شَتَّى حَتَّى أَخْرُجَ إِلَى النَّاسِ فَأَعْهَدَ إِلَيْهِمْ قَالَتْ فَأَقْعَدْنَاهُ فِي مِخْضَبٍ لِحَفْصَةَ فَصَبَبْنَا عَلَيْهِ الْمَاءَ صَبًّا أَوْ شَنَنَّا عَلَيْهِ شَنًّا الشَّكُّ مِنْ قِبَلِ مُحَمَّدِ بْنِ إِسْحَقَ فَوَجَدَ رَاحَةً فَخَرَجَ فَصَعِدَ الْمِنْبَرَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ وَاسْتَغْفَرَ لِلشُّهَدَاءِ مِنْ أَصْحَابِ أُحُدٍ وَدَعَا لَهُمْ ثُمَّ قَالَ أَمَّا بَعْدُ فَإِنَّ الْأَنْصَارَ عَيْبَتِي الَّتِي أَوَيْتُ إِلَيْهَا فَأَكْرِمُوا كَرِيمَهُمْ وَتَجَاوَزُوا عَنْ مُسِيئِهِمْ إِلَّا فِي حَدٍّ أَلَا إِنَّ عَبْدًا مِنْ عِبَادِ اللَّهِ قَدْ خُيِّرَ بَيْنَ الدُّنْيَا وَبَيْنَ مَا عِنْدَ اللَّهِ فَاخْتَارَ مَا عِنْدَ اللَّهِ فَبَكَى أَبُو بَكْرٍ وَظَنَّ أَنَّهُ يَعْنِي نَفْسَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رِسْلِكَ يَا أَبَا بَكْرٍ سُدُّوا هَذِهِ الْأَبْوَابَ الشَّوَارِعَ إِلَى الْمَسْجِدِ إِلَّا بَابَ أَبِي بَكْرٍ فَإِنِّي لَا أَعْلَمُ امْرَأً أَفْضَلَ عِنْدِي يَدًا فِي الصُّحْبَةِ مِنْ أَبِي بَكْرٍ","id":"Telah mengabarkan kepada kami [Farwah bin Abu Al Maghra`] telah menceritakan kepada kami [Ibrahim bin Mukhtar] dari [Muhammad bin Ishaq] dari [Muhammad bin Ka'ab] dari ['Urwah] dari ['Aisyah] Radliyallahu'anha ia berkata: Nabi shallallahu 'alaihi wasallam bersabda ketika sakit beliau: \" Siramkanlah kepadaku tujuh ember air dari tujuh sumur yang berbeda-beda, sehingga aku bisa keluar kepada orang-orang untuk memenuhi janji mereka\" perawi berkata: \"Maka kami dudukkan beliau pada bejana milik Hafsah Radliyallahu'anha, kami siramkan atau kami tuangkan air kepadanya -keraguan redaksi kami siramkan atau kami tuangkan ini dari Muhammad bin Ishaq-, maka beliau mendapatkan ketenangan, lalu beliau keluar dan menaiki mimbar; seraya bersabda: \" Kaum Anshar adalah manusia kepercayaan dan penjaga rahasiaku, tempat aku berlindung, kecuali jika mereka benar-benar melanggar hukum. Ingatlah, ada seorang hamba Allah Subhanahu wa Ta'ala diberi kebebasan memilih antara dunia dan apa yang ada di sisi Allah Subhanahu wa Ta'ala, maka ia memilih apa yang ada di sisi Allah Subhanahu wa Ta'ala \" Lalu Abu Bakar Radliyallahu'anhu menangis, ia beranggapan bahwa ucapan nabi shallallahu 'alaihi wasallam itu dialamatkan untuk dirinya. Lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Tunggu dulu wahai Abu Bakar, tutuplah pintu-pintu jalan yang menuju ke masjid (Nabawi) kecuali pintu Abu Bakar, karena aku tidak mengenal seorang pun yang lebih utama bagiku dalam persahabatan dan pembelaan daripada Abu Bakar Radliyallahu'anhu\". "},"79":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدّ��ثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ عَنْ سُلَيْمَانَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ قَالَتْ أُوذِنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالصَّلَاةِ فِي مَرَضِهِ فَقَالَ مُرُوا أَبَا بَكْرٍ يُصَلِّي بِالنَّاسِ ثُمَّ أُغْمِيَ عَلَيْهِ فَلَمَّا سُرِّيَ عَنْهُ قَالَ هَلْ أَمَرْتُنَّ أَبَا بَكْرٍ يُصَلِّي بِالنَّاسِ فَقُلْتُ إِنَّ أَبَا بَكْرٍ رَجُلٌ رَقِيقٌ فَلَوْ أَمَرْتَ عُمَرَ فَقَالَ أَنْتُنَّ صَوَاحِبُ يُوسُفَ مُرُوا أَبَا بَكْرٍ يُصَلِّي بِالنَّاسِ فَرُبَّ قَائِلٍ مُتَمَنٍّ وَيَأْبَى اللَّهُ وَالْمُؤْمِنُونَ","id":"Telah mengabarkan kepada kami [Sa'id bin Manshur] telah menceritakan kepada kami [Fulaih bin Sulaiman] dari [Sulaiman bin Abdurrahman] dari [Al Qasim bin Muhammad] dari ['Aisyah] Radliyallahu'anha ia berkata: \"Rasulullah Shallallahu 'Alaihi wa Aallam mengizinkan untuk mengumandangkan adzan shalat, kemudian beliau bersabda: \"Perintahkanlah Abu Bakar untuk mengimami orang-orang\", lalu beliau jatuh pingsan. Ketika beliau siuman, beliau bertanya: \"Apakah aku telah memerintahkan Abu Bakar Radliyallahu'anhu untuk mengimami orang-orang?. Lalu aku (perawi) berkata: \"Bukankah Abu Bakar seorang yang lembut hingga mudah menangis, tidak sebaiknyakah baginda memerintahkan Umar saja?\". Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \" Ah,, Kamu ini seperti saudara-saudara Yusuf saja, perintahkan Abu Bakar untuk mengimami orang-orang, berapa banyak orang yang berangan-angan tetapi Allah Subhaanallahu wa Ta'ala dan orang-orang yang beriman tidak menginginkannya\". "},"80":{"ar":" أَخْبَرَنَا عَبْدُ الْوَهَّابِ بْنُ سَعِيدٍ الدِّمَشْقِيُّ حَدَّثَنَا شُعَيْبٌ هُوَ ابْنُ إِسْحَقَ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي يَعِيشُ بْنُ الْوَلِيدِ حَدَّثَنِي مَكْحُولٌ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَصَابَ أَحَدَكُمْ مُصِيبَةٌ فَلْيَذْكُرْ مُصِيبَتَهُ بِي فَإِنَّهَا مِنْ أَعْظَمِ الْمَصَائِبِ","id":"Telah mengabarkan kepada kami [Abdul Wahab bin Sa'id Ad Dimasyqi] telah menceritakan kepada kami [Syu'aib Ibnu Ishaq], telah menceritakan kepada kami [Al 'Auza'i] telah menceritakan kepadaku [Ya'isy bin Al Walid] telah menceritakan kepadaku [Makhul] Bahwasannya Nabi shallallahu 'alaihi wasallam bersabda: \" Apabila salah seorang diantara kalian terkena musibah, maka bayangkanlah musibah yang menimpanya itu menimpaku, maka itu merupakan musibah yang paling besar\". "},"81":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا فِطْرٌ عَنْ عَطَاءٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَصَابَ أَحَدَكُمْ مُصِيبَةٌ فَلْيَذْكُرْ مُصَابَهُ بِي فَإِنَّهَا مِنْ أَعْظَمِ الْمَصَائِبِ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Fithr] dari ['Atha`] ia berkata: Rasulullah shallallahu 'alaihi wasallam: \" Jika suatu musibah menimpa seseorang dari kalian maka bayangkanlah musibah itu menimpaku, maka hal itu adalah termasuk musibah yang terbesar\". "},"82":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّ فَاطِمَةَ قَالَتْ يَا أَنَسُ كَيْفَ طَابَتْ أَنْفُسُكُمْ أَنْ تَحْثُوا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ التُّرَابَ وَقَالَتْ يَا أَبَتَاهْ مِنْ رَبِّهِ مَا أَدْنَاهْ وَا أَبَتَاهْ جَنَّةُ الْفِرْدَوْسِ مَأْوَاهْ وَا أَبَتَاهْ إِلَى جِبْرِيلَ نَنْعَاهْ وَا أَبَتَاهْ أَجَابَ رَبًّا دَعَاهْ قَالَ حَمَّادٌ حِينَ حَدَّثَ ثَابِتٌ بَكَى و قَالَ ثَابِتٌ حِينَ حَدَّثَ أَنَسٌ بَكَى","id":"Telah menceritakan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari [Tsabit] dari [Anas bin Malik] Radliyallahu'anhu Bahwasannya [Fatimah] Radliyallahu'anha bertanya: \" Wahai Anas, bagaimana dirimu senang menaburkan tanah pada (makam) Rasulullah shallallahu 'alaihi wasallam? Dan Fatimah seraya melantunkan uneg-unegnya: \"Wahai ayahku yang alangkah dekatnya dengan Rabbnya, wahai ayahku yang surga firdaus adalah tempat kembalinya, wahai ayahku yang kepada Jibril 'Aalaihissalam kami memberitahukan kematiannya, wahai ayahku yang dia memenuhi Rabb(nya) ketika memanggilnya\". Hammad Rahimahullah berkata: \"Ketika Tsabit menyampaikan hadits ini, ia menangis\". Tsabit berkata: \"Anas Radliyallahu'anhu ketika menyampaikan hadits ini beliau menangis\". "},"83":{"ar":" حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍ وَذَكَرَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ شَهِدْتُهُ يَوْمَ دَخَلَ الْمَدِينَةَ فَمَا رَأَيْتُ يَوْمًا قَطُّ كَانَ أَحْسَنَ وَلَا أَضْوَأَ مِنْ يَوْمٍ دَخَلَ عَلَيْنَا فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَشَهِدْتُهُ يَوْمَ مَوْتِهِ فَمَا رَأَيْتُ يَوْمًا كَانَ أَقْبَحَ وَلَا أَظْلَمَ مِنْ يَوْمٍ مَاتَ فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad Salamah] dari [Tsabit] dari [Anas] Radliyallahu'anhu ia mengenang Nabi shallallahu 'alaihi wasallam, \" Aku menyaksikan beliau ketika memasuki Madinah, aku tidak pernah melihat hari yang lebih baik dan lebih cerah daripada hari saat kedatangan Rasulullah shallallahu 'alaihi wasallam ke Madinah, dan aku juga menyaksikan hari wafatnya, maka aku tidak melihat satu hari yang lebih buruk dan lebih gelap daripada hari wafatnya Rasulullah shallallahu 'alaihi wasallam \". "},"84":{"ar":" حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا سَعِيدُ بْنُ زَيْدٍ حَدَّثَنَا عَمْرُو بْنُ مَالِكٍ النُّكْرِيُّ حَدَّثَنَا أَبُو الْجَوْزَاءِ أَوْسُ بْنُ عَبْدِ اللَّهِ قَالَ قُحِطَ أَهْلُ الْمَدِينَةِ قَحْطًا شَدِيدًا فَشَكَوْا إِلَى عَائِشَةَ فَقَالَتْ انْظُرُوا قَبْرَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاجْعَلُوا مِنْهُ كِوًى إِلَى السَّمَاءِ حَتَّى لَا يَكُونَ بَيْنَهُ وَبَيْنَ السَّمَاءِ سَقْفٌ قَالَ فَفَعَلُوا فَمُطِرْنَا مَطَرًا حَتَّى نَبَتَ الْعُشْبُ وَسَمِنَتْ الْإِبِلُ حَتَّى تَفَتَّقَتْ مِنْ الشَّحْمِ فَسُمِّيَ عَامَ الْفَتْقِ","id":"Telah menceritakan kepada kami [Abu Nu'man] telah menceritakan kepada kami [Sa'id bin Zaid] telah menceritakan kepada kami [Umar bin Malik An Nukri] telah menceritakan kepada kami [Abu Al Jauza` Aus bin Abdullah], ia berkata: \"Suatu hari penduduk Madinah dilanda kekeringan yang sangat hebat, dan saat itu mereka mengadu kepada [Aisyah] Radliyallahu'anha, kemudian ia berkata: \"Pergilah ke kubur Nabi shallallahu 'alaihi wasallam, buatlah lubang ke arah langit dan jangan sampai ada atap diantaranya dengan langit. Kemudian Abu Al Jauza` melanjutkan kisahnya: \" kemudian masyarakat Madinah melakukan apa yang diperintahkan Aisyah Radliyallahu'anha, setelah itu, turunlah hujan dan rerumputan pun tumbuh dan ternak-ternak menjadi sehat. Karenanya tahun tersebut disebut dengan tahun kemenangan\". "},"85":{"ar":" أَخْبَرَنَا مَرْوَانُ بْنُ مُحَمَّدٍ عَنْ سَعِيدِ بْنِ عَبْدِ الْعَزِيزِ قَالَ لَمَّا كَانَ أَيَّامُ الْحَرَّةِ لَمْ يُؤَذَّنْ فِي مَسْجِدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثًا وَلَمْ يُقَمْ وَلَمْ يَبْرَحْ سَعِيدُ بْنُ الْمُسَيَّبِ مِنْ الْمَسْجِدِ وَكَانَ لَا يَعْرِفُ وَقْتَ الصَّلَاةِ إِلَّا بِهَمْهَمَةٍ يَسْمَعُهَا مِنْ قَبْرِ النَّبِيِّ فَذَكَرَ مَعْنَاهُ","id":"Telah mengabarkan kepada kami [Marwan bin Muhammad] dari [Sa'id bin Abdul Aziz] ia berkata: \" Ketika terjadi musim kering yang dahsyat, tidak ada adzan di masjid Nabawi sebanyak tiga kali, dan tidak pula iqamah. Dan, [Sa'id bin Al Musayyib] tidak keluar dari masjid Nabi shallallahu 'alaihi wasallam. Ia tidak mengetahui waktu shalat kecuali setelah mendengar suara-suara dari arah kubur Nabi shallallahu 'alaihi wasallam. Kemudian ia menyebutkan maknanya. "},"86":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي خَالِدٌ هُوَ ابْنُ يَزِيدَ عَنْ سَعِيدٍ هُوَ ابْنُ أَبِي هِلَالٍ عَنْ نُبَيْهِ بْنِ وَهْبٍ أَنَّ كَعْبًا دَخَلَ عَلَى عَائِشَةَ فَذَكَرُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ كَعْبٌ مَا مِنْ يَوْمٍ يَطْلُعُ إِلَّا نَزَلَ سَبْعُونَ أَلْفًا مِنْ الْمَلَائِكَةِ حَتَّى يَحُفُّوا بِقَبْرِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَضْرِبُونَ بِأَجْنِحَتِهِمْ وَيُصَلُّونَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا أَمْسَوْا عَرَجُوا وَهَبَطَ مِثْلُهُمْ فَصَنَعُوا مِثْلَ ذَلِكَ حَتَّى إِذَا انْشَقَّتْ عَنْهُ الْأَرْضُ خَرَجَ فِي سَبْعِينَ أَلْفًا مِنْ الْمَلَائِكَةِ يَزِفُّونَهُ","id":"Telah menceritakan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku, [Al Laits] telah menceritakan kepadaku, [Khalid Ibnu Yazid], dari [Sa`id Ibnu Abu Hilal] dari [Nubaih bin Wahb] bahwasanya Ka'ab masuk mengunjungi Aisyah Radliyallahu'anha. Kemudian para sahabat menyebut-nyebut nama Rasulullah shallallahu 'alaihi wasallam, [Ka'ab] berkata: \" Tiada satu hari pun (terlewati) kecuali turun seribu malaikat sehingga mengelilingi makam Nabi shallallahu 'alaihi wasallam, mereka mengepakkan sayapnya dan bershalawat kepada Nabi shallallahu 'alaihi wasallam. Sampai apabila sore hari tiba, mereka naik (ke atas langit,) dan turunlah malaikat semisal dan melakukan perbuatan semisal yang tadi, hingga apabila bumi ini terbelah, Beliau shallallahu 'alaihi wasallam keluar diiringi oleh tujuh puluh ribu malaikat\". "},"87":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ أَخْبَرَنَا ثَوْرُ بْنُ يَزِيدَ حَدَّثَنِي خَالِدُ بْنُ مَعْدَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَمْرٍو عَنْ عِرْبَاضِ بْنِ سَارِيَةَ قَالَ صَلَّى لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْفَجْرِ ثُمَّ وَعَظَنَا مَوْعِظَةً بَلِيغَةً ذَرَفَتْ مِنْهَا الْعُيُونُ وَوَجِلَتْ مِنْهَا الْقُلُوبُ فَقَالَ قَائِلٌ يَا رَسُولَ اللَّهِ كَأَنَّهَا مَوْعِظَةُ مُوَدِّعٍ فَأَوْصِنَا فَقَالَ أُوصِيكُمْ بِتَقْوَى اللَّهِ وَالسَّمْعِ وَالطَّاعَةِ وَإِنْ كَانَ عَبْدًا حَبَشِيًّا فَإِنَّهُ مَنْ يَعِشْ مِنْكُمْ بَعْدِي فَسَيَرَى اخْتِلَافًا كَثِيرًا فَعَلَيْكُمْ بِسُنَّتِي وَسَنَّةِ الْخُلَفَاءِ الرَّاشِدِينَ الْمَهْدِيِّينَ عَضُّوا عَلَيْهَا بِالنَّوَاجِذِ وَإِيَّاكُمْ وَالْمُحْدَثَاتِ فَإِنَّ كُلَّ مُحْدَثَةٍ بِدْعَةٌ و قَالَ أَبُو عَاصِمٍ مَرَّةً وَإِيَّاكُمْ وَمُحْدَثَاتِ الْأُمُورِ فَإِنَّ كُلَّ بِدْعَةٍ ضَلَالَةٌ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] telah mengabarkan kepada kami [Tsaur bin Yazid] telah menceritakan kepadaku [Khalid bin Ma'dan] dari [Abdur Rahman bin 'Amr] dari ['Irbadl bin Sariah] ia berkata; \" Rasulullah shallallahu 'alaihi wasallam shalat subuh bersama kami, kemudian beliau memberikan wejangan dengan wejangan yang sangat dalam hingga air mata (kami) bercucuran dan bergetarlah hati- hati (kami), kemudian seseorang bertanya; \" wahai Rasulullah shallallahu 'alaihi wasallam seakan-akan wejangan ini adalah wejangan penutup (yang engkau berikan), maka berikanlah kami wasiat. Lalu Beliau berkata: \" Aku wasiatkan kepada kalian untuk bertakwa kepada Allah Subhaanallahu wa Ta'ala dan selalu mendengar dan ta'at (kepada para pemimpin), meskipun ia seorang budak dari Habasyah, sesungguhnya barang siapa diantara kalian yang hidup setelahku niscaya ia melihat perbedaan yang banyak, maka kalian harus mengikuti sunnahku dan sunnah khulafa`urrasyidin yang lurus, gigitlah dengan gigi geraham kalian (peganglah dengan teguh), berhati-hatilah dengan segala sesuatu yang baru (perkara bid`ah), karena sesuatu yang baru itu bid`ah\". Abu 'Ashim berkata: \"Hendaklah kalian berhati-hati terhadap perkara-perkara yang baru (dalam agama), karena setiap bid`ah itu sesat\"."},"88":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يُونُسَ بْنِ يَزِيدَ عَنْ الزُّهْرِيِّ قَالَ كَانَ مَنْ مَضَى مِنْ عُلَمَائِنَا يَقُولُونَ الِاعْتِصَامُ بِالسُّنَّةِ نَجَاةٌ وَالْعِلْمُ يُقْبَضُ قَبْضًا سَرِيعًا فَنَعْشُ الْعِلْمِ ثَبَاتُ الدِّينِ وَالدُّنْيَا وَفِي ذَهَابِ الْعِلْمِ ذَهَابُ ذَلِكَ كُلِّهِ","id":"Telah mengabarkan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Al `Auza'i] dari [Yunus bin Yazid] dari [Az Zuhri] ia berkata: \"Tak terlewat satu pun dari ulama-ulama kita melainkan mereka berkata: ' Berpegang teguh kepada sunnah merupakan kesuksesan, dan ilmu akan dicabut dengan cepat, penegakkan ilmu itu merupakan penegakkan agama dan dunia, dan dengan hilangnya ilmu maka hilanglah semua itu\"."},"89":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى بْنِ أَبِي عَمْرٍو السَّيْبَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ الدَّيْلَمِيِّ قَالَ بَلَغَنِي أَنَّ أَوَّلَ الدِّينِ تَرْكًا السُّنَّةُ يَذْهَبُ الدِّينُ سُنَّةً سُنَّةً كَمَا يَذْهَبُ الْحَبْلُ قُوَّةً قُوَّةً","id":"Telah mengabarkan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Al `Auza'i] dari [Yahya bin Abu 'Amr As Saibani] dari [Abdullah bin Ad Dailami] ia berkata: \"Telah sampai (kabar) kepadaku bahwa yang paling pertama dari masalah agama yang ditinggalkan adalah sunnah, agama ini akan hilang sunnahnya satu persatu sebagaimana terputusnya seutas tali sedikit demi sedikit\". "},"90":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ حَسَّانَ قَالَ مَا ابْتَدَعَ قَوْمٌ بِدْعَةً فِي دِينِهِمْ إِلَّا نَزَعَ اللَّهُ مِنْ سُنَّتِهِمْ مِثْلَهَا ثُمَّ لَا يُعِيدُهَا إِلَيْهِمْ إِلَى يَوْمِ الْقِيَامَةِ","id":"Telah mengabarkan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Al `Auza'i] dari [Hassan] ia berkata: \" Tidaklah suatu kaum membuat satu bid`ah dalam agama mereka melainkan Allah Subhaanallahu wa Ta'ala akan mencabut dari sunnah mereka seperti bagian bid`ah (yang mereka perbuat) kemudian Dia tidak mengembalikan lagi sunnah tersebut sampai hari kiamat\". "},"91":{"ar":" أَخْبَرَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ قَالَ مَا ابْتَدَعَ رَجُلٌ بِدْعَةً إِلَّا اسْتَحَلَّ السَّيْفَ","id":"Telah mengabarkan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ayyub] dari [Abu Kilabah] ia berkata: \" Tidaklah seorang berbuat bid`ah kecuali ia menghalalkan pedang ditebaskan\". "},"92":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ قَالَ إِنَّ أَهْلَ الْأَهْوَاءِ أَهْلُ الضَّلَالَةِ وَلَا أَرَى مَصِيرَهُمْ إِلَّا النَّارَ فَجَرِّبْهُمْ فَلَيْسَ أَحَدٌ مِنْهُمْ يَنْتَحِلُ قَوْلًا أَوْ قَالَ حَدِيثًا فَيَتَنَاهَى بِهِ الْأَمْرُ دُونَ السَّيْفِ وَإِنَّ النِّفَاقَ كَانَ ضُرُوبًا ثُمَّ تَلَا { وَمِنْهُمْ مَنْ عَاهَدَ اللَّهَ } { وَمِنْهُمْ مَنْ يَلْمِزُكَ فِي الصَّدَقَاتِ } { وَمِنْهُمْ الَّذِينَ يُؤْذُونَ النَّبِيَّ } فَاخْتَلَفَ قَوْلُهُمْ وَاجْتَمَعُوا فِي الشَّكِّ وَالتَّكْذِيبِ وَإِنَّ هَؤُلَاءِ اخْتَلَفَ قَوْلُهُمْ وَاجْتَمَعُوا فِي السَّيْفِ وَلَا أَرَى مَصِيرَهُمْ إِلَّا النَّارَ قَالَ حَمَّادٌ ثُمَّ قَالَ أَيُّوبُ عِنْدَ ذَا الْحَدِيثِ أَوْ عِنْدَ الْأَوَّلِ وَكَانَ وَاللَّهِ مِنْ الْفُقَهَاءِ ذَوِي الْأَلْبَابِ يَعْنِي أَبَا قِلَابَةَ","id":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah] ia berkata: \" Sesungguhnya pemuja hawa nafsu adalah orang-orang yang sesat, dan aku tidak melihat akhir perjalanan yang mereka tempuh kecuali neraka. Ujilah mereka itu. Tidak ada seorang pun dari mereka yang menyitir perkataan atau berkata, hingga persoalannya tiada lain adalah pedang. Sesungguhnya kemunafikan sudah menjadi ciri khas mereka. Kemudian ia membaca ayat \"WA MINHUM MAN 'AHADALLAHA' (Dan diantara mereka ada orang yang telah berikrar kepada Allah Subhaanallahu wa Ta'ala) -Qs. At Taubah: 75-, dan ayat \"WA MINHUM MAN YALMIZUKA FIS SHADAQAAT' (Dan diantara mereka ada orang yang mencelamu tentang (pembagian) zakat) -Qs. At Taubah: 58-, dan ayat \"WAMINHUMULLADZINA YU`DZUUNANABIYYA' (Dan diantara mereka 'orang-orang munafik' ada yang menyakiti Nabi shallallahu 'alaihi wasallam) -Qs. Attaubah: 116-,. Kemudian mereka berbeda pendapat dan berselisih, dan akhirnya mereka berkumpul dalam keraguan dan kedustaan,. Sesungguhnya mereka berbeda pendapat dan bersatu dalam gelayut pedang. Dan aku tidak melihat perjalanan mereka kecuali ke neraka\". Hammad berkata: \"Ayyub berkata tentang hadits ini atau hadits awal, demi Allah Subhaanallahu wa Ta'ala, ia termasuk salah seorang pakar fikih yang sangat cerdas, maksudku adalah Abu Qilabah\"."},"93":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا الْمَسْعُودِيُّ عَنْ عَبْدِ الْمَلِكِ بْنِ مَيْسَرَةَ عَنْ النَّزَّالِ بْنِ سَبْرَةَ قَالَ مَا خَطَبَ عَبْدُ اللَّهِ خُطْبَةً بِالْكُوفَةِ إِلَّا شَهِدْتُهَا فَسَمِعْتُهُ يَوْمًا وَسُئِلَ عَنْ رَجُلٍ يُطَلِّقُ امْرَأَتَهُ ثَمَانِيَةً وَأَشْبَاهِ ذَلِكَ قَالَ هُوَ كَمَا قَالَ ثُمَّ قَالَ إِنَّ اللَّهَ أَنْزَلَ كِتَابَهُ وَبَيَّنَ بَيَانَهُ فَمَنْ أَتَى الْأَمْرَ مِنْ قِبَلِ وَجْهِهِ فَقَدْ بُيِّنَ لَهُ وَمَنْ خَالَفَ فَوَاللَّهِ مَا نُطِيقُ خِلَافَكُمْ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Al Mas'udi] dari [Abdul Malik bin Maisarah] dari [An Nazzal bin Sabrah] ia berkata: Tidaklah [Abdullah] menyampaikan satu khutbah pun di kota Kufah melainkan aku menghadirinya. Suatu hari aku pernah mendengar (ia berhutbah) dan ia ditanya tentang seseorang yang menthalaq (mencerai) isterinya sebanyak delapan kali atau yang seperti itu, maka ia menjawab: \"Telah jatuh apa yang ia katakan\", lalu ia berkata: \"Allah telah menurunkan kitab-Nya dan memberikan penjelasan tentangnya, barang siapa yang melakukan suatu hal yang sesuai dengan yang (datang) dari-Nya, sungguh itu telah dijelaskan kepadanya, tetapi barang siapa yang menyalahi, demi Allah kami tidak mampu melayani tindakan salah kalian\". "},"94":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي عَبْدُ الْمَلِكِ بْنُ مَيْسَرَةَ قَالَ سَمِعْتُ النَّزَّالَ بْنَ سَبْرَةَ قَالَ شَهِدْتُ عَبْدَ اللَّهِ وَأَتَاهُ رَجُلٌ وَامْرَأَةٌ فِي تَحْرِيمٍ فَقَالَ إِنَّ اللَّهَ قَدْ بَيَّنَ فَمَنْ أَتَى الْأَمْرَ مِنْ قِبَلِ وَجْهِهِ فَقَدْ بُيِّنَ وَمَنْ خَالَفَ فَوَاللَّهِ مَا نُطِيقُ خِلَافَكُمْ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalitsi] telah menceritakan kepada kami [Syu'bah] ia berkata: telah mengabarkan kepada kepadaku [Abdul Malik bin maisarah] ia berkata: aku mendengar [An Nazzal bin Sabrah] berkata: Aku pernah menyaksikan [Abdullah] ketika seorang lelaki dan wanita mendatanginya (untuk menanyakan) hal tentang pengharaman hubungan keduanya, maka ia menjawab: \" Allah telah menurunkan kitab-Nya, barang siapa yang melakukan suatu hal yang sesuai dengan syareat-Nya, sungguh itu telah dijelaskan baginya, tetapi barang siapa yang menyalahi, demi Allah kami tidak mampu menanggung beban penyelewengan kalian\". "},"95":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا حَفْصٌ عَنْ أَشْعَثَ عَنْ ابْنِ سِيرِينَ أَنَّهُ كَانَ لَا يَقُولُ بِرَأْيِهِ إِلَّا شَيْئًا سَمِعَهُ","id":"Telah mengabarkan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Hafsh] dari [`Asy'ats] dari [Ibnu Sirin]: \"Bahwasanya ia tidak pernah berkata dengan pendapatnya kecuali sesuatu yang pernah ia dengar\". "},"96":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ قَالَ مَا قُلْتُ بِرَأْيِي مُنْذُ ثَلَاثُونَ سَنَةً قَالَ أَبُو هِلَالٍ مُنْذُ أَرْبَعِينَ سَنَةً","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] ia berkata: \" Aku tidak pernah berpendapat dengan pendapatku semata sejak tiga puluh tahun yang lalu. [Abu Hilal] berkata: \"Bahkan sejak empat puluh tahun\". "},"97":{"ar":" حَدَّثَنَا مَخْلَدُ بْنُ مَالِكٍ حَدَّثَنَا حَكَّامُ بْنُ سَلْمٍ عَنْ أَبِي خَيْثَمَةَ عَنْ عَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ قَالَ سُئِلَ عَطَاءٌ عَنْ شَيْءٍ قَالَ لَا أَدْرِي قَالَ قِيلَ لَهُ أَلَا تَقُولُ فِيهَا بِرَأْيِكَ قَالَ إِنِّي أَسْتَحْيِي مِنْ اللَّهِ أَنْ يُدَانَ فِي الْأَرْضِ بِرَأْيِي","id":"Telah menceritakan kepada kami [Makhlad bin Malik] telah menceritakan kepada kami [Hakkam bin Salm] dari [Abu Khaitsamah] dari [Abdul Aziz bin Rufai'] ia berkata: ['Atho`] ditanya tentang suatu hal, lalu ia menjawab: 'Aku tidak tahu' kemudian seseorang berkata: 'mengapa kamu tidak jawab hal tersebut dengan pendapatmu (saja)? ', ia menjawab: ' Aku malu kepada Allah untuk menjadikan pendapatku sebagai pedoman di muka bumi'.\"."},"98":{"ar":" أَخْبَرَنَا إِسْمَعِيلُ بْنُ أَبَانَ حَدَّثَنَا حَاتِمٌ هُوَ ابْنُ إِسْمَعِيلَ عَنْ عِيسَى عَنْ الشَّعْبِيِّ قَالَ إِيَّاكُمْ وَالْمُقَايَسَةَ وَالَّذِي نَفْسِي بِيَدِهِ لَئِنْ أَخَذْتُمْ بِالْمُقَايَسَةِ لَتُحِلُّنَّ الْحَرَامَ وَلَتُحَرِّمُنَّ الْحَلَالَ وَلَكِنْ مَا بَلَغَكُمْ عَنْ مَنْ حَفِظَ مِنْ أَصْحَابِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاعْمَلُوا بِهِ","id":"Telah mengabarkan kepada kmi [Ismail bin Abaan] telah menceritakan kepada kami [Hatim] dari [Isa] dari [As Sya'bi] ia berkata: \" Berhati-hatilah kalian melakukan qiyas dengan semata-mata mengandalkan otak (rasio) semata, demi Dzat yang jiwaku berada di tanganNya, jika kalian melakukannya maka kalian akan menghalalkan yang haram dan mengharamkan yang halal, tetapi berita yang sampai kepada kalian dari para sahabat Muhammad shallallahu 'alaihi wasallam yang pandai agama, kerjakanlah\"."},"99":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ ابْنِ عَوْنٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ عَلْقَمَةَ قَالَ جَاءَ رَجُلٌ إِلَى عَبْدِ اللَّهِ فَقَالَ إِنَّهُ طَلَّقَ امْرَأَتَهُ الْبَارِحَةَ ثَمَانِيًا قَالَ بِكَلَامٍ وَاحِدٍ قَالَ بِكَلَامٍ وَاحِدٍ قَالَ فَيُرِيدُونَ أَنْ يُبِينُوا مِنْكَ امْرَأَتَكَ قَالَ نَعَمْ قَالَ وَجَاءَهُ رَجُلٌ فَقَالَ إِنَّهُ طَلَّقَ امْرَأَتَهُ مِائَةَ طَلْقَةٍ قَالَ بِكَلَامٍ وَاحِدٍ قَالَ بِكَلَامٍ وَاحِدٍ قَالَ فَيُرِيدُونَ أَنْ يُبِينُوا مِنْكَ امْرَأَتَكَ قَالَ نَعَمْ فَقَالَ عَبْدُ اللَّهِ مَنْ طَلَّقَ كَمَا أَمَرَهُ اللَّهُ فَقَدْ بَيَّنَ اللَّهُ الطَّلَاقَ وَمَنْ لَبَّسَ عَلَى نَفْسِهِ وَكَّلْنَا بِهِ لَبْسَهُ وَاللَّهِ لَا تُلَبِّسُونَ عَلَى أَنْفُسِكُمْ وَنَتَحَمَّلُهُ نَحْنُ هُوَ كَمَا تَقُولُونَ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [Ibnu 'Aun] dari [Muhammad bin Sirin] dari [Alqamah] ia berkata: Seseorang menemui Abdullah, ia menyampaikan uneg-unegnya bahwa ia semalam telah menceraikan isterinya sebanyak delapan kali. Ia (Abdullah) bertanya: 'dengan satu ucapan? ', orang itu menjawab: 'dengan satu ucapan'. Abdullah bertanya: Terus mereka menginginkan agar kamu (menthalaq) ba`in isterimu'?, ia menjawab: 'Ya, benar'. Kemudian ('Alqamah) menceritakan lagi: \" Dan juga pernah Abdullah didatangi seseorang dan menceritakan bahwa ia telah menceraikan isterinya seratus kali'. Abdullah bertanya: 'dengan satu ucapan? ', ia menjawab: 'ya, dengan satu ucapan'. Lalu Abdullah bertanya: 'terus mereka menginginkan agar kamu (menthalaq) ba`in isterimu? ', ia menjawab: 'ya, benar'. Maka [Abdullah] berkata: \" Barang siapa yang menthalaq (isterinya) sesuai dengan cara yang telah Allah jelaskan, sungguh Allah telah menjelaskan thalaq. Sebaliknya barang siapa melakukan tindakan gegabah pada dirinya (tindakan ngawur yang tak ada keterangan), kami pasrahkan kengawuran atau gegabahannya kepadanya, demi Allah, Janganlah sekali-kali kalian melakukan tindakan gegabah diri kalian, sehingga kami merasa kepayahan sebagaimana uneg-uneg yang kalian sampaikan kepadaku ini'\"."},"100":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ الْقَاسِمِ قَالَ لَأَنْ يَعِيشَ الرَّجُلُ جَاهِلًا بَعْدَ أَنْ يَعْلَمَ حَقَّ اللَّهِ عَلَيْهِ خَيْرٌ لَهُ مِنْ أَنْ يَقُولَ مَا لَا يَعْلَمُ","id":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritaklan kepada kami [Hammad bin Zaid] dari [Yahya bin Sa'id] dari [Al Qasim] ia berkata: Seseorang hidup dalam kebodohan setelah ia mengetahui hak Allah atasnya itu lebih baik baginya dari pada ia mengatakan apa yang tidak ia ketahui\". "},"101":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ ابْنِ عَوْنٍ قَالَ سُئِلَ الْقَاسِمُ عَنْ شَيْءٍ قَدْ سَمَّاهُ فَقَالَ مَا أَضْطَرُّ إِلَى مَشُورَةٍ وَمَا أَنَا مِنْ ذَا فِي شَيْءٍ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [Ibnu 'Aun] ia berkata: \"Pernah [Al Qasim] ditanya tentang suatu hal yang ia ceritakan, maka ia menjawab: ' Aku tidak perlu untuk bermusyawarah, dan itu kuanggap tidak masalah\"."},"102":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ سُفْيَانَ بْنِ عُيَيْنَةَ عَنْ يَحْيَى قَالَ قُلْتُ لِلْقَاسِمِ مَا أَشَدَّ عَلَيَّ أَنْ تُسْأَلَ عَنْ الشَّيْءِ لَا يَكُونُ عِنْدَكَ وَقَدْ كَانَ أَبُوكَ إِمَامًا قَالَ إِنَّ أَشَدَّ مِنْ ذَلِكَ عِنْدَ اللَّهِ وَعِنْدَ مَنْ عَقَلَ عَنْ اللَّهِ أَنْ أُفْتِيَ بِغَيْرِ عِلْمٍ أَوْ أَرْوِيَ عَنْ غَيْرِ ثِقَةٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Katsir] dari [Sufyan bin 'Uyainah] dari [Yahya] ia berkata: \"Aku berkata kepada [Al Qasim]: 'Alangkah berat bagiku jika engkau ditanya tentang sesuatu dan engkau tidak mengetahuinya sementara ayahmu adalah seorang imam? '. Ia berkata: 'Yang lebih berat dari hal itu di sisi Allah dan orang-orang yang memahami Allah yaitu aku berfatwa tanpa dasar ilmu atau aku meriwayatkan (satu hadits) dari seorang yang tidak dipercaya'\"."},"103":{"ar":" أَخْبَرَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا حَمَّادُ بْنُ يَزِيدَ الْمِنْقَرِيُّ حَدَّثَنِي أَبِي قَالَ جَاءَ رَجُلٌ يَوْمًا إِلَى ابْنِ عُمَرَ فَسَأَلَهُ عَنْ شَيْءٍ لَا أَدْرِي مَا هُوَ فَقَالَ لَهُ ابْنُ عُمَرَ لَا تَسْأَلْ عَمَّا لَمْ يَكُنْ فَإِنِّي سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ يَلْعَنُ مَنْ سَأَلَ عَمَّا لَمْ يَكُنْ","id":"Telah mengabarkan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Ahmad bin Yazid Al Manqari] telah menceritakan kepadaku [ayahku] ia berkata: \"Pada suatu hari seseorang datang kepada Ibnu umar radliallahu 'anhu, ia menanyakan sesuatu tetapi aku tidak tahu hal apa itu. Kemudian [Ibnu Umar] radliallahu 'anhu berkata: \"Janganlah kamu menanyakan sesuatu yang belum terjadi, karena aku pernah mendengar [Umar bin Khtthab] radliallahu 'anhu melaknat orang yang bertanya suatu hal yang belum terjadi\"."},"104":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ نَافِعٍ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ بَلَغَنَا أَنَّ زَيْدَ بْنَ ثَابِتٍ الْأَنْصَارِيَّ كَانَ يَقُولُ إِذَا سُئِلَ عَنْ الْأَمْرِ أَكَانَ هَذَا فَإِنْ قَالُوا نَعَمْ قَدْ كَانَ حَدَّثَ فِيهِ بِالَّذِي يَعْلَمُ وَالَّذِي يَرَى وَإِنْ قَالُوا لَمْ يَكُنْ قَالَ فَذَرُوهُ حَتَّى يَكُونَ","id":"Telah mengabarkan kepada kami [Al Hakam bin Nafi'] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] ia berkata: \" [Telah sampai berita] kepada kami bahwa [Zaid bin Tsabit Al `Anshari] radliallahu 'anhu, apabila ia ditanya sesuatu selalu berkata: ' Apakah hal ini sudah terjadi? ', apabila mereka menjawab: 'Ya', sungguh ia menjawab pertanyaan sesuai dengan apa yang ia ketahui, tetapi jika mereka menjawab: 'belum terjadi', maka ia pasti mengatakan: 'tunggulah sampai benar-benar terjadi'\"."},"105":{"ar":" أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا أَبُو هِشَامٍ الْمَخْزُومِيُّ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا دَاوُدُ عَنْ عَامِرٍ قَالَ سُئِلَ عَمَّارُ بْنُ يَاسِرٍ عَنْ مَسْأَلَةٍ فَقَالَ هَلْ كَانَ هَذَا بَعْدُ قَالُوا لَا قَالَ دَعُونَا حَتَّى تَكُونَ فَإِذَا كَانَتْ تَجَشَّمْنَاهَا لَكُمْ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Abu Hisyam Al Makhzumi] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Daud] dari ['Amir] ia berkata: \" ['Ammar bin Yasir] radliallahu 'anhu jika ditanya tentang suatu masalah, maka ia berkata: ' Apakah hal ini sudah terjadi?, mereka menjawab: 'belum', ia berkata: 'biarkanlah sampai hal itu benar-benar terjadi. Apabila telah terjadi kami akan memberikan jawabannya kepada kalian\"."},"106":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْمَدَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ طَاوُسٍ قَالَ قَالَ عُمَرُ عَلَى الْمِنْبَرِ أُحَرِّجُ بِاللَّهِ عَلَى رَجُلٍ سَأَلَ عَمَّا لَمْ يَكُنْ فَإِنَّ اللَّهَ قَدْ بَيَّنَ مَا هُوَ كَائِنٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad] telah menceritakan kepada kami [Sufyan] dari ['Amr] dari [Thawus] ia berkata: \" [Umar] radliallahu 'anhu berkata (ketika) di atas mimbar: ' Demi Allah aku sangat tidak suka dengan orang yang bertanya sesuatu yang belum terjadi, sebab Allah menjelaskan permasalahan yang terjadi'\"."},"107":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ عَطَاءٍ عَنْ سَعِيدٍ عَنْ ابْنِ عَبَّاسٍ قَالَ مَا رَأَيْتُ قَوْمًا كَانُوا خَيْرًا مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا سَأَلُوهُ إِلَّا عَنْ ثَلَاثَ عَشْرَةَ مَسْأَلَةً حَتَّى قُبِضَ كُلُّهُنَّ فِي الْقُرْآنِ مِنْهُنَّ { يَسْأَلُونَكَ عَنْ الشَّهْرِ الْحَرَامِ } { وَيَسْأَلُونَكَ عَنْ الْمَحِيضِ } قَالَ مَا كَانُوا يَسْأَلُونَ إِلَّا عَمَّا يَنْفَعُهُمْ","id":"Telah mengabarkan kepada kami [Abdullah bin Muhammad bin Abu Syaibah] telah menceritakan kepada kami [Ibnu Fudlail] dari ['Atho`] dari [Sa'id] dari [Ibnu 'Abbas] radliallahu 'anhu ia berkata: \" Aku tidak pernah melihat suatu kaum yang lebih baik dari pada para sahabat Rasulullah shallallahu 'alaihi wasallam, mereka tidak pernah menanyakan (kepada Nabi shallallahu 'alaihi wasallam) sampai beliau wafat kecuali tentang tiga belas masalah, semuanya ada dalam Al Qur`an. Diantara yang ditanyakan itu adalah: \"YAS`ALUUNAKA ANISSYAHRIL HARAAM\" (Mereka bertanya kepadamu tentang bulan-bulan haram) -Qs. Al Baqarah: 217-, dan \"WA YAS`ALUNAKA ANIL MAHIDL\" (Mereka bertanya kepada kamu tentang haidl) -Qs. Al Baqarah: 222-\"."},"108":{"ar":" حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا ابْنُ عَوْنٍ عَنْ عُمَيْرِ بْنِ إِسْحَقَ قَالَ لَمَنْ أَدْرَكْتُ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْثَرُ مِمَّنْ سَبَقَنِي مِنْهُمْ فَمَا رَأَيْتُ قَوْمًا أَيْسَرَ سِيرَةً وَلَا أَقَلَّ تَشْدِيدًا مِنْهُمْ","id":"Telah menceritakan kepada kami [Utsman bin Umar] telah mengabarkan kepada kami [Ibnu 'Aun] dari ['Umair bin Ishaq] ia berkata: \" Orang-orang yang sempat aku temui dari para sahabat Rasulullah shallallahu 'alaihi wasallam lebih banyak yang telah wafat mendahuluiku, aku tidak pernah dapati satu kaum yang lebih ringan perjalanan hidupnya dan lebih sederhana dalam suatu permasalahan dari pada mereka\"."},"109":{"ar":" أَخْبَرَنِي الْعَبَّاسُ بْنُ سُفْيَانَ عَنْ زَيْدِ بْنِ حُبَابٍ أَخْبَرَنِي رَجَاءُ بْنُ أَبِي سَلَمَةَ قَالَ سَمِعْتُ عُبَادَةَ بْنَ نُسَيٍّ الْكِنْدِيَّ وَسُئِلَ عَنْ امْرَأَةٍ مَاتَتْ مَعَ قَوْمٍ لَيْسَ لَهَا وَلِيٌّ فَقَالَ أَدْرَكْتُ أَقْوَامًا مَا كَانُوا يُشَدِّدُونَ تَشْدِيدَكُمْ وَلَا يَسْأَلُونَ مَسَائِلَكُمْ","id":"Telah mengabarkan kepadaku [Al 'Abbas bin Sufyan] dari [Zaid bin Hubab] telah mengabarkan kepadaku [Raja` bin Abu Salamah] ia berkata: \"Aku pernah mendengar ['Ubadah bin Nusai Al Kindi], ia ditanya tentang seorang wanita yang mati di suatu kaum dan tidak memiliki wali, maka ia berkata: ' Telah aku dapati beberapa kaum mereka tidak memiliki sikap keras sekeras kalian, mereka juga tidak menanyakan apa yang kalian tanyakan'\"."},"110":{"ar":" أَخْبَرَنَا الْعَبَّاسُ بْنُ سُفْيَانَ أَخْبَرَنَا زَيْدُ بْنُ حُبَابٍ أَخْبَرَنِي رَجَاءُ بْنُ أَبِي سَلَمَةَ حَدَّثَنِي خَالِدُ بْنُ حَازِمٍ عَنْ هِشَامِ بْنِ مُسْلِمٍ الْقُرَشِيِّ قَالَ كُنْتُ مَعَ ابْنِ مُحَيْرِيزٍ بِمَرْجِ الدِّيبَاجِ فَرَأَيْتُ مِنْهُ خَلْوَةً فَسَأَلْتُهُ عَنْ مَسْأَلَةٍ فَقَالَ لِي مَا تَصْنَعُ بِالْمَسَائِلِ قُلْتُ لَوْلَا الْمَسَائِلُ لَذَهَبَ الْعِلْمُ قَالَ لَا تَقُلْ ذَهَبَ الْعِلْمُ إِنَّهُ لَا يَذْهَبُ الْعِلْمُ مَا قُرِئَ الْقُرْآنُ وَلَكِنْ لَوْ قُلْتَ يَذْهَبُ الْفِقْهُ","id":"Telah mengabarkan kepada kami [Al 'Abbas bin Sufyan] telah mengabarkan kepada kami [Zaid bin Hubab] telah mengabarkan kepadaku [Raja` bin Abu Salamah] telah menceritaan kepadaku [Khalid bin Hazim] dari [Hisyam bin Muslim Al Qurasyi] ia berkata: \"Dahulu aku bersama [Ibnu Muhairiz] di hamparan sutra, aku melihatnya sedang sendirian lalu aku menanyakan sesuatu hal, maka ia menanyakan kepadaku: ' Apa yang akan kamu lakukan tentang permasalahan-permasalahan tersebut? 'Aku menjawab: 'Sekiranya tidak ada (pembahasan) masalah-masalah maka akan hilanglah ilmu. Ia pun berkata 'Kamu jangan mengatakan ilmu itu hilang, ilmu tidak akan hilang selama Al- Qur`an dibaca, akan tetapi yang paling tepat kau katakan telah hilang pemahaman terhadapnya'\"."},"111":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ أَنَّ عُمَرَ قَالَ يَا أَيُّهَا النَّاسُ إِنَّا لَا نَدْرِي لَعَلَّنَا نَأْمُرُكُمْ بِأَشْيَاءَ لَا تَحِلُّ لَكُمْ وَلَعَلَّنَا نُحَرِّمُ عَلَيْكُمْ أَشْيَاءَ هِيَ لَكُمْ حَلَالٌ إِنَّ آخِرَ مَا نَزَلَ مِنْ الْقُرْآنِ آيَةُ الرِّبَا وَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يُبَيِّنْهَا لَنَا حَتَّى مَاتَ فَدَعُوا مَا يَرِيبُكُمْ إِلَى مَا لَا يَرِيبُكُمْ","id":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Salamah] dari [Daud] dari [As Sya'bi], bahwasanya [Umar] radliallahhu 'anhu berkata; \"Wahai manusia, kami tidak mengetahui mungkin saja kami memerintah kalian melakukan beberapa hal yang tidak halal bagi kalian, dan mungkin saja kami mengharamkan beberapa hal atas kalian padahal ia halal bagi kalian, sesungguhnya yang terakhir turun dari Al Qur`an adalah ayat (tentang) riba. Dan Rasulullah shallallahu 'alaihi wasallam tidak menjelaskannya kepada kami hingga beliau wafat maka tinggalkanlah apa saja yang membuat kalian ragu dan berpeganglah pada sesuatau yang kalian tidak ragu (padanya).\" "},"112":{"ar":" أَخْبَرَنَا سَلْمُ بْنُ جُنَادَةَ حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ عَمِّهِ قَالَ خَرَجْتُ مِنْ عِنْدِ إِبْرَاهِيمَ فَاسْتَقْبَلَنِي حَمَّادٌ فَحَمَّلَنِي ثَمَانِيَةَ أَبْوَابٍ مَسَائِلَ فَسَأَلْتُهُ فَأَجَابَنِي عَنْ أَرْبَعٍ وَتَرَكَ أَرْبَعًا","id":"Telah mengabarkan kepada kami [Salm bin Junadah] telah menceritakan kepada kami [Ibnu Idris] dari [pamannya] ia berkata: \"Aku baru saja pulang dari majlis [Ibrahim], lalu Hammad menemuiku dan memberi tugas kepadaku delapan permasalahan. Hari selanjutnya kedelapan masalah itu kutanyakan kepadanya, lalu ia menjawab empat permasalahan dan meninggalkan empat permasalahan (lainnya) \". "},"113":{"ar":" أَخْبَرَنَا قَبِيصَةُ أَخْبَرَنَا سُفْيَانُ عَنْ عَبْدِ الْمَلِكِ بْنِ أَبْجَرَ عَنْ زُبَيْدٍ قَالَ مَا سَأَلْتُ إِبْرَاهِيمَ عَنْ شَيْءٍ إِلَّا عَرَفْتُ الْكَرَاهِيَةَ فِي وَجْهِهِ","id":"Telah mengabarkan kepada kami [Qabishah] Telah mengabarkan kepada kami [Sufiyan] dari [Abdul Malik bin Abjar] dari [Zubaid] ia berkata: \" Tidaklah aku bertanya kepada [Ibrahim] tentang satu hal kecuali aku melihat tanda ketidaksukaan di wajahnya\"."},"114":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْمَدَ حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ عَنْ عُمَرَ بْنِ أَبِي زَائِدَةَ قَالَ مَا رَأَيْتُ أَحَدًا أَكْثَرَ أَنْ يَقُولَ إِذَا سُئِلَ عَنْ شَيْءٍ لَا عِلْمَ لِي بِهِ مِنْ الشَّعْبِيِّ","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad] telah menceritakan kepada kami [Ishaq bin Mansur] dari [Umar bin Abu Zaidah] ia berkata: \" Aku tidak pernah melihat seorangpun lebih banyak mengatakan: 'aku tidak mempunyai ilmu tentang hal itu' -ketika ia ditanya tentang suatu permasalahan- dibandingkan dengan [As Sya'bi] \"."},"115":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ أَخْبَرَنَا أَحْمَدُ بْنُ بَشِيرٍ حَدَّثَنَا شُعْبَةُ عَنْ جَعْفَرِ بْنِ إِيَاسٍ قَالَ قُلْتُ لِسَعِيدِ بْنِ جُبَيْرٍ مَا لَكَ لَا تَقُولُ فِي الطَّلَاقِ شَيْئًا قَالَ مَا مِنْهُ شَيْءٌ إِلَّا قَدْ سَأَلْتُ عَنْهُ وَلَكِنِّي أَكْرَهُ أَنْ أُحِلَّ حَرَامًا أَوْ أُحَرِّمَ حَلَالًا","id":"Telah mengabarkan kepada kami [Abdullah bin Sa'id] telah mengabarkan kepada kami [Ahmad bin Basyir] telah menceritakan kepada kami [Syu'bah] dari [Ja'far bin Iyas] ia berkata: \"Aku bertanya kepada [Sa'id bin Jubair] radliallahu 'anhu ' Apa yang membuat engkau tidak mengatakan (mengeluarkan pendapat hukum) tentang thalaq? ia menjawab tidak ada satu pun masalah tentang thalaq kecuali aku pernah menanyakannya, akan tetapi aku khawatir, aku menghalalkan yang haram dan mengharamkan yang halal'\"."},"116":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ عَطَاءِ بْنِ السَّائِبِ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ أَبِي لَيْلَى يَقُولُ لَقَدْ أَدْرَكْتُ فِي هَذَا الْمَسْجِدِ عِشْرِينَ وَمِائَةً مِنْ الْأَنْصَارِ وَمَا مِنْهُمْ مِنْ أَحَدٍ يُحَدِّثُ بِحَدِيثٍ إِلَّا وَدَّ أَنَّ أَخَاهُ كَفَاهُ الْحَدِيثَ وَلَا يُسْأَلُ عَنْ فُتْيَا إِلَّا وَدَّ أَنَّ أَخَاهُ كَفَاهُ الْفُتْيَا","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari ['Atho`bin As Sa`ib] ia berkata aku pernah mendengar [Abdurrahman bin Abu Laila] mengatakan: \" Sungguh telah kudapati di masjid ini (Nabawi) seratus dua puluh orang dari kaum anshar, tidak ada seorang pun dari mereka yang menceritakan suatu hadits kecuali ia lebih senang jika saudaranya yang mengutarakan hadis, Dan tidaklah ia ditanya tentang satu fatwa hukum melainkan ia lebih senang jika saudaranya yang mengutarakan fatwa\". "},"117":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ الْحَجَّاجِ قَالَ سَمِعْتُ سُفْيَانَ عَنْ ابْنِ الْمُنْكَدِرِ قَالَ إِنَّ الْعَالِمَ يَدْخُلُ فِيمَا بَيْنَ اللَّهِ وَبَيْنَ عِبَادِهِ فَلْيَطْلُبْ لِنَفْسِهِ الْمَخْرَجَ","id":"Telah mengabarkan kepada kami [Ahmad bin Al Hajjaj] ia berkata: Aku mendengar [Sufyan] dari [Ibnu Al Munkadir] ia berkata \" Seorang ulama (berada) diantara Allah dan para hambaNya, maka hendaklah ia meminta jalan keluar untuk dirinya\"."},"118":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ قُدَامَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ مِسْعَرٍ قَالَ أَخْرَجَ إِلَيَّ مَعْنُ بْنُ عَبْدِ الرَّحْمَنِ كِتَابًا فَحَلَفَ لِي بِاللَّهِ إِنَّهُ خَطُّ أَبِيهِ فَإِذَا فِيهِ قَالَ عَبْدُ اللَّهِ وَالَّذِي لَا إِلَهَ إِلَّا هُوَ مَا رَأَيْتُ أَحَدًا كَانَ أَشَدَّ عَلَى الْمُتَنَطِّعِينَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا رَأَيْتُ أَحَدًا كَانَ أَشَدَّ عَلَيْهِمْ مِنْ أَبِي بَكْرٍ وَإِنِّي لَأَرَى عُمَرَ كَانَ أَشَدَّ خَوْفًا عَلَيْهِمْ أَوْ لَهُمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Qudamah] telah mengabarkan kepada kami [Abu Usamah] dari [Mis'ar] ia berkata: [Ma'an bin Abdur Rahman] pernah menyodorkan kepadaku sebuah kitab dan ia bersumpah dengan kalimat, \"Demi Allah, kitab tersebut adalah hasil tulisan [Ayahnya]. Ternyata dalam kitab tersebut terdapat tulisan ' [Abdullah] berkata; \" Demi Dzat yang tidak ada Tuhan melainkan Dia, aku tidak pernah melihat orang yang sikapnya lebih keras terhadap orang-orang yang suka melampui batas daripada Rasulullah shallallahu'alaihi wasallam, selanjutnya tidak kulihat orang yang lebih keras sikapnya terhadap mereka daripada Abu Bakar radliallahu 'anhu. Dan aku lihat Umar termasuk orang yang paling khawatir terhadap mereka atau bencana yang akan menimpa mereka \"."},"119":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زَمْعَةُ بْنُ صَالِحٍ عَنْ عُثْمَانَ بْنِ حَاضِرٍ الْأَزْدِيِّ قَالَ دَخَلْتُ عَلَى ابْنِ عَبَّاسٍ فَقُلْتُ أَوْصِنِي فَقَالَ نَعَمْ عَلَيْكَ بِتَقْوَى اللَّهِ وَالِاسْتِقَامَةِ اتَّبِعْ وَلَا تَبْتَدِعْ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zam'ah bin Shalih] dari [Utsman bin Hadlr Al Azdi] ia berkata; \" Aku pernah datang menemui [Ibnu Abbas] radliallahu 'anhu, kemudian aku berkata kepadanya: 'Berikanlah wasiat untukku'. Ia menjawab; Ya, akan aku berikan wasiat untukmu. Bertakwalah kepada Allah dan bersikaplah istiqomah di jalanNya. Ikutilah sunnah dan jangan membuat bid'ah\"."},"120":{"ar":" أَخْبَرَنَا يُوسُفُ بْنُ مُوسَى حَدَّثَنَا أَزْهَرُ عَنْ ابْنِ عَوْنٍ عَنْ ابْنِ سِيرِينَ قَالَ مَا دَامَ عَلَى الْأَثَرِ فَهُوَ عَلَى الطَّرِيقِ","id":"Telah mengabarkan kepada kami [Yusuf bin Musa] telah menceritakan kepada kami [Azhar] dari [Ibnu 'Aun] dari [Ibnu Sirin] ia berkata; \" Selama seseorang di rel atsar, berarti ia berada di atas jalur yang benar\". "},"121":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي قِلَابَةَ قَالَ قَالَ عَبْدُ اللَّهِ بْنُ مَسْعُودٍ تَعَلَّمُوا الْعِلْمَ قَبْلَ أَنْ يُقْبَضَ وَقَبْضُهُ أَنْ يَذْهَبَ أَهْلُهُ أَلَا وَإِيَّاكُمْ وَالتَّنَطُّعَ وَالتَّعَمُّقَ وَالْبِدَعَ وَعَلَيْكُمْ بِالْعَتِيقِ","id":"Telah mengabarkan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Al `Auza'i] dari [Yahya bin Abu Katsir] dari [Abu Qilabah] ia berkata; [Abdullah bin Mas'ud] radliallahu 'anhu berkata; \" Pelajarilah ilmu sebelum ia dicabut. Dan, dicabutnya ilmu dengan cara ulama diwafatkan. Oleh karena itu, tinggalkanlah bid'ah, bersilat lidah dan sikap sering mengada-ada dan melampui batas hingga persoalan menjadi rumit. Dan, berpegang teguhlah kepada sesuatu yang kuno, yaitu sunnah dan atsar (ucapan sahabat) \"."},"122":{"ar":" أَخْبَرَنَا إِبْرَاهِيمُ بْنُ مُوسَى حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ سَعِيدِ بْنِ أَبِي أَيُّوبَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَجْرَؤُكُمْ عَلَى الْفُتْيَا أَجْرَؤُكُمْ عَلَى النَّارِ","id":"Telah mengabarkan kepada kami [Ibrahim bin Musa] telah menceritakan kepada kami [Ibnu Al Mubarak] dari [Sa'id bin Abu Ayyub] dari ['Ubaidullah bin Abu Ja'far] ia berkata: \"Rasulullah shallallahu 'alaihi wasallam bersabda: ' Siapa yang paling tergesa-gesa dalam mengeluarkan fatwa, ialah yang paling cepat menuju ke neraka'\"."},"123":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ عَبْدَةَ بْنِ أَبِي لُبَابَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ مَنْ أَحْدَثَ رَأْيًا لَيْسَ فِي كِتَابِ اللَّهِ وَلَمْ تَمْضِ بِهِ سُنَّةٌ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَدْرِ عَلَى مَا هُوَ مِنْهُ إِذَا لَقِيَ اللَّهَ عَزَّ وَجَلَّ","id":"Telah mengabarkan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Al `Auza'i] dari ['Abdah bin Abu Lubabah] dari [Ibnu Abbas] radliallahu 'anhu ia berkata: \" Barang siapa yang mengada-adakan pendapat selain dari Kitab Allah dan sunnah Rasulullah shallallahu 'alaihi wasallam, ia tidak tahu bagaimana kondisinya ketika bertemu Allah kelak\"."},"124":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْمَدَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي سِنَانٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَ مَنْ أَفْتَى بِفُتْيَا يُعَمَّى عَلَيْهَا فَإِثْمُهَا عَلَيْهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Abu Sinan] dari [Sa'id bin Jubair] dari [Ibnu Abbas] radliallahu 'anhu ia berkata: \" Barang siapa berfatwa tidak diketahui dasarnya, dosanya dilimpahkan kepadanya\"."},"125":{"ar":" أَخْبَرَنَا الْحُسَيْنُ بْنُ مَنْصُورٍ حَدَّثَنَا الْحُسَيْنُ بْنُ الْوَلِيدِ عَنْ وُهَيْبٍ عَنْ هِشَامٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ أَنَّهُ كَانَ لَا يُفْتِي فِي الْفَرْجِ بِشَيْءٍ فِيهِ اخْتِلَافٌ","id":"Telah mengabarkan kepada kami [Al Husain bin mansur] telah menceritakan kepada kami [Al Husain bin Al Walid] dari [Wuhaib] dari [Hisyam] dari [Muhammad bin Sirin] Bahwasanya ia tidak pernah berfatwa tentang permasalahan farji (kemaluan) yang masih ada perbedaan pendapat pada masalah tersebut\"."},"126":{"ar":" حَدَّثَنَا بِشْرُ بْنُ الْحَكَمِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَ سَأَلْتُهُ عَنْ رَجُلٍ أَدْرَكَهُ رَمَضَانَانِ فَقَالَ أَكَانَ أَوْ لَمْ يَكُنْ قَالَ لَمْ يَكُنْ بَعْدُ فَقَالَ اتْرُكْ بَلِيَّتَهُ حَتَّى تَنْزِلَ قَالَ فَدَلَسْنَا لَهُ رَجُلًا فَقَالَ قَدْ كَانَ فَقَالَ يُطْعِمُ عَنْ الْأَوَّلِ مِنْهُمَا ثَلَاثِينَ مِسْكِينًا لِكُلِّ يَوْمٍ مِسْكِينٌ","id":"Telah mengabarkan kepada kami [Bisyr bin Al Hakam] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari ['Amr bin Maimun] dari [ayahnya] dari [Ibnu Abbas] radliallahu 'anhu: \"Aku pernah bertanya kepadanya (Ibnu Abbas radliallahu 'anhu) tentang seseorang yang mendapati dua bulan ramadlan, lalu ia berkata: ' Apakah sudah terjadi atau belum? ', ia menjawab: 'belum terjadi'. Kemudian ia berkata: 'Tinggalkanlah sampai hal itu terjadi', ia berkata: 'kami menyiasati dengan pura-pura (menghadirkan) seseorang, lalu ia berkata: 'sudah pernah terjadi', maka (Ibnu Abbas) mnjawab: 'Ia harus memberi makan untuk (bulan ramadlan) yang pertama sebanyak tiga puluh orang miskin, setiap harinya satu orang miskin'\"."},"127":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ عِمْرَانَ حَدَّثَنَا إِسْحَقُ بْنُ سُلَيْمَانَ حَدَّثَنَا الْعُمَرِيُّ عَنْ عُبَيْدِ بْنِ جُرَيْجٍ قَالَ كُنْتُ أَجْلِسُ بِمَكَّةَ إِلَى ابْنِ عُمَرَ يَوْمًا وَإِلَى ابْنِ عَبَّاسٍ يَوْمًا فَمَا يَقُولُ ابْنُ عُمَرَ فِيمَا يُسْأَلُ لَا عِلْمَ لِي أَكْثَرُ مِمَّا يُفْتِي بِهِ","id":"Telah mengabarkan kepada kami [Abdullah bin Imran] telah menceritakan kepada kami [Ishaq bin Sulaiman] telah menceritakan kepada kami [Al 'Umari] dari ['Ubaid bin Juraij] ia berkata: \"Dahulu sewaktu di Makkah aku selalu duduk di (kajian ilmu) Ibnu Umar radliallahu 'anhu sehari dan di (kajian) Ibnu Abbas di hari lainnya. Dan [Ibnu Umar] ketika ditanya lebih banyak menjawab dengan jawaban: ' Aku tidak tahu' dibandingkan berfatwa dalam masalah tersebut\". "},"128":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ قَالَ قَالَ عَبْدُ اللَّهِ تَعَلَّمُوا فَإِنَّ أَحَدَكُمْ لَا يَدْرِي مَتَى يُخْتَلُّ إِلَيْهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Al A'masy] dari [Abu Wa`il] ia berkata: \" [Abdullah] berkata: ' Hendaklah kalian belajar, karena salah seorang diantara kalian tidak tahu kapan ia diperselisihkan'\"."},"129":{"ar":" أَخْبَرَنَا إِبْرَاهِيمُ بْنُ مُوسَى وَعَمْرُو بْنُ زُرَارَةَ عَنْ عَبْدِ الْعَزِيزِ بْنِ مُحَمَّدٍ عَنْ أَبِي سُهَيْلٍ قَالَ كَانَ عَلَى امْرَأَتِي اعْتِكَافُ ثَلَاثَةِ أَيَّامٍ فِي الْمَسْجِدِ الْحَرَامِ فَسَأَلْتُ عُمَرَ بْنَ عَبْدِ الْعَزِيزِ وَعِنْدَهُ ابْنُ شِهَابٍ قَالَ قُلْتُ عَلَيْهَا صِيَامٌ قَالَ ابْنُ شِهَابٍ لَا يَكُونُ اعْتِكَافٌ إِلَّا بِصِيَامٍ فَقَالَ لَهُ عُمَرُ بْنُ عَبْدِ الْعَزِيزِ أَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا قَالَ فَعَنْ أَبِي بَكْرٍ قَالَ لَا قَالَ فَعَنْ عُمَرَ قَالَ لَا قَالَ فَعَنْ عُثْمَانَ قَالَ لَا قَالَ عُمَرُ مَا أَرَى عَلَيْهَا صِيَامًا فَخَرَجْتُ فَوَجَدْتُ طَاوُسًا وَعَطَاءَ بْنَ أَبِي رَبَاحٍ فَسَأَلْتُهُمَا فَقَالَ طَاوُسٌ كَانَ ابْنُ عَبَّاسٍ لَا يَرَى عَلَيْهَا صِيَامًا إِلَّا أَنْ تَجْعَلَهُ عَلَى نَفْسِهَا قَالَ وَقَالَ عَطَاءٌ ذَلِكَ رَأْيِي","id":"Telah mengabarkan kepada kami [Ibrahim bin Musa] dan ['Amru bin Zurarah] dari [Abdul Aziz bin Muhammad] dari [Abu Suhail] ia berkata; \"Dahulu, isteriku pernah bernadzar untuk beri'tikaf di Masjidil Haram selama tiga hari. Kemudian, aku bertanya kepada Umar bin Abdul Aziz rahimahullahu yang saat itu sedang bersama Syihab. Aku bertanya: 'Apakah ia juga wajib berpuasa? ', Ibnu Syihab menjawab: 'Tidak ada i'itikaf kecuali dilakukan sambil berpuasa'. Saat itu, Umar bin Abdul Aziz rahimahullahu terus bertanya: 'Adakah keterangan yang demikian berasal dari Nabi salallahu 'alihi wa sallam? ' Ia menjawab: 'tidak'. Kemudian, Umar bin Abdul Aziz rahimahullahu bertanya: 'Adakah keterangan dari Abu Bakar radliallahu 'anhu? ' ia menjawab: 'tidak ada', ia bertanya: 'adakah keterangan dari Umar radliallahu 'anhu? ', ia menjawab: 'tidak ada juga' ia bertanya: 'adakah keterangan dari Utsman radliallahu 'anhu? ', ia menjawab: 'tidak ada'. Umar rahimahullahu berkata: 'Menurutku tidak wajib bagi wanita itu untuk berpuasa', Lalu aku keluar dan bertemu Thawus dan 'Atho` bin Abu Rabbah, aku bertanya kepada keduanya. [Thawus] menjawab: 'Dahulu [Ibnu Abbas] radliallahu 'anhu (pernah berfatwa) bahwa wanita tersebut tidak wajib puasa, kecuali jika ia bernadzar untuk berpuasa'. Kemudian `Atha` berkata: 'Begitu juga pendapatku'\". "},"130":{"ar":" حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبُو عَقِيلٍ حَدَّثَنَا سَعِيدٌ الْجُرَيْرِيُّ عَنْ أَبِي نَضْرَةَ قَالَ لَمَّا قَدِمَ أَبُو سَلَمَةَ الْبَصْرَةَ أَتَيْتُهُ أَنَا وَالْحَسَنُ فَقَالَ لِلْحَسَنِ أَنْتَ الْحَسَنُ مَا كَانَ أَحَدٌ بِالْبَصْرَةِ أَحَبَّ إِلَيَّ لِقَاءً مِنْكَ وَذَلِكَ أَنَّهُ بَلَغَنِي أَنَّكَ تُفْتِي بِرَأْيِكَ فَلَا تُفْتِ بِرَأْيِكَ إِلَّا أَنْ تَكُونَ سُنَّةٌ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ كِتَابٌ مُنْزَلٌ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Abu 'Aqil] telah menceritakan kepada kami [Sa'id Al Jurairi] dari [Abu Nadlrah] ia berkata: \"Sewaktu [Abu Salamah] datang ke kota Bashrah, aku dan Al Hasan menemuinya, lalu ia berkata kepada Al Hasan: 'Apakah kamu Al Hasan? ', Tidak ada seorang pun yang di kota ini yang lebih ingin aku temui melebihimu', hal itu karena telah sampai kabar kepadaku, bahwa kamu telah berfatwa dengan akalmu. Janganlah kamu berfatwa dengan pendapatmu, kecuali berdasarkan sunnah dari Rasulullah shallallahu 'alaihi wasallam, atau dari Kitab yang telah diturunkan (Al Qur`an) '\". "},"131":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ حُرَيْثِ بْنِ ظُهَيْرٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَ أَتَى عَلَيْنَا زَمَانٌ لَسْنَا نَقْضِي وَلَسْنَا هُنَالِكَ وَإِنَّ اللَّهَ قَدْ قَدَّرَ مِنْ الْأَمْرِ أَنْ قَدْ بَلَغْنَا مَا تَرَوْنَ فَمَنْ عَرَضَ لَهُ قَضَاءٌ بَعْدَ الْيَوْمِ فَلْيَقْضِ فِيهِ بِمَا فِي كِتَابِ اللَّهِ عَزَّ وَجَلَّ فَإِنْ جَاءَهُ مَا لَيْسَ فِي كِتَابِ اللَّهِ فَلْيَقْضِ بِمَا قَضَى بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنْ جَاءَهُ مَا لَيْسَ فِي كِتَابِ اللَّهِ وَلَمْ يَقْضِ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلْيَقْضِ بِمَا قَضَى بِهِ الصَّالِحُونَ وَلَا يَقُلْ إِنِّي أَخَافُ وَإِنِّي أُرَى فَإِنَّ الْحَرَامَ بَيِّنٌ وَالْحَلَالَ بَيِّنٌ وَبَيْنَ ذَلِكَ أُمُورٌ مُشْتَبِهَةٌ فَدَعْ مَا يَرِيبُكَ إِلَى مَا لَا يَرِيبُكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Al A'masy] dari ['Umarah bin 'Umair] dari [Huraits bin Zhuhair] dari [Abdullah bin Mas'ud] ia berkata: \" Akan datang kepada kami satu zaman, kami bukan orang-orang yang memutuskan dan kami pun waktu itu tidak ada di situ, Dan sesungguhnya Allah sudah mentakdirkan sesuatu yang belum kalian lihat (belum terjadi). Maka barang siapa yang mendapatkan masalah setelah hari ini, hendaklah ia memutuskan sesuai dengan Kitab Allah subhanallahu wa ta'ala, jika masalahnya tidak ada dalam Al Qur`an, hendaklah ia memutuskan sesuai dengan apa yang telah diputuskan Rasulullah shallallahu 'alaihi wasallam. Tetapi jika ia datang kepadanya masalah yang tidak ada dalam Al Qur`an dan keputusan Rasulullah shallallahu 'alaihi wasallam, hendaklah ia memutuskan dengan apa yang telah diputuskan oleh orang-orang yang shalih, dan jangan ia katakan: 'Aku takut', atau berkata: 'Menurutku'. Sesungguhnya perkara yang haram telah jelas dan yang halal itu telah jelas dan diantara keduanya adalah perkara yang mutasyabih (samar-samar). Maka tinggalkan apa yang kalian ragu dan berpegang teguhlah pada sesuatu yang kalian tidak ragu padanya\"."},"132":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ ابْنِ مَسْعُودٍ قَالَ إِنَّ الَّذِي يُفْتِي النَّاسَ فِي كُلِّ مَا يُسْتَفْتَى لَمَجْنُونٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Al A'masy] dari [Abu Wa`il] dari [Ibnu Mas'ud] ia berkata: \" Orang yang selalu berfatwa dalam setiap permasalahan yang ditanyakan (kepadanya) adalah orang gila\". "},"133":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ هِشَامٍ عَنْ مُحَمَّدٍ عَنْ حُذَيْفَةَ قَالَ إِنَّمَا يُفْتِي النَّاسَ ثَلَاثَةٌ رَجُلٌ إِمَامٌ أَوْ وَالٍ وَرَجُلٌ يَعْلَمُ نَاسِخَ الْقُرْآنِ مِنْ الْمَنْسُوخِ قَالُوا يَا حُذَيْفَةُ وَمَنْ ذَاكَ قَالَ عُمَرُ بْنُ الْخَطَّابِ أَوْ أَحْمَقُ مُتَكَلِّفٌ","id":"Telah menhabarkan kepada kami [Sa'id bin 'Amir] dari [Hisyam] dari [Muhammad] dari [Hudzaifah] ia berkata: \" Ada tiga golongan manusia yang memberikan fatwa (yaitu): Seorang imam, atau wali (yang mengatur urusan kaum muslimin) atau seorang yang mengetahui nasikh dan mansukh dalam Al Qur`an, mereka bertanya: 'Wahai Hudzaifah, lalu siapakah gerangan dia itu? ', Itu Umar bin Khatthab radliallahu 'anhu, Atau orang bodoh yang memaksakan diri'\"."},"134":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ أَخْبَرَنَا أَبُو أُسَامَةَ عَنْ هِشَامِ بْنِ حَسَّانَ عَنْ مُحَمَّدٍ عَنْ أَبِي عُبَيْدَةَ بْنِ حُذَيْفَةَ قَالَ قَالَ حُذَيْفَةُ إِنَّمَا يُفْتِي النَّاسَ أَحَدُ ثَلَاثَةٍ رَجُلٌ عَلِمَ نَاسِخَ الْقُرْآنِ مِنْ مَنْسُوخِهِ قَالُوا وَمَنْ ذَاكَ قَالَ عُمَرُ بْنُ الْخَطَّابِ قَالَ وَأَمِيرٌ لَا يَجِدُ بُدًّا أَوْ أَحْمَقُ مُتَكَلِّفٌ ثُمَّ قَالَ مُحَمَّدٌ فَلَسْتُ بِوَاحِدٍ مِنْ هَذَيْنِ وَأَرْجُو أَنْ لَا أَكُونَ الثَّالِثَ","id":"Telah mengabarkan kepada kami [Abdullah bin Sa'id] telah mengabarkan kepada kami [Abu `Usamah] dari [Hisyam bin Hassan] dari [Muhammad] dari [Abu 'Ubaidah bin Hudzaifah] ia berkata: \" [Hudzaifah] berkata: 'Orang yang berfatwa kepada orang lain adalah salah satu dari tiga golongan: Seorang yang mengetahui nasikh dan mansukh dalam Al Qur`an', mereka bertanya: 'Siapakah ia gerangan? ', Umar bin Khatthab radliallahu 'anhu menyambung: 'atau seorang pemimpin yang tidak takut, atau orang bodoh yang memaksakan diri'\". Kemudian Muhammad berkata: \"Aku bukanlah satu dari dua kriteria (pertama) dan aku berharap tidak menjadi bagian yang ke tiga\"."},"135":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا حُمَيْدٌ عَنْ أَبِي رَجَاءٍ عَنْ أَبِي الْمُهَلَّبِ أَنَّ أَبَا مُوسَى قَالَ فِي خُطْبَتِهِ مَنْ عَلِمَ عِلْمًا فَلْيُعَلِّمْهُ النَّاسَ وَإِيَّاهُ أَنْ يَقُولَ مَا لَا عِلْمَ لَهُ بِهِ فَيَمْرُقَ مِنْ الدِّينِ وَيَكُونَ مِنْ الْمُتَكَلِّفِينَ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Humaid] dari [Abu Raja`] dari [Abu Al Muhallab]: \" [Abu Musa] radliallahu 'anhu berkata dalam khutbahnya: ' Barang siapa yang mengetahui suatu ilmu, hendaklah ia mengajarkannya kepada manusia, dan berhati-hatilah seseorang yang mengatakan sesuatu yang ia tidak memiliki ilmu tentangnya, ia akan melenceng dari agama dan menjadi orang-orang yang memaksakan diri'\". "},"136":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ عَنْ خَالِدِ بْنِ عَبْدِ اللَّهِ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِي الْبَخْتَرِيِّ وَزَاذَانَ قَالَا قَالَ عَلِيٌّ وَا بَرْدَهَا عَلَى الْكَبِدِ إِذَا سُئِلْتُ عَمَّا لَا أَعْلَمُ أَنْ أَقُولَ اللَّهُ أَعْلَمُ","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] dari [Khalid bin Abdullah] dari ['Atho` bin As Sa`ib] dari [Abu Al Bakhtari] dan [Zaadzan] keduanya berkata: \" ['Ali] berkata: ' Alangkah sejuknya hati ini, jika aku ditanya tentang sesuatu yang tidak aku ketahui, kemudian aku mengatakan: Allahu a'lam'\"."},"137":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا عُمَيْرُ بْنُ عَرْفَجَةَ حَدَّثَنَا رَزِينٌ أَبُو النُّعْمَانِ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَ إِذَا سُئِلْتُمْ عَمَّا لَا تَعْلَمُونَ فَاهْرُبُوا قَالُوا وَكَيْفَ الْهَرَبُ يَا أَمِيرَ الْمُؤْمِنِينَ قَالَ تَقُولُونَ اللَّهُ أَعْلَمُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami ['Umair bin 'Arfajah] telah menceritakan kepada kami [Razin Abu An Nu'man] dari ['Ali bin Abu Thalib] radliallahu 'anhu ia berkata: \" Apabila kalian ditanya tentang sesuatu yang tidak kalian ketahui maka menghindarlah'. Mereka bertanya: 'Bagaimana cara menghindarnya wahai amirul mu`minin? ', ia menjawab: 'Dengan kalian mengatakan: Allahu a'lam '\". "},"138":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ حُمَيْدٍ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ مُسْلِمٍ الْبَطِينِ عَنْ عَزْرَةَ التَّمِيمِيِّ قَالَ قَالَ عَلِيٌّ وَا بَرْدَهَا عَلَى الْكَبِدِ ثَلَاثَ مَرَّاتٍ قَالُوا وَمَا ذَلِكَ يَا أَمِيرَ الْمُؤْمِنِينَ قَالَ أَنْ يُسْأَلَ الرَّجُلُ عَمَّا لَا يَعْلَمُ فَيَقُولُ اللَّهُ أَعْلَمُ","id":"Telah mengabarkan kepada kami [Muhammad bin Humaid] telah menceritakan kepada kami [Jarir] dari [Mansur] dari [Muslim Al Bathin] dari ['Azrah At Tamimi] ia berkata: \" [Ali] radliallahu 'anhu berkata: ' Alangkah sejuknya hati ini', --beliau mengulangi ucapannya sebanyak tiga kali--, mereka bertanya: 'Apakah hal itu wahai amirul mu`minin? ', ia menjawab: '(ketika) seorang ditanya tentang sesuatu yang tidak ia ketahui lalu ia mengucapkan: Allahu a'lam '\"."},"139":{"ar":" أَخْبَرَنَا فَرْوَةُ بْنُ أَبِي الْمَغْرَاءِ أَخْبَرَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ أَنَّ رَجُلًا سَأَلَهُ عَنْ مَسْأَلَةٍ فَقَالَ لَا عِلْمَ لِي بِهَا فَلَمَّا أَدْبَرَ الرَّجُلُ قَالَ ابْنُ عُمَرَ نِعْمَ مَا قَالَ ابْنُ عُمَرَ سُئِلَ عَمَّا لَا يَعْلَمُ فَقَالَ لَا عِلْمَ لِي بِهِ","id":"Telah mengabarkan kepada kami [Farwah bin Abu Al Maghra`] telah mengabarkan kepada kami ['Ali bin Mushir] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Ibnu Umar] radliallahu 'anhu: \"Bahwasanya seorang telah bertanya kepadanya tentang satu masalah, lalu ia berkata: ' Aku tidak mempunyai ilmu tentang hal itu, lalu setelah orang tersebut pergi, Ibnu Umar radliallahu 'anhu berkata: 'Alangkah bagusnya apa yang dikatakan Ibnu Umar radliallahu 'anhu, ia ditanya tentang satu hal yang tidak ia ketahui lalu ia katakan: 'aku tidak memiliki ilmu dalam hal itu'\"."},"140":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا عَبْدُ اللَّهِ الْعُمَرِيُّ عَنْ نَافِعٍ أَنَّ رَجُلًا أَتَى ابْنَ عُمَرَ يَسْأَلُهُ عَنْ شَيْءٍ فَقَالَ لَا عِلْمَ لِي ثُمَّ الْتَفَتَ بَعْدَ أَنْ قَفَّا الرَّجُلُ فَقَالَ نِعْمَ مَا قَالَ ابْنُ عُمَرَ سُئِلَ عَمَّا لَا يَعْلَمُ فَقَالَ لَا عِلْمَ لِي يَعْنِي ابْنُ عُمَرَ نَفْسَهُ","id":"Telah mengabarkan kepada kami [Abdullah bin Maslamah] telah menceritakan kepada kami [Abdullah Al 'Umari] dari [Nafi']: \" Seorang lelaki datang kepada Ibnu Umar radliallahu 'anhu bertanya sesuatu, lalu ia ([Ibnu Umar] radliallahu 'anhu) berkata: 'Aku tidak tahu', Setelah si penanya berpaling, (Ibnu Umar) menoleh dan berkata dalam hati: 'Alangkah bagusnya apa yang dikatakan Ibnu Umar radliallahu 'anhu, ia ditanya tentang sesuatu yang tidak ia ketahui, lalu ia katakan: 'Aku tidak tahu'. "},"141":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ حُمَيْدٍ حَدَّثَنَا جَرِيرٌ عَنْ مُغِيرَةَ قَالَ كَانَ عَامِرٌ إِذَا سُئِلَ عَنْ شَيْءٍ يَقُولُ لَا أَدْرِي فَإِنْ رُدُّوا عَلَيْهِ قَالَ إِنْ شِئْتَ كُنْتُ حَلَفْتُ لَكَ بِاللَّهِ إِنْ كَانَ لِي بِهِ عِلْمٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Humaid] telah menceritakan kepada kami [Jarir] dari [Mughirah] ia berkata: \"Dahulu ['Amir] jika ditanya tentang sesuatu, ia selalu akan menjawab: 'Aku tidak tahu', tetapi jika mereka memaksa untuk menjawabnya, ia berkata: 'Jika aku mau, maka aku akan bersumpah demi Allah bahwa aku memang tidak tahu'\". "},"142":{"ar":" أَخْبَرَنَا يَعْلَى حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ قَالَ قَالَ عَبْدُ اللَّهِ كَيْفَ أَنْتُمْ إِذَا لَبِسَتْكُمْ فِتْنَةٌ يَهْرَمُ فِيهَا الْكَبِيرُ وَيَرْبُو فِيهَا الصَّغِيرُ وَيَتَّخِذُهَا النَّاسُ سُنَّةً فَإِذَا غُيِّرَتْ قَالُوا غُيِّرَتْ السُّنَّةُ قَالُوا وَمَتَى ذَلِكَ يَا أَبَا عَبْدِ الرَّحْمَنِ قَالَ إِذَا كَثُرَتْ قُرَّاؤُكُمْ وَقَلَّتْ فُقَهَاؤُكُمْ وَكَثُرَتْ أُمَرَاؤُكُمْ وَقَلَّتْ أُمَنَاؤُكُمْ وَالْتُمِسَتْ الدُّنْيَا بِعَمَلِ الْآخِرَةِ","id":"Telah mengabarkan kepada kami [Ya'la] telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] ia berkata: \" [Abdullah] pernah berkata: ' Bagaimana sikap kalian jika ditimpa kekacauan, yang tua menjadi pikun, yang kecil tiba-tiba menjadi dewasa, dan manusia menjadikan kekacauan itu sebagai sunnah, dan tiba-tiba telah diubah, mereka katakan: 'sunnah telah diubah! ', mereka bertanya: 'kapan hal itu terjadi wahai Abu Abdur Rahman? ', ia menjawab: 'Ketika telah banyak orang yang bisa membaca, namun sedikit yang ahli fikih (paham maknanya). Banyak orang yang duduk di pemerintahan, namun sedikit yang amanah. Dan dunia dicari dengan ilmu akhirat'\". "},"143":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ عَنْ خَالِدِ بْنِ عَبْدِ اللَّهِ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَ كَيْفَ أَنْتُمْ إِذَا لَبِسَتْكُمْ فِتْنَةٌ يَهْرَمُ فِيهَا الْكَبِيرُ وَيَرْبُو فِيهَا الصَّغِيرُ إِذَا تُرِكَ مِنْهَا شَيْءٌ قِيلَ تُرِكَتْ السُّنَّةُ قَالُوا وَمَتَى ذَاكَ قَالَ إِذَا ذَهَبَتْ عُلَمَاؤُكُمْ وَكَثُرَتْ جُهَلَاؤُكُمْ وَكَثُرَتْ قُرَّاؤُكُمْ وَقَلَّتْ فُقَهَاؤُكُمْ وَكَثُرَتْ أُمَرَاؤُكُمْ وَقَلَّتْ أُمَنَاؤُكُمْ وَالْتُمِسَتْ الدُّنْيَا بِعَمَلِ الْآخِرَةِ وَتُفُقِّهَ لِغَيْرِ الدِّينِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] dari [Khalid bin Abdullah] dari [Yazid bin Abu Ziyad] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] ia berkata: \" Bagaimana sikap kalian jika ditimpa ketidakberesan, yang tua menjadi pikun dan yang kecil menjadi dewasa. Dan jika ketidakberesan itu ditinggal, akan dikatakan: 'sunnah telah ditinggalkan', mereka bertanya: 'Kapan hal itu terjadi? ', ia menjawab: 'Jika telah pergi para ulama` kalian, dan semakin banyak orang-orang bodoh dari kalian, jika semakin banyak orang yang pandai membaca tetapi sedikit yang ahli fikih, dan semakin banyak para pemimpin kalian tetapi sedikit yang amanah, serta dunia sudah dicari dengan amalan akhirat dan ia diperdalam tetapi bukan untuk (kepentingan) agama'\". "},"144":{"ar":" أَخْبَرَنَا صَالِحُ بْنُ سُهَيْلٍ مَوْلَى يَحْيَى بْنِ أَبِي زَائِدَةَ حَدَّثَنَا يَحْيَى عَنْ مُجَالِدٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ قَالَ لَا يَأْتِي عَلَيْكُمْ عَامٌ إِلَّا وَهُوَ شَرٌّ مِنْ الَّذِي كَانَ قَبْلَهُ أَمَا إِنِّي لَسْتُ أَعْنِي عَامًا أَخْصَبَ مِنْ عَامٍ وَلَا أَمِيرًا خَيْرًا مِنْ أَمِيرٍ وَلَكِنْ عُلَمَاؤُكُمْ وَخِيَارُكُمْ وَفُقَهَاؤُكُمْ يَذْهَبُونَ ثُمَّ لَا تَجِدُونَ مِنْهُمْ خَلَفًا وَيَجِيءُ قَوْمٌ يَقِيسُونَ الْأُمُورَ بِرَأْيِهِمْ","id":"Telah mengabarkan kepada kami [Shalih bin Suhail] -bekas budak Yahya bin Abu Za`idah-, telah menceritakan kepada kami [Yahya] dari [Mujalid] dari [As Sya'bi] dari [Masruq] dari [Abdullah] ia berkata: \" Tidaklah akan datang satu tahun, kecuali tahun tersebut lebih jelek dari sebelumnya, Aku tidak bermaksud mengatakan bahwa suatu tahun lebih baik dari pada tahun lainnya, dan seorang amir (pemimpin) lebih baik dari amir lainnya. Akan tetapi ulama`-ulama`, orang-orang pilihan, dan para ahli fikih kalian telah banyak yang wafat, kemudian kalian tidak mendapatkan ganti mereka, hingga datang orang-orang yang menggunakan qiyas (analogi dalam masalah agama) berdasarkan akal semata\"."},"145":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْمَدَ بْنِ أَبِي خَلَفٍ حَدَّثَنَا يَحْيَى بْنُ سُلَيْمٍ قَالَ سَمِعْتُ دَاوُدَ بْنَ أَبِي هِنْدٍ عَنْ ابْنِ سِيرِينَ قَالَ أَوَّلُ مَنْ قَاسَ إِبْلِيسُ وَمَا عُبِدَتْ الشَّمْسُ وَالْقَمَرُ إِلَّا بِالْمَقَايِيسِ","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad bin Abu Khalaf] telah menceritakan kepada kami [Yahya bin sulaim] ia berkata: \"Aku pernah mendengar [Daud bin Hindun] dari [Ibnu Sirin] rahimahullahu, ia berkata: ' Yang pertama-tama menggunakan qiyas adalah iblis, dan tidaklah matahari dan bulan disembah melainkan karena alasan qiyas'\"."},"146":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ أَنَّهُ قَالَ إِنِّي أَخَافُ أَوْ أَخْشَى أَنْ أَقِيسَ فَتَزِلَّ قَدَمِي","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] telah menceritakan kepada kami [Abu 'Awanah] dari [Isma'il bin Abu Khalid] dari [As Sya'bi] dari [Masruq] bahwa ia berkata: \" Aku takut atau khawatir melakukan qiyas lalu tergelincirlah kakiku\"."},"147":{"ar":" أَخْبَرَنَا صَدَقَةُ بْنُ الْفَضْلِ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ إِسْمَعِيلَ عَنْ الشَّعْبِيِّ قَالَ وَاللَّهِ لَئِنْ أَخَذْتُمْ بِالْمَقَايِيسِ لَتُحَرِّمُنَّ الْحَلَالَ وَلَتُحِلُّنَّ الْحَرَامَ","id":"Telah mengabarkan kepada kami [Shadaqah bin Al Fadl] telah menceritakan kepada kami [Abu Khalid Al `Ahmar] dari [Isma'il] dari [As Sya'bi] ia berkata: \" Demi Allah jika kalian menggunakan qiyas niscaya kalian akan mengharamkan yang halal dan akan menghalalkan yang haram\"."},"148":{"ar":" أَخْبَرَنَا الْحَسَنُ بْنُ بِشْرٍ حَدَّثَنَا أَبِي عَنْ إِسْمَعِيلَ عَنْ عَامِرٍ أَنَّهُ قَالَ كَانَ يَقُولُ مَا أَبْغَضَ إِلَيَّ أَرَأَيْتَ أَرَأَيْتَ يَسْأَلُ الرَّجُلُ صَاحِبَهُ فَيَقُولُ أَرَأَيْتَ وَكَانَ لَا يُقَايِسُ","id":"Telah mengabarkan kepada kami [Al Hasan bin Bisyr] telah menceritakan kepada kami [ayahku] dari [Isma'il] dari ['Amir] Bahwasanya ia berkata: \" Suatu hal yang paling membangkitkan kemarahanku adalah jika seseorang bertanya; menurut anda bagaimana, menurut anda bagaimana. Seorang bertanya kepada temannya: 'menurut anda bagaimana'. Dan Amir tidak melakukan qiyas'\"."},"149":{"ar":" أَخْبَرَنَا صَدَقَةُ بْنُ الْفَضْلِ أَخْبَرَنَا ابْنُ عُيَيْنَةَ عَنْ إِسْمَعِيلَ عَنْ الشَّعْبِيِّ قَالَ لَوْ أَنَّ هَؤُلَاءِ كَانُوا عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَنَزَلَتْ عَامَّةُ الْقُرْآنِ يَسْأَلُونَكَ يَسْأَلُونَكَ","id":"Telah mengabarkan kepada kami [Shadaqah bin Al Fadl] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Isma'il] dari [As Sya'bi] ia berkata: \" Sekiranya mereka itu berada pada zaman Nabi shallallahu 'alaihi wasallam, niscaya kebanyakan ayat Al Qur`an yang turun adalah YAS`ALUUNAKA, YAS`ALUUNAKA (mereka bertanya kepadamu) \". "},"150":{"ar":" أَخْبَرَنَا إِسْمَعِيلُ بْنُ أَبَانَ أَخْبَرَنِي مُحَمَّدٌ هُوَ ابْنُ طَلْحَةَ عَنْ مَيْمُونٍ أَبِي حَمْزَةَ قَالَ قَالَ لِي إِبْرَاهِيمُ يَا أَبَا حَمْزَةَ وَاللَّهِ لَقَدْ تَكَلَّمْتُ وَلَوْ وَجَدْتُ بُدًّا مَا تَكَلَّمْتُ وَإِنَّ زَمَانًا أَكُونُ فِيهِ فَقِيهَ أَهْلِ الْكُوفَةِ زَمَانُ سُوءٍ","id":"Telah mengabarkan kepada kami [Isma'il bin `Abaan] telah mengabarkan kepadaku [Muhammad Ibnu Thalhah], dari [Maimun Abu Hamzah] ia berkata: \" [Ibrahim] berkata kepadaku: 'Wahai Abu Hamzah, demi Allah, aku telah berkata (berfatwa), sekiranya ada yang menggantikan, aku tidak mau berkata (berfatwa), sesungguhnya zaman saat aku menjadi seorang ahli fikih kota Kufah adalah zaman yang tidak baik\"."},"151":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ لَيْثٍ عَنْ مُجَاهِدٍ قَالَ قَالَ عُمَرُ إِيَّاكَ وَالْمُكَايَلَةَ يَعْنِي فِي الْكَلَامِ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Laits] dari [Mujahid] ia berkata: \" [Umar] radliallahu 'anhu berkata: ' Berhati-hatilah dengan mengqiyaskan sesuatu\" Yaitu dalam perkataan."},"152":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا مَالِكٌ هُوَ ابْنُ مِغْوَلٍ قَالَ قَالَ لِيَ الشَّعْبِيُّ مَا حَدَّثُوكَ هَؤُلَاءِ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخُذْ بِهِ وَمَا قَالُوهُ بِرَأْيِهِمْ فَأَلْقِهِ فِي الْحُشِّ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Malik Ibnu Mighwal], ia berkata: [As Sya'bi] telah berkata kepadaku: \"Apa yang mereka ceritakan dari Rasulullah shallallahu 'alaihi wasallam maka ambilah, dan apa yang mereka katakan (berdasarkan) pendapat mereka maka lemparkanlah ke WC\". "},"153":{"ar":" أَخْبَرَنِي الْعَبَّاسُ بْنُ سُفْيَانَ عَنْ زَيْدِ بْنِ حُبَابٍ أَخْبَرَنِي رَجَاءُ بْنُ أَبِي سَلَمَةَ قَالَ سَمِعْتُ عَبْدَةَ بْنَ أَبِي لُبَابَةَ يَقُولُ قَدْ رَضِيتُ مِنْ أَهْلِ زَمَانِي هَؤُلَاءِ أَنْ لَا يَسْأَلُونِي وَلَا أَسْأَلُهُمْ إِنَّمَا يَقُولُ أَحَدُهُمْ أَرَأَيْتَ أَرَأَيْتَ","id":"Telah mengabarkan kepada kami [Al 'Abbas bin Sufyan] dari [Zaid bin hubab], telah mengabarkan kepada kami [Raja` bin Abu Salamah] ia berkata: Aku mendengar ['Abdah bin Abu Lubabah] berkata: 'Sungguh aku senang (jika) masyarakat pada zamanku, mereka tidak bertanya kepadaku dan aku juga tidak bertanya kepada mereka, (Aku sangat tidak suka) karena mereka selalu bertanya: 'Bagaimana menurut pendapatmu, bagaimana menurut pendapatmu\"."},"154":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا وَرْقَاءُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ { وَلَا تَتَّبِعُوا السُّبُلَ } قَالَ الْبِدَعَ وَالشُّبُهَاتِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Warqa`] dari [Ibnu Abu Najih] dari [Mujahid]: \"Dan janganlah kalian mengikuti jalan-jalan itu, ia menafsirkan: 'Yaitu bid`ah dan syubhat-syubhat' \"."},"155":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ أَخْبَرَنَا عَمْرُو بْنُ يَحْيَى قَالَ سَمِعْتُ أَبِي يُحَدِّثُ عَنْ أَبِيهِ قَالَ كُنَّا نَجْلِسُ عَلَى بَابِ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَبْلَ صَلَاةِ الْغَدَاةِ فَإِذَا خَرَجَ مَشَيْنَا مَعَهُ إِلَى الْمَسْجِدِ فَجَاءَنَا أَبُو مُوسَى الْأَشْعَرِيُّ فَقَالَ أَخَرَجَ إِلَيْكُمْ أَبُو عَبْدِ الرَّحْمَنِ بَعْدُ قُلْنَا لَا فَجَلَسَ مَعَنَا حَتَّى خَرَجَ فَلَمَّا خَرَجَ قُمْنَا إِلَيْهِ جَمِيعًا فَقَالَ لَهُ أَبُو مُوسَى يَا أَبَا عَبْدِ الرَّحْمَنِ إِنِّي رَأَيْتُ فِي الْمَسْجِدِ آنِفًا أَمْرًا أَنْكَرْتُهُ وَلَمْ أَرَ وَالْحَمْدُ لِلَّهِ إِلَّا خَيْرًا قَالَ فَمَا هُوَ فَقَالَ إِنْ عِشْتَ فَسَتَرَاهُ قَالَ رَأَيْتُ فِي الْمَسْجِدِ قَوْمًا حِلَقًا جُلُوسًا يَنْتَظِرُونَ الصَّلَاةَ فِي كُلِّ حَلْقَةٍ رَجُلٌ وَفِي أَيْدِيهِمْ حَصًى فَيَقُولُ كَبِّرُوا مِائَةً فَيُكَبِّرُونَ مِائَةً فَيَقُولُ هَلِّلُوا مِائَةً فَيُهَلِّلُونَ مِائَةً وَيَقُولُ سَبِّحُوا مِائَةً فَيُسَبِّحُونَ مِائَةً قَالَ فَمَاذَا قُلْتَ لَهُمْ قَالَ مَا قُلْتُ لَهُمْ شَيْئًا انْتِظَارَ رَأْيِكَ وَانْتِظَارَ أَمْرِكَ قَالَ أَفَلَا أَمَرْتَهُمْ أَنْ يَعُدُّوا سَيِّئَاتِهِمْ وَضَمِنْتَ لَهُمْ أَنْ لَا يَضِيعَ مِنْ حَسَنَاتِهِمْ ثُمَّ مَضَى وَمَضَيْنَا مَعَهُ حَتَّى أَتَى حَلْقَةً مِنْ تِلْكَ الْحِلَقِ فَوَقَفَ عَلَيْهِمْ فَقَالَ مَا هَذَا الَّذِي أَرَاكُمْ تَصْنَعُونَ قَالُوا يَا أَبَا عَبْدِ الرَّحْمَنِ حَصًى نَعُدُّ بِهِ التَّكْبِيرَ وَالتَّهْلِيلَ وَالتَّسْبِيحَ قَالَ فَعُدُّوا سَيِّئَاتِكُمْ فَأَنَا ضَامِنٌ أَنْ لَا يَضِيعَ مِنْ حَسَنَاتِكُمْ شَيْءٌ وَيْحَكُمْ يَا أُمَّةَ مُحَمَّدٍ مَا أَسْرَعَ هَلَكَتَكُمْ هَؤُلَاءِ صَحَابَةُ نَبِيِّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَوَافِرُونَ وَهَذِهِ ثِيَابُهُ لَمْ تَبْلَ وَآنِيَتُهُ لَمْ تُكْسَرْ وَالَّذِي نَفْسِي بِيَدِهِ إِنَّكُمْ لَعَلَى مِلَّةٍ هِيَ أَهْدَى مِنْ مِلَّةِ مُحَمَّدٍ أَوْ مُفْتَتِحُو بَابِ ضَلَالَةٍ قَالُوا وَاللَّهِ يَا أَبَا عَبْدِ الرَّحْمَنِ مَا أَرَدْنَا إِلَّا الْخَيْرَ قَالَ وَكَمْ مِنْ مُرِيدٍ لِلْخَيْرِ لَنْ يُصِيبَهُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنَا أَنَّ قَوْمًا يَقْرَءُونَ الْقُرْآنَ لَا يُجَاوِزُ تَرَاقِيَهُمْ وَايْمُ اللَّهِ مَا أَدْرِي لَعَلَّ أَكْثَرَهُمْ مِنْكُمْ ثُمَّ تَوَلَّى عَنْهُمْ فَقَالَ عَمْرُو بْنُ سَلَمَةَ رَأَيْنَا عَامَّةَ أُولَئِكَ الْحِلَقِ يُطَاعِنُونَا يَوْمَ النَّهْرَوَانِ مَعَ الْخَوَارِجِ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah memberitakan kepada kami ['Amr bin Yahya] ia berkata: \"Aku mendengar [ayahku] menceritakan dari [ayahnya], ia berkata: 'Dahulu kami pernah duduk di depan pintu [Abdullah bin Mas'ud] radliallahu 'anhu sebelum shalat subuh, ketika ia keluar kami berjalan bersamanya menuju masjid. Kemudian Abu Musa Al 'Asy'ari radliallahu 'anhu datang menemui kami dan bertanya: 'Apakah Abu Abdur Rahman telah datang menemui kalian? ', kami menjawab: 'belum', lalu beliau duduk bersama kami hingga (Abu Abdur Rahman) datang. Tatkala ia datang, kami semua berdiri dan menghampirinya, Abu Musa berkata kepadanya: 'Wahai Abu Abdur Rahman, baru saja di masjid aku melihat satu kejadian baru yang tidak aku sukai. Setahuku, Alhamdulillah, sekali pun itu diniyati kebaikan. Ia bertanya: 'apakah itu gerangan? ', 'Jika kamu masih hidup kamu akan melihatnya', Kata Abu Musa. Abu Musa melanjutkan: 'Aku melihat di masjid, sekelompok orang yang (duduk) melingkar sambil menunggu shalat, setiap lingkaran ada seorang (pemandu) nya dan tangan-tangan mereka membawa kerikil, lalu si (pemandu) berkata: 'ucapkanlah takbir seratus kali' dan mereka bertakbir seratus kali, 'dan ucapkanlah tahlil seratus kali' lalu mereka bertahlil seratus kali, 'dan ucapkanlah tasbih seratus kali' lalu mereka mengucapkan tasbih seratus kali. Abu Abdurrahman bertanya: 'Lantas apa yang telah kau katakan kepada mereka? ' Abu Musa menjawab: 'Aku belum berkata apa pun kepada mereka, karena aku menunggu pendapatmu atau perintahmu'. Abu Abdurrahman berkata: 'Tidak sebaiknyakah kamu perintahkan saja mereka untuk menghitung dosa-dosa mereka, serta kamu jamin bahwa kebaikan mereka tidak akan hilang?. Kemudian Abu Abdurrahman beranjak dan kami pun beranjak bersamanya, hingga ia sampai di lokasi jama'ah dzikir yang diceritakannya. Ia berdiri di hadapan mereka, dan berkata: 'Apa yang sedang kalian lakukan? ', mereka menjawab: 'Wahai Abu Abdur Rahman, ini adalah batu-batu kerikil untuk menghitung takbir, tahlil dan tasbih'. Ia berkata: 'Hendaklah kalian menghitung dosa-dosa kalian (saja), aku menjamin amal kebaikan kalian tidak akan hilang, celakalah kalian umat Muhammad shallallahu 'alaihi wasallam, alangkah cepatnya masa kehancuran kalian, padahal mereka para sahabat Nabi shallallahu 'alaihi wasallam masih banyak, dan baju mereka belum basah, juga periuknya belum pecah, demi Dzat yang jiwaku berada di genggaman tangannya, sesungguhnya kalian seakan-akan memiliki agama yang lebih baik dari agama yang dibawa oleh Nabi Muhammad shallallahu 'alaihi wasallam, atau kalian sengaja hendak membuka pintu kesesatan?, mereka menjawab: 'Demi Allah wahai Abu Abdur rahman kami tidak menginginkan kecuali kebaikan'. Abu Abdurrahman menjawab: 'Berapa banyak orang yang menginginkan kebaikan tetapi ia tidak dapat mencapainya, sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah menceritakan kepada kami bahwa ada satu kaum yang membaca Al Qur`an namun tidak melampaui tenggorokan mereka, demi Allah, aku tidak tahu siapa tahu mayoritas mereka adalah dari kalian\", Abu Abdurrahman lantas berpaling dari mereka. 'Amr bin Salamah berkata: 'Kami melihat kebanyakan dari yang berada di kelompok jama'ah dzikir tersebut dihari selanjutnya mencaci-maki kami pada hari (perang) Nahrawan bersama orang-orang khawarij ' \". "},"156":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْمَدَ بْنِ أَبِي خَلَفٍ حَدَّثَنَا يَحْيَى بْنُ سُلَيْمٍ حَدَّثَنِي جَعْفَرُ بْنُ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ الْأَنْصَارِيِّ قَالَ خَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ إِنَّ أَفْضَلَ الْهَدْيِ هَدْيُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَشَرَّ الْأُمُورِ مُحْدَثَاتُهَا وَكُلَّ بِدْعَةٍ ضَلَالَةٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad bin Abu Khalaf] telah menceritakan kepada kami [Yahya bin Sulaim] ia berkata: \"Telah menceritakan kepada kami [Ja'far bin Muhammad] dari [ayahnya] dari [Jabir bin Abdullah Al Anshari] radliallahu 'anhu ia berkata: \"Rasulullah subhanallahu wa ta'ala berkhutbah (di depan kami) lalu beliau memuji Allah dan mengagungkanNya, kemudian beliau bersabda: 'Sesungguhnya petunjuk yang terbaik adalah petunjuk Muhammad shallallahu 'alaihi wasallam dan seburuk-buruk perkara adalah hal baru yang diada-adakan dan setiap bid`ah adalah sesat' \"."},"157":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عُيَيْنَةَ عَنْ أَبِي إِسْحَقَ الْفَزَارِيِّ عَنْ أَسْلَمَ الْمِنْقَرِيِّ عَنْ بِلَادِ بْنِ عِصْمَةَ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مَسْعُودٍ يَقُولُ وَكَانَ إِذَا كَانَ عَشِيَّةَ الْخَمِيسِ لِلَيْلَةِ الْجُمُعَةِ قَامَ فَقَالَ إِنَّ أَصْدَقَ الْقَوْلِ قَوْلُ اللَّهِ وَإِنَّ أَحْسَنَ الْهَدْيِ هَدْيُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالشَّقِيُّ مَنْ شَقِيَ فِي بَطْنِ أُمِّهِ وَإِنَّ شَرَّ الرَّوَايَا رَوَايَا الْكَذِبِ وَشَرَّ الْأُمُورِ مُحْدَثَاتُهَا وَكُلَّ مَا هُوَ آتٍ قَرِيبٌ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Uyainah] dari [Abu Ishak Al Fazari] dari [Aslam Al Minqari] dari [Bilad bin 'Ishmah] ia berkata: \"Aku mendengar [Abdullah bin Mas'ud] radliallahu 'anhu berkata -Dan ini kebiasaan beliau jika hari kamis malam jum'at--: 'Sesungguhnya perkataan yang paling benar adalah perkataan Allah, petunjuk yang paling baik adalah petunjuk Muhammad shallallahu 'alaihi wasallam, kesengsaraan telah ditentukan sejak di rahim ibu, sejelek-jelek periwayatan adalah periwayatan yang bohong, dan seburuk-buruk perkara adalah perkara bid`ah, dan segala yang aku sebutkan ini sudah dekat waktu kedatangannya) \". "},"158":{"ar":" أَخْبَرَنِي مُحَمَّدُ بْنُ عُيَيْنَةَ عَنْ أَبِي إِسْحَقَ الْفَزَارِيِّ عَنْ لَيْثٍ عَنْ أَيُّوبَ عَنْ ابْنِ سِيرِينَ قَالَ مَا أَخَذَ رَجُلٌ بِبِدْعَةٍ فَرَاجَعَ سُنَّةً","id":"Telah mengabarkan kepadaku [Muhammad bin 'Uyainah] dari [Abu Ishak Al Fazari] dari [Laits] dari [Ayyub] dari [Ibnu Sirin] ia berkata: \"Seseorang yang mengambil bid`ah, tak bakalan kembali kepada sunnah.\" "},"159":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ أَبُو الْوَلِيدِ الْهَرَوِيُّ حَدَّثَنَا مُعَاذُ بْنُ مُعَاذٍ عَنْ ابْنِ عَوْنٍ عَنْ عَمْرِو بْنِ سَعِيدٍ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ حَيَّةَ بِنْتِ أَبِي حَيَّةَ قَالَتْ دَخَلَ عَلَيْنَا رَجُلٌ بِالظَّهِيرَةِ فَقُلْتُ يَا عَبْدَ اللَّهِ مِنْ أَيْنَ أَقْبَلْتَ قَالَ أَقْبَلْتُ أَنَا وَصَاحِبٌ لِي فِي بُغَاءٍ لَنَا فَانْطَلَقَ صَاحِبِي يَبْغِي وَدَخَلْتُ أَنَا أَسْتَظِلُّ بِالظِّلِّ وَأَشْرَبُ مِنْ الشَّرَابِ فَقُمْتُ إِلَى لُبَيْنَةٍ حَامِضَةٍ رُبَّمَا قَالَتْ فَقُمْتُ إِلَى ضَيْحَةٍ حَامِضَةٍ فَسَقَيْتُهُ مِنْهَا فَشَرِبَ وَشَرِبْتُ قَالَتْ وَتَوَسَّمْتُهُ فَقُلْتُ يَا عَبْدَ اللَّهِ مَنْ أَنْتَ فَقَالَ أَنَا أَبُو بَكْرٍ قُلْتُ أَنْتَ أَبُو بَكْرٍ صَاحِبُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّذِي سَمِعْتُ بِهِ قَالَ نَعَمْ قَالَتْ فَذَكَرْتُ غَزْوَنَا خَثْعَمًا وَغَزْوَةَ بَعْضِنَا بَعْضًا فِي الْجَاهِلِيَّةِ وَمَا جَاءَ اللَّهُ بِهِ مِنْ الْأُلْفَةِ وَأَطْنَابِ الْفَسَاطِيطِ وَشَبَّكَ ابْنُ عَوْنٍ أَصَابِعَهُ وَوَصَفَهُ لَنَا مُعَاذٌ وَشَبَّكَ أَحْمَدُ فَقُلْتُ يَا عَبْدَ اللَّهِ حَتَّى مَتَى تَرَى أَمْرَ النَّاسِ هَذَا قَالَ مَا اسْتَقَامَتْ الْأَئِمَّةُ قُلْتُ مَا الْأَئِمَّةُ قَالَ أَمَا رَأَيْتِ السَّيِّدَ يَكُونُ فِي الْحِوَاءِ فَيَتَّبِعُونَهُ وَيُطِيعُونَهُ فَمَا اسْتَقَامَ أُولَئِكَ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah Abu Al Walid Al Harawi] telah menceritakan kepada kami [Mu'adz bin Mu'adz] dari [Ibnu 'Aun] dari ['Amr bin Sa'id] dari [Abu Zur'ah bin 'Amr bin Jarir] dari [Hayyah binti Abu Hayyah] ia berkata: \"Seorang laki-laki datang menemui kami pada siang hari, lalu aku bertanya: 'Wahai hamba Allah, kamu datang dari arah mana?\" Ia menjawab: aku datang bersama sahabatku untuk membereskan keperluan kami, lalu sahabatku pergi untuk satu keperluan, maka aku masuk kesini untuk berteduh dan minum. Lalu aku bangkit mengambil susu yang asam (difermentasi). Mungkin ia berkata dengan redaksi: \"QUMTU ILAA DLAIHATIN HAAMIDLAH\"-Perawi ragu kepastian redaksi kalimatnya-- lalu aku suguhkan dan ia pun meminumnya dan aku juga minum. Ia berkata: \"Dan aku mencoba menyeledikinya, aku bertanya: 'Wahai hamba Allah siapakah kamu gerangan? ', ia menjawab: 'Aku [Abu Bakar] ', aku bertanya lagi: 'kamu Abu Bakar sahabat Rasulullah shallallahu 'alaihi wasallam yang pernah aku dengar? ', ia menjawab: 'Ya, benar'. Hayyah bin Abi Hayyah berkata: 'Kemudian kuceritakan kembali peperangan kami alias perang Khats'am, dan peperangan lainnya yang terjadi diantara kami sewaktu zaman jahiliyah dahulu, dan kemudian Allah datang (untuk memancangkan) tali-tali tenda, dan Abu 'Aun mengaitkan jari-jemarinya satu sama lain, dan Mu'adz memperagakan itu pada kami, dan Ahmad pun mengaitkan juga (jari-jemarinya). Kemudian aku bertanya: 'Wahai hamba Allah (kira-kira) sampai kapan kamu dapat lihat kondisi manusia (yang bagus) seperti ini? ', ia menjawab: 'Selama para pemimpin (mereka) tetap istiqamah. Aku bertanya: 'Lho kenapa kok pemimpin? ' ia menjawab: 'Tidakkah kamu lihat bahwa seorang tuan (pemimpin) itu selalu ditengah-tengah perkumpulan rerumahan, lalu orang-orang mengikuti dan menaatinya, dan itu pun terkadang orang-orang tidak mau istiqamah?\". "},"160":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الصَّلْتِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ أَبِيهِ عَنْ أَخٍ لِعَدِيِّ بْنِ أَرْطَاةَ عَنْ أَبِي الدَّرْدَاءِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَخْوَفُ مَا أَخَافُ عَلَيْكُمْ الْأَئِمَّةَ الْمُضِلِّينَ","id":"Telah mengabarkan kepada kami [Muhammad bin As Shalt] telah menceritakan kepada kami [Ibarahim bin Sa'ad] dari [ayahnya] dari [saudara 'Adi bin `Arthah] dari [Abu Darda`] radliallahu 'anhu ia berkata: rasulullah shallallahu 'alaihi wasallam bersabda: \"Yang paling aku takutkan dari kalian adalah para pemimpin yang menyesatkan\". "},"161":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ وَاصِلٍ عَنْ امْرَأَةٍ يُقَالُ لَهَا عَائِذَةُ قَالَتْ رَأَيْتُ ابْنَ مَسْعُودٍ يُوصِي الرِّجَالَ وَالنِّسَاءَ وَيَقُولُ مَنْ أَدْرَكَ مِنْكُنَّ مِنْ امْرَأَةٍ أَوْ رَجُلٍ فَالسَّمْتَ الْأَوَّلَ فَإِنَّكُمْ عَلَى الْفِطْرَةِ قَالَ عَبْدُ اللَّهِ السَّمْتُ الطَّرِيقُ","id":"Telah mengabarkan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Abdur Rahman bin Mahdi] dari [Sufyan] dari [Washil] dari seorang wanita -yang dikenal (dengan nama) [A`idzah] -, ia berkata: \"Aku pernah melihat [Ibnu Mas'ud] memberi wasiat kepada orang laki-laki dan perempuan, ia berkata: 'Siapa saja dari laki-laki atau perempuan hendaklah ia berpegang pada Assamtu yang pertama, pastilah kita akan berada dalam dijalan fitrah' \". Abdullah mengatakan: \"Yang dimaksud dengan AsSamtu adalah jalan\". "},"162":{"ar":" أَخْبَرَنَا مَنْصُورُ بْنُ سَلَمَةَ الْخُزَاعِيُّ عَنْ شَرِيكٍ عَنْ أَبِي حَمْزَةَ عَنْ إِبْرَاهِيمَ قَالَ لَقَدْ أَدْرَكْتُ أَقْوَامًا لَوْ لَمْ يُجَاوِزْ أَحَدُهُمْ ظُفْرًا لَمَا جَاوَزْتُهُ كَفَى إِزْرَاءً عَلَى قَوْمٍ أَنْ تُخَالَفَ أَفْعَالُهُمْ ","id":"Telah mengabarkan kepada kami [Mansur bin Salamah Al Khuza'i] dari [Syarik] dari [Abu Hamzah] dari [Ibrahim] ia berkata: \"Sungguh telah aku dapati beberapa kaum yang sekiranya salah satu dari mereka tidak melampaui seujung kuku, niscaya aku tidak juga akan melampauinya. Cukuplah dianggap menghina suatu kaum jika perbuatan mereka diselisihi\"."},"163":{"ar":" أَخْبَرَنَا يَعْلَى حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ عَطَاءٍ { أَطِيعُوا اللَّهَ وَأَطِيعُوا الرَّسُولَ وَأُولِي الْأَمْرِ مِنْكُمْ } قَالَ أُولُو الْعِلْمِ وَالْفِقْهِ وَطَاعَةُ الرَّسُولِ اتِّبَاعُ الْكِتَابِ وَالسُّنَّةِ","id":"Telah mengabarkan kepada kami [Ya'la] telah menceritakan kepada kami [Abdul Malik] dari ['Atha`]: \"`ATHII'ULLAHA WA `ATHII'UR RASUULA WA `ULIL `AMRI MINKUM\" (Dan taatlah kepada Allah dan taatlah kepada Rasul shallallahu 'alaihi wasallam serta taatlah kepada pemimpin diantara kalian) ia berkata: '(Ulul `amri yaitu) yang mempunyai ilmu dan fikih, dan yang dimaksud taat kepada Rasul adalah mengikuti Al Qur`an dan sunnah' \"."},"164":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ أَدْهَمَ قَالَ سَأَلْتُ ابْنَ شُبْرُمَةَ عَنْ شَيْءٍ وَكَانَتْ عِنْدِي مَسْأَلَةٌ شَدِيدَةٌ فَقُلْتُ رَحِمَكَ اللَّهُ انْظُرْ فِيهَا قَالَ إِذَا وَضَحَ لِيَ الطَّرِيقُ وَوَجَدْتُ الْأَثَرَ لَمْ أَحْبَسْ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Ibrahim bin Adham] ia berkata: \"Pernah aku bertanya kepada [Ibnu Syubrumah] tentang suatu hal yang ketika itu aku mempunyai masalah yang sangat berat. aku berkata: 'Mohon selidiki permasalahan itu, semoga Allah merahmatimu', ia menjawab: 'Apabila jelas jalan bagiku dan aku telah menemukan atsar, aku tidak akan menyembunyikannya' \". "},"165":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ الْهَيْثَمِ حَدَّثَنَا عَوْفٌ عَنْ رَجُلٍ يُقَالُ لَهُ سُلَيْمَانُ بْنُ جَابِرٍ مِنْ أَهْلِ هَجَرَ قَالَ قَالَ ابْنُ مَسْعُودٍ قَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعَلَّمُوا الْعِلْمَ وَعَلِّمُوهُ النَّاسَ تَعَلَّمُوا الْفَرَائِضَ وَعَلِّمُوهُ النَّاسَ تَعَلَّمُوا الْقُرْآنَ وَعَلِّمُوهُ النَّاسَ فَإِنِّي امْرُؤٌ مَقْبُوضٌ وَالْعِلْمُ سَيُقْبَضُ وَتَظْهَرُ الْفِتَنُ حَتَّى يَخْتَلِفَ اثْنَانِ فِي فَرِيضَةٍ لَا يَجِدَانِ أَحَدًا يَفْصِلُ بَيْنَهُمَا","id":"Telah mengabarkan kepada kami [Utsman bin Al Haitsam] telah menceritakan kepada kami ['Auf] dari seseorang -ia dikenal dengan sebutan [Sulaiman bin Jabir] dari penduduk Hajar-, ia berkata: \" [Ibnu Mas'ud] pernah berkata: 'Rasulullah shallallahu 'alaihi wasallam pernah bersabda kepadaku: Hendaklah kalian belajar ilmu, dan ajarkanlah kepada manusia, pelajarilah ilmu fara`idl dan ajarkanlah kepada manusia, pelajarilah Al Qur`an dan ajarkanlah kepada manusia, karena aku seorang yang akan dipanggil (wafat), dan ilmu senantiasa akan berkurang sedangkan kekacauan akan muncul hingga ada dua orang yang akan berselisih pendapat tentang (wajib atau tidaknya) suatu kewajiban, dan keduanya tidak mendapatkan orang yang dapat memutuskan antara keduanya\"."},"166":{"ar":" أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عُمَرُ بْنُ أَبِي خَلِيفَةَ قَالَ سَمِعْتُ زِيَادَ بْنَ مِخْرَاقٍ ذَكَرَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَ أَرْسَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُعَاذَ بْنَ جَبَلٍ وَأَبَا مُوسَى إِلَى الْيَمَنِ قَالَ تَسَانَدَا وَتَطَاوَعَا وَبَشِّرَا وَلَا تُنَفِّرَا فَقَدِمَا الْيَمَنَ فَخَطَبَ النَّاسَ مُعَاذٌ فَحَضَّهُمْ عَلَى الْإِسْلَامِ وَأَمَرَهُمْ بِالتَّفَقُّهِ وَالْقُرْآنِ وَقَالَ إِذَا فَعَلْتُمْ ذَلِكَ فَاسْأَلُونِي أُخْبِرْكُمْ عَنْ أَهْلِ الْجَنَّةِ مِنْ أَهْلِ النَّارِ فَمَكَثُوا مَا شَاءَ اللَّهُ أَنْ يَمْكُثُوا فَقَالُوا لِمُعَاذٍ قَدْ كُنْتَ أَمَرْتَنَا إِذَا نَحْنُ تَفَقَّهْنَا وَقَرَأْنَا أَنْ نَسْأَلَكَ فَتُخْبِرَنَا بِأَهْلِ الْجَنَّةِ مِنْ أَهْلِ النَّارِ فَقَالَ لَهُمْ مُعَاذٌ إِذَا ذُكِرَ الرَّجُلُ بِخَيْرٍ فَهُوَ مِنْ أَهْلِ الْجَنَّةِ وَإِذَا ذُكِرَ بِشَرٍّ فَهُوَ مِنْ أَهْلِ النَّارِ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [Umar bin Abu Khalifah] ia berkata: Aku pernah mendengar [Ziyad bin Mikhraq] menyebutkan dari [Abdullah bin Umar] ia berkata: \"Rasulullah shallallahu 'alaihi wasallam mengutus Mu'adz bin Jabal dan Abu Musa radliallahu 'anhuma ke negara Yaman, beliau berkata: 'Hendaknya kalian saling bersandar, dan saling membantu, dan hendaknya kalian berdua memberikan (kepada mereka) kabar gembira dan janganlah kalian berdua membuat (mereka) lari (dari ajaran Islam), kemudian keduanya datang ke Yaman, lalu Mu'adz memberikan khutbah kepada orang-orang, mengajak mereka untuk masuk Islam, dan memerintahkan kepada mereka untuk memperdalam isi Al Qur`an, dan ia juga berkata: 'Jika kalian sudah lakukan itu semua maka tanyalah kepadaku, akan kukabarkan kepada kalian tentang penghuni surga dan penghuni neraka, mereka (para penghuni surga dan neraka) berada di dalamnya tergantung seberapa lama Allah menghendaki, kemudian mereka berkata kepada Mu'adz: 'Sungguh kamu telah memerintahkan kami, jika kami sudah memperdalam Islam dan telah membaca (mempelajari) Al Qur`an agar kami menanyakanmu (tentang penghuni surga dan neraka), maka kabarkanlah kepada kami tentang penghuni surga dan neraka', kemudian Mu'adz berkata kepada mereka: 'Jika seorang dikenal baik, ia penghuni surga, dan jika seorang dikenal jelek, ia penghuni neraka' \"."},"167":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ هُوَ ابْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ أُسَامَةَ بْنِ الْهَادِ عَنْ عَبْدِ الْوَهَّابِ عَنْ ابْنِ شِهَابٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ مُعَاوِيَةَ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ يُرِدْ اللَّهُ بِهِ خَيْرًا يُفَقِّهْهُ فِي الدِّينِ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abdullah bin Usamah bin Al Had] dari [Abdul Wahab] dari [Ibnu Syihab] dari [Humaid bin Abdur Rahman] dari [Mu'awiyah] radliallahu 'anhu ia berkata: \"Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Barangsiapa yang Allah inginkan menjadi orang baik, Allah jadikan dirinya paham agama\"."},"168":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ سُلَيْمَانَ عَنْ إِسْمَعِيلَ بْنِ جَعْفَرٍ عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدِ بْنِ أَبِي هِنْدٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يُرِدْ اللَّهُ بِهِ خَيْرًا يُفَقِّهْهُ فِي الدِّينِ","id":"Telah mengabarkan kepada kami [Sa'id bin Sulaiman] dari [Isma'il bin Ja'far] dari [Abdullah bin Sa'id bin Abu Hindun] dari [ayahnya] dari [Ibnu Abbas] radliallahu 'anhu ia berkata: \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Barangsiapa yang Allah inginkan menjadi baik, Allah jadikan dirinya paham agama' \"."},"169":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ الزَّهْرَانِيُّ أَخْبَرَنَا إِسْمَعِيلُ هُوَ ابْنُ جَعْفَرٍ حَدَّثَنَا عَمْرُو بْنُ أَبِي عَمْرٍو عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْحُوَيْرِثِ عَنْ مُحَمَّدِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِ أَنَّهُ شَهِدَ خُطْبَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي يَوْمِ عَرَفَةَ فِي حَجَّةِ الْوَدَاعِ أَيُّهَا النَّاسُ إِنِّي وَاللَّهِ لَا أَدْرِي لَعَلِّي لَا أَلْقَاكُمْ بَعْدَ يَوْمِي هَذَا بِمَكَانِي هَذَا فَرَحِمَ اللَّهُ مَنْ سَمِعَ مَقَالَتِي الْيَوْمَ فَوَعَاهَا فَرُبَّ حَامِلِ فِقْهٍ وَلَا فِقْهَ لَهُ وَرُبَّ حَامِلِ فِقْهٍ إِلَى مَنْ هُوَ أَفْقَهُ مِنْهُ وَاعْلَمُوا أَنَّ أَمْوَالَكُمْ وَدِمَاءَكُمْ حَرَامٌ عَلَيْكُمْ كَحُرْمَةِ هَذَا الْيَوْمِ فِي هَذَا الشَّهْرِ فِي هَذَا الْبَلَدِ وَاعْلَمُوا أَنَّ الْقُلُوبَ لَا تُغِلُّ عَلَى ثَلَاثٍ إِخْلَاصِ الْعَمَلِ لِلَّهِ وَمُنَاصَحَةِ أُولِي الْأَمْرِ وَعَلَى لُزُومِ جَمَاعَةِ الْمُسْلِمِينَ فَإِنَّ دَعْوَتَهُمْ تُحِيطُ مِنْ وَرَائِهِمْ","id":"Telah mengabarkan kepada kami [Sulaiman bin Daud Az Zahrani] telah mengabarkan kepada kami [Isma'il Ibnu Ja'far], telah menceritakan kepada kami ['Amr bin Abu 'Amr] dari [Abdur Rahman bin Al Huwairits] dari [Muhammad bin Jubair bin Muth'im] dari [ayahnya] Bahwasanya ia menghadiri hutbah Rasulullah shallallahu 'alaihi wasallam pada hari Arafah ketika haji wada', beliau bersabda: \"Wahai sekalian manusia, demi Allah, aku tidak tahu mungkin aku tidak akan bertemu kalian lagi setelah hari ini, dan di tempat ini, Allah akan merahmati orang yang mendengarkan perkataanku serta mau menjaganya, mungkin saja ada seorang yang membawa ilmu fikih tetapi ia tidak punya pemahaman, dan mungkin saja ada orang yang menyampaikan ilmu fikih kepada orang yang lebih memahaminya. Ketauhilah bahwa harta-harta, dan darah-darah kalian terjaga kehormatannya atas kalian, sebagaimana kehormatan hari, bulan dan tanah ini. Dan ketahuilah, bahwa hati seorang muslim tidak akan dengki dengan tiga hal: ikhlas dalam beramal hanya untuk Allah, saling memberi nasehat dengan para pemimpin, dan senantiasa berada dalam barisan orang-orang muslim. Karena doa mereka akan menjaga dari belakang kalian\". "},"170":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدٌ هُوَ ابْنُ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ مُحَمَّدِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِ قَالَ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْخَيْفِ مِنْ مِنًى فَقَالَ نَضَّرَ اللَّهُ عَبْدًا سَمِعَ مَقَالَتِي فَوَعَاهَا ثُمَّ أَدَّاهَا إِلَى مَنْ لَمْ يَسْمَعْهَا فَرُبَّ حَامِلِ فِقْهٍ لَا فِقْهَ لَهُ وَرُبَّ حَامِلِ فِقْهٍ إِلَى مَنْ هُوَ أَفْقَهُ مِنْهُ ثَلَاثٌ لَا يُغِلُّ عَلَيْهِنَّ قَلْبُ الْمُؤْمِنِ إِخْلَاصُ الْعَمَلِ لِلَّهِ وَطَاعَةُ ذَوِي الْأَمْرِ وَلُزُومُ الْجَمَاعَةِ فَإِنَّ دَعْوَتَهُمْ تَكُونُ مِنْ وَرَائِهِمْ","id":"Telah mengabarkan kepada kami [Ahmad bin Khalid] telah menceritakan kepada kami [Muhammad Ibnu Ishak], dari [Az Zuhri] dari [Muhammad bin Jubair bin Muth'im] dari [ayahnya] ia berkata: \"Rasulullah shallallahu 'alaihi wasallam berdiri di (masjid) khaif di Mina seraya bersabda: 'Semoga Allah memperbagus rupa seseorang yang mendengarkan perkataanku lantas menjaganya, kemudian menyampaikannya kepada orang yang tidak mendengarnya (dariku), berapa banyak orang yang membawa ilmu fikih tetapi ia tidak punya pemahaman, dan berapa banyak ada orang yang menyampaikan ilmu fikih kepada orang yang lebih memahaminya, ada tiga hal yang hati seorang mu`min tidak hasad padanya: ikhlas beramal hanya untuk Allah, taat kepada para pemimpin, dan senantiasa berada dalam barisan kaum muslimin, karena doa mereka menyokong dari belakang mereka\". "},"171":{"ar":" أَخْبَرَنَا عِصْمَةُ بْنُ الْفَضْلِ حَدَّثَنَا حَرَمِيُّ بْنُ عُمَارَةَ عَنْ شُعْبَةَ عَنْ عُمَرَ بْنِ سُلَيْمَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبَانَ بْنِ عُثْمَانَ عَنْ أَبِيهِ قَالَ خَرَجَ زَيْدُ بْنُ ثَابِتٍ مِنْ عِنْدِ مَرْوَانَ بْنِ الْحَكَمِ بِنِصْفِ النَّهَارِ قَالَ فَقُلْتُ مَا خَرَجَ هَذِهِ السَّاعَةَ مِنْ عِنْدِ مَرْوَانَ إِلَّا وَقَدْ سَأَلَهُ عَنْ شَيْءٍ فَأَتَيْتُهُ فَسَأَلْتُهُ فَقَالَ نَعَمْ سَأَلَنِي عَنْ حَدِيثٍ سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَضَّرَ اللَّهُ امْرَأً سَمِعَ مِنَّا حَدِيثًا فَحَفِظَهُ فَأَدَّاهُ إِلَى مَنْ هُوَ أَحْفَظُ مِنْهُ فَرُبَّ حَامِلِ فِقْهٍ لَيْسَ بِفَقِيهٍ وَرُبَّ حَامِلِ فِقْهٍ إِلَى مَنْ هُوَ أَفْقَهُ مِنْهُ لَا يَعْتَقِدُ قَلْبُ مُسْلِمٍ عَلَى ثَلَاثِ خِصَالٍ إِلَّا دَخَلَ الْجَنَّةَ قَالَ قُلْتُ مَا هُنَّ قَالَ إِخْلَاصُ الْعَمَلِ لِلَّهِ وَالنَّصِيحَةُ لِوُلَاةِ الْأَمْرِ وَلُزُومُ الْجَمَاعَةِ فَإِنَّ دَعْوَتَهُمْ تُحِيطُ مِنْ وَرَائِهِمْ وَمَنْ كَانَتْ الْآخِرَةُ نِيَّتَهُ جَعَلَ اللَّهُ غِنَاهُ فِي قَلْبِهِ وَجَمَعَ لَهُ شَمْلَهُ وَأَتَتْهُ الدُّنْيَا وَهِيَ رَاغِمَةٌ وَمَنْ كَانَتْ الدُّنْيَا نِيَّتَهُ فَرَّقَ اللَّهُ عَلَيْهِ شَمْلَهُ وَجَعَلَ فَقْرَهُ بَيْنَ عَيْنَيْهِ وَلَمْ يَأْتِهِ مِنْ الدُّنْيَا إِلَّا مَا قُدِّرَ لَهُ قَالَ وَسَأَلْتُهُ عَنْ صَلَاةِ الْوُسْطَى قَالَ هِيَ الظُّهْرُ","id":"Telah mengabarkan kepada kami ['Ishmah bin Al fadl] telah menceritakan kepada kami [Harami bin 'Umarah] dari [Syu'bah] dari [Umar bin Sulaiman] dari [Abdur Rahman bin `Abaan bin Utsman] dari [ayahnya] ia berkata: \"Di pertengahan hari [Zaid bin Tsabit] keluar (setelah menemui) Marwan bin Hakam, -perawi berkata: aku berkata: 'Dia (Zaid bin Tsabit) tidak akan keluar dari tempat Marwan pada waktu seperti ini kecuali ia telah menanyakan kepadanya tentang sesuatu (yang penting) ', lalu aku menemuinya dan bertanya kepadanya, ia pun menjawab: 'Ya, benar ia (Marwan) Telah menanyakan kepadaku tentang satu hadis yang aku dengar dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: 'Semoga Allah membaguskan rupa seseorang yang mendengarkan hadis dari kami lalu ia menjaganya (menghafalnya) dan menyampaikannya kepada orang yang lebih hafal darinya, berapa banyak orang yang membawa ilmu fikih tetapi ia bukan ahli fikih, dan mungkin saja ada orang yang menyampaikan ilmu fikih kepada orang yang lebih paham (tentang fikih), Tidaklah (hati) seorang muslim meyakini tiga hal ini melainkan ia akan masuk ke surga, aku bertanya: 'Apa saja itu? ', beliau menjawab: 'Ikhlas dalam beramal hanya untuk Allah, memberi nasehat kepada para pemimpin, dan senantiasa bersama dengan jama`ah (kaum muslimin), karena doa mereka akan menyokong mereka dari belakang. Dan barang siapa yang akhirat sebagai tujuannya, Allah memberinya rasa cukup dalam hatinya, dan Ia akan mengumpulkan dunia untuknya, serta dunia akan mendatanginya dengan keinginan yang sangat besar. Sebaliknya barang siapa yang dunia menjadi tujuannya, Allah akan memisahkan apa yang dikumpulkannya dari dirinya, dan menjadikan kefakiran ada di depan kedua matanya (sangat dekat dengannya), dan dunia tidak menghampirinya kecuali bagian yang telah ditetapkan untuknya. Ia (perawi) ' berkata: 'lalu aku bertanya tentang shalat wushtha? ', ia (Zaid bin Tsabit) menjawab: 'Itu shalat zhuhur' \"."},"172":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Isa] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Abu Az Zubair] dari [Jabir] ia berkata: Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang berbohong dengan sengaja atas namaku, hendaknya ia persiapkan tempat duduknya dari api neraka\"."},"173":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَبْدِ الْأَعْلَى عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Isa] telah menceritakan kepada kami [Abu 'Awanah] dari [Abdul A'laa] dari [Sa'id bin Jubair] dari [Ibnu Abbas] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barang siapa yang berbohong dengan sengaja atas namaku, hendaknya ia persiapkan tempat duduknya dari api neraka\"."},"174":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي يَزِيدُ بْنُ عَبْدِ اللَّهِ عَنْ عَمْرِو بْنِ عَبْدِ اللَّهِ بْنِ عُرْوَةَ عَنْ عَبْدِ اللَّهِ بْنِ عُرْوَةَ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ الزُّبَيْرِ أَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ حَدَّثَ عَنِّي كَذِبًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku [Yazid bin Abdullah] dari ['Amr bin Abdullah bin 'Urwah] dari [Abdullah bin 'Urwah] dari [Abdullah bin Az Zubair] dari [Az Zubair] bahwasanya ia mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang menyampaikan satu hadis dariku, padahal dia berbohong, hendaklah ia persiapkan tempat duduknya dari api neraka\"."},"175":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ حُمَيْدٍ حَدَّثَنِي الصَّبَّاحُ بْنُ مُحَارِبٍ عَنْ عُمَرَ بْنِ عَبْدِ اللَّهِ بْنِ يَعْلَى بْنِ مُرَّةَ عَنْ أَبِيهِ عَنْ جَدِّهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah mengabarkan kepada kami [Muhammad bin Humaid] telah menceritakan kepadaku [As Shabbah bin Muharib] dari [Umar bin Abdullah bin Ya'laa bin Murrah] dari [ayahnya] dari [kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang berbohong dengan sengaja atas namaku, hendaklah ia persiapkan tempat duduknya dari api neraka\"."},"176":{"ar":" أَخْبَرَنَا أَسَدُ بْنُ مُوسَى حَدَّثَنَا شُعْبَةُ عَنْ عَتَّابٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُ لَوْلَا أَنِّي أَخْشَى أَنْ أُخْطِئَ لَحَدَّثْتُكُمْ بِأَشْيَاءَ سَمِعْتُهَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ قَالَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَاكَ أَنِّي سَمِعْتُهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah mengabarkan kepada kami [Asad bin Musa] telah menceritakan kepada kami [Syu'bah] dari ['Attab] ia berkata: \"Aku pernah mendengar [Anas bin Malik] radliallahu 'anhu berkata: ' Kalau aku tidak hawatir akan salah, sungguh akan aku ceritakan banyak hal yang aku dengar dari Rasulullah shallallahu 'alaihi wasallam (atau yang Rasulullah shallallahu 'alaihi wasallam sabdakan), hal itu karena aku pernah mendengar beliau bersabda: 'Barang siapa yang berdusta atas namaku dengan sengaja, hendaklah ia siapkan tempat duduknya dari api neraka' \"."},"177":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ أَخْبَرَنَا أَبُو دَاوُدَ عَنْ شُعْبَةَ عَنْ عَبْدِ الْعَزِيزِ وَعَنْ حَمَّادِ بْنِ أَبِي سُلَيْمَانَ وَعَنْ التَّيْمِيِّ وَعَنْ عَتَّابٍ مَوْلَى ابْنِ هُرْمُزَ سَمِعُوا أَنَسَ بْنَ مَالِكٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah] telah mengabarkan kepada kami [Abu Daud] dari [Syu'bah] dari [Abdul Aziz], dan dari [Hammad bin Abu Sulaiman] dari [At taimi] dari ['Attab] -bekas budak Ibnu Hurmuz-, mereka telah mendengar [Anas bin Malik] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barang siapa yang berbohong atasku dengan sengaja, hendaknya ia siapkan tempat duduknya dari api neraka\"."},"178":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدٌ هُوَ ابْنُ إِسْحَقَ عَنْ مَعْبَدِ بْنِ كَعْبٍ عَنْ أَبِي قَتَادَةَ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ عَلَى الْمِنْبَرِ يَا أَيُّهَا النَّاسُ إِيَّاكُمْ وَكَثْرَةَ الْحَدِيثِ عَنِّي فَمَنْ قَالَ عَلَيَّ فَلَا يَقُلْ إِلَّا حَقًّا أَوْ إِلَّا صِدْقًا وَمَنْ قَالَ عَلَيَّ مَا لَمْ أَقُلْ فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah mengabarkan kepada kami [Ahmad bin Khalid] telah menceritakan kepada kami [Muhammad Ibnu Ishak], dari [Ma'bad bin Ka'ab] dari [Abu Qatadah] ia berkata: 'Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda dari atas mimbar: 'Wahai manusia sekalian, hendaklah kalian berhati-hati terhadap berlebihan menyampaikan hadis dariku, karena barang siapa berkata atas namaku, maka ia tidak boleh berkata kecuali yang benar dan jujur, dan barang siapa yang berkata dengan sengaja atas namaku apa yang tidak pernah aku katakan, hendaknya ia siapkan tempat duduknya dari api neraka' \"."},"179":{"ar":" أَخْبَرَنَا هَارُونُ بْنُ مُعَاوِيَةَ عَنْ إِبْرَاهِيمَ بْنِ سُلَيْمَانَ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ مُحَمَّدِ بْنِ بِشْرٍ عَنْ أَنَسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah mengabarkan kepada kami [Harun bin Mu'awiyah] dari [Ibrahim bin Sulaiman] dari ['Ashim Al Ahwal] dari [Muhammad bin Bisyr] dari [Anas] radliallahu 'anhu ia berkata: \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Barang siapa yang berbohong dengan sengaja atas namaku, hendaknya ia siapkan tempat duduknya dari api neraka' \". "},"180":{"ar":" أَخْبَرَنَا جَعْفَرُ بْنُ عَوْنٍ أَخْبَرَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ لَا يَقْبِضُ الْعِلْمَ انْتِزَاعًا يَنْتَزِعُهُ مِنْ النَّاسِ وَلَكِنْ قَبْضُ الْعِلْمِ قَبْضُ الْعُلَمَاءِ فَإِذَا لَمْ يُبْقِ عَالِمًا اتَّخَذَ النَّاسُ رُءُوسًا جُهَّالًا فَسُئِلُوا فَأَفْتَوْا بِغَيْرِ عِلْمٍ فَضَلُّوا وَأَضَلُّوا","id":"Telah mengabarkan kepada kami [Ja'far bin 'Aun] telah mengabarkan kepada kami [Hisyam] dari [ayahnya] dari [Abdullah bin 'Amr] ia berkata: \"Rasulullah shallahu 'alaihi wa sallam bersabda: 'Allah tidak akan mencabut ilmu dari manusia secara langsung, akan tetapi dicabutnya ilmu itu dengan diwafatkannya para ulama`, sehingga ketika tidak tersisa seorang ulama` pun, manusia akan menjadikan orang-orang yang bodoh sebagai pemimpin, lalu mereka ditanya dan mereka berfatwa tanpa dasar ilmu, mereka itu sesat dan menyesatkan' \"."},"181":{"ar":" أَخْبَرَنَا مُوسَى بْنُ خَالِدٍ أَخْبَرَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ الْحَجَّاجِ عَنْ عَوْفِ بْنِ مَالِكٍ عَنْ الْقَاسِمِ أَبِي عَبْدِ الرَّحْمَنِ مَوْلَى عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ أَبِي أُمَامَةَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ خُذُوا الْعِلْمَ قَبْلَ أَنْ يَذْهَبَ قَالُوا وَكَيْفَ يَذْهَبُ الْعِلْمُ يَا نَبِيَّ اللَّهِ وَفِينَا كِتَابُ اللَّهِ قَالَ فَغَضِبَ لَا يُغْضِبُهُ اللَّهُ ثُمَّ قَالَ ثَكِلَتْكُمْ أُمَّهَاتُكُمْ أَوَلَمْ تَكُنِ التَّوْرَاةُ وَالْإِنْجِيلُ فِي بَنِي إِسْرَائِيلَ فَلَمْ يُغْنِيَا عَنْهُمْ شَيْئًا إِنَّ ذَهَابَ الْعِلْمِ أَنْ يَذْهَبَ حَمَلَتُهُ إِنَّ ذَهَابَ الْعِلْمِ أَنْ يَذْهَبَ حَمَلَتُهُ","id":"Telah mengabarkan kepada kami [Musa bin Khalid] telah mengabarkan kepada kami [Mu'tamir bin Sulaiman] dari [Al Hajjaj] dari ['Auf bin Malik] dari [Al Qasim Abu Abdur Rahman] -bekas budak Abdur Rahman bin Yazid-, dari [Abu Umamah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Ambilah ilmu sebelum ia hilang', mereka bertanya: 'Bagaimana ilmu bisa hilang wahai Nabi Allah, sedang Al Qur`an masih berada bersama kami? ', perawi berkata: 'lalu beliau marah', seraya berkata: 'TSAKILATKUM UMMAHATUKUM, Bukankah Taurat dan Injil ada bersama Bani Isra`il tetapi keduanya tidak memberikan manfaat bagi mereka? ', sesungguhnya hilangnya ilmu itu dengan wafatnya para pemegangnya, sesungguhnya hilangnya ilmu itu dengan wafatnya para pemegangnya' \". "},"182":{"ar":" حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا ثَابِتُ بْنُ يَزِيدَ حَدَّثَنَا هِلَالٌ هُوَ ابْنُ خَبَّابٍ قَالَ سَأَلْتُ سَعِيدَ بْنَ جُبَيْرٍ قُلْتُ يَا أَبَا عَبْدِ اللَّهِ مَا عَلَامَةُ هَلَاكِ النَّاسِ قَالَ إِذَا هَلَكَ عُلَمَاؤُهُمْ","id":"Telah mengabarkan kepada kami [Abu An Anu'man] telah menceritakan kepada kami [Tsabit bin Yazid] telah menceritakan kepada kami [Hilal Ibnu Khabbab], ia berkata: \"Aku pernah bertanya kepada [Sa'id bin Jubair]: Wahai Abu Abdullah, apa saja tanda kehancuran manusia?, lalu ia menjawab: 'Jika ulama` mereka telah rusak' \". "},"183":{"ar":" أَخْبَرَنَا مَالِكُ بْنُ إِسْمَعِيلَ حَدَّثَنَا مَسْعُودُ بْنُ سَعْدٍ الْجُعْفِيُّ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ عَبْدِ اللَّهِ بْنِ رُبَيِّعَةَ عَنْ سَلْمَانَ قَالَ لَا يَزَالُ النَّاسُ بِخَيْرٍ مَا بَقِيَ الْأَوَّلُ حَتَّى يَتَعَلَّمَ أَوْ يُعَلِّمَ الْآخِرَ فَإِنْ هَلَكَ الْأَوَّلُ قَبْلَ أَنْ يُعَلِّمَ أَوْ يَتَعَلَّمَ الْآخِرُ هَلَكَ النَّاسُ","id":"Telah mengabarkan kepada kami [Malik bin Isma'il] telah menceritakan kepada kami [Mas'ud bin Sa'ad Al Ju'fi] dari ['Atha` bin As Sa`ib] dari [Abdullah bin Rabi'ah] dari [Salman] ia berkata: \"Manusia akan tetap dalam keadaan baik-baik saja, selama ada generasi awal hingga ia belajar atau mengajar generasi yang selanjutnya, apabila generasi awal tiada sebelum ia belajar atau mengajar generasi selanjutnya maka manusia akan hancur lebur\". "},"184":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الصَّلْتِ حَدَّثَنَا أَبُو كُدَيْنَةَ عَنْ قَابُوسَ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَ هَلْ تَدْرُونَ مَا ذَهَابُ الْعِلْمِ قُلْنَا لَا قَالَ ذَهَابُ الْعُلَمَاءِ","id":"Telah mengabarkan kepada kami [Muhammad bin As Shalt] telah menceritakan kepada kami [Abu Kudainah] dari [Qabus] dari [ayahnya] dari [Ibnu Abbas] radliallau 'anhu ia berkata: \"Apakah kalian tahu apa yang dimaksud dengan hilangnya ilmu itu?, kami menjawab: '(kami) tidak tahu', ia berkata: 'Meninggalnya para ulama`' \". "},"185":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الصَّلْتِ عَنْ مَنْصُورِ بْنِ أَبِي الْأَسْوَدِ عَنْ حُصَيْنٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ أَبِي الدَّرْدَاءِ قَالَ مَا لِي أَرَى عُلَمَاءَكُمْ يَذْهَبُونَ وَجُهَّالَكُمْ لَا يَتَعَلَّمُونَ فَتَعَلَّمُوا قَبْلَ أَنْ يُرْفَعَ الْعِلْمُ فَإِنَّ رَفْعَ الْعِلْمِ ذَهَابُ الْعُلَمَاءِ","id":"Telah mengabarkan kepada kami [Muhammad bin As Shalt] dari [Mansur bin Abu Al `Aswad] dari [Hushain] dari [Salim bin Abu Al Ja'd] dari [Abu Darda`] radliallahu 'anhu ia berkata: \" Mengapa aku melihat para ulama` kalian wafat sedang orang-orang bodoh diantara kalian tidak (mau) belajar?, hendaklah kalian belajar sebelum ilmu itu diangkat, karena pengangkatan ilmu itu dengan kepergian (wafat) -nya para ulama`\". "},"186":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ أَسَدٍ أَبُو عَاصِمٍ حَدَّثَنَا عَبْثَرٌ عَنْ بُرْدٍ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ أَبِي الدَّرْدَاءِ قَالَ النَّاسُ عَالِمٌ وَمُتَعَلِّمٌ وَلَا خَيْرَ فِيمَا بَعْدَ ذَلِكَ","id":"Telah mengabarkan kepada kami [Ahmad bin Asad Abu 'Ashim] telah menceritakan kepada kami ['Abtsar] dari [Burd] dari [Sulaiman bin Musa] dari [Abu Darda`] radliallahu 'anhu ia berkata: \"Manusia itu (terbagi menjadi dua) golongan, yang berilmu serta pelajar (pemburu ilmu), sungguh tidak ada kebaikan pada golongan yang ketiga\"."},"187":{"ar":" أَخْبَرَنَا قَبِيصَةُ أَخْبَرَنَا سُفْيَانُ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَ اغْدُ عَالِمًا أَوْ مُتَعَلِّمًا أَوْ مُسْتَمِعًا وَلَا تَكُنِ الرَّابِعَ فَتَهْلِكَ","id":"Telah mengabarkan kepada kami [Qabishah] telah mengabarkan kepada kami [Sufyan] dari ['Atha` bin As Sa`ib] dari [Al Hasan] dari [Abdullah bin mas'ud] radliallahu 'anhu ia berkata: \"Siapkanlah diri kamu (untuk menjadi) seorang ulama`, seorang pelajar, atau seorang pendengar setia, dan janganlah kamu menjadi (bagian) dari yang keempat, niscaya kamu akan celaka\"."},"188":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا خَالِدٌ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ عَبْدِ اللَّهِ بْنِ رُبَيِّعَةَ قَالَ قَالَ سَلْمَانُ لَا يَزَالُ النَّاسُ بِخَيْرٍ مَا بَقِيَ الْأَوَّلُ حَتَّى يَتَعَلَّمَ الْآخِرُ فَإِذَا هَلَكَ الْأَوَّلُ قَبْلَ أَنْ يَتَعَلَّمَ الْآخِرُ هَلَكَ النَّاسُ","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] telah mengabarkan kepada kami [Khalid] dari ['Atha` bin As Sa`ib] dari [Abdullah bin Rabi'ah] ia berkata: \" [Salman] berkata: 'Manusia akan tetap dalam keadaan baik-baik saja selama masih ada generasi awal, hingga generasi berikutnya belajar (darinya), jika generasi awal telah hilang sebelum generasi akhir belajar, hancurlah manusia\"."},"189":{"ar":" أَخْبَرَنَا وَهْبُ بْنُ جَرِيرٍ وَعُثْمَانُ بْنُ عُمَرَ قَالَا أَخْبَرَنَا ابْنُ عَوْنٍ عَنْ مُحَمَّدٍ عَنْ الْأَحْنَفِ قَالَ قَالَ عُمَرُ تَفَقَّهُوا قَبْلَ أَنْ تُسَوَّدُوا","id":"Telah mengabarkan kepada kami [Wahab bin Jarir] dan [Utsman bin Umar] keduanya berkata: \"telah menceritakan kepada kami [Ibnu 'Aun] dari [Muhammad] dari [Al Ahnaf] ia berkata: \" [Umar] telah berkata: 'Hendaklah kalian belajar sebelum kalian tidak bisa berbuat apa-apa\"."},"190":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُبَارَكِ أَخْبَرَنَا بَقِيَّةُ حَدَّثَنَا صَدَقَةُ بْنُ عَبْدِ اللَّهِ أَنَّ الْمُهَاصِرَ بْنَ حَبِيبٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُ تَعَالَى إِنِّي لَسْتُ كُلَّ كَلَامِ الْحَكِيمِ أَتَقَبَّلُ وَلَكِنِّي أَتَقَبَّلُ هَمَّهُ وَهَوَاهُ فَإِنْ كَانَ هَمُّهُ وَهَوَاهُ فِي طَاعَتِي جَعَلْتُ صَمْتَهُ حَمْدًا لِي وَوَقَارًا وَإِنْ لَمْ يَتَكَلَّمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mubarak] telah mengabarkan kepada kami [Baqiyyah] telah menceritakan kepada kami [Shadaqah bin Abdullah] Bahwasanya [Al Muhashir bin Habib] telah berkata: \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Allah berfirman': 'Tidak semua perkataan orang yang bijak Aku terima, tetapi Aku hanya menerima berdasarkan niat dan keinginannya, jika niat dan keinginannya semata dalam ketaatan kepada-Ku, maka Aku jadikan diamnya itu sebagai pujian, meski ia tidak sedang memuji' \". "},"191":{"ar":" أَخْبَرَنَا مَخْلَدُ بْنُ مَالِكٍ عَنْ حَجَّاجِ بْنِ مُحَمَّدٍ عَنْ لَيْثِ بْنِ سَعْدٍ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ أَبِي الزَّاهِرِيَّةِ يَرْفَعُ الْحَدِيثَ إِنَّ اللَّهَ تَعَالَى قَالَ أَبُثُّ الْعِلْمَ فِي آخِرِ الزَّمَانِ حَتَّى يَعْلَمَهُ الرَّجُلُ وَالْمَرْأَةُ وَالْعَبْدُ وَالْحُرُّ وَالصَّغِيرُ وَالْكَبِيرُ فَإِذَا فَعَلْتُ ذَلِكَ بِهِمْ أَخَذْتُهُمْ بِحَقِّي عَلَيْهِمْ","id":"Telah mengabarkan kepada kami [Makhlad bin Malik] dari [Hajjaj bin Muhammad] dari [Laits bin sa'ad] dari [Mu'awiyah bin Shalih] dari [Abu Az Zahiriyyah] ia telah memarfu'kan hadis ini: \" Allah telah berfirman: 'Aku tebarkan ilmu pada akhir zaman, sehingga laki-laki, wanita, budak, orang merdeka, anak kecil, serta orang dewasa mengetahuinya, jika Aku telah lakukan hal itu, niscaya Aku akan mengambil hakKu dari mereka' \"."},"192":{"ar":" أَخْبَرَنَا يَعْلَى حَدَّثَنَا مُحَمَّدُ بْنُ عَوْنٍ عَنْ إِبْرَاهِيمَ بْنِ عِيسَى قَالَ قَالَ ابْنُ مَسْعُودٍ لَا تَعَلَّمُوا الْعِلْمَ لِثَلَاثٍ لِتُمَارُوا بِهِ السُّفَهَاءَ وَتُجَادِلُوا بِهِ الْعُلَمَاءَ وَلِتَصْرِفُوا بِهِ وُجُوهَ النَّاسِ إِلَيْكُمْ وَابْتَغُوا بِقَوْلِكُمْ مَا عِنْدَ اللَّهِ فَإِنَّهُ يَدُومُ وَيَبْقَى وَيَنْفَدُ مَا سِوَاهُ","id":"Telah mengabarkan kepada kammi [Ya'la] telah menceritakan kepada kami [Muhammad bin 'Aun] dari [Ibrahim bin isa] ia berkata: \" [Ibnu Mas'ud] telah berkata: 'Janganlah kalian mencari ilmu untuk tiga hal: Untuk menghina orang bodoh, mendebat para ulama`, serta untuk mencari perhatian orang-orang. Dan carilah dengan perkataan kalian apa yang ada di sisi Allah, sebab hal itu terus berlanjut dan tersisa, serta menepis selainnya' \"."},"193":{"ar":" وَبِهَذَا الْإِسْنَادِ قَالَ كُونُوا يَنَابِيعَ الْعِلْمِ مَصَابِيحَ الْهُدَى أَحْلَاسَ الْبُيُوتِ سُرُجَ اللَّيْلِ جُدُدَ الْقُلُوبِ خُلْقَانَ الثِّيَابِ تُعْرَفُونَ فِي أَهْلِ السَّمَاءِ وَتَخْفَوْنَ عَلَى أَهْلِ الْأَرْضِ_","id":"Dan dengan sanad ini (sama dengan hadits sebelumnya), ia ([Ibnu Mas'ud]) berkata: \"Jadilah kalian sumber pengetahuan, lentera petunjuk yang selalu menerangi rumah, cahaya malam hari, hatinya senantiasa suci, berbaju apa adanya, (sehingga) kalian dikenal oleh penghuni langit, dan tidak dikenal oleh penghuni bumi\". "},"194":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ حَدَّثَنَا مُحَمَّدُ بْنُ عُمَارَةَ بْنِ حَزْمٍ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَطْلُبُ هَذَا الْعِلْمَ أَحَدٌ لَا يُرِيدُ بِهِ إِلَّا الدُّنْيَا إِلَّا حَرَّمَ اللَّهُ عَلَيْهِ عَرْفَ الْجَنَّةِ يَوْمَ الْقِيَامَةِ","id":"Telah mengabarkan kepaada kami [Abu Ashim] telah menceritakan kepada kami [Muhammad bin Umarah bin Hazm] telah menceritakan kepada kami [Abdullah bin Abdur Rahman] ia berkata; \"Rasulullah salallahu 'alaihi wa sallam bersabda; 'Tidaklah seseorang menuntut ilmu ini dan ia tidak menghendaki kecuali dunia, melainkan Allah mengharamkan aroma surga baginya\"."},"195":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا عُمَرُ بْنُ مَزْيَدٍ عَنْ أَوْفَى بْنِ دَلْهَمٍ أَنَّهُ بَلَغَهُ عَنْ عَلِيٍّ قَالَ تَعَلَّمُوا الْعِلْمَ تُعْرَفُوا بِهِ وَاعْمَلُوا بِهِ تَكُونُوا مِنْ أَهْلِهِ فَإِنَّهُ سَيَأْتِي بَعْدَ هَذَا زَمَانٌ لَا يَعْرِفُ فِيهِ تِسْعَةُ عُشَرَائِهِمْ الْمَعْرُوفَ وَلَا يَنْجُو مِنْهُ إِلَّا كُلُّ نُوَمَةٍ فَأُولَئِكَ أَئِمَّةُ الْهُدَى وَمَصَابِيحُ الْعِلْمِ لَيْسُوا بِالْمَسَايِيحِ وَلَا الْمَذَايِيعِ الْبُذْرِ قَالَ أَبُو مُحَمَّد نُوَمَةٌ غَافِلٌ عَنْ الشَّرِّ الْمَذَايِيعُ الْبُذْرِ كَثِيرُ الْكَلَامِ","id":"Telah mengabarkan kepada kami [Utsman bin Umar] menceritakan kepada kami [Umar bin Yazid] dari [Aufa bin Dahlan], bahwasanya telah [disampaikan kabar] dari [Ali] radliallahu 'anhu ia berkata; \" Pelajarilah ilmu, kamu akan mengenalnya, dan amalkanlah ilmu kalian, kalian menjadi ahlinya. Akan datang satu jaman yang ketika itu sembilan persepuluh kebaikan sudah tidak dikenali lagi. Tidak ada yang selamat kecuali sekelompok kecil. Mereka adalah para pemimpin yang tercerahkan dan menjadi cahaya ilmu, mereka bukanlah orang yang selalu berbuat buruk dan mengadu domba, dan mereka juga bukan orang yang hanya pandai bicara \"."},"196":{"ar":" أَخْبَرَنَا مَرْوَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الْعَزِيزِ عَنْ يَزِيدَ بْنِ جَابِرٍ قَالَ قَالَ مُعَاذُ بْنُ جَبَلٍ اعْمَلُوا مَا شِئْتُمْ بَعْدَ أَنْ تَعْلَمُوا فَلَنْ يَأْجُرَكُمْ اللَّهُ بِالْعِلْمِ حَتَّى تَعْمَلُوا","id":"Telah mengabarkan kepada kami [Marwan bin Muhammad] telah menceritakan kepada kami [Sa'id bin Abdul Aziz] dari [Yazid bin Jabir] ia berkata; \" [Muadz bin Jabal] berkata; 'Kerjakanlah sesuatu semaksimalkemampuan kalian setelah kalian mempelajari ilmu. Kalian tidak diberikan ganjaran oleh Allah atas ilmu kalian hingga kalian mengamalkannya' \". "},"197":{"ar":" أَخْبَرَنَا إِسْمَعِيلُ بْنُ أَبَانَ عَنْ ابْنِ الْقَاسِمِ بْنِ قَيْسٍ حَدَّثَنِي يُونُسُ بْنُ سَيْفٍ الْحِمْصِيُّ قَالَ حَدَّثَنِي أَبُو كَبْشَةَ السَّلُولِيُّ قَالَ سَمِعْتُ أَبَا الدَّرْدَاءِ يَقُولُ إِنَّ مِنْ أَشَرِّ النَّاسِ عِنْدَ اللَّهِ مَنْزِلَةً يَوْمَ الْقِيَامَةِ عَالِمًا لَا يَنْتَفِعُ بِعِلْمِهِ","id":"Telah mengabarkan kepada kami [Ismail bin Aban] dari [Ibnu Al Qasim bin Qois] ia berkata: Telah menceritakan kepadaku [Yunus bin Saif Al Himshi] ia berkata: Telah menceritakan kepadaku [Abu Kabsyah As Saluli] ia berkata: \" Aku pernah mendengar [Abu Darda] ` radliallahu 'anhu berkata: 'Orang terjelek tempatnya di sisi Allah pada hari kiamat adalah seorang yang memiki ilmu, namun ia tidak mengamalkannya\". "},"198":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا أَبُو قُدَامَةَ عَنْ مَالِكِ بْنِ دِينَارٍ قَالَ قَالَ أَبُو الدَّرْدَاءِ مَنْ يَزْدَدْ عِلْمًا يَزْدَدْ وَجَعًا وَقَالَ أَبُو الدَّرْدَاءِ مَا أَخَافُ عَلَى نَفْسِي أَنْ يُقَالَ لِي مَا عَلِمْتَ وَلَكِنْ أَخَافُ أَنْ يُقَالَ لِي مَاذَا عَمِلْتَ","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] telah mengabarkan kepada kami [Abu Qudamah] dari [Malik bin Dinar] ia berkata: \" [Abu Darda] ` radliallahu 'anhu pernah berkata: 'Barang siapa yang bertambah ilmunya, bertambah pula bebannya. Dan Abu Darda` radliallahu 'anhu berkata: 'Aku tidak takut akan pernyataan atasku: Apa yang telah kamu ketahui? Namun yang aku takutkan adalah pernyataan atasku: Apa yang telah kamu kerjakan?\". "},"199":{"ar":" أَخْبَرَنَا هَارُونُ بْنُ مُعَاوِيَةَ عَنْ حَفْصِ بْنِ غِيَاثٍ قَالَ سَمِعْتُ ابْنَ جُرَيْجٍ يَذْكُرُ عَمَّنْ حَدَّثَهُ عَنْ ابْنِ عَبَّاسٍ قَالَ تَدَارُسُ الْعِلْمِ سَاعَةً مِنْ اللَّيْلِ خَيْرٌ مِنْ إِحْيَائِهَا و قَالَ أَبُو هُرَيْرَةَ إِنِّي لَأُجَزِّئُ اللَّيْلَ ثَلَاثَةَ أَجْزَاءٍ فَثُلُثٌ أَنَامُ وَثُلُثٌ أَقُومُ وَثُلُثٌ أَتَذَكَّرُ أَحَادِيثَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menghabarka kepada kami [Harun bin Mu'awiyah] dari [Hafsh bin Ghiats] ia berkata: Aku telah mendengar [Ibnu Juraij] menerangkan apa yang telah [diceritakan padanya] dari [Ibnu Abbas] radliallahu 'anhu ia berkata: \" Mempelajari ilmu dalam satu malam lebih baik dibandingkan dengan menghidupkannya (Memperbanyak ibadah) \". [Abu Hurairah] radliallahu 'anhu pernah berkata: \"Sungguh aku membagi malamku menjadi tiga bagian, sepertiga waktu malam untuk tidur, sepertiga untuk beribadah, dan sepertiga lagi untuk mempelajari hadis Rasulullah salallhu 'alaihi wa sallam \". "},"200":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا ثَابِتُ بْنُ يَزِيدَ حَدَّثَنَا عَاصِمٌ قَالَ سَأَلْتُ الشَّعْبِيَّ عَنْ حَدِيثٍ فَحَدَّثَنِيهِ فَقُلْتُ إِنَّهُ يُرْفَعُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَا عَلَى مَنْ دُونَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَبُّ إِلَيْنَا فَإِنْ كَانَ فِيهِ زِيَادَةٌ أَوْ نُقْصَانٌ كَانَ عَلَى مَنْ دُونَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Tsabit bin Yazid] telah menceritakan kepada kami ['Ashim] ia berkata: \"Aku bertanya kepada [As Sya'bi] tentang satu hadis lalu ia menceritakannya kepadaku, aku bertanya kepadanya: \"(Apakah hadis itu dihukumi marfu' kepada Nabi sallallahu 'alai wa sallam? ia menjawab: \"Tidak, yang tidak marfu' kepada Nabi sallallahu 'alai wa sallam lebih aku sukai, maka jika ada penambahan atau pengurangan hal itu bukan dari Nabi sallallahu 'alaihi wa sallam\". "},"201":{"ar":" أَخْبَرَنَا إِسْحَقُ بْنُ عِيسَى حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَبِي هَاشِمٍ عَنْ إِبْرَاهِيمَ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُحَاقَلَةِ وَالْمُزَابَنَةِ فَقِيلَ لَهُ أَمَا تَحْفَظُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثًا غَيْرَ هَذَا قَالَ بَلَى وَلَكِنْ أَقُولُ قَالَ عَبْدُ اللَّهِ قَالَ عَلْقَمَةُ أَحَبُّ إِلَيَّ","id":"Telah mengabarkan kepada kami [Ishak bin Isa] telah menceritakan kepada kami [Hammad bin Zaid] dari [Abu Hasym] dari [Ibrahim] ia berkat: \"Rasulullah sallallhu 'alai wa sallam melarang muhaaqalah dan muzaabanah 'Kemudian ada seseorang bertanya kepadanya: 'Tidaklah anda menyimpan hadis lain dari Rasululah sallallhu 'alai wa sallam? Ia menjawab: ' Ya ada, tetapi aku lebih suka mengutip: ' Abdullah berkata: 'Al Qamah berkata' 'Suatu hal yang paling kusukai.....\". "},"202":{"ar":" أَخْبَرَنَا أَسَدُ بْنُ مُوسَى حَدَّثَنَا مُعَاوِيَةُ عَنْ رَبِيعَةَ بْنِ يَزِيدَ قَالَ كَانَ أَبُو الدَّرْدَاءِ إِذَا حَدَّثَ حَدِيثًا قَالَ اللَّهُمَّ إِلَّا هَكَذَا أَوْ كَشَكْلِهِ","id":"Telah mengabarkan kepada kami [`Asad bin Musa] telah menceritakan kepada kami [Mu'awiyah] dari [Rabi'ah bin Yazid] ia berkata: \" [Abu Darda`] apabila menceritakan hadis dari Rasulullah sallallahu 'alaihi wa sallam ia berkata: 'Ya Allah semoga yang seperti demikian atau yang seperti redaksinya' \"."},"203":{"ar":" حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا ابْنُ عَوْنٍ عَنْ مُسْلِمٍ أَبِي عَبْدِ اللَّهِ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ أَبِيهِ عَنْ عَمْرِو بْنِ مَيْمُونٍ قَالَ كُنْتُ لَا تَفُوتُنِي عَشِيَّةُ خَمِيسٍ إِلَّا آتِي فِيهَا عَبْدَ اللَّهِ بْنَ مَسْعُودٍ فَمَا سَمِعْتُهُ يَقُولُ لِشَيْءٍ قَطُّ قَالَ رَسُولُ اللَّهِ حَتَّى كَانَتْ ذَاتَ عَشِيَّةٍ فَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَاغْرَوْرَقَتَا عَيْنَاهُ وَانْتَفَخَتْ أَوْدَاجُهُ فَأَنَا رَأَيْتُهُ مَحْلُولَةً أَزْرَارُهُ وَقَالَ أَوْ مِثْلُهُ أَوْ نَحْوُهُ أَوْ شَبِيهٌ بِهِ","id":"Telah menceritakan kepada kami [Utsman bin Umar] telah mengabarkan kepada kami [Ibnu 'Aun] dari [Muslim Abu Abdullah] dari [Ibrahim At Taimi] dari [ayahnya] dari ['Amr bin Maimun] ia berkata: \"Aku tidak pernah luput pada setiap kamis sore melainkan selalu mengunjungi [Abdullah bin Mas'ud] radliallahu 'anhu, aku tidak pernah mendengarnya ia mengatakan dengan redaksi \"Rasulullah sallallahu 'alaihi wa sallam bersabda\", hingga pada satu sore ia berkata: 'Rasulullah sallalllahu 'alaihi wa sallam bersabda' maka kedua matanya berlinang air mata, dan keluarlah otot lehernya, aku pun melihatnya kancing celananya terlepas. Lantas Ia berkata: 'Atau semisalnya, menyerupainya, atau yang sepadan dengannya' \". "},"204":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا أَشْعَثُ عَنْ الشَّعْبِيِّ وَابْنِ سِيرِينَ أَنَّ ابْنَ مَسْعُودٍ كَانَ إِذَا حَدَّثَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْأَيَّامِ تَرَبَّدَ وَجْهُهُ وَقَالَ هَكَذَا أَوْ نَحْوَهُ هَكَذَا أَوْ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepadakami [Asy'ats] dari [As Sya'bi] dan [Ibnu Sirin]: \" [Ibnu Mas'ud] radliallahu 'anhu apabila menceritakan hadis dari Rasulullah sallallahu 'alaihi wa sallam beberapa hari, maka berubahlah rona wajahnya, setelah itu ia berkata: 'Seperti ini atau yang menyerupainya, seperti ini atau yang menyerupainya\"."},"205":{"ar":" أَخْبَرَنَا أَسَدُ بْنُ مُوسَى حَدَّثَنَا شُعْبَةُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي السَّفَرِ عَنْ الشَّعْبِيِّ قَالَ جَالَسْتُ ابْنَ عُمَرَ سَنَةً فَلَمْ أَسْمَعْهُ يَذْكُرُ حَدِيثًا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [`Asad bin Musa] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Abdullah bin Abu As Safar] dari [As Sya'bi] ia berkata: \"Aku bergaul bersama [Ibnu Umar] radliallahu 'anhu selama satu tahun, maka aku tidak pernah mendengar ia menyebutkan satu haditspun dari Rasulullah sallallahu 'alaihi wa sallam\". "},"206":{"ar":" أَخْبَرَنَا عَاصِمُ بْنُ يُوسُفَ حَدَّثَنَا أَبُو بَكْرٍ عَنْ أَبِي حَصِينٍ عَنْ الشَّعْبِيِّ عَنْ ثَابِتِ بْنِ قُطْبَةَ الْأَنْصَارِيِّ قَالَ كَانَ عَبْدُ اللَّهِ يُحَدِّثُنَا فِي الشَّهْرِ بِالْحَدِيثَيْنِ أَوْ الثَّلَاثَةِ","id":"Telah mengabarkan kepada kami ['Ashim bin Yusuf] telah menceritakan kepada kami [Abu Bakar] dari [Abu Hashin] dari [As Sya'bi] dari [Tsabit bin Quthbah Al Anshari] ia berkata: \" [Abdullah] dalam satu bulan hanya menyampaikan dua atau tiga hadis Nabi sallallahu 'alaihi wa sallam kepada kami\"."},"207":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ابْنِ عَوْنٍ عَنْ مُحَمَّدٍ قَالَ كَانَ أَنَسٌ قَلِيلَ الْحَدِيثِ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ إِذَا حَدَّثَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَوْ كَمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Sulaiman bin Harb] ia berkata: telah menceritakan kepada kami [Hammad bin Zaid] dari [Ibnu 'Aun] dari [Muhammad] ia berkata: \" [Anas] radliallahu 'anhu (termasuk) orang yang sedikit menyampaikan hadis dari Rasulullah sallallahu 'alaihi wa sallam, dan jika ia menceritakan hadis dari Rasulullah sallallahu 'alaihi wa sallam ia (selalu) berkata: 'Atau seperti yang dikatakan Rasulullah sallallahu 'alaihi wa sallam' \". "},"208":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا إِسْمَعِيلُ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ قَالَ كَانَ أَنَسٌ إِذَا حَدَّثَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثًا قَالَ أَوْ كَمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Utsman bin Muhammad] telah menceritakan kepada kami [Isma'il] dari [Ayyub] dari [Muhammad] ia berkata: \" [Anas] radliallahu 'anhu apabila menceritakan hadis dari Rasulullah sallallahu 'alaihi wa sallam ia (selalu) berkata: 'Atau seperti yang dikatakan Rasulullah sallallahu 'alaihi wa sallam\"."},"209":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ حَدَّثَنِي السَّائِبُ بْنُ يَزِيدَ قَالَ خَرَجْتُ مَعَ سَعْدٍ إِلَى مَكَّةَ فَمَا سَمِعْتُهُ يُحَدِّثُ حَدِيثًا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى رَجَعْنَا إِلَى الْمَدِينَةِ","id":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Yahya bin Sa'id] ia berkata: telah menceritakan kepadaku [As Sa`ib bin Yazid] ia berkata: \"Aku pergi ke Makkah bersama [Sa'ad], maka aku tidak pernah mendengarnya bercerita tentang hadis dari Rasulullah sallallahu 'alaihi wa sallam hingga kami kembali ke Madinah\"."},"210":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي مُعَاوِيَةُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِيهِ جُبْيَرِ بْنِ نُفَيْرٍ عَنْ أَبِي الدَّرْدَاءِ قَالَ كُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَشَخَصَ بِبَصَرِهِ إِلَى السَّمَاءِ ثُمَّ قَالَ هَذَا أَوَانُ يُخْتَلَسُ الْعِلْمُ مِنْ النَّاسِ حَتَّى لَا يَقْدِرُوا مِنْهُ عَلَى شَيْءٍ فَقَالَ زِيَادُ بْنُ لَبِيدٍ الْأَنْصَارِيُّ يَا رَسُولَ اللَّهِ وَكَيْفَ يُخْتَلَسُ مِنَّا وَقَدْ قَرَأْنَا الْقُرْآنَ فَوَاللَّهِ لَنَقْرَأَنَّهُ وَلَنُقْرِئَنَّهُ نِسَاءَنَا وَأَبْنَاءَنَا فَقَالَ ثَكِلَتْكَ أُمُّكَ يَا زِيَادُ إِنْ كُنْتُ لَأَعُدُّكَ مِنْ فُقَهَاءِ أَهْلِ الْمَدِينَةِ هَذِهِ التَّوْرَاةُ وَالْإِنْجِيلُ عِنْدَ الْيَهُودِ وَالنَّصَارَى فَمَاذَا يُغْنِي عَنْهُمْ قَالَ جُبَيْرٌ فَلَقِيتُ عُبَادَةَ بْنَ الصَّامِتِ قَالَ قُلْتُ أَلَا تَسْمَعُ مَا يَقُولُ أَخُوكَ أَبُو الدَّرْدَاءِ فَأَخْبَرْتُهُ بِالَّذِي قَالَ قَالَ صَدَقَ أَبُو الدَّرْدَاءِ إِنْ شِئْتَ لَأُحَدِّثَنَّكَ بِأَوَّلِ عِلْمٍ يُرْفَعُ مِنْ النَّاسِ الْخُشُوعُ يُوشِكُ أَنْ تَدْخُلَ مَسْجِدَ الْجَمَاعَةِ فَلَا تَرَى فِيهِ رَجُلًا خَاشِعًا","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepada kami [Mu'awiyah] dari [Abdur Rahman bin Jubair bin nufair] dari ayahnya - [Jubair bin Nufair] -, dari [Abu Darda`] radliallahu 'anhu ia berkata: \"Dahulu kami bersama Rasulullah sallallahu 'alaihi wa sallam, beliau menengadahkan pandangannya ke langit, kemudian bersabda: 'Sekarang adalah waktu ilmu terampas dari (genggaman) manusia, hingga mereka tidak menghargainya sedikit pun', lalu Ziyad bin Labid Al Anshari radliallahu 'anhu bertanya: 'Wahai Rasulullah sallallahu 'alaihi wa sallam, bagaimana ilmu itu bisa terampas dari kami sedang kami (selalu) membaca Al Qur`an?, demi Allah kami akan selalu membacanya dan mengajarkannya kepada isteri-isteri dan anak-anak kami. kemudian beliau berkata: 'Celaka wahai Ziyad, aku telah menganggapmu sebagai ahli fikih bagi penduduk kota Madinah, (bukankah) Taurat dan Injil masih berada di (tangan) orang-orang Yahudi dan Nasrani, dan hal itu tidakkah bisa mencerahkan mereka? ', Jubair berkata: 'kemudian aku bertemu dengan ['Ubadah bin As Shamit] radliallahu 'anhu, aku bertanya: 'apakah kamu pernah mendengar apa yang telah dikatakan saudaramu Abu Darda` radliallahu 'anhu? '. Lalu aku kabarkan kepadanya apa yang telah dikatakannya, ia berkata: 'Abu Darda` radliallahu 'anhu benar, jika kamu berkehendak maka aku akan menceritakan kepadamu tentang ilmu pertama yang dicabut dari manusia, yaitu kekhusyu'an, hingga hampir-hampir kamu masuk ke masjid dan kamu tidak dapati di sana orang yang khusyu' ' \"."},"211":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ أَسَدٍ أَبُو عَاصِمٍ حَدَّثَنَا يَحْيَى بْنُ يَمَانٍ عَنْ سُفْيَانَ عَنْ لَيْثٍ عَنْ رَجُلٍ عَنْ ابْنِ عُمَرَ قَالَ لَا يَكُونُ الرَّجُلُ عَالِمًا حَتَّى لَا يَحْسُدَ مَنْ فَوْقَهُ وَلَا يَحْقِرَ مَنْ دُونَهُ وَلَا يَبْتَغِيَ بِعِلْمِهِ ثَمَنًا","id":"Telah mengabarkan kepada kami [Ahmad bin `Asad Abu 'Ashim] telah menceritakan kepada kami [Yahya bin Yaman] dari [Sufyan] dari [Laits] dari [seseorang] dari [Ibnu Umar] radliallahu 'anhu ia berkata: \"Seseorang tidak menjadi seorang ulama sampai ia tidak hasad (dengki) terhadap orang yang (keilmuannya) di atasnya, dan tidak meremehkan orang yang (keilmuannya) di bawahnya, serta tidak mengharap upah dari ilmunya\"."},"212":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ سُلَيْمَانَ عَنْ أَبِي أُسَامَةَ عَنْ مِسْعَرٍ قَالَ سَمِعْتُ عَبْدَ الْأَعْلَى التَّيْمِيَّ يَقُولُ مَنْ أُوتِيَ مِنْ الْعِلْمِ مَا لَا يُبْكِيهِ لَخَلِيقٌ أَنْ لَا يَكُونَ أُوتِيَ عِلْمًا يَنْفَعُهُ لِأَنَّ اللَّهَ تَعَالَى نَعَتَ الْعُلَمَاءَ ثُمَّ قَرَأَ الْقُرْآنَ { إِنَّ الَّذِينَ أُوتُوا الْعِلْمَ إِلَى قَوْلِهِ يَبْكُونَ }","id":"Telah mengabarkan kepada kami [Sa'id bin Sulaiman] dari [Abu Usamah] dari [Mis'ar] ia berkata: \"Aku pernah mendengar [Abdul A'la At Taimi] berkata: 'Barangsiapa yang dianugerahi ilmu dan ilmunya tidak membuatnya menangis kepada Allah, berarti ia mendapatkan ilmu yang tidak bermanfaat, karena Allah mensifati para ulama, kemudian ia membaca Al Qur`an: INNALLADZIINA UUTUL 'ILMA\" (sesungguhnya orang-orang yang dianugerahi ilmu) sampai firmanNya: \"YABKUUN\" (mereka selalu menangis) -Qs. Al Isra`: 107-108-' \"."},"213":{"ar":" أَخْبَرَنَا عِصْمَةُ بْنُ الْفَضْلِ حَدَّثَنَا زَيْدُ بْنُ حُبَابٍ عَنْ مُبَارَكِ بْنِ فَضَالَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ الْعُمَرِيِّ عَنْ أَبِي حَازِمٍ قَالَ لَا تَكُونُ عَالِمًا حَتَّى يَكُونَ فِيكَ ثَلَاثُ خِصَالٍ لَا تَبْغِي عَلَى مَنْ فَوْقَكَ وَلَا تَحْقِرُ مَنْ دُونَكَ وَلَا تَأْخُذُ عَلَى عِلْمِكَ دُنْيَا","id":"Telah mengabarkan kepada kami ['Ishmah bin Al Fadlel] telah menceritakan kepada kami [Zaid bin Hubab] dari [Mubarak bin Fadlalah] dari [Ubaidullah bin Umar Al 'Umari] dari [Abu Hazim] ia berkata: \"Kamu tidak akan menjadi seorang ulama hingga ada tiga hal dalam dirimu: Kamu tidak dengki terhadap orang yang (keilmuannya) di atasmu, dan kamu tidak meremehkan orang yang (keilmuannya) ada di bawah kamu, serta kamu tidak mengambil (mencari) dunia dengan ilmu kamu\"."},"214":{"ar":" أَخْبَرَنَا الْحَسَنُ بْنُ عَرَفَةَ حَدَّثَنَا الْمُبَارَكُ بْنُ سَعِيدٍ عَنْ أَخِيهِ سُفْيَانَ الثَّوْرِيِّ عَنْ عِمْرَانَ الْمِنْقَرِيِّ قَالَ قُلْتُ لِلْحَسَنِ يَوْمًا فِي شَيْءٍ قَالَهُ يَا أَبَا سَعِيدٍ لَيْسَ هَكَذَا يَقُولُ الْفُقَهَاءُ فَقَالَ وَيْحَكَ وَرَأَيْتَ أَنْتَ فَقِيهًا قَطُّ إِنَّمَا الْفَقِيهُ الزَّاهِدُ فِي الدُّنْيَا الرَّاغِبُ فِي الْآخِرَةِ الْبَصِيرُ بِأَمْرِ دِينِهِ الْمُدَاوِمُ عَلَى عِبَادَةِ رَبِّهِ","id":"Telah mengabarkan kepada kami [Al Hasan bin 'Arafah] telah menceritakan kepada kami [Al Mubarak bin Sa'id] dari saudaranya - [Sufyan Al Tsauri] -, dari [Imran Al Minqari] ia berkata: \"Pada satu hari aku pernah bertanya kepada Al hasan tentang sesuatu, ia terus berkomentar: 'Wahai Abu Sa'id, bukan demikian yang telah disampaikan oleh para ahli fikih?, maka [Alhasan] menjawab: 'Celaka kamu, kamu telah menganggap dirimu seorang ahli fikih, hanyasanya seorang ahli fikih adalah ia yang bersikap zuhud dari (gemerlapnya) dunia dan cinta akan akhirat, yang berilmu dalam permasalahan agamanya, serta selalu (menjaga) ibadahnya kepada Tuhannya' \"."},"215":{"ar":" أَخْبَرَنَا الْحَسَنُ بْنُ عَرَفَةَ حَدَّثَنَا النَّضْرُ بْنُ إِسْمَعِيلَ الْبَجَلِيُّ عَنْ مِسْعَرٍ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ قَالَ قِيلَ لَهُ مَنْ أَفْقَهُ أَهْلِ الْمَدِينَةِ قَالَ أَتْقَاهُمْ لِرَبِّهِ","id":"Telah mengabarkan kepada kami [Al Hasan bin 'Arafah] telah menceritakan kepada kami [An Nadlr bin Ismail Al Bajali] dari [Mis'ar] dari [Sa'ad bin Ibrahim] ia berkata: \"ia ditanya: 'Siapakah orang yang paling menguasai ilmu fikih dari penduduk Madinah? ', ia menjawab: 'yaitu orang yang paling bertakwa kepada Tuhannya' \"."},"216":{"ar":" أَخْبَرَنَا الْحَسَنُ بْنُ عَرَفَةَ حَدَّثَنَا الْحُسَيْنُ بْنُ عَلِيٍّ عَنْ لَيْثِ بْنِ أَبِي سُلَيْمٍ عَنْ مُجَاهِدٍ قَالَ إِنَّمَا الْفَقِيهُ مَنْ يَخَافُ اللَّهَ","id":"Telah mengabarkan kepada kami [Al Hasan bin 'Arafah] telah menceritakan kepada kami [Al Husain bin Ali] dari [Laits bin Abu Sulaim] dari [Mujahid] ia berkata: \"Seorang ahli fikih hanyalah yang takut kepada Allah\"."},"217":{"ar":" حَدَّثَنَا الْحَسَنُ بْنُ عَرَفَةَ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ لَيْثٍ عَنْ يَحْيَى بْنِ عَبَّادٍ قَالَ قَالَ عَلِيٌّ الْفَقِيهُ حَقُّ الْفَقِيهِ الَّذِي لَا يُقَنِّطُ النَّاسَ مِنْ رَحْمَةِ اللَّهِ وَلَا يُؤَمِّنُهُمْ مِنْ عَذَابِ اللَّهِ وَلَا يُرَخِّصُ لَهُمْ فِي مَعَاصِي اللَّهِ إِنَّهُ لَا خَيْرَ فِي عِبَادَةٍ لَا عِلْمَ فِيهَا وَلَا خَيْرَ فِي عِلْمٍ لَا فَهْمَ فِيهِ وَلَا خَيْرَ فِي قِرَاءَةٍ لَا تَدَبُّرَ فِيهَا","id":"Telah mengabarkan kepada kami [Al Hasan bin 'Arafah] telah menceritakan kepada kami [Ismail bin Ibrahim] dari [Laits] dari [Yahya bin 'Abbad] ia berkata: \" [Ali] radliallahu 'anhu telah berkata: 'Seorang yang benar-benar ahli fikih adalah orang yang tidak membuat manusia putus asa dari rahmat Allah, jangan membuat mereka merasa aman dari adzab Allah dan jangan memberikan mereka kemudahan hingga akhirnya terjatuh ke dalam perbuatan maksiat. Sesungguhnya tidak ada kebaikan dalam ibadah yang dilakukan tanpa dasar ilmu, tidak ada kebaikan dalam ilmu tanpa pemahaman dan tidak ada kebaikan dalam membaca Al qur`an tanpa merenungi maknanya' \"."},"218":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ يَزِيدَ بْنِ حَازِمٍ حَدَّثَنِي عَمِّي جَرِيرُ بْنُ زَيْدٍ أَنَّهُ سَمِعَ تُبَيْعًا يُحَدِّثُ عَنْ كَعْبٍ قَالَ إِنِّي لَأَجِدُ نَعْتَ قَوْمٍ يَتَعَلَّمُونَ لِغَيْرِ الْعَمَلِ وَيَتَفَقَّهُونَ لِغَيْرِ الْعِبَادَةِ وَيَطْلُبُونَ الدُّنْيَا بِعَمَلِ الْآخِرَةِ وَيَلْبَسُونَ جُلُودَ الضَّأْنِ وَقُلُوبُهُمْ أَمَرُّ مِنْ الصَّبْرِ فَبِي يَغْتَرُّونَ أَوْ إِيَّايَ يُخَادِعُونَ فَحَلَفْتُ بِي لَأُتِيحَنَّ لَهُمْ فِتْنَةً تَتْرُكُ الْحَلِيمَ فِيهَا حَيْرَانَ","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari [Yazid bin Hazim] ia berkata: telah menceritakan kepadaku pamanku - [Jarir bin Zaid] -: ia mendengar [Tubai'] menceritakan dari [Ka'ab] ia berkata: \"Telah kudapatkan sifat satu kaum, mereka belajar bukan untuk diamalkan, mereka perdalam fikih bukan untuk beribadah, serta mereka jadikan amal akhirat untuk mendapatkan dunia, mereka mengenakan kulit domba, hati mereka lebih pahit dari pada buah yang paling pahit, mereka menipuku, aku bersumpah, aku akan menguji mereka dengan satu ujian, yang menjadikan mereka kebingungan\". "},"219":{"ar":" أَخْبَرَنَا بِشْرُ بْنُ الْحَكَمِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ الصَّمَدِ الْعَمِّيُّ حَدَّثَنَا أَبُو عِمْرَانَ الْجَوْنِيُّ عَنْ هَرِمِ بْنِ حَيَّانَ أَنَّهُ قَالَ إِيَّاكُمْ وَالْعَالِمَ الْفَاسِقَ فَبَلَغَ عُمَرَ بْنَ الْخَطَّابِ فَكَتَبَ إِلَيْهِ وَأَشْفَقَ مِنْهَا مَا الْعَالِمُ الْفَاسِقُ قَالَ فَكَتَبَ إِلَيْهِ هَرِمٌ يَا أَمِيرَ الْمُؤْمِنِينَ وَاللَّهِ مَا أَرَدْتُ بِهِ إِلَّا الْخَيْرَ يَكُونُ إِمَامٌ يَتَكَلَّمُ بِالْعِلْمِ وَيَعْمَلُ بِالْفِسْقِ فَيُشَبِّهُ عَلَى النَّاسِ فَيَضِلُّوا","id":"Telah mengabarkan kepada kami [Bisyr bin Al Hakam] telah menceritakan kepada kami [Abdul Aziz bin Abdus shamad Al 'Ammi] telah menceritakan kepada kami [Abu Imran Al Jauni] dari [Haram bin Hayyan], ia berkata: \"Hendaklah kalian berhati-hati terhadap ulama fasik. Pernyataan ini sampai ke telinga Umar bin Al Khatthab radliallahu 'anhu, kontan ia langsung menulis surat kepada Haram bin Hayyan, dengan setengah mengingatkan, [Umar] bertanya: 'Apa yang kamu maksud seorang ulama yang fasik? ', Haram membalas surat dengan mengatakan: 'Wahai amirul mu`minin, aku tidak menginginkan dengan hal itu kecuali kebaikan semata, yang kumaksud mereka berbicara dengan ilmu tetapi beramal dengan kefasikan, (sikapnya yang demikian membuat) bias di depan manusia, hingga mereka menjadi sesat' \"."},"220":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ الْأَوْزَاعِيِّ قَالَ قَالَ عُمَرُ بْنُ عَبْدِ الْعَزِيزِ إِذَا رَأَيْتَ قَوْمًا يُنْتِجُونَ بِأَمْرٍ دُونَ عَامَّتِهِمْ فَهُمْ عَلَى تَأْسِيسِ الضَّلَالَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Katsir] dari [Al 'Auza'i] ia berkata: \" [Umar bin Abdul Aziz] pernah berkata: 'Jika kamu melihat satu kaum yang mengurai masalah (untuk kepentingan diri mereka sendiri) tanpa mempedulikan kebanyakan orang, mereka berada dalam pondasi kesesatan\"."},"221":{"ar":" أَخْبَرَنَا إِبْرَاهِيمُ بْنُ إِسْحَقَ عَنْ ابْنِ الْمُبَارَكِ عَنْ الْأَوْزَاعِيِّ قَالَ قَالَ إِبْلِيسُ لِأَوْلِيَائِهِ مِنْ أَيِّ شَيْءٍ تَأْتُونَ بَنِي آدَمَ فَقَالُوا مِنْ كُلِّ شَيْءٍ قَالَ فَهَلْ تَأْتُونَهُمْ مِنْ قِبَلِ الِاسْتِغْفَارِ قَالُوا هَيْهَاتَ ذَاكَ شَيْءٌ قُرِنَ بِالتَّوْحِيدِ قَالَ لَأَبُثَّنَّ فِيهِمْ شَيْئًا لَا يَسْتَغْفِرُونَ اللَّهَ مِنْهُ قَالَ فَبَثَّ فِيهِمْ الْأَهْوَاءَ","id":"Telah mengabarkan kepada kami [Ibrahim bin Ishak] dari [Ibnu Al Mubarak] dari [Al 'Auza'i] ia berkata: \"Iblis berkata kepada pengikutnya, Dari sisi mana saja kalian datang (menggoda) manusia?, mereka menjawab: 'dari segala arah', ia bertanya lagi: 'Apakah kalian akan datang (menggoda) mereka dari arah istighfar? ', mereka menjawab: 'tidak mungkin, karena hal itu sangat berkaitan dengan tauhid, ia berkata: 'Aku akan sebarkan sesuatu diantara mereka hingga mereka tidak beristighfar kepada Allah. Dia (Al 'Auza'i) berkata: 'Lalu iblis menyebarkan (keinginan mengikuti) hawa nafsu kepada mereka' \". "},"222":{"ar":" أَخْبَرَنَا إِبْرَاهِيمُ بْنُ إِسْحَقَ عَنْ الْمُحَارِبِيِّ عَنْ الْأَعْمَشِ عَنْ مُجَاهِدٍ قَالَ مَا أَدْرِي أَيُّ النِّعْمَتَيْنِ عَلَيَّ أَعْظَمُ أَنْ هَدَانِي لِلْإِسْلَامِ أَوْ عَافَانِي مِنْ هَذِهِ الْأَهْوَاءِ","id":"Telah mengabarkan kepada kami [Ibrahim bin Ishak] dari [Al Muharibi] dari [Al A'masy] dari [Mujahid], ia berkata: Aku tidak tahu diantara dua nikmat yang aku terima, manakah yang lebih besar, Allah memberiku hidayah dengan Islam atau Allah menjagaku dari rongrongan hawa nafsu\"."},"223":{"ar":" أَخْبَرَنَا مُوسَى بْنُ خَالِدٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ الْأَعْوَرِ عَنْ حَبَّةَ بْنِ جُوَيْنٍ قَالَ سَمِعْتُ عَلِيًّا أَوْ قَالَ قَالَ عَلِيٌّ لَوْ أَنَّ رَجُلًا صَامَ الدَّهْرَ كُلَّهُ وَقَامَ الدَّهْرَ كُلَّهُ ثُمَّ قُتِلَ بَيْنَ الرُّكْنِ وَالْمَقَامِ لَحَشَرَهُ اللَّهُ يَوْمَ الْقِيَامَةِ مَعَ مَنْ يُرَى أَنَّهُ كَانَ عَلَى هُدًى","id":"Telah mengabarkan kepada kami [Musa bin khalid] telah menceritakan kepada kami [Isa bin Yunus] dari [Al A'masy] dari [Muslim Al A'war] dari [Habbah bin Juwain] ia berkata: Aku pernah mendengar [Ali], -atau ia berkata: Ali telah berkata: - 'Kalau seseorang puasa setahun penuh, dan shalat malam setahun penuh, kemudian ia terbunuh diantara rukun yamani dan maqam Ibrahim, niscaya Allah mengumpulkannya dihari kiamat bersama siapa saja yang memandangnya bahwa dia berada di jalan hidayah\"."},"224":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ حُمَيْدٍ عَنْ هَارُونَ هُوَ ابْنُ الْمُغِيرَةِ عَنْ شُعَيْبٍ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ أَبِي صَادِقٍ قَالَ قَالَ سَلْمَانُ لَوْ وَضَعَ رَجُلٌ رَأْسَهُ عَلَى الْحَجَرِ الْأَسْوَدِ فَصَامَ النَّهَارَ وَقَامَ اللَّيْلَ لَبَعَثَهُ اللَّهُ يَوْمَ الْقِيَامَةِ مَعَ هَوَاهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Humaid] dari [Harun Ibnu Al Mughirah] dari [Syu'aib] dari [Salamah bin Kuhail] dari [Abu Shadiq] ia berkata: [Salman] berkata: \"Sekiranya seseorang meletakkan kepalanya pada hajar aswad, berpuasa pada siang hari, dan shalat pada malam hari, Allah membangkitkannya pada hari kiamat bersama keinginannya \"."},"225":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الصَّلْتِ حَدَّثَنَا مَنْصُورٌ هُوَ ابْنُ أَبِي الْأَسْوَدِ عَنْ الْحَارِثِ بْنِ حَصِيرَةَ عَنْ أَبِي صَادِقٍ الْأَزْدِيِّ عَنْ رَبِيعَةَ بْنِ نَاجِذٍ قَالَ قَالَ عَلِيٌّ كُونُوا فِي النَّاسِ كَالنَّحْلَةِ فِي الطَّيْرِ إِنَّهُ لَيْسَ مِنْ الطَّيْرِ شَيْءٌ إِلَّا وَهُوَ يَسْتَضْعِفُهَا وَلَوْ يَعْلَمُ الطَّيْرُ مَا فِي أَجْوَافِهَا مِنْ الْبَرَكَةِ لَمْ يَفْعَلُوا ذَلِكَ بِهَا خَالِطُوا النَّاسَ بِأَلْسِنَتِكُمْ وَأَجْسَادِكُمْ وَزَايِلُوهُمْ بِأَعْمَالِكُمْ وَقُلُوبِكُمْ فَإِنَّ لِلْمَرْءِ مَا اكْتَسَبَ وَهُوَ يَوْمَ الْقِيَامَةِ مَعَ مَنْ أَحَبَّ","id":"Telah mengabarkan kepada kami [Muhammad bin As Shalt] telah m, enceritakan kepada kami [Mansur Ibnu Abu Al Aswad], dari [Al Harits bin Hashirah] dari [Abu Shadiq Al `Azdi] dari [Rabi'ah bin Najid] ia berkata: \" [Ali] radliallahu 'anhu berkata: 'Jadilah kalian semua diantara manusia seperti lebah yang berada dalam perut burung. Sesungguhnya tidak ada satu jenis burung pun kecuali akan melemahkan apa yang ada dalam perutnya. Padahal jika burung itu tahu apa yang ada dalam perutnya mendatangkan keberkahan, ia tidak akan bersikap demikian. Hendaklah kalian bergaul dengan manusia dengan lisan (ucapan) dan anggota badan (perilaku). Tetapi buatlah perbedaan dari mereka dengan amal dan hati kalian. Sesungguhnya setiap orang akan mendapatkan balasan sesuai apa yang dilakukannya, dan di hari kiamat nanti seorang akan dibangkitkan bersama orang yang dicintaintya\"."},"226":{"ar":" أَخْبَرَنَا الْوَلِيدُ بْنُ شُجَاعٍ حَدَّثَنِي بَقِيَّةُ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ قَالَ نِعْمَ وَزِيرُ الْعِلْمِ الرَّأْيُ الْحَسَنُ","id":"Telah mengabarkan kepada kami [Al Walid bin Syuja'] ia berkata: \"Telah menceritakan kepadaku [Baqiyyah] dari [Al 'Auza'i] dari [Az Zuhri] ia berkata: \"Sebaik-baik pembantu orang yang alim adalah pemikiran yang baik\"."},"227":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا زَائِدَةُ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ قَالَ كَفَى بِالْمَرْءِ عِلْمًا أَنْ يَخْشَى اللَّهَ وَكَفَى بِالْمَرْءِ جَهْلًا أَنْ يُعْجَبَ بِعِلْمِهِ قَالَ و قَالَ مَسْرُوقٌ الْمَرْءُ حَقِيقٌ أَنْ يَكُونَ لَهُ مَجَالِسُ يَخْلُو فِيهَا فَيَذْكُرُ ذُنُوبَهُ فَيَسْتَغْفِرُ اللَّهَ تَعَالَى مِنْهَا","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Zaidah] dari [Al A'masy] dari [Muslim] dari [Masruq] ia berkata: \"Cukuplah seseorang dianggap berilmu jika ia takut kepada Allah, dan cukuplah seseorang dianggap bodoh jika ia bangga dengan ilmunya, perawi berkata: Masruq berkata: 'Hendaknya seseorang memiliki tempat khusus yang ia pergunakan untuk menyendiri dan mengingat dosanya, kemudian ia memohon ampun kepada Allah' \". "},"228":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْمَدَ بْنِ أَبِي خَلَفٍ حَدَّثَنِي مَعْنٌ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ الْعَلَاءِ بْنِ الْحَارِثِ عَنْ مَكْحُولٍ عَنْ وَاثِلَةَ بْنِ الْأَسْقَعِ قَالَ إِذَا حَدَّثْنَاكُمْ بِالْحَدِيثِ عَلَى مَعْنَاهُ فَحَسْبُكُمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad bin Abu Khalaf] telah menceritakan kepadaku [Ma'an] dari [Mu'awiyah bin Shalih] dari [Al 'Ala` bin Al Harits] dari [Makhul] dari [Watsilah bin Al `Asfa'] ia berkata: \"Apabila kami menceritakan satu hadits kepada kalian dengan redaksi maknanya, maka hal itu sudah cukup bagi kalian\". "},"229":{"ar":" أَخْبَرَنَا عَاصِمُ بْنُ يُوسُفَ حَدَّثَنَا فُضَيْلُ بْنُ عِيَاضٍ عَنْ هِشَامٍ عَنْ ابْنِ سِيرِينَ أَنَّهُ كَانَ إِذَا حَدَّثَ لَمْ يُقَدِّمْ وَلَمْ يُؤَخِّرْ وَكَانَ الْحَسَنُ إِذَا حَدَّثَ قَدَّمَ وَأَخَّرَ","id":"Telah mengabarkan kepada kami ['Ashim bin Yusuf] telah menceritakan kepada kami [Fudlail bin 'Iyadl] dari [Hisyam] dari [Ibnu Sirin]: \"Apabila ia menceritakan satu hadits, ia tidak pernah mendahulukan atau mengakhirkan (mengubah redaksi kalimatnya), sementara [Al Hasan] apabila menceritakan satu hadits terkadang mendahulukan dan mengakhirkan (redaksinya) \"."},"230":{"ar":" أَخْبَرَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا جَرِيرُ بْنُ حَازِمٍ قَالَ كَانَ الْحَسَنُ يُحَدِّثُ بِالْحَدِيثِ الْأَصْلُ وَاحِدٌ وَالْكَلَامُ مُخْتَلِفٌ","id":"Telah mengabarkan kepada kami [Muslim bin Ibrahim] telah mengabarkan kepada kami [Jarir bin Hazim] ia berkata: \" [Al Hasan] apabila menceritakan hadits (mengatakan): Haditsnya satu (sama), namun redaksi pengungkapannya bisa berbeda\"."},"231":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْمَدَ حَدَّثَنَا سُفْيَانُ عَنْ مُحَمَّدِ بْنِ سُوقَةَ عَنْ مُحَمَّدِ بْنِ عَلِيِّ بْنِ الْحُسَيْنِ قَالَ حَدَّثَ عُبَيْدُ بْنُ عُمَيْرٍ عَبْدَ اللَّهِ بْنَ عُمَرَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الْمُنَافِقِ مَثَلُ الشَّاةِ بَيْنَ الرَّبِيضَيْنِ أَوْ بَيْنَ الْغَنَمَيْنِ فَقَالَ ابْنُ عُمَرَ لَا إِنَّمَا قَالَ كَذَا وَكَذَا قَالَ وَكَانَ ابْنُ عُمَرَ إِذَا سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَزِدْ فِيهِ وَلَمْ يُنْقِصْ مِنْهُ وَلَمْ يُجَاوِزْهُ وَلَمْ يُقَصِّرْ عَنْهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad] telah menceritakan kepada kami [Sufyan] dari [Muhammad bin Suqah] dari [Muhammad bin Ali bin Al Husain] ia berkata: \" [Ubaid bin Umair] menceritakan kepada Abdullah bin Umar, ia berkata: Rasulullah sallallahu 'alaihi wa sallam bersabda: 'perumpamaan orang munafik seperti seekor kambing diantara dua kandang kambing atau diantara dua kambing, [Ibnu Umar] berkata: 'tidak, sesungguhnya beliau bersabda demikian dan demikian'. Dia (Ali bin Al Husain) berkata: 'Ibnu Umar radliallahu 'anhu jika mendengar (sabda) Nabi ia tidak menambahi, tidak mengurangi, tidak memanjangkan serta tidak memendekkannya' \". "},"232":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا ابْنُ عُلَيَّةَ عَنْ ابْنِ عَوْنٍ قَالَ كَانَ الشَّعْبِيُّ وَالنَّخَعِيُّ وَالْحَسَنُ يُحَدِّثُونَ بِالْحَدِيثِ مَرَّةً هَكَذَا وَمَرَّةً هَكَذَا فَذَكَرْتُ ذَلِكَ لِمُحَمَّدِ بْنِ سِيرِينَ فَقَالَ أَمَا إِنَّهُمْ لَوْ حَدَّثُوا بِهِ كَمَا سَمِعُوهُ كَانَ خَيْرًا لَهُمْ","id":"Telah mengabarkan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Ibnu 'Ulayyah] dari [Ibnu 'Aun] ia berkata: \"Pernah [As Sya'bi], [An Nakha'i], dan [Al Hasan] menceritakan hadits (dengan redaksi) tertentu, dan (suatu saat dengan redaksi) yang berbeda, lalu aku menyampaikan hal tersebut kepada [Muhammad bin Sirin], lantas ia berkata: \"Bila mereka menceritakan hadis tertentu, sebagaimana mereka dengar apa adanya, hal itu lebih baik.\" "},"233":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا عَثَّامٌ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ أَبِي مَعْمَرٍ قَالَ إِنِّي لَأَسْمَعُ الْحَدِيثَ لَحْنًا فَأَلْحَنُ اتِّبَاعًا لِمَا سَمِعْتُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Ala`], telah menceritakan kepada kami ['Atsam] dari [Al A'masy] dari ['Umarah ibnu 'Umair] dari [Abu Ma'mar] ia berkata: \"Pernah aku mendengar hadits lahnan (secara takwil atau makna) maka aku takwilkan hadits sebagaimana yang aku dengar\"."},"234":{"ar":" أَخْبَرَنَا بِشْرُ بْنُ الْحَكَمِ حَدَّثَنَا سُفْيَانُ عَنْ إِبْرَاهِيمَ بْنِ مَيْسَرَةَ قَالَ رَأَى مُجَاهِدٌ طَاوُسًا فِي الْمَنَامِ كَأَنَّهُ فِي الْكَعْبَةِ يُصَلِّي مُتَقَنِّعًا وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى بَابِ الْكَعْبَةِ فَقَالَ لَهُ يَا عَبْدَ اللَّهِ اكْشِفْ قِنَاعَكَ وَأَظْهِرْ قِرَاءَتَكَ قَالَ فَكَأَنَّهُ عَبَّرَهُ عَلَى الْعِلْمِ فَانْبَسَطَ بَعْدَ ذَلِكَ فِي الْحَدِيثِ","id":"Telah mengabarkan kepada kami [Bisyr bin Al Hakam] telah menceritakan kepada kami [Sufyan] dari [Ibrahim bin Maisarah] ia berkata: [Mujahid] melihat Thawus dalam mimpinya, dia di Ka`bah mendirikan shalat sambil menutupi muka dengan kain, sementara Nabi sallallahu 'alaihi wa sallam berada di pintu Ka`bah. Kontan beliau berkata kepadanya: Wahai Abdullah bukalah kain penutup wajahmu dan tampakkan bacaanmu\". Dia berkata: Seakan-akan Rasulullah sallallahu 'alaihi wa sallam memberikan gambaran tentang ilmu, setelah itu Thawus lebih terbuka dan sering meriwayatkan hadits\"."},"235":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ الْأَوْزَاعِيِّ عَنْ بَحِيرٍ عَنْ خَالِدِ بْنِ مَعْدَانَ قَالَ النَّاسُ عَالِمٌ وَمُتَعَلِّمٌ وَمَا بَيْنَ ذَلِكَ هَمَجٌ لَا خَيْرَ فِيهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Katsir] dari [Al 'Auza'i] dari [Bahir] dari [Khalid bin Ma'dan] ia berkata: \"Manusia (terbagi dua) yaitu alim (orang yang mengajar) dan pelajar, selain itu adalah orang hina yang tidak ada kebaikan\"."},"236":{"ar":" أَخْبَرَنَا بِشْرُ بْنُ الْحَكَمِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ رَجَاءٍ عَنْ هِشَامٍ عَنْ الْحَسَنِ قَالَ كَانُوا يَقُولُونَ مَوْتُ الْعَالِمِ ثُلْمَةٌ فِي الْإِسْلَامِ لَا يَسُدُّهَا شَيْءٌ مَا اخْتَلَفَ اللَّيْلُ وَالنَّهَارُ","id":"Telah mengabarkan kepada kami [Bisyr bin Hakam] telah menceritakan kepada kami [Abdullah bin Rajab] dari [Hisyam] dari [Hasan] ia berkata: \"Mereka berkata bahwa wafatnya seorang alim laksana robeknya sesuatu yang tidak bisa ditambal, selama masih ada siang dan malam\"."},"237":{"ar":" أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا وَكِيعٌ قَالَ قَالَ سُفْيَانُ مَا أَعْلَمُ عَمَلًا أَفْضَلَ مِنْ طَلَبِ الْعِلْمِ وَحِفْظِهِ لِمَنْ أَرَادَ اللَّهَ بِهِ قَالَ قَالَ الْحَسَنُ بْنُ صَالِحٍ إِنَّ النَّاسَ لَيَحْتَاجُونَ إِلَى هَذَا الْعِلْمِ فِي دِينِهِمْ كَمَا يَحْتَاجُونَ إِلَى الطَّعَامِ وَالشَّرَابِ فِي دُنْيَاهُمْ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] telah mengabarkan kepada kami [Waki'] dia berkata: [Sufyan] berkata: \"Aku tidak mengetahui suatu amalan yang lebih utama dari pada mencari ilmu dan menjaganya, bagi siapa yang Allah kehendaki. Sufyan juga berkata: Berkata Al Hasan bin Shalih: 'Manusia membutuhkan ilmu ini untuk agamanya, sebagaimana mereka membutuhkan ilmu untuk makanan dan minuman dalam dunia mereka' \"."},"238":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ وَجَعْفَرُ بْنُ عَوْنٍ قَالَا حَدَّثَنَا مِسْعَرٌ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ قَالَ قَالَ أَبُو الدَّرْدَاءِ تَعَلَّمُوا قَبْلَ أَنْ يُقْبَضَ الْعِلْمُ فَإِنَّ قَبْضَ الْعِلْمِ قَبْضُ الْعُلَمَاءِ وَإِنَّ الْعَالِمَ وَالْمُتَعَلِّمَ فِي الْأَجْرِ سَوَاءٌ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] dan telah mengabarkan kepada kami [Ja'far bin 'Aun] berkata: telah menceritakan kepada kami [Mis'ar] dari ['Amr bin Murrah] dari [Salim bin Abu Al Ja'd] ia berkata: berkata [Abu Darda`] radliallahu 'anhu: \"Belajarlah kalian sebelum ilmu dicabut, sesungguhnya dicabutnya ilmu dengan diwafatkan ulama. Sesungguhnya orang alim (yang mengajarkan ilmu) dan manusia terpelajar (yang berburu ilmu) memperoleh pahala sama\"."},"239":{"ar":" أَخْبَرَنَا هَارُونُ بْنُ مُعَاوِيَةَ عَنْ حَفْصِ بْنِ غِيَاثٍ عَنْ أَبِي عَبْدِ اللَّهِ الْخُرَاسَانِيِّ عَنْ الضَّحَّاكِ وَلَكِنْ كُونُوا رَبَّانِيِّينَ بِمَا كُنْتُمْ تُعَلِّمُونَ الْكِتَابَ قَالَ حَقٌّ عَلَى كُلِّ مَنْ قَرَأَ الْقُرْآنَ أَنْ يَكُونَ فَقِيهًا","id":"Telah mengabarkan kepada kami [Harun bin Mu'awiyah] dari [Hafsh bin Ghiyats] dari [Abi Abdullah Al Khurasani] dari [Ad Dlahaq] -Ia mengomentari ayat- 'Akan tetapi jadilah kalian semua Rabbaniyyun karena kamu selalu mengajarkan Al kitab' (Surat Ali-Imran; 79), dia berkata: \"adalah kewajiban setiap orang yang membaca Al Qur`an untuk menjadi faqih (mengetahui maksud atau isinya secara mendalam) \"."},"240":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عُيَيْنَةَ عَنْ أَبِي إِسْحَقَ الْفَزَارِيِّ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ { كُونُوا رَبَّانِيِّينَ } قَالَ عُلَمَاءُ فُقَهَاءُ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Uyainah] dari [Abu Ishaq Al Fazari] dari ['Atha' bin As Sa`ib] dari [Sa'id bin Jubair] ia berkata: \"jadilah kalian semua Rabbaniyyun\" dia berkata: maksudnya adalah ulama yang ahli fikih\"."},"241":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ سَمِعْتُ سُفْيَانَ بْنَ عُيَيْنَةَ يَقُولُ يُرَادُ لِلْعِلْمِ الْحِفْظُ وَالْعَمَلُ وَالِاسْتِمَاعُ وَالْإِنْصَاتُ وَالنَّشْرُ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'id] ia berkata: \"aku telah mendengar [Sufyan bin 'Uyainah] berkata: \"Yang dimaksud ilmu adalah menghafal, beramal, mendengar, diam dan menyebarkan\"."},"242":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ الرَّقِّيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَمْرٍو عَنْ زَيْدٍ هُوَ ابْنُ أَبِي أُنَيْسَةَ عَنْ سَيَّارٍ عَنْ الْحَسَنِ قَالَ مَنْهُومَانِ لَا يَشْبَعَانِ مَنْهُومٌ فِي الْعِلْمِ لَا يَشْبَعُ مِنْهُ وَمَنْهُومٌ فِي الدُّنْيَا لَا يَشْبَعُ مِنْهَا فَمَنْ تَكُنِ الْآخِرَةُ هَمَّهُ وَبَثَّهُ وَسَدَمَهُ يَكْفِي اللَّهُ ضَيْعَتَهُ وَيَجْعَلُ غِنَاهُ فِي قَلْبِهِ وَمَنْ تَكُنِ الدُّنْيَا هَمَّهُ وَبَثَّهُ وَسَدَمَهُ يُفْشِي اللَّهُ عَلَيْهِ ضَيْعَتَهُ وَيَجْعَلُ فَقْرَهُ بَيْنَ عَيْنَيْهِ ثُمَّ لَا يُصْبِحُ إِلَّا فَقِيرًا وَلَا يُمْسِي إِلَّا فَقِيرًا","id":"Telah mengabarkan kepada kami [Abdullah bin Ja'far Ar Raqi] dari [Ubaidullah bin 'Amr] dari [Zaid Ibnu Abu Unaisah] dari [Sayyar] dari [Al Hasan] ia berkata: \"Ada dua golongan orang rakus yang tidak pernah merasa kenyang, Pertama orang yang rakus terhadap ilmu, Kedua orang yang rakus terhadap dunia. Barang siapa yang menjadikan akhirat sebagai tujuan, semboyan, dan kesukaannya, Allah mencukupkan kekurangannya (amal perbuatannya) dan Allah menjadikan kekayaannya di hatinya. Dan barangsiapa menjadikan dunia sebagai tujuan, semboyan dan kesukaannya, maka Allah menjadikan hartanya berlimpah dan menjadikan kefakiran di depan matanya, kemudian dia tidak menjadi selain sebagai orang fakir di pagi dan sore harinya\"."},"243":{"ar":" أَخْبَرَنَا جَعْفَرُ بْنُ عَوْنٍ أَخْبَرَنَا أَبُو عُمَيْسٍ عَنْ عَوْنٍ قَالَ قَالَ عَبْدُ اللَّهِ مَنْهُومَانِ لَا يَشْبَعَانِ صَاحِبُ الْعِلْمِ وَصَاحِبُ الدُّنْيَا وَلَا يَسْتَوِيَانِ أَمَّا صَاحِبُ الْعِلْمِ فَيَزْدَادُ رِضًا لِلرَّحْمَنِ وَأَمَّا صَاحِبُ الدُّنْيَا فَيَتَمَادَى فِي الطُّغْيَانِ ثُمَّ قَرَأَ عَبْدُ اللَّهِ { كَلَّا إِنَّ الْإِنْسَانَ لَيَطْغَى أَنْ رَآهُ اسْتَغْنَى } قَالَ وَقَالَ الْآخَرُ { إِنَّمَا يَخْشَى اللَّهَ مِنْ عِبَادِهِ الْعُلَمَاءُ }","id":"Telah mengabarkan kepada kami [Ja'far bin 'Aun] telah mengabarkan kepada kami [Abu 'Umais] dari ['Aun] ia berkata: \" [Abdullah] berkata: 'Ada dua golongan yang tidak pernah merasa kenyang, yaitu pemilik ilmu dan pemilik dunia, dan keduanya tidak sama. Adapun pemilik ilmu semakin menambah kerelaan terhadap Ar Rahman, dan pemilik dunia selalu melampaui batas (menambah kelaliman), kemudian Abdullah membaca: \"KALLA INNAL INSAANA LAYATHGHAA AN RA`AHUS TAGHNAA\" (Ketahuilah! Sesungguhnya manusia benar-benar melampaui batas, karena ia melihat dirinya serba cukup), dia berkata juga, yang lain juga berkata: 'Yang takut kepada Allah diantara hambaNya, hanyalah ulama\"."},"244":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ عِمْرَانَ حَدَّثَنَا يَحْيَى بْنُ يَمَانٍ قَالَ سَمِعْتُ سُفْيَانَ مُنْذُ أَرْبَعِينَ سَنَةً قَالَ مَا كَانَ طَلَبُ الْحَدِيثِ أَفْضَلَ مِنْهُ الْيَوْمَ قَالُوا لِسُفْيَانَ إِنَّهُمْ يَطْلُبُونَهُ بِغَيْرِ نِيَّةٍ قَالَ طَلَبُهُمْ إِيَّاهُ نِيَّةٌ","id":"Telah mengabarkan kepada kami [Abdullah bin Imran] telah menceritakan kepada kami [Yahya bin Yaman] ia berkata: \"Aku pernah mendengar [Sufyan] sejak empat puluh tahun yang lalu, ia berkata: 'Hari ini tak ada yang lebih utama daripada perburuan hadis. Mereka berkomentar kepada Sofyan; \"Paling-paling mereka mencarinya tanpa niat\". Kontan Sofyan berkata: \"Pencarian mereka untuk berburu hadis itu sendiri merupakan niat' \". "},"245":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْأَجْلَحِ قَالَ حَدَّثَنِي أَبِي عَنْ مُجَاهِدٍ قَالَ طَلَبْنَا هَذَا الْعِلْمَ وَمَا لَنَا فِيهِ كَبِيرُ نِيَّةٍ ثُمَّ رَزَقَ اللَّهُ بَعْدُ فِيهِ النِّيَّةَ","id":"Telah mengabarkan kepada kami [Abdullah bin Sa`ad] telah menceritakan kepada kami [Abdullah bin Al Ajlah] telah menceritakan kepadaku [ayahku] dari [Mujahid] ia berkata: \"Dahulu kami mencari ilmu ini dengan tanpa niat yang benar. Kemudian Allah memberi niat (kepada kami) di kemudian hari\"."},"246":{"ar":" أَخْبَرَنَا بِشْرُ بْنُ ثَابِتٍ الْبَزَّارُ حَدَّثَنَا حَسَّانُ بْنُ مُسْلِمٍ عَنْ يُونُسَ بْنِ عُبَيْدٍ عَنْ الْحَسَنِ قَالَ لَقَدْ طَلَبَ أَقْوَامٌ الْعِلْمَ مَا أَرَادُوا بِهِ اللَّهَ وَلَا مَا عِنْدَهُ قَالَ فَمَا زَالَ بِهِمْ الْعِلْمُ حَتَّى أَرَادُوا بِهِ اللَّهَ وَمَا عِنْدَهُ","id":"Telah mengabarkan kepada kami [Bisyr bin Tsabit Al Bazzar] telah menceritakan kepada kami [Hassan bin Muslim] dari [Yunus bin Ubaid] dari [Al Hasan] ia berkata: \"Sungguh ada beberapa kaum yang mencari ilmu sedang mereka menghendaki hal itu bukan karena Allah dan bukan untuk memperoleh yang ada di sisiNya, maka tak henti-hentinya mereka mencari ilmu hingga mereka menghendakinya karena Allah dan untuk memperoleh apa yang ada di sisiNya\"."},"247":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ قَالَ قَالَ أَبُو مُسْلِمٍ الْخَوْلَانِيُّ الْعُلَمَاءُ ثَلَاثَةٌ فَرَجُلٌ عَاشَ فِي عِلْمِهِ وَعَاشَ مَعَهُ النَّاسُ فِيهِ وَرَجُلٌ عَاشَ فِي عِلْمِهِ وَلَمْ يَعِشْ مَعَهُ فِيهِ أَحَدٌ وَرَجُلٌ عَاشَ النَّاسُ فِي عِلْمِهِ وَكَانَ وَبَالًا عَلَيْهِ","id":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah] ia berkata: \" [Abu Muslim Al Khaulani] pernah berkata: 'Ulama' itu ada tiga: Pertama Ulama' yang hidup dengan ilmunya dan manusia lain hidup dengan ilmunya, Kedua ulama' yang hidup dengan ilmunya dan tidak seorang pun mendapatkan manfaat ilmu tersebut, dan ketiga ulama yang masyarakat hidup dengan ilmunya, namun ilmu tersebut justru mencelakaan dirinya sendiri\"."},"248":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ عُثْمَانَ بْنِ الْأَسْوَدِ عَنْ عَطَاءٍ قَالَ قَالَ مُوسَى يَا رَبِّ أَيُّ عِبَادِكَ أَحْكَمُ قَالَ الَّذِي يَحْكُمُ لِلنَّاسِ كَمَا يَحْكُمُ لِنَفْسِهِ قَالَ يَا رَبِّ أَيُّ عِبَادِكَ أَغْنَى قَالَ أَرْضَاهُمْ بِمَا قَسَمْتُ لَهُ قَالَ يَا رَبِّ أَيُّ عِبَادِكَ أَخْشَى لَكَ قَالَ أَعْلَمُهُمْ بِي","id":"Telah mengabarkan kepada kami [Ubaidullah bin Musa] dari [Utsman bin Al Aswad] dari ['Atha`] ia berkata: \"Nabi Musa 'alaihaihissalam: 'Ya Rabbi, siapakah diantara hamba-Mu yang paling bijaksana?, Allah menjawab: 'yaitu orang yang menghukumi manusia sebagaimana ia menghukumi untuk dirinya sendiri. Beliau juga berkata: ' Wahai Tuhanku siapa diantara hamba-Mu yang paling kaya? Allah menjawab: 'Ia adalah orang yang paling rela dengan apa-apa yang Aku bagikan kepadanya'. Beliau juga bertanya: 'Wahai Tuhanku siapakah dari hambaMu yang paling takut kepadaMu? Allah menjawab: 'Mereka yang paling tahu tentang diriKu' \"."},"249":{"ar":" أَخْبَرَنَا مَكِّيُّ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ عَنْ الْحَسَنِ قَالَ الْعِلْمُ عِلْمَانِ فَعِلْمٌ فِي الْقَلْبِ فَذَلِكَ الْعِلْمُ النَّافِعُ وَعِلْمٌ عَلَى اللِّسَانِ فَذَلِكَ حُجَّةُ اللَّهِ عَلَى ابْنِ آدَمَ أَخْبَرَنَا عَاصِمُ بْنُ يُوسُفَ عَنْ فُضَيْلِ بْنِ عِيَاضٍ عَنْ هِشَامٍ عَنْ الْحَسَنِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَ ذَلِكَ","id":"Telah mengabarkan kepada kami [Makki bin Ibrahim] telah menceritakan kepada kami [Hisyam] dari [Al Hasan] ia berkata: \"Ilmu itu ada dua, yaitu ilmu dalam hati, itulah ilmu yang bermanfaat dan ilmu yang ada di lisan, itulah hujjah Allah atas Ibnu Adam (manusia) \". ['Ashim bin Yusuf] mengabarkan kepada kami dari [Fudhail bin Iyadh] dari [Hisyam] dari [Al Hasan] dari Rasulullah sallallahu 'alaihi wa sallam seperti itu\"."},"250":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَ تَعَلَّمُوا تَعَلَّمُوا فَإِذَا عَلِمْتُمْ فَاعْمَلُوا","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] telah mengabarkan kepada kami [Khalid bin Abdullah] dari [Yazid bin Abu Ziyad] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] ia berkata: \"Belajarlah kalian semua, belajarlah kalian semua, Jika kalian semua telah mengetahui maka amalkanlah\"."},"251":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ هِشَامٍ صَاحِبِ الدَّسْتَوَائِيِّ قَالَ قَرَأْتُ فِي كِتَابٍ بَلَغَنِي أَنَّهُ مِنْ كَلَامِ عِيسَى تَعْمَلُونَ لِلدُّنْيَا وَأَنْتُمْ تُرْزَقُونَ فِيهَا بِغَيْرِ عَمَلٍ وَلَا تَعْمَلُونَ لِلْآخِرَةِ وَأَنْتُمْ لَا تُرْزَقُونَ فِيهَا إِلَّا بِالْعَمَلِ وَإِنَّكُمْ عُلَمَاءَ السَّوْءِ الْأَجْرَ تَأْخُذُونَ وَالْعَمَلَ تُضَيِّعُونَ يُوشِكُ رَبُّ الْعَمَلِ أَنْ يَطْلُبَ عَمَلَهُ وَتُوشِكُونَ أَنْ تَخْرُجُوا مِنْ الدُّنْيَا الْعَرِيضَةِ إِلَى ظُلْمَةِ الْقَبْرِ وَضِيقِهِ اللَّهُ نَهَاكُمْ عَنْ الْخَطَايَا كَمَا أَمَرَكُمْ بِالصَّلَاةِ وَالصِّيَامِ كَيْفَ يَكُونُ مِنْ أَهْلِ الْعِلْمِ مَنْ سَخِطَ رِزْقَهُ وَاحْتَقَرَ مَنْزِلَتَهُ وَقَدْ عَلِمَ أَنَّ ذَلِكَ مِنْ عِلْمِ اللَّهِ وَقُدْرَتِهِ كَيْفَ يَكُونُ مِنْ أَهْلِ الْعِلْمِ مَنْ اتَّهَمَ اللَّهَ فِيمَا قَضَى لَهُ فَلَيْسَ يَرْضَى شَيْئًا أَصَابَهُ كَيْفَ يَكُونُ مِنْ أَهْلِ الْعِلْمِ مَنْ دُنْيَاهُ آثَرُ عِنْدَهُ مِنْ آخِرَتِهِ وَهُوَ فِي الدُّنْيَا أَفْضَلُ رَغْبَةً كَيْفَ يَكُونُ مِنْ أَهْلِ الْعِلْمِ مَنْ مَصِيرُهُ إِلَى آخِرَتِهِ وَهُوَ مُقْبِلٌ عَلَى دُنْيَاهُ وَمَا يَضُرُّهُ أَشْهَى إِلَيْهِ أَوْ قَالَ أَحَبُّ إِلَيْهِ مِمَّا يَنْفَعُهُ كَيْفَ يَكُونُ مِنْ أَهْلِ الْعِلْمِ مَنْ يَطْلُبُ الْكَلَامَ لِيُخْبِرَ بِهِ وَلَا يَطْلُبُهُ لِيَعْمَلَ بِهِ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [Hisyam] pengarang kitab Ad Dastawa`i ia berkata: \"Aku pernah membaca dalam sebuah kitab, telah sampai kepadaku bahwa kitab itu dari ucapan Isa 'alaihissalam: 'Kamu semua beramal untuk dunia padahal kamu semua diberi rizki disana tanpa amal, dan kamu semua tidak beramal untuk akhirat dan padahal kamu semua tidak diberi rizki disana kecuali dengan beramal. Celakalah kalian semua ulama` su` (ulama yang jahat), kalian semua mengambil pahala, sedang amal kalian sia-siakan. Khawatirkan olehmu jangan-jangan pemilik amal (Allah) meminta amalnya, dan dikhawatirkan kalian semua keluar dari dunia yang luas menuju kegelapan kubur dan kesempitannya. Allah melarang kalian semua berbuat kesalahan sebagaimana Ia memerintahkan kalian semua shalat dan puasa. Bagaimana mungkin seseorang menjadi seorang alim jika ia khawatir terhadap rizkinya dan merendahkan derajatnya padahal ia tahu bahwa hal itu dari ilmu Allah dan taqdirNya?, Bagaimana mungkin seseorang dianggap sebagai orang berilmu sedang dia menghujat Allah terhadap apa yang telah ditentukan-Nya, dan dia tidak ridha atas sesuatu yang menimpa dirinya?. Bagaimana bisa dianggap sebagai orang berilmu, seseorang yang lebih mengutamakan dunia di sisinya dari pada akhiratnya dan dia lebih mementingkan masalah dunia?, bagaimana bisa dianggap sebagai orang yang berilmu, seseorang yang berjalan menuju akhirat, namun ia selalu mengejar dunia, dan apa-apa yang membahayakannya lebih ia sukai (atau dia berkata: aku lebih mencintainya) dari apa-apa yang membawa manfaat kepadanya?, bagaimana bisa dianggap sebagai orang yang berilmu, orang yang mencari Al kalam (ilmu) untuk sekedar diinformasikan dan tidak mencarinya untuk beramal?\"."},"252":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا حَرِيزٌ عَنْ حَبِيبِ بْنِ عُبَيْدٍ قَالَ كَانَ يُقَالُ تَعَلَّمُوا الْعِلْمَ وَانْتَفِعُوا بِهِ وَلَا تَعَلَّمُوهُ لِتَتَجَمَّلُوا بِهِ فَإِنَّهُ يُوشِكُ إِنْ طَالَ بِكُمْ عُمُرٌ أَنْ يَتَجَمَّلَ ذُو الْعِلْمِ بِعِلْمِهِ كَمَا يَتَجَمَّلُ ذُو الْبِزَّةِ بِبِزَّتِهِ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Hariz] dari [Habib bin Ubaid] ia berkata: \"Pelajarilah ilmu dan ambillah manfaat, dan janganlah kalian mempelajarinya karena ingin memperbagus diri dengan ilmu. Siapa tahu kalian berumur panjang, dan ketika itu orang yang mempunyai ilmu memperbagus dirinya dengan ilmunya seperti orang yang mempunyai kain dan dipergunakannya untuk memperindah diri.\""},"253":{"ar":" أَخْبَرَنَا نُعَيْمُ بْنُ حَمَّادٍ حَدَّثَنَا بَقِيَّةُ عَنْ الْأَحْوَصِ بْنِ حَكِيمٍ عَنْ أَبِيهِ قَالَ سَأَلَ رَجُلٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الشَّرِّ فَقَالَ لَا تَسْأَلُونِي عَنْ الشَّرِّ وَاسْأَلُونِي عَنْ الْخَيْرِ يَقُولُهَا ثَلَاثًا ثُمَّ قَالَ أَلَا إِنَّ شَرَّ الشَّرِّ شِرَارُ الْعُلَمَاءِ وَإِنَّ خَيْرَ الْخَيْرِ خِيَارُ الْعُلَمَاءِ","id":"Telah mengabarkan kepada kami [Nu'aim bin Hammad] telah menceritakan kepada kami [Baqiyyah] dari [Al `Ahwash bin Hakim] dari [ayahnya] ia berkata: \"Seorang laki-laki bertanya kepada Rasulullah sallallahu 'alaihi wa sallam tentang kejahatan, maka Rasulullah sallallahu 'alaihi wa sallam menjawab: \"Janganlah anda sekalian bertanya kepadaku tentang kejahatan, dan bertanyalah kepadaku tentang kebaikan\". Rasul berkata tiga kali, kemudian beliau bersabda: \"Ketahuilah bahwa sejelek-jelek kejahatan adalah kejahatan ulama, dan sebaik-baik kebaikan adalah kebaikan ulama.\""},"254":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ قَالَ زَعَمَ لِي سُفْيَانُ قَالَ كَانَ الرَّجُلُ لَا يَطْلُبُ الْعِلْمَ حَتَّى يَتَعَبَّدَ قَبْلَ ذَلِكَ أَرْبَعِينَ سَنَةً","id":"Telah mengabarkan kepada kami [Abu 'Ashim] berkata: \"Sepertinya [Sofyan] pernah mengatakan kepadaku: \"Pernah ada seorang laki-laki yang tidak mencari ilmu hingga ia mau berkorban untuk ibadah, dan itu memerlukan waktu empat puluh tahun.\""},"255":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ بُرْدِ بْنِ سِنَانٍ أَبِي الْعَلَاءِ عَنْ مَكْحُولٍ قَالَ مَنْ طَلَبَ الْعِلْمَ لِيُمَارِيَ بِهِ السُّفَهَاءَ وَلِيُبَاهِيَ بِهِ الْعُلَمَاءَ أَوْ لِيَصْرِفَ بِهِ وُجُوهَ النَّاسِ إِلَيْهِ فَهُوَ فِي نَارِ جَهَنَّمَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Burd bin Sinan Abu Al 'Ala`] dari [Makhul] berkata: \"Barang siapa mencari ilmu sekedar untuk berbantah-bantahan dengan orang bodoh, untuk menandingi para ulama dan untuk mencari muka manusia, dia masuk neraka jahannam\"."},"256":{"ar":" أَخْبَرَنَا إِسْمَعِيلُ بْنُ أَبَانَ حَدَّثَنَا يَحْيَى بْنُ يَمَانٍ عَنْ الْمِنْهَالِ بْنِ خَلِيفَةَ عَنْ مَطَرٍ الْوَرَّاقِ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ ابْنِ عَبَّاسٍ قَالَ إِنَّمَا يُحْفَظُ حَدِيثُ الرَّجُلِ عَلَى قَدْرِ نِيَّتِهِ","id":"Telah mengabarkan kepada kami [Isma'il bin Abban] telah menceritakan kepada kami [Yahya bin Yaman] dari [Minhal bin Khalifah] [dari [Mathar Al Warraq] dari [Syahr bin Hausyab] dari [Ibnu Abbas] radliallahu 'anhu ia berkata: \" Perkataan seseorang akan diingat sesuai dengan kadar niatnya\"."},"257":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ عَنْ حَمَّادِ بْنِ زَيْدٍ عَنْ أَيُّوبَ قَالَ قَالَ أَبُو قِلَابَةَ لَا تُجَالِسُوا أَهْلَ الْأَهْوَاءِ وَلَا تُجَادِلُوهُمْ فَإِنِّي لَا آمَنُ أَنْ يَغْمِسُوكُمْ فِي ضَلَالَتِهِمْ أَوْ يَلْبِسُوا عَلَيْكُمْ مَا كُنْتُمْ تَعْرِفُونَ","id":"Telah mengabarkan kepada kami [Sulaiman bin harb] dari [Hammad bin Zaid] dari [Ayyub] ia berkata: \" [Abu Qilabah] pernah berkata: 'Janganlah kalian bergaul dengan orang yang mengikuti hawa nafsu, dan jangan pula kalian berdebat dengan mereka, karena aku khawatir akan menjerumuskan kalian dalam kesesatan, atau mencampuradukkan perkara-perkara yang kalian ketahui' \"."},"258":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ قَالَ رَآنِي سَعِيدُ بْنُ جُبَيْرٍ جَلَسْتُ إِلَى طَلْقِ بْنِ حَبِيبٍ فَقَالَ لِي أَلَمْ أَرَكَ جَلَسْتَ إِلَى طَلْقِ بْنِ حَبِيبٍ لَا تُجَالِسَنَّهُ","id":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] ia berkata: \" [Sa'id bin Jubair] pernah melihatku duduk bersama dengan Thalq bin Habib, lalu ia berkata kepadaku: 'Bukankah aku pernah melihatmu duduk bersama dengan Thalq bin Habib, janganlah kamu duduk bersamanya' \"."},"259":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ أَخْبَرَنَا حَيْوَةُ بْنُ شُرَيْحٍ حَدَّثَنِي أَبُو صَخْرٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّهُ جَاءَهُ رَجُلٌ فَقَالَ إِنَّ فُلَانًا يَقْرَأُ عَلَيْكَ السَّلَامَ قَالَ بَلَغَنِي أَنَّهُ قَدْ أَحْدَثَ فَإِنْ كَانَ قَدْ أَحْدَثَ فَلَا تَقْرَأْ عَلَيْهِ السَّلَامَ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] telah mengabarkan kepada kami [Haiwah bin Syuraih] telah menceritakan kepadaku [Abu Shakhr] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhu: \"Seorang laki-laki datang menemuinya lalu berkata: 'Sesungguhnya si fulan menyampaikan salam untukmu', lalu ia berkata: 'Telah sampai berita kepadaku bahwa ia berbuat bid'ah, jika benar ia telah berbuat bid'ah maka janganlah kamu sampaikan salamku untuknya' \"."},"260":{"ar":" أَخْبَرَنَا مَخْلَدُ بْنُ مَالِكٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَغْرَاءَ حَدَّثَنَا الْأَعْمَشُ قَالَ كَانَ إِبْرَاهِيمُ لَا يَرَى غِيبَةً لِلْمُبْتَدِعِ","id":"Telah mengabarkan kepada kami [Makhlad bin Malik] telah menceritakan kepada kami [Abdur Rahman bin Maghra`] telah menceritakan kepada kami [Al A'masy] ia berkata: \" [Ibrahim] berpendapat bahwa membicarakan ahli bid'ah tidak termasuk mengghibah\"."},"261":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ حُمَيْدٍ حَدَّثَنَا جَرِيرٌ عَنْ ابْنِ شُبْرُمَةَ عَنْ الشَّعْبِيِّ قَالَ إِنَّمَا سُمِّيَ الْهَوَى لِأَنَّهُ يَهْوِي بِصَاحِبِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Humaid] telah menceritakan kepada kami [Jarir] dari [Ibnu Syubrumah] dari [As Sya'bi] ia berkata: \"Hanyasanya disebut hawa nafsu, karena ia menjerumuskan pelakunya\". "},"262":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ أَسْمَاءَ بْنِ عُبَيْدٍ قَالَ دَخَلَ رَجُلَانِ مِنْ أَصْحَابِ الْأَهْوَاءِ عَلَى ابْنِ سِيرِينَ فَقَالَا يَا أَبَا بَكْرٍ نُحَدِّثُكَ بِحَدِيثٍ قَالَ لَا قَالَا فَنَقْرَأُ عَلَيْكَ آيَةً مِنْ كِتَابِ اللَّهِ قَالَ لَا لِتَقُومَانِ عَنِّي أَوْ لَأَقُومَنَّ قَالَ فَخَرَجَا فَقَالَ بَعْضُ الْقَوْمِ يَا أَبَا بَكْرٍ وَمَا كَانَ عَلَيْكَ أَنْ يَقْرَأَا عَلَيْكَ آيَةً مِنْ كِتَابِ اللَّهِ قَالَ إِنِّي خَشِيتُ أَنْ يَقْرَأَا عَلَيَّ آيَةً مِنْ كِتَابِ اللَّهِ فَيُحَرِّفَانِهَا فَيَقِرُّ ذَلِكَ فِي قَلْبِي","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [`Asma` bin 'Ubaid] ia berkata: \"Ada dua orang (yang dikenal) memperturutkan hawa nafsu masuk menemui [Ibnu Sirin] kemudian keduanya berkata; 'Wahai Abu Bakar, bolehkah kami menceritakan kepadamu suatu hadits? ', ia menjawab: 'Tidak', keduanya berkata: 'Bagaimana kalau kami membacakan kepadamu sebuah ayat dari kitab Allah?, ia menjawab: 'tidak, kamu berdua yang pergi meninggalkanku ataukah aku yang harus pergi meninggalkan kamu berdua'. ia berkata: 'maka kedua orang itu pergi'. Sebagian orang-orang berkata kepadanya: 'Wahai Abu Bakar mengapa tidak kamu biarkan saja dia membacakan sebuah ayat dari kitab Allah? ', ia menjawab: 'Aku khawatir ia membacakan sebuah ayat kepadaku (tetapi) kemudian mereka putarbalikkan maknanya, dan hal itu bisa tertanam dalam hatiku' \"."},"263":{"ar":" أَخْبَرَنَا سَعِيدٌ عَنْ سَلَّامِ بْنِ أَبِي مُطِيعٍ أَنَّ رَجُلًا مِنْ أَصْحَابِ الْأَهْوَاءِ قَالَ لِأَيُّوبَ يَا أَبَا بَكْرٍ أَسْأَلُكَ عَنْ كَلِمَةٍ قَالَ فَوَلَّى وَهُوَ يُشِيرُ بِأُصْبُعِهِ وَلَا نِصْفَ كَلِمَةٍ وَأَشَارَ لَنَا سَعِيدٌ بِخِنْصِرِهِ الْيُمْنَى","id":"Telah mengabarkan kepada kami [Sa'id] dari [Salam bin Abu Muthi']: \"Ada seorang (yang selalu) mengikuti hawa nafsu berkata kepada [Ayyub]: 'Wahai Abu Bakar, bolehkah aku meminta kepadamu satu kalimat saja?\", Abu Bakar berpaling sambil memberikan isyarat dengan jarinya, dan ia tidak menjawab walau dengan satu kalimat pun, dan Sa'id memberikan isyarat kepada kami dengan jari kelingkingnya yang kanan\"."},"264":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ عَنْ حَمَّادِ بْنِ زَيْدٍ عَنْ كُلْثُومِ بْنِ جَبْرٍ أَنَّ رَجُلًا سَأَلَ سَعِيدَ بْنَ جُبَيْرٍ عَنْ شَيْءٍ فَلَمْ يُجِبْهُ فَقِيلَ لَهُ فَقَالَ أَزِيشَانْ","id":"Telah mengabarkan kepada kami [Sulaiman bin harb] dari [Hammad bin Zaid] dari [Kultsum bin Jabr]: \"Ada seorang bertanya kepada [Sa'id bin Jubair] tentang sesuatu dan ia tidak menjawabnya, kemudian ada seorang yang bertanya: 'Mengapa kamu bersikap demikian? ', ia menjawab: 'Azisyan (ia termasuk bagian dari orang yang suka membuat bid'ah dan memperturutkan hawa nafsu) ' \". "},"265":{"ar":" أَخْبَرَنَا أَحْمَدُ حَدَّثَنَا زَائِدَةُ عَنْ هِشَامٍ عَنْ الْحَسَنِ وَابْنِ سِيرِينَ أَنَّهُمَا قَالَا لَا تُجَالِسُوا أَصْحَابَ الْأَهْوَاءِ وَلَا تُجَادِلُوهُمْ وَلَا تَسْمَعُوا مِنْهُمْ","id":"Telah mengabarkan kepada kami [Ahmad] telah menceritakan kepada kami [Za`idah] dari [Hisyam] dari [Al Hasan] dan [Ibnu Sirin] keduanya berkata: \"Janganlah kalian duduk-duduk bersama orang-orang yang mengumbar atau mengikuti hawa nafsunya, jangan berbantah-bantahan bersama mereka dan janganlah kalian mendengarkan dari mereka\"."},"266":{"ar":" أَخْبَرَنَا أَحْمَدُ حَدَّثَنَا شَرِيكٌ عَنْ أُمَيٍّ عَنْ الشَّعْبِيِّ قَالَ إِنَّمَا سُمُّوا أَصْحَابَ الْأَهْوَاءِ لِأَنَّهُمْ يَهْوُونَ فِي النَّارِ","id":"Telah mengabarkan kepada kami [Ahmad] telah menceritakan kepada kami [Syarik] dari [`Umay] dari [As Sya'bi] ia berkata: \"Mereka disebut sebagai Ashhabul Ahwa`, karena mereka akan jatuh ke dalam api neraka\". "},"267":{"ar":" أَخْبَرَنَا بِشْرُ بْنُ الْحَكَمِ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ مَيْسَرَةَ قَالَ مَا رَأَيْتُ أَحَدًا مِنْ النَّاسِ الشَّرِيفُ وَالْوَضِيعُ عِنْدَهُ سَوَاءٌ غَيْرَ طَاوُسٍ وَهُوَ يَحْلِفُ عَلَيْهِ","id":"Telah mengabarkan kepada kami [Bisyr bin Al Hakam] telah menceritakan kepada kami [Sufyan] dari [Ibnu Maisarah] ia berkata: 'Aku tidak melihat satu orang pun, yang baginya orang mulia dan orang sederhana sama saja disisinya kecuali [Thawus], dan ia bersumpah untuk hal yang demikian\"."},"268":{"ar":" أَخْبَرَنَا بِشْرُ بْنُ الْحَكَمِ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ قَالَ كُنَّا نَكْرَهُ كِتَابَةَ الْعِلْمِ حَتَّى أَكْرَهَنَا عَلَيْهِ السُّلْطَانُ فَكَرِهْنَا أَنْ نَمْنَعَهُ أَحَدًا","id":"Telah mengabarkan kepada kami [Bisyr bin Al Hakam] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] ia berkata: \"Dahulu kami tidak suka menulis ilmu hingga ahirnya pemerintah memaksa kami, maka kami (akhirnya) tidak suka melarang seseorang melakukan hal tersebut\"."},"269":{"ar":" أَخْبَرَنَا يُوسُفُ بْنُ مُوسَى حَدَّثَنَا مُعَاذُ بْنُ مُعَاذٍ حَدَّثَنَا ابْنُ عَوْنٍ قَالَ كَلَّمُوا مُحَمَّدًا فِي رَجُلٍ يَعْنِي يُحَدِّثُهُ فَقَالَ لَوْ كَانَ رَجُلًا مِنْ الزِّنْجِ لَكَانَ عِنْدِي وَعَبْدُ اللَّهِ بْنُ مُحَمَّدٍ فِي هَذَا سَوَاءً","id":"Telah mengabarkan kepada kami [Yusuf bin musa] telah menceritakan kepada kami [Mu'adz bin Mu'adz] telah menceritakan kepada kami [Ibnu 'Aun] ia berkata: \"Orang-orang mengomentari [Muhammad] karena meladeni seseorang yang diajaknya bicara. Kontan Aun bin Abdullah berkomentar: Walaupun yang diajaknya bicara itu berasal dari suku Az Zinji (yang berkulit hitam), ia bagiku dan Abdullah bin Muhammad tetap sama saja\"."},"270":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ عَنْ حَمَّادِ بْنِ زَيْدٍ عَنْ الصَّلْتِ بْنِ رَاشِدٍ سَأَلَ سَلْمُ بْنُ قُتَيْبَةَ طَاوُسًا عَنْ مَسْأَلَةٍ فَلَمْ يُجِبْهُ فَقِيلَ لَهُ هَذَا سَلْمُ بْنُ قُتَيْبَةَ قَالَ ذَلِكَ أَهْوَنُ لَهُ عَلَيَّ","id":"Telah mengabarkan kepada kami [Yahya bin Hassan] dari [Hammad bin Zaid] dari [As Shalt bin Rasyid] ia berkata: \"Salam bin Qutaibah pernah bertanya kepada [Thawus] tentang suatu masalah, tetapi ia tidak menjawabnya, lalu dikatakan kepadanya: 'Yang bertanya kepadamu ini Salam bin Qutaibah' ia menjawab: 'Kabar yang demikian pun tidak mempengaruhiku' \"."},"271":{"ar":" أَخْبَرَنَا إِبْرَاهِيمُ بْنُ إِسْحَقَ عَنْ بَقِيَّةَ قَالَ حَدَّثَنِي حَبِيبُ بْنُ صَالِحٍ قَالَ مَا خِفْتُ أَحَدًا مِنْ النَّاسِ مَخَافَةَ خَالِدِ بْنِ مَعْدَانَ","id":"Telah mengabarkan kepada kami [Ibrahim bin Ishak] dari [Baqiyyah] ia berkata: [Habib bin Shalih] pernah berkata: 'Aku tidak pernah takut pada seorang pun seperti ketakutanku kepada Khalid bin Ma'dan\"."},"272":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ مُغِيرَةَ قَالَ كُنَّا نَهَابُ إِبْرَاهِيمَ هَيْبَةَ الْأَمِيرِ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Mughirah] ia berkata: \"Kami menghormati (segan kepada) Ibrahim sebagaimana kami menghormati seorang Raja\"."},"273":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ قَالَ حَدَّثَ سَعِيدُ بْنُ جُبَيْرٍ يَوْمًا بِحَدِيثٍ فَقُمْتُ إِلَيْهِ فَاسْتَعَدْتُهُ فَقَالَ لِي مَا كُلَّ سَاعَةٍ أَحْلُبُ فَأُشْرَبُ","id":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad Ibnu Zaid], dari [Ayyub] ia berkata: \"Pada suatu hari [Sa'id bin Jubair] membicarakan satu hadits, kemudian aku berdiri menemuinya dan memintanya mengulangi kembali', kemudian ia berkata: 'Tidaklah setiap saat aku memerah susu lalu diminumkan\"."},"274":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ حُمَيْدٍ حَدَّثَنَا هَارُونُ هُوَ ابْنُ الْمُغِيرَةِ وَيَحْيَى بْنُ ضُرَيْسٍ عَنْ عَمْرِو بْنِ أَبِي قَيْسٍ عَنْ عَطَاءٍ أَنَّ أَبَا عَبْدِ الرَّحْمَنِ كَرِهَ الْحَدِيثَ فِي الطَّرِيقِ","id":"Telah mengabarkan kepada kami [Muhammad bin Humaid] telah menceritakan kepada kami [Harun Ibnu Al Mughirah] dan [Yahya bin Dlurais] dari ['Amr bin Abu Qais] dari ['Atha`]: \" [Abu Abdur Rahman] membenci menceritakan sebuah hadits di jalanan\"."},"275":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ عِمْرَانَ حَدَّثَنَا يَحْيَى بْنُ ضُرَيْسٍ حَدَّثَنَا أَبُو سِنَانٍ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ قَالَ كُنَّا عِنْدَ سَعِيدِ بْنِ جُبَيْرٍ فَحَدَّثَ بِحَدِيثٍ فَقَالَ لَهُ رَجُلٌ مَنْ حَدَّثَكَ هَذَا أَوْ مِمَّنْ سَمِعْتَ هَذَا فَغَضِبَ وَمَنَعَنَا حَدِيثَهُ حَتَّى قَامَ","id":"Telah mengabarkan kepada kami [Abdullah bin Imran] telah menceritakan kepada kami [Yahya bin Dlurais] telah menceritakan kepada kami [Abu Sinan] dari [Habib bin Abu Tsabit] ia berkata: \"Kami berada di samping [Sa'id bin Jubair], lalu dia membicarakan sebuah hadits. Seorang laki-laki berkata kepadanya: 'Siapa yang menceritakan kepadamu tentang (hadits) ini, atau dari siapa kamu mendengar (hadits) ini? ', kemudian ia marah dan tidak melanjutkan pembicaraan haditsnya hingga beranjak pergi\"."},"276":{"ar":" أَخْبَرَنَا أَبُو مَعْمَرٍ إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ سُفْيَانَ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ قَالَ لَوْ رَفَقْتُ بِابْنِ عَبَّاسٍ لَأَصَبْتُ مِنْهُ عِلْمًا كَثِيرًا","id":"Telah mengabarkan kepada kami [Abu Ma'mar Isma'il bin Ibrahim], dari [Sufyan] dari [Az Zuhri] dari [Abu Salamah] ia berkata: \"Kalau saja dahulu aku berteman dengan Ibnu Abbas niscaya aku mendapatkan ilmu yang banyak\"."},"277":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ أَخْبَرَنَا بَقِيَّةُ عَنْ أُمِّ عَبْدِ اللَّهِ بِنْتِ خَالِدٍ قَالَتْ مَا رَأَيْتُ أَحَدًا أَكْرَمَ لِلْعِلْمِ مِنْ أَبِي","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah mengabarkan kepada kami [Baqiyyah] dari [Ummu Abdullah binti Khalid] ia berkata: \"Aku tidak pernah melihat seorang pun yang lebih memuliakan ilmu dari [ayahku] \"."},"278":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْمَدَ حَدَّثَنَا سُفْيَانُ عَنْ مِسْعَرٍ قَالَ قَالَ سَعْدُ بْنُ إِبْرَاهِيمَ لَا يُحَدِّثْ عَنْ رَسُولِ اللَّهِ إِلَّا الثِّقَاتُ","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad] telah menceritakan kepada kami [Sufyan] dari [Mas'ar] ia berkata: \" [Sa'ad bin Ibrahim] pernah berkata: \"Tidak boleh siapapun menceritakan satu hadits dari Rasulullah sallallahu 'alaihi wa sallam kecuali jika dipercaya\"."},"279":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ حُمَيْدٍ حَدَّثَنَا جَرِيرٌ عَنْ عَاصِمٍ عَنْ ابْنِ سِيرِينَ قَالَ كَانُوا لَا يَسْأَلُونَ عَنْ الْإِسْنَادِ ثُمَّ سَأَلُوا بَعْدُ لِيَعْرِفُوا مَنْ كَانَ صَاحِبَ سُنَّةٍ أَخَذُوا عَنْهُ وَمَنْ لَمْ يَكُنْ صَاحِبَ سُنَّةٍ لَمْ يَأْخُذُوا عَنْهُ قَالَ أَبُو مُحَمَّد مَا أَظُنُّهُ سَمِعَهُ مِنْ عَاصِمٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Humaid] telah menceritakan kepada kami [Jarir] dari ['Ashim] dari [Ibnu Sirin] ia berkata: \"Dahulu, mereka tidak bertanya tentang sanad (jalur periwayatan hadits), kemudian mereka bertanya untuk mengenal para perawi, jika ia orang yang mengikut sunnah maka mereka ambil (hadits) nya, dan jika bukan, mereka tidak mengambilnya\"."},"280":{"ar":" أَخْبَرَنَا مُحَمَّدٌ حَدَّثَنَا جَرِيرٌ عَنْ عُمَارَةَ بْنِ الْقَعْقَاعِ قَالَ قَالَ إِبْرَاهِيمُ إِذَا حَدَّثْتَنِي فَحَدِّثْنِي عَنْ أَبِي زُرْعَةَ فَإِنَّهُ حَدَّثَنِي بِحَدِيثٍ ثُمَّ سَأَلْتُهُ بَعْدَ ذَلِكَ بِسَنَةٍ فَمَا أَخْرَمَ مِنْهُ حَرْفًا","id":"Telah mengabarkan kepada kami [Muhammad] telah menceritakan kepada kami [Jarir] dari ['Umarah bin Al Qa'qa'] ia berkata: \"I [brahim] pernah berkata: 'Jika kamu hendak menceritakan (hadits) maka ceritakanlah melalui jalur Abu Zur'ah, karena ia telah menceritakan kepadaku satu hadits, kemudian aku bertanya kepadanya setahun berikutnya, dan tidak ada satu huruf pun yang berubah\"."},"281":{"ar":" أَخْبَرَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ابْنِ عَوْنٍ عَنْ مُحَمَّدٍ قَالَ إِنَّ هَذَا الْعِلْمَ دِينٌ فَلْيَنْظُرْ الرَّجُلُ عَمَّنْ يَأْخُذُ دِينَهُ","id":"Terlah mengabarkan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ibnu 'Aun] dari [Muhammad] ia berkata: \"Ilmu (sanad) ini merupakan (bagian dari) agama, maka hendaklah seseorang memperhatikan dari siapa ia mengambil agamanya\"."},"282":{"ar":" أَخْبَرَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ هُشَيْمٍ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ قَالَ كَانُوا إِذَا أَتَوْا الرَّجُلَ لِيَأْخُذُوا عَنْهُ نَظَرُوا إِلَى صَلَاتِهِ وَإِلَى سَمْتِهِ وَإِلَى هَيْئَتِهِ","id":"Telah mengabarkan kepada kami [Isma'il bin Ibrahim] dari [Husyaim] dari [Mughirah] dari [Ibrahim] ia berkata: \"Dahulu, mereka ketika mendatangi seseorang untuk mengambil (suatu hadits), mereka melihat (terlebih dahulu) tentang shalat orang tersebut dan sunnahnya serta sikap hidupnya, kemudian baru mereka mengambil (hadits) nya\"."},"283":{"ar":" أَخْبَرَنَا أَبُو مَعْمَرٍ إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ أَبِي جَعْفَرٍ الرَّازِيُّ عَنْ أَبِيهِ عَنْ الرَّبِيعِ عَنْ أَبِي الْعَالِيَةِ قَالَ كُنَّا نَأْتِي الرَّجُلَ لِنَأْخُذَ عَنْهُ فَنَنْظُرُ إِذَا صَلَّى فَإِنْ أَحْسَنَهَا جَلَسْنَا إِلَيْهِ وَقُلْنَا هُوَ لِغَيْرِهَا أَحْسَنُ وَإِنْ أَسَاءَهَا قُمْنَا عَنْهُ وَقُلْنَا هُوَ لِغَيْرِهَا أَسْوَأُ قَالَ أَبُو مَعْمَرٍ لَفْظُهُ نَحْوُ هَذَا","id":"Telah mengabarkan kepada kami [Abu Ma'mar Isma'il bin Ibrahim] telah mengabarkan kepada kami [Abdullah bin Abu Ja'far Ar Razi] dari [ayahnya] dari [Ar Rabi'] dari [Abul 'Aliyah] ia berkata: \"Dahulu kami jika menemui seseorang untuk mengambil (ilmu) nya, maka kami melihat (bagaimana) shalatnya, jika ia baik dalam menunaikannya, kami duduk dengannya, lalu kami berkata: Dia (dalam amalan selain shalat) pasti lebih baik, tetapi jika ia buruk dalam menunaikannya, maka kami segera beranjak pergi meninggalkannya, lalu kami katakan: 'Dia (dalam amalan selain shalat) pasti lebih buruk\". Abu Ma'mar berkata: \"Redaksinya seperti ini\"."},"284":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ قَالَ لَا أَدْرِي سَمِعْتُهُ مِنْهُ أَوْ لَا ابْنُ عَوْنٍ عَنْ مُحَمَّدٍ إِنَّ هَذَا الْعِلْمَ دِينٌ فَانْظُرُوا عَمَّنْ تَأْخُذُونَ دِينَكُمْ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] ia berkata: \"Aku tidak tahu mendengarnya dari dia atau bukan [Ibnu 'Aun] dari [Muhammad] ia berkata: \"Sesungguhnya ilmu ini adalah (bagian dari) agama, karena itu hendaklah kalian perhatikan dari siapa kalian mengambil agama kalian\"."},"285":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْمَدَ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامِ بْنِ حُجَيْرٍ عَنْ طَاوُسٍ قَالَ جَاءَ بُشَيْرُ بْنُ كَعْبٍ إِلَى ابْنِ عَبَّاسٍ فَجَعَلَ يُحَدِّثُهُ فَقَالَ ابْنُ عَبَّاسٍ أَعِدْ عَلَيَّ الْحَدِيثَ الْأَوَّلَ قَالَ لَهُ بُشَيْرٌ مَا أَدْرِي عَرَفْتَ حَدِيثِي كُلَّهُ وَأَنْكَرْتَ هَذَا أَوْ عَرَفْتَ هَذَا وَأَنْكَرْتَ حَدِيثِي كُلَّهُ فَقَالَ ابْنُ عَبَّاسٍ إِنَّا كُنَّا نُحَدِّثُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ لَمْ يَكُنْ يُكْذَبُ عَلَيْهِ فَلَمَّا رَكِبَ النَّاسُ الصَّعْبَ وَالذَّلُولَ تَرَكْنَا الْحَدِيثَ عَنْهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad] telah menceritakan kepada kami [Sufyan] dari [Hisyam bin Hujair] dari [Thawus] ia berkata: \"Basyir bin Ka'ab pernah datang menemui Ibnu Abbas, lalu ia menceritakan hadits kepadanya, lalu [Ibnu Abbas] berkata: 'Tolong ulangi hadits yang pertama', Basyir berkata kepadanya: 'Aku tidak tahu apakah kamu mengakui semua hadisku, atau kamu menolak hadits yang ini dan mengakui yang ini, atau menolak seluruh haditsku?. Lalu Ibnu Abbas berkata: 'Kami menceritakan hadits dari Rasulullah sallallahu 'alaihi wa sallam ketika tidak ada kebohongan atas nama Nabi sallallahu 'alaihi wa sallam. Namun ketika manusia menemui kesulitan (membedakan kejujuran perawi) dan menceritakan hadis diperlonggar, kami menahan diri untuk tidak meriwayatkan hadits dari beliau' \". "},"286":{"ar":" أَخْبَرَنَا إِسْمَعِيلُ بْنُ أَبَانَ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ مَعْمَرٍ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَ كُنَّا نَحْفَظُ الْحَدِيثَ وَالْحَدِيثُ يُحْفَظُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى رَكِبْتُمْ الصَّعْبَ وَالذَّلُولَ","id":"Telah mengabarkan kepada kami [Isma'il bin `Aban] ia berkata: \"telah menceritakan kepada kami [Abdullah bin Al Mubarak] dari [Ma'mar] dari [Ibnu Thawus] dari [ayahnya] dari [Ibnu Abbas] ia berkata: 'Dahulu kami menjaga hadits dan hadits senantiasa terjaga dari Rasulullah sallallahu 'alaihi wa sallam hingga kalian menemui kesulitan (membedakan kejujuran perawi) dan menceritakan hadis diperlonggar\". "},"287":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ لَيْثٍ عَنْ طَاوُسٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ يُوشِكُ أَنْ يَظْهَرَ شَيَاطِينُ قَدْ أَوْثَقَهَا سُلَيْمَانُ يُفَقِّهُونَ النَّاسَ فِي الدِّينِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Laits] dari [Thawus] dari [Abdullah bin 'Amr] ia berkata: \"Hampir saja setan-setan (yang pernah tunduk kepada Nabi Sulaiman 'alaihissalam menampakkan diri dan mengajarkan manusia tentang agama\"."},"288":{"ar":" أَخْبَرَنَا مُوسَى بْنُ خَالِدٍ حَدَّثَنَا مُعْتَمِرٌ عَنْ أَبِيهِ قَالَ لِيُتَّقَى مِنْ تَفْسِيرِ حَدِيثِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا يُتَّقَى مِنْ تَفْسِيرِ الْقُرْآنِ","id":"Telah mengabarkan kepada kami [Musa bin Khalid] telah menceritakan kepada kami [Mu'tamir] dari [ayahnya] ia berkata: \"Hendaknya seseorang bersikap hati-hati dalam menafsirkan hadits Rasulullah sallallahu 'alaihi wa sallam sebagaimana ia bersikap hati-hati dalam menafsirkan Al Qur`an\"."},"289":{"ar":" أَخْبَرَنَا صَدَقَةُ بْنُ الْفَضْلِ حَدَّثَنَا مُعْتَمِرٌ عَنْ أَبِيهِ قَالَ قَالَ ابْنُ عَبَّاسٍ أَمَا تَخَافُونَ أَنْ تُعَذَّبُوا أَوْ يُخْسَفَ بِكُمْ أَنْ تَقُولُوا قَالَ رَسُولُ اللَّهِ وَقَالَ فُلَانٌ","id":"Telah mengabarkan kepada kami [Shadaqah bin Al Fadl] telah menceritakan kepada kami [Mu'tamir] dari [ayahnya] ia berkata: \" [Ibnu Abbas] pernah berkata: 'Tidakkah kalian takut akan diadzab atau ditenggelamkan jika kalian mengatakan: Rasulullah sallallahu 'alaihi wa sallam bersabda dan si fulan berkata \". "},"290":{"ar":" أَخْبَرَنَا الْحَسَنُ بْنُ بِشْرٍ حَدَّثَنَا الْمُعَافَى عَنْ الْأَوْزَاعِيِّ قَالَ كَتَبَ عُمَرُ بْنُ عَبْدِ الْعَزِيزِ إِنَّهُ لَا رَأْيَ لِأَحَدٍ فِي كِتَابِ اللَّهِ وَإِنَّمَا رَأْيُ الْأَئِمَّةِ فِيمَا لَمْ يَنْزِلْ فِيهِ كِتَابٌ وَلَمْ تَمْضِ بِهِ سُنَّةٌ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا رَأْيَ لِأَحَدٍ فِي سُنَّةٍ سَنَّهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Al Hasan bin bisyr] telah menceritakan kepada kami [Al Mu'afi] dari [Al 'Auza'i] ia berkata: \" [Umar bin Abdul Aziz] pernah menulis surat (yang isinya): 'Tidak boleh ada pendapat seseorang mengenai hal-hal yang telah diputuskan dalam kitabullah. Hanyasanya pendapat para Imam dalam hal-hal yang belum ada penjelasannya dalam Al quran, atau sunnah Rasulullah Shallallahu Alahi wa Sallam belum menjelaskannya, dan tidak ada pula pendapat seseorang dalam sunnah yang telah di sunnahkan oleh Rasullah Shallallahu Alaihi Wa Sallam\". "},"291":{"ar":" حَدَّثَنَا مُوسَى بْنُ خَالِدٍ حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ أَنَّ عُمَرَ بْنَ عَبْدِ الْعَزِيزِ خَطَبَ فَقَالَ يَا أَيُّهَا النَّاسُ إِنَّ اللَّهَ لَمْ يَبْعَثْ بَعْدَ نَبِيِّكُمْ نَبِيًّا وَلَمْ يُنْزِلْ بَعْدَ هَذَا الْكِتَابِ الَّذِي أَنْزَلَ عَلَيْهِ كِتَابًا فَمَا أَحَلَّ اللَّهُ عَلَى لِسَانِ نَبِيِّهِ فَهُوَ حَلَالٌ إِلَى يَوْمِ الْقِيَامَةِ وَمَا حَرَّمَ عَلَى لِسَانِ نَبِيِّهِ فَهُوَ حَرَامٌ إِلَى يَوْمِ الْقِيَامَةِ أَلَا وَإِنِّي لَسْتُ بِقَاصٍّ وَلَكِنِّي مُنَفِّذٌ وَلَسْتُ بِمُبْتَدِعٍ وَلَكِنِّي مُتَّبِعٌ وَلَسْتُ بِخَيْرٍ مِنْكُمْ غَيْرَ أَنِّي أَثْقَلُكُمْ حِمْلًا أَلَا وَإِنَّهُ لَيْسَ لِأَحَدٍ مِنْ خَلْقِ اللَّهِ أَنْ يُطَاعَ فِي مَعْصِيَةِ اللَّهِ أَلَا هَلْ أَسْمَعْتُ","id":"Telah menceraitakan kepada kami [Musa bin Khalid] telah menceritakan kepada kami [Mu'tamir bin Sulaiman] dari [Ubaidullah bin Umar], bahwasanya [Umar bin Abdul Aziz] berhutbah, ia berkata: \"Wahai sekalian manusia, Allah subhanallahu wa ta'ala tidak mengutus seorang nabi pun setelah Nabi kalian, dan Allah subhanallahu wa ta'ala tidak menurunkan sebuah kitab pun setelah kitab yang diturunkan kepadanya ini. Apa-apa yang telah Allah subhanallahu wa ta'ala halalkan melalui lisan NabiNya, hal itu halal sampai hari kiamat, dan apa-apa yang diharamkan melalui lisan NabiNya, hal itu haram sampai hari kiamat. Ketahuilah bahwasannya aku tidak dapat memutuskan, tetapi aku hanya bisa melaksanakan, aku tidak membuat amalan baru/bid`ah, tetapi aku hanyalah muttabi` (seorang pengikut sunah), aku tidaklah orang yang terbaik dari kalian semua, akan tetapi aku adalah orang yang paling berat bebannya dari kamu semua, dan seseorang dari makhluk Allah subhanallahu wa ta'ala tidak berhak ditaati dalam hal maksiat kepada Allah subhanallahu wa ta'ala, ketahuilah apakah aku telah memperdengarkan (kepada kalian)?\""},"292":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ هِشَامِ بْنِ حُجَيْرٍ قَالَ كَانَ طَاوُسٌ يُصَلِّي رَكْعَتَيْنِ بَعْدَ الْعَصْرِ فَقَالَ لَهُ ابْنُ عَبَّاسٍ اتْرُكْهُمَا قَالَ إِنَّمَا نُهِيَ عَنْهَا أَنْ تُتَّخَذُ سُلَّمًا قَالَ ابْنُ عَبَّاسٍ فَإِنَّهُ قَدْ نُهِيَ عَنْ صَلَاةٍ بَعْدَ الْعَصْرِ فَلَا أَدْرِي أَتُعَذَّبُ عَلَيْهَا أَمْ تُؤْجَرُ لِأَنَّ اللَّهَ يَقُولُ { وَمَا كَانَ لِمُؤْمِنٍ وَلَا مُؤْمِنَةٍ إِذَا قَضَى اللَّهُ وَرَسُولُهُ أَمْرًا أَنْ يَكُونَ لَهُمْ الْخِيَرَةُ مِنْ أَمْرِهِمْ } قَالَ سُفْيَانُ تُتَّخَذَ سُلَّمًا يَقُولُ يُصَلِّي بَعْدَ الْعَصْرِ إِلَى اللَّيْلِ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'id] telah mencertitakan kepada kami [Sufyan bin 'Uyainah] dari [Hisyam bin Hujair] ia berkata: \"Thawus pernah shalat dua rakaat setelah (selesai) shalat Ashr, lalu [Ibnu Abbas] berkata kepadanya: 'Tinggalkanlah dua rakaat tersebut', ia (Thawus) berkata: 'Yang dilarang adalah jika menjadikannya sebagai sullaman, Ibnu Abbas berkata: 'Sesungguhnya telah dilarang shalat setelah Ashr, aku tidak tahu apakah (dengannya) kamu disiksa atasnya atau diberi pahala, karena Allah subhanallahu wa ta'ala telah berfirman: \"WA MAA KAANA LI MU`MININ WA LAA MU`MINATIN IDZAA QADLALLAHU WA RASUULUHU AMRAN AN YAKUNA LAHUMUL KHIYARATU MIN AMRIHIM\" (Dan tidaklah patut bagi laki-laki yang mu`min dan tidak pula bagi perempuan yang mu`min, Apabila Allah subhanallahu wa ta'ala dan RasulNya telah menetapkan suatu ketetapan, akan ada bagi mereka pilihan yang lain tentang urusan mereka) -Qs. Al Ahzab: 36-. Sufyan berkata: 'Yang dimaksud dengan kata sullaman adalah melaksanakan shalat setelah ashr sampai malam' \". "},"293":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا ابْنُ نُمَيْرٍ عَنْ مُجَالِدٍ عَنْ عَامِرٍ عَنْ جَابِرٍ أَنَّ عُمَرَ بْنَ الْخَطَّابِ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنُسْخَةٍ مِنْ التَّوْرَاةِ فَقَالَ يَا رَسُولَ اللَّهِ هَذِهِ نُسْخَةٌ مِنْ التَّوْرَاةِ فَسَكَتَ فَجَعَلَ يَقْرَأُ وَوَجْهُ رَسُولِ اللَّهِ يَتَغَيَّرُ فَقَالَ أَبُو بَكْرٍ ثَكِلَتْكَ الثَّوَاكِلُ مَا تَرَى مَا بِوَجْهِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَظَرَ عُمَرُ إِلَى وَجْهِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَعُوذُ بِاللَّهِ مِنْ غَضَبِ اللَّهِ وَغَضَبِ رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَضِينَا بِاللَّهِ رَبًّا وَبِالْإِسْلَامِ دِينًا وَبِمُحَمَّدٍ نَبِيًّا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَوْ بَدَا لَكُمْ مُوسَى فَاتَّبَعْتُمُوهُ وَتَرَكْتُمُونِي لَضَلَلْتُمْ عَنْ سَوَاءِ السَّبِيلِ وَلَوْ كَانَ حَيًّا وَأَدْرَكَ نُبُوَّتِي لَاتَّبَعَنِي","id":"Tealah mengabarkan kepada kami [Muhammad bin Al 'Ala`] telah menceritakan kepada kami [Ibnu Numair] dari [Mujalid] dari ['Amir] dari [Jabir], bahwasanya Umar bin Al Khatthab pernah datang menemui Rasulullah sallallahu 'alaihi wa sallam dengan membawa satu salinan dari kitab Taurat, lalu ia berkata: 'Wahai Rasulullah sallallahu 'alaihi wa sallam?! Nabi tidak menyambutnya selain diam, Umar membacakan (Taurat) dan Rasulullah sallallahu 'alaihi wa sallam nampak berubah raut mukanya, lalu Abu Bakar berkata: 'TSAKILATKATTshallallahu 'alaihi wasallamAAKUL, apakah kamu tidak melihat perubahan wajah Rasulullah sallallahu 'alaihi wa sallam? Ketika Umar melihat perubahan wajah Rasulullah sallallahu 'alaihi wa sallam, ia berkata: 'Aku berlindung kepada Allah subhanallahu wa ta'ala dari kemarahan Allah subhanallahu wa ta'ala dan kemarahan RasulNya, kami rela Allah subhanallahu wa ta'ala sebagai Tuhan dan agama Islam sebagai agama, dan Muhammad sebagai Nabi'. Maka Rasulullah sallallahu 'alaihi wa sallam bersabda: 'Demi Dzat yang jiwa Muhammad dalam genggamanNya jika Musa ada diantara kalian semua lalu kalian mengikutinya dan meninggalkan aku, niscaya kalian akan tersesat dari jalan yang lurus, dan kalau sekiranya ia (Nabi Musa 'alaihissalam) masih hidup, dan ia dapati kenabianku, niscaya ia akan mengikutiku' \". "},"294":{"ar":" حَدَّثَنَا قَبِيصَةُ أَخْبَرَنَا سُفْيَانُ عَنْ أَبِي رَبَاحٍ شَيْخٌ مِنْ آلِ عُمَرَ قَالَ رَأَى سَعِيدُ بْنُ الْمُسَيَّبِ رَجُلًا يُصَلِّي بَعْدَ الْعَصْرِ الرَّكْعَتَيْنِ يُكْثِرُ فَقَالَ لَهُ فَقَالَ يَا أَبَا مُحَمَّدٍ أَيُعَذِّبُنِي اللَّهُ عَلَى الصَّلَاةِ قَالَ لَا وَلَكِنْ يُعَذِّبُكَ اللَّهُ بِخِلَافِ السُّنَّةِ","id":"Telah menceritakan kepada kami [Qabishah] telah mengabarkan kepada kami [Sufyan] dari [Abu Rabah] -seorang tua dari keluarga umar-, ia berkata: \" [Sa'id bin Al Musayyab] pernah melihat seorang yang shalat dua rakaat setelah shalat Ashr, lalu ia bertanya kepadanya: 'Wahai Abu Muhammad, apakah Allah subhanallahu wa ta'ala akan mengadzabku atas shalat ini? ', ia (Sa'id bin Al Musayyab) menjawab: 'Tidak, akan tetapi Allah subhanallahu wa ta'ala akan mengadzabmu lantaran kamu menyelisihi sunah' \"."},"295":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي ابْنُ عَجْلَانَ عَنْ الْعَجْلَانِ عَنْ أَبِي هُرَيْرَةَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَمَا رَجُلٌ يَتَبَخْتَرُ فِي بُرْدَيْنِ خَسَفَ اللَّهُ بِهِ الْأَرْضَ فَهُوَ يَتَجَلْجَلُ فِيهَا إِلَى يَوْمِ الْقِيَامَةِ فَقَالَ لَهُ فَتًى قَدْ سَمَّاهُ وَهُوَ فِي حُلَّةٍ لَهُ يَا أَبَا هُرَيْرَةَ أَهَكَذَا كَانَ يَمْشِي ذَلِكَ الْفَتَى الَّذِي خُسِفَ بِهِ ثُمَّ ضَرَبَ بِيَدِهِ فَعَثَرَ عَثْرَةً كَادَ يَتَكَسَّرُ مِنْهَا فَقَالَ أَبُو هُرَيْرَةَ لِلْمَنْخَرَيْنِ وَلِلْفَمِ { إِنَّا كَفَيْنَاكَ الْمُسْتَهْزِئِينَ }","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] ia berkata: \"Telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku [Ibnu 'Ajlan] dari [Al 'Ajlan] dari [Abu Hurairah] dari Rasulullah sallallahu 'alaihi wa sallam pernah bersabda: 'Pernah ada seorang laki-laki berjalan dengan penuh kecongkaan dengan pakaian kebanggaan yang dikenakannya. Allah subhanallahu wa ta'ala menenggelamkannya ke dalam bumi, lalu ia pun meronta-ronta dalam bumi hingga hari kiamat'. Setelah itu ada seorang laki-laki -yang ia sebutkan namanya-dengan pakaian kebanggaannya berujar: 'Wahai Abu Hurairah, beginikah cara berjalannya seorang pemuda yang ditenggelamkan ke dalam bumi itu?, kemudian ia menggelepar dengan memukul-mukulkan tangannya, terpeleset, terbanting hingga hampir retak kakinya. Lalu Abu Hurairah berkata untuk hidung dan mulutnya: 'Sesungguhnya Kami memelihara kamu dari (kejahatan) orang-orang yang memperolok-olokkkan (kamu) ' \""},"296":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ حُمَيْدٍ حَدَّثَنَا هَارُونُ هُوَ ابْنُ الْمُغِيرَةِ عَنْ عَمْرِو بْنِ أَبِي قَيْسٍ عَنْ الزُّبَيْرِ بْنِ عَدِيٍّ عَنْ خِرَاشِ بْنِ جُبَيْرٍ قَالَ رَأَيْتُ فِي الْمَسْجِدِ فَتًى يَخْذِفُ فَقَالَ لَهُ شَيْخٌ لَا تَخْذِفْ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْخَذْفِ فَغَفَلَ الْفَتَى وَظَنَّ أَنَّ الشَّيْخَ لَا يَفْطِنُ لَهُ فَخَذَفَ فَقَالَ لَهُ الشَّيْخُ أُحَدِّثُكَ أَنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْ الْخَذْفِ ثُمَّ تَخْذِفُ وَاللَّهِ لَا أَشْهَدُ لَكَ جَنَازَةً وَلَا أَعُودُكَ فِي مَرَضٍ وَلَا أُكَلِّمُكَ أَبَدًا فَقُلْتُ لِصَاحِبٍ لِي يُقَالُ لَهُ مُهَاجِرٌ انْطَلِقْ إِلَى خِرَاشٍ فَاسْأَلْهُ فَأَتَاهُ فَسَأَلَهُ عَنْهُ فَحَدَّثَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Humaid] telah menceritakan kepada kami [Harun Ibnu Al Mughirah], dari ['Amr bin Abu Qais] dari [Az Zubair bin 'Adi] dari [Khirasy bin Jubair] ia berkata: \"(Suatu hari) aku pernah melihat seoprang pemuda sedang melempar (dengan alat pelontar) di dalam masjid, kemudian [seorang syaikh] berkata: 'Janganlah kamu melempar karena aku pernah mendengar Rasulullah sallallahu 'alaihi wa sallam melarang hal demikian', mendengar pernyataan itu si pemuda nampak tidak acuh dan melempar kembali, kemudian syaikh tersebut berkata lagi kepadanya: 'Aku ceritakan kepadamu aku pernah mendengar rasulullah sallallahu 'alaihi wa sallam melarang untuk melempar, tetapi kamu tetap melempar?, demi Allah subhanallahu wa ta'ala aku tidak akan mengantarkan jenazahmu, dan tidak akan menjenguk ketika kamu sakit, serta aku tidak akan bercakap-cakap denganmu' \". Lalu aku berkata kepada sahabatku yang bernama Muhajir: \"Pergilah ke Khirasy dan tanyakanlah kepadanya, kemudian ia mendatanginya, dan menanyakannya, lalu ia (perawi tersebut) menceritakan kisah itu\". "},"297":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْخَذْفِ وَقَالَ إِنَّهَا لَا تَصْطَادُ صَيْدًا وَلَا تَنْكِي عَدُوًّا وَلَكِنَّهَا تَكْسِرُ السِّنَّ وَتَفْقَأُ الْعَيْنَ فَرَفَعَ رَجُلٌ بَيْنَهُ وَبَيْنَ سَعِيدٍ قَرَابَةٌ شَيْئًا مِنْ الْأَرْضِ فَقَالَ هَذِهِ وَمَا تَكُونُ هَذِهِ فَقَالَ سَعِيدٌ أَلَا أُرَانِي أُحَدِّثُكَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ تَهَاوَنُ بِهِ لَا أُكَلِّمُكَ أَبَدًا","id":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Sa'id bin Jubair] dari [Abdullah bin Mughaffal] ia berkata: \"Rasulullah sallallahu 'alaihi wa sallam melarang permainan melempar dengan batu kecil (Khadzf), beliau bersabda: 'Cara yang demikian tidak dapat digunakan untuk berburu dan menyerang musuh, cara yang demikian hanya dapat merusak gigi dan mencederai mata'. Kemudian ada seorang pemuda (Yang masih ada hubungan kerabat dengan Sa'id) mengangkat segenggam tanah lalu ia berkata: 'Benda ini, dan untuk apa benda ini? ', melihat sikap pemuda yang demikian Sa'id berkata: 'Tidakah kamu melihat aku sedang menceritakan kepadamu hadits dari Rasulullah sallallahu 'alaihi wa sallam, namun kamu malah melecehkannya. Sungguh aku tidak akan berbicara lagi denganmu' \"."},"298":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا كَهْمَسُ بْنُ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ قَالَ رَأَى عَبْدُ اللَّهِ بْنُ مُغَفَّلٍ رَجُلًا مِنْ أَصْحَابِهِ يَخْذِفُ فَقَالَ لَا تَخْذِفْ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَنْهَى عَنْ الْخَذْفِ وَكَانَ يَكْرَهُهُ وَإِنَّهُ لَا يُنْكَأُ بِهِ عَدُوٌّ وَلَا يُصَادُ بِهِ صَيْدٌ وَلَكِنَّهُ قَدْ يَفْقَأُ الْعَيْنَ وَيَكْسِرُ السِّنَّ ثُمَّ رَآهُ بَعْدَ ذَلِكَ يَخْذِفُ فَقَالَ لَهُ أَلَمْ أُخْبِرْكَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَنْهَى عَنْهُ ثُمَّ أَرَاكَ تَخْذِفُ وَاللَّهِ لَا أُكَلِّمُكَ أَبَدًا","id":"Telah mengabarkan kepada kami [Abdullah bin Yazid] telah menceritakan kepada kami [Kahmas bin Al Hasan] dari [Abdullah bin Buraidah] ia berkata: \" [Abdullah bin Mughaffal] pernah melihat seorang sahabatnya melempar (dengan batu kecil), maka ia berkata: 'Rasulullah sallallahu 'alaihi wa sallam telah melarang melempar (dengan batu kecil) dan juga membencinya, dan ia tidak bisa digunakan untuk mengusir musuh dan tidak bisa digunakan untuk berburu. Ia hanya berakibat menciderai mata dan mematahkan gigi. Kemudian ia melihatnya tetap melempar lagi, maka ia berkata lagi kepadanya: 'Bukankah aku telah kabarkan kepadamu Rasulullah sallallahu 'alaihi wa sallam melarangnya, tetapi aku masih melihatmu melempar?, Demi Allah subhanallahu wa ta'ala aku tidak akan berbicara denganmu' \". "},"299":{"ar":" أَخْبَرَنَا مَرْوَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا سَعِيدُ بْنُ بَشِيرٍ عَنْ قَتَادَةَ قَالَ حَدَّثَ ابْنُ سِيرِينَ رَجُلًا بِحَدِيثٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَجُلٌ قَالَ فُلَانٌ كَذَا وَكَذَا فَقَالَ ابْنُ سِيرِينَ أُحَدِّثُكَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَتَقُولُ قَالَ فُلَانٌ لَا أُكَلِّمُكَ أَبَدًا","id":"Telah mengabarkan kepada kami [Marwan bin Muhammad] telah menceritakan kepada kami [Sa'id bin Basyir] dari [Qatadah] ia berkata: \" [Ibnu Sirin] pernah menceritakan sebuah hadits dari Nabi sallallahu 'alaihi wa sallam kepada seseorang, lalu orang tersebut berkata: 'Si fulan pernah berkata begini dan begini', maka Ibnu Sirin berkata: 'Aku menceritakan hadits dari Nabi sallallahu 'alaihi wa sallam kepadamu, sedangkan kamu mengatakan telah berkata si fulan?, aku tidak akan berbicara dengan mu' "},"300":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا اسْتَأْذَنَتْ أَحَدَكُمْ امْرَأَتُهُ إِلَى الْمَسْجِدِ فَلَا يَمْنَعْهَا فَقَالَ فُلَانُ بْنُ عَبْدِ اللَّهِ إِذًا وَاللَّهِ أَمْنَعُهَا فَأَقْبَلَ عَلَيْهِ ابْنُ عُمَرَ فَشَتَمَهُ شَتِيمَةً لَمْ أَرَهُ يَشْتِمُهَا أَحَدًا قَبْلَهُ قَطُّ ثُمَّ قَالَ أُحَدِّثُكَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَتَقُولُ إِذًا وَاللَّهِ أَمْنَعُهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Katsir] dari [Al 'Auza'i] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar]: \"Rasulullah sallallahu 'alaihi wa sallam bersabda: 'Apabila seorang perempuan meminta izin ke masjid, janganlah kamu melarangnya '. Lalu ada seseorang berkata: 'Meski demikian, Demi Allah subhanallahu wa ta'ala, aku tetap akan melarangnya, maka Ibnu Umar mendekatinya dan mencela sikapnya dengan celaan yang tidak pernah aku lihat sebelumnya, kemudian ia berkata: 'Kamu ini bagaimana, aku menceritakan hadits dari Rasulullah sallallahu 'alaihi wa sallam, sebaliknya kamu malah mengatakan meski demikian aku tetap akan melarangnya? ' \". "},"301":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ حُمَيْدٍ حَدَّثَنَا هَارُونُ بْنُ الْمُغِيرَةِ عَنْ مَعْرُوفٍ عَنْ أَبِي الْمُخَارِقِ قَالَ ذَكَرَ عُبَادَةُ بْنُ الصَّامِتِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ دِرْهَمَيْنِ بِدِرْهَمٍ فَقَالَ فُلَانٌ مَا أَرَى بِهَذَا بَأْسًا يَدًا بِيَدٍ فَقَالَ عُبَادَةُ أَقُولُ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَتَقُولُ لَا أَرَى بِهِ بَأْسًا وَاللَّهِ لَا يُظِلُّنِي وَإِيَّاكَ سَقْفٌ أَبَدًا","id":"Telah mengabarkan kepada kami [Muhammad bin Humaid] telah menceritakan kepada kami [Harun bin Al Mughirah] dari [Ma'ruf] dari [Abu Al Mukhariq] ia berkata: \"[Ubadah bin As Shamit] pernah menyebutkan, Nabi sallallahu 'alaihi wa sallam melarang menukar dua dirham dengan satu dirham, lalu ada seseorang berkata: 'Aku anggap hal itu tidak masalah, selama dilakukan secara kontan': Maka 'Ubadah berkata: 'Aku mengatakan Nabi sallallahu 'alaihi wa sallam bersabda (demikian) sedangkan kamu katakan aku anggap tidak ada masalah?, Demi Allah subhanallahu wa ta'ala aku tidak akan bernaung di bawah satu atap bersamamu' \"."},"302":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يَزِيدَ الرِّفَاعِيُّ حَدَّثَنَا أَبُو عَامِرٍ الْعَقَدِيُّ عَنْ زَمْعَةَ عَنْ سَلَمَةَ بْنِ وَهْرَامٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَطْرُقُوا النِّسَاءَ لَيْلًا قَالَ وَأَقْبَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَافِلًا فَانْسَاقَ رَجُلَانِ إِلَى أَهْلَيْهِمَا فَكِلَاهُمَا وَجَدَ مَعَ امْرَأَتِهِ رَجُلًا","id":"Telah mengabarkan kepada kami [Muhammad bin Yazid Ar Rifa'i] telah menceritakan kepada kami [Abu 'Amir Al 'Aqadi] dari [Zam'ah] dari [Salamah bin Wahram] dari ['Ikrimah] dari [Ibnu Abbas] dari Nabi sallallahu 'alaihi wa sallam beliau bersabda: \"Janganlah kalian pulang ke rumah menemui isteri secara mengejutkan pada malam hari'. Ia (Ibnu Abbas) berkata: 'suatu saat, Rasulullah sallallahu 'alaihi wa sallam melihat satu kafilah datang dan dua orang laki-laki dari rombongan itu nekad mendatangi rumahnya pada malam hari, dan keduanya dapatkan isterinya sedang bersama laki-laki lain\"."},"303":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ حَرْمَلَةَ الْأَسْلَمِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَدِمَ مِنْ سَفَرٍ نَزَلَ الْمُعَرَّسَ ثُمَّ قَالَ لَا تَطْرُقُوا النِّسَاءَ لَيْلًا فَخَرَجَ رَجُلَانِ مِمَّنْ سَمِعَ مَقَالَتَهُ فَطَرَقَا أَهْلَيْهِمَا فَوَجَدَ كُلُّ وَاحِدٍ مِنْهُمَا مَعَ امْرَأَتِهِ رَجُلًا","id":"Telah mengabarkan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Al 'Auza'i] telah menceritakan kepada kami [Abdur Rahman bin Harmalah Al `Aslami] dari [Sa'id bin Al Musayyab] ia berkata: \"Rasulullah sallallahu 'alaihi wa sallam jika beliau datang dari safar (bepergian jauh) beliau turun di tempat peristirahatan, kemudian beliau bersabda: 'Janganlah kalian semua mendatangi isteri-isteri kalian pada waktu malam hari'. Kemudian ada dua orang laki-laki yang mendengar sabda beliau melakukan tindakan nekad dengan menemui keluarganya, dan masing-masing mendapati isterinya sedang bersama laki-laki lain ' \""},"304":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ حَرْمَلَةَ قَالَ جَاءَ رَجُلٌ إِلَى سَعِيدِ بْنِ الْمُسَيَّبِ يُوَدِّعُهُ بِحَجٍّ أَوْ عُمْرَةٍ فَقَالَ لَهُ لَا تَبْرَحْ حَتَّى تُصَلِّيَ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَخْرُجُ بَعْدَ النِّدَاءِ مِنْ الْمَسْجِدِ إِلَّا مُنَافِقٌ إِلَّا رَجُلٌ أَخْرَجَتْهُ حَاجَتُهُ وَهُوَ يُرِيدُ الرَّجْعَةَ إِلَى الْمَسْجِدِ فَقَالَ إِنَّ أَصْحَابِي بِالْحَرَّةِ قَالَ فَخَرَجَ قَالَ فَلَمْ يَزَلْ سَعِيدٌ يَوْلَعُ بِذِكْرِهِ حَتَّى أُخْبِرَ أَنَّهُ وَقَعَ مِنْ رَاحِلَتِهِ فَانْكَسَرَتْ فَخِذُهُ","id":"Telah mengabarkan kepada kami [Abu Al Mughirah] telah menceritajkan kepada kami [Al 'Auza'i] telah menceritakan kepada kami [Abdur Rahman bin Harmalah] ia berkata: 'Ada seorang laki-laki datang menemui [Sa'id bin Al Musayyib] hendak berpamitan untuk menunaikan haji atau umrah, lalu ia (Sa'id bin Al Musayyib) berkata kepadanya: 'Janganlah kamu pergi melakukan perjalanan hingga kamu shalat (terlebih dahulu), karena Rasulullah sallallahu 'alaihi wa sallam pernah bersabda: 'Tidaklah seseorang keluar meninggalkan masjid setelah dikumandangkannya adzan kecuali ia seorang munafik, kecuali jika ia mempunyai keperluan yang sangat mendesak dan berniat kembali lagi ke masjid', kemudian laki-laki tersebut berkata: 'Maaf, para sahabatku telah ada di Harrah (maka aku harus menyusul), laki-laki itu pun tetap ngotot keluar masjid', Abdur Rahman bin Harmalah berkata: 'Laki-laki tersebut tetap saja nekad keluar' dan Sa'id terus saja mengingatkannya hingga datang kabar laki-laki tersebut terjatuh dalam perjalanannya dan tulang pahanya patah' \". "},"305":{"ar":" أَخْبَرَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَ لَا تُمِلُّوا النَّاسَ","id":"Telah mengabarkan kepada kami ['Abdus Shamad bin 'Abdul Warits] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishak] dari [Abu Al `Ahwash] dari [Abdullah] ia berkata: \"Janganlah kalian semua putus harapan\"."},"306":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا أَشْعَثُ عَنْ كُرْدُوسٍ عَنْ عَبْدِ اللَّهِ قَالَ إِنَّ لِلْقُلُوبِ نَشَاطًا وَإِقْبَالًا وَإِنَّ لَهَا تَوْلِيَةً وَإِدْبَارًا فَحَدِّثُوا النَّاسَ مَا أَقْبَلُوا عَلَيْكُمْ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Asy'ats] dari [Kurdus] dari [Abdullah] ia berkata: \"Hati memiliki waktu saat semangat dan menerima, sebaliknya kadang ia berpaling dan menolak, maka hendaklah kalian mengajak berbicara dengan manusia sekiranya mereka bisa menerima\"."},"307":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا أَبُو هِلَالٍ قَالَ سَمِعْتُ الْحَسَنَ يَقُولُ كَانَ يُقَالُ حَدِّثْ الْقَوْمَ مَا أَقْبَلُوا عَلَيْكَ بِوُجُوهِهِمْ فَإِذَا الْتَفَتُوا فَاعْلَمْ أَنَّ لَهُمْ حَاجَاتٍ","id":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Abu Hilal] ia berkata: \"Aku pernah mendengar [Al Hasan] berkata: 'Dahulu, ada pepatah mengatakan, 'Bicaralah kepada manusia selama wajah mereka masih mengarah kepadamu, dan di saat wajah mereka mulai berpaling, ketahuilah mereka memiliki kepentingan lain' \"."},"308":{"ar":" أَخْبَرَنَا أَبُو مَعْمَرٍ عَنْ سُفْيَانَ بْنِ عُيَيْنَةَ قَالَ حَدَّثَ زَيْدُ بْنُ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ أَنَّهُمْ اسْتَأْذَنُوا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَنْ يَكْتُبُوا عَنْهُ فَلَمْ يَأْذَنْ لَهُمْ","id":"Telah mengabarkan kepada kami [Abu Ma'mar] dari [Sufyan bin 'Uyainah] ia berkata: \"Telah menceritakan kepada kami [Zaid bin `Aslam] dari ['Atha` bin Yasar] dari [Abu Sa'id Al Khudri]: 'Mereka meminta izin kepada Nabi sallallahu 'alaihi wa sallam untuk boleh menulis sesuatu dari selain Al Qur`an, namun beliau tidak mengizinkan mereka\". "},"309":{"ar":" أَخْبَرَنَا بِشْرُ بْنُ الْحَكَمِ عَنْ سُفْيَانَ بْنِ عُيَيْنَةَ عَنْ ابْنِ شُبْرُمَةَ عَنْ الشَّعْبِيِّ أَنَّهُ كَانَ يَقُولُ يَا شِبَاكُ أَرُدُّ عَلَيْكَ يَعْنِي الْحَدِيثَ مَا أَرَدْتُ أَنْ يُرَدَّ عَلَيَّ حَدِيثٌ قَطُّ","id":"Telah mengabarkan kepada kami [Bisyr bin Al Hakam] dari [Sufyan bin 'Uyainah] dari [Ibnu Syubrumah] dari [As Sya'bi]: Ia pernah berkata: \"Wahai Syibak, akan kukembalikan hadis kepadamu sebab aku tidak ingin satu pun hadis dikembalikan kepadaku\"."},"310":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ الْأَوْزَاعِيِّ قَالَ كَانَ قَتَادَةُ يَكْرَهُ الْكِتَابَةَ فَإِذَا سَمِعَ وَقْعَ الْكِتَابِ أَنْكَرَهُ وَالْتَمَسَهُ بِيَدِهِ أَخْبَرَنَا أَبُو الْمُغِيرَةِ قَالَ كَانَ الْأَوْزَاعِيُّ يَكْرَهُهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Katsir] dari [Al 'Auza'i] ia berkata: \" [Qatadah] membenci penulisan hadits, jika dia mendengar penulisan kitab beliau mengingkarinya dan menghapus dengan tangannya. [Abu Al Mughirah] berkata: 'Dan Al 'Auza'i membencinya' \"."},"311":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ أَنَّ إِبْرَاهِيمَ كَانَ يَكْرَهُ الْكِتَابَ يَعْنِي الْعِلْمَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Mansur]: \" [Ibrahim] tidak menyukai penulisan, maksudnya penulisan ilmu\"."},"312":{"ar":" أَخْبَرَنَا يُوسُفُ بْنُ مُوسَى أَخْبَرَنَا أَزْهَرُ عَنْ ابْنِ عَوْنٍ عَنْ ابْنِ سِيرِينَ قَالَ لَوْ كُنْتُ مُتَّخِذًا كِتَابًا لَاتَّخَذْتُ رَسَائِلَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Yusuf bin Musa] telah menceritakan kepada kami [`Azhar] dari [Ibnu 'Aun] dari [Ibnu Sirin] rahimahullah ia berkata: \"Jika aku mengambil (menyetujui penulisan ilmu), niscaya aku menulis risalah-risalah Nabi sallallahu 'alaihi wa sallam\"."},"313":{"ar":" أَخْبَرَنَا إِسْمَعِيلُ بْنُ أَبَانَ حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ شُعْبَةَ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ قَالَ قَالَ لِي عَبِيدَةُ لَا تُخَلِّدَنَّ عَلَيَّ كِتَابًا","id":"Telah mengabarkan kepada kami [Isma'il bin Aban] telah menceritakan kepada kami [Ibnu Idris] dari [Syu'bah] dari [Al Hakam] dari [Ibrahim] ia berkata: \" ['Abidah] pernah berkata kepadaku: 'Janganlah kamu mengabadikanku dengan cara menulis apa yang kamu dapat dariku'."},"314":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ هِشَامٍ قَالَ مَا كَتَبْتُ عَنْ مُحَمَّدٍ إِلَّا حَدِيثَ الْأَعْمَاقِ فَلَمَّا حَفِظْتُهُ مَحَوْتُهُ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [Hisyam] ia berkata: \": Aku tidak menulis dari Muhammad selain hadits yang sangat panjang, dan tatkala aku telah menghafalnya, aku menghapusnya\"."},"315":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ عِمْرَانَ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا شُعْبَةُ عَنْ الْمُغِيرَةِ عَنْ إِبْرَاهِيمَ قَالَ مَا كَتَبْتُ شَيْئًا قَطُّ","id":"Telah mengabarkan kepada kami [Abdullah bin Imran] telah menceritakan kepada kami [Abu Daud] telah menceritakan kepada kami [Syu'bah] dari [Al Mughirah] dari [Ibrahim] ia berkata: \"Aku tidak pernah menulis sesuatu pun sama sekali\"."},"316":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ عِمْرَانَ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا شُعْبَةُ عَنْ إِسْمَعِيلَ بْنِ رَجَاءٍ عَنْ إِبْرَاهِيمَ قَالَ سَأَلْتُ عَبِيدَةَ قِطْعَةَ جِلْدٍ أَكْتُبُ فِيهِ فَقَالَ يَا إِبْرَاهِيمُ لَا تُخَلِّدَنَّ عَنِّي كِتَابًا أَخْبَرَنَا عَبْدُ اللَّهِ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ مِثْلَهُ","id":"Telah mengabarkan kepada kami [Abdullah bin Imran] telah menceritakan kepada kami [Abu Daud] telah menceritakan kepada kami [Syu'bah] dari [Isma'il bin Raja`] dari [Ibrahim] ia pernah berkata: \"Aku pernah bertanya kepada ['Abidah] tentang selembar kulit (ilmu) yang kutulis kepadanya. Lalu ia berkata: 'Jangan kamu tulis apa yang kamu dapat dariku\". Lalu ia berkata: \"Wahai Ibrahim, janganlah kamu mengabadikanku dengan cara menulis apa yang kamu dapat dariku'. Telah menceritakan kepada kami [Abdullah] telah menceritakan kepada kami [Abu Daud] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Ibrahim] dari ['Abidah]: \"Dengan redaksi yang sama\"."},"317":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَمَّادٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ سُلَيْمَانَ بْنِ عَتِيكٍ عَنْ أَبِي مَعْشَرٍ عَنْ إِبْرَاهِيمَ أَنَّهُ كَانَ يَكْرَهُ أَنْ يُكْتَبَ الْحَدِيثُ فِي الْكَرَارِيسِ وَيَقُولُ يُشَبَّهُ بِالْمَصَاحِفِ قَالَ يَحْيَى وَوَجَدْتُ فِي كِتَابِي عَنْ زِيَادٍ الْكَاتِبِ عَنْ أَبِي مَعْشَرٍ وَاكْتُبْ كَيْفَ شِئْتَ","id":"Telah mengabarkan kepada kami [Yahya bin Hammad] telah menceritakan kepada kami [Abu 'Awanah] dari [Sulaiman bin 'Atik] dari [Abu Ma'syar] dari [Ibrahim]: \"Ia membenci menulis hadits di atas kertas, ia mengatakan: 'Hal itu menyerupai mushhaf (Al Qur`an), Yahya berkata: 'Aku dapati dalam kitabku dari Ziyad Al Katib dari Abu Ma'syar, 'Tulislah sekehendakmu' \"."},"318":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْمَدَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ وَهْبِ بْنِ مُنَبِّهٍ عَنْ أَخِيهِ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُ لَيْسَ أَحَدٌ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْثَرَ حَدِيثًا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنِّي إِلَّا مَا كَانَ مِنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو فَإِنَّهُ كَانَ يَكْتُبُ وَلَا أَكْتُبُ","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad] telah menceritakan kepada kami [Sufyan] dari ['Amr] dari [Wahab bin Munabbih] dari [saudaranya]: Ia pernah mendengar [Abu Hurairah] berkata: \"Tidak ada seorang pun dari para sahabat Nabi sallallahu 'alaihi wa sallam yang lebih banyak meriwayatkan hadits Nabi sallallahu 'alaihi wa sallam dibandingkan diriku kecuali yang diriwayatkan dari Abdullah bin 'Amr, itu karena dahulu menulis sedang aku tidak menulis (hadits-hadits tersebut) \"."},"319":{"ar":" أَخْبَرَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ بْنِ الْأَخْنَسِ قَالَ حَدَّثَنِي الْوَلِيدُ بْنُ عَبْدِ اللَّهِ عَنْ يُوسُفَ بْنِ مَاهَكَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ كُنْتُ أَكْتُبُ كُلَّ شَيْءٍ أَسْمَعُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُرِيدُ حِفْظَهُ فَنَهَتْنِي قُرَيْشٌ وَقَالُوا تَكْتُبُ كُلَّ شَيْءٍ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَشَرٌ يَتَكَلَّمُ فِي الْغَضَبِ وَالرِّضَا فَأَمْسَكْتُ عَنْ الْكِتَابِ فَذَكَرْتُ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَوْمَأَ بِإِصْبَعِهِ إِلَى فِيهِ وَقَالَ اكْتُبْ فَوَالَّذِي نَفْسِي بِيَدِهِ مَا خَرَجَ مِنْهُ إِلَّا حَقٌّ","id":"Telah mengabarkan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Ubaidullah bin Al Akhnas] ia berkata: telah menceritakan kepadaku [Al Walid bin Abdullah] dari [Yusuf bin Mahak] dari [Abdullah bin 'Amr] ia berkata: \"Dahulu aku menulis semua yang aku dengar dari Rasulullah sallallahu 'alaihi wa sallam, aku hendak menghafalkannya tetapi masyarakat Quraisy melarangku, mereka berkata: 'Kamu menulis semua yang kamu dengar dari Rasulullah sallallahu 'alaihi wa sallam, bukankah Rasulullah sallallahu 'alaihi wa sallam juga manusia ia berbicara pada saat sedang marah dan senang? ', kemudian aku berhenti dari menulis, kemudian aku ceritakan hal itu kepada Rasulullah sallallahu 'alaihi wa sallam, maka beliau mengisyaratkan dengan jarinya ke mulutnya seraya berkata: 'Tulislah, Demi Dzat yang jiwaku berada dalam genggamannya, tidaklah yang keluar dari (utusan Allah subhanallahu wa ta'ala) selain kebenaran semata' \". "},"320":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي خَالِدُ بْنُ يَزِيدَ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ عَبْدِ الْوَاحِدِ بْنِ قَيْسٍ قَالَ أَخْبَرَنِي مُخْبِرٌ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو أَنَّهُ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي أُرِيدُ أَنْ أَرْوِيَ مِنْ حَدِيثِكَ فَأَرَدْتُ أَنْ أَسْتَعِينَ بِكِتَابِ يَدِي مَعَ قَلْبِي إِنْ رَأَيْتَ ذَلِكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ كَانَ قَالَهُ عِ حَدِيثِي ثُمَّ اسْتَعِنْ بِيَدِكَ مَعَ قَلْبِكَ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] ia berkata: telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku [Khalid bin Yazid] dari [Sa'id bin Abu Hilal] dari [Abdul Wahid bin Qais] ia berkata: telah mengabarkan kepadaku [seorang pembawa kabar] dari [Abdullah bin 'Amr]: \"Ia mendatangi Rasulullah sallallahu 'alaihi wa sallam dan berkata: 'Wahai Rasulullah sallallahu 'alaihi wa sallam, aku ingin meriwayatkan hadits darimu, dan aku ingin membantu hatiku (hafalan) dengan tulisan tanganku jika baginda mengijinkannya', kemudian Rasulullah sallallahu 'alaihi wa sallam menjawab: 'Jika memang haditsku, kamu bisa membantu (hafalan) mu dengan tulisan tanganmu' \"."},"321":{"ar":" أَخْبَرَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ أَبُو مَعْمَرٍ عَنْ أَبِي ضَمْرَةَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ قَالَ كَتَبَ عُمَرُ بْنُ عَبْدِ الْعَزِيزِ إِلَى أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ أَنْ اكْتُبْ إِلَيَّ بِمَا ثَبَتَ عِنْدَكَ مِنْ الْحَدِيثِ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِحَدِيثِ عَمْرَةَ فَإِنِّي قَدْ خَشِيتُ دُرُوسَ الْعِلْمِ وَذَهَابَهُ","id":"Telah mengabarkan kepada kami [Isma'il bin Ibrahim Abu Ma'mar] dari [Abu Dlamrah] dari [Yahya bin Sa'id] dari [Abdullah bin Dinar] ia berkata: \" [Umar bin Abdul Aziz] pernah menulis surat kepada Abu Bakar bin Muhammad bin 'Amr bin Hazm: 'Tuliskanlah untukku hadits yang ada padamu dari hadits Rasulullah sallallahu 'alaihi wa sallam dan hadits 'Amrah, karena aku khawatir akan musnah dan hilangnya ilmu (dengan wafatnya para ulama`) ' \"."},"322":{"ar":" حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُسْلِمٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ قَالَ كَتَبَ عُمَرُ بْنُ عَبْدِ الْعَزِيزِ إِلَى أَهْلِ الْمَدِينَةِ أَنْ انْظُرُوا حَدِيثَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاكْتُبُوهُ فَإِنِّي قَدْ خِفْتُ دُرُوسَ الْعِلْمِ وَذَهَابَ أَهْلِهِ","id":"Telah menceritakan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Abdul Aziz bin Muslim] dari [Abdullah bin Dinar] ia berkata: \" [Umar bin Abdul Aziz] pernah menulis surat untuk penduduk kota Madinah: 'Hendaknya kalian meneliti hadits Rasulullah sallallahu 'alaihi wa sallam, kemudian kalian tulis, karena aku khawatir musnah dan hilangnya ilmu (dengan wafatnya para ulama`) ' \"."},"323":{"ar":" أَخْ��َرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا سَوَادَةُ بْنُ حَيَّانَ قَالَ سَمِعْتُ مُعَاوِيَةَ بْنَ قُرَّةَ أَبَا إِيَاسٍ يَقُولُ كَانَ يُقَالُ مَنْ لَمْ يَكْتُبْ عِلْمَهُ لَمْ يُعَدَّ عِلْمُهُ عِلْمًا","id":"Telah mengabarkan kepada kami [Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Saudah bin Hayyan] ia berkata: \"Aku pernah mendengar [Mu'awiyah bin Qurrah Abu Iyas] berkata: 'Dahulu ada ungkapan, 'Barangsiapa yang tidak menuliskan ilmunya, ilmunya tidak kembali menjadi ilmu' \"."},"324":{"ar":" أَخْبَرَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُثَنَّى حَدَّثَنِي ثُمَامَةُ بْنُ عَبْدِ اللَّهِ بْنِ أَنَسٍ أَنَّ أَنَسًا كَانَ يَقُولُ لِبَنِيهِ يَا بَنِيَّ قَيِّدُوا هَذَا الْعِلْمَ","id":"Telah mengabarkan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Abdullah bin Al Mutsanna] telah menceritakan kepadaku [Tsumamah bin Abdullah bin Anas], [Anas] mengatakan kepada anak-anaknya: \"Wahai anak-anakku hendaklah kalian ikat ilmu ini\"."},"325":{"ar":" أَخْبَرَنَا إِسْمَعِيلُ بْنُ أَبَانَ حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ مَهْدِيِّ بْنِ مَيْمُونٍ عَنْ سَلْمٍ الْعَلَوِيِّ قَالَ رَأَيْتُ أَبَانَ يَكْتُبُ عِنْدَ أَنَسٍ فِي سَبُّورَةٍ","id":"Telah mengabarkan kepada kami [Isma'il bin Aban] telah menceritakan kepada kami [Ibnu Idris] dari [Mahdi bin Maimun] dari [Salam Al 'Alawi] ia berkata: \"Aku melihat Aban menulis di sisi [Anas] di papan tulis\"."},"326":{"ar":" أَخْبَرَنَا مَخْلَدُ بْنُ مَالِكٍ حَدَّثَنَا مُعَاذٌ حَدَّثَنَا عِمْرَانُ بْنُ حُدَيْرٍ عَنْ أَبِي مِجْلَزٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ قَالَ كُنْتُ أَكْتُبُ مَا أَسْمَعُ مِنْ أَبِي هُرَيْرَةَ فَلَمَّا أَرَدْتُ أَنْ أُفَارِقَهُ أَتَيْتُهُ بِكِتَابِهِ فَقَرَأْتُهُ عَلَيْهِ وَقُلْتُ لَهُ هَذَا سَمِعْتُ مِنْكَ قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Makhlad bin Malik] telah menceritakan kepada kami [Mu'adz] telah menceritakan kepada kami [Imran bin Hudair] dari [Abu Mijlaz] dari [Basyir bin Nahik] ia berkata: \"Dahulu aku menulis apa yang aku dengar dari [Abu hurairah], tatkala aku ingin meninggalkannya aku mendatanginya dengan membawa kitab itu lalu aku membacakannya kepadanya serta aku mengatakan kepadanya: 'Inilah yang telah aku dengar darimu', dan ia menjawab: 'Ya, benar' \"."},"327":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ سَعِيدٍ أَخْبَرَنَا شَرِيكٌ عَنْ طَارِقِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ كُنْتُ أَسْمَعُ مِنْ ابْنِ عُمَرَ وَابْنِ عَبَّاسٍ الْحَدِيثَ بِاللَّيْلِ فَأَكْتُبُهُ فِي وَاسِطَةِ الرَّحْلِ","id":"Telah mengabarkan kepada kami [Muhammad bin Sa'id] telah mengabarkan kepada kami [Syarik] dari [Thariq bin Abdur Rahman] dari [Sa'id bin Jubair] ia berkata: \"Suatu malam, aku pernah mendengar hadits dari Ibnu Umar dan Ibnu Abbas radiallahu 'anhuma, lalu aku menulisnya di pertengahan jalan\"."},"328":{"ar":" أَخْبَرَنَا الْوَلِيدُ بْنُ شُجَاعٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ قَالَ حَدَّثَنَاهُ عَاصِمٌ عَنْ شَقِيقٍ عَنْ جَرِيرٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَنَّ سُنَّةً حَسَنَةً عُمِلَ بِهَا بَعْدَهُ كَانَ لَهُ مِثْلُ أَجْرِ مَنْ عَمِلَ بِهَا مِنْ غَيْرِ أَنْ يُنْقَصَ مِنْ أَجْرِهِ شَيْءٌ وَمَنْ سَنَّ سُنَّةً سَيِّئَةً كَانَ عَلَيْهِ مِثْلُ وِزْرِ مَنْ عَمِلَ بِهَا مِنْ غَيْرِ أَنْ يُنْقَصَ مِنْ أَوْزَارِهِ شَيْءٌ","id":"Telah mengabarkan kepada kami [Al Walid bin Syuja'] telah menceritakan kepada kami [Sufyan bin 'Uyainah] ia berkata: ['Ashim] menceritakan kepada kami, dari [Syaqiq] dari [Jarir] ia berkata: Rasulullah sallallahu 'alaihi wa sallam bersabda: \"Barangsiapa memberi contoh kebaikan dan contoh itu diamalkan (diikuti), ia mendapat pahala orang yang mencontohnya tanpa dikurangi sedikit pun pahala orang yang mencontoh. Sebaliknya barangsiapa memberi contoh keburukan dan contoh itu diamalkan (diikuti), ia mendapat dosa sebanyak dosa orang yang mencontohnya, tanpa didikurangi sedikit pun dari dosa-dosa orang yang mencontoh.\""},"329":{"ar":" أَخْبَرَنَا الْوَلِيدُ بْنُ شُجَاعٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ يَعْقُوبَ مَوْلَى الْحُرَقَةِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ دَعَا إِلَى هُدًى كَانَ لَهُ مِنْ الْأَجْرِ مِثْلُ أُجُورِ مَنْ اتَّبَعَهُ لَا يَنْقُصُ ذَلِكَ مِنْ أُجُورِهِمْ شَيْئًا وَمَنْ دَعَا إِلَى ضَلَالَةٍ كَانَ عَلَيْهِ مِنْ الْإِثْمِ مِثْلُ آثَامِ مَنْ تَبِعَهُ لَا يَنْقُصُ ذَلِكَ مِنْ آثَامِهِمْ شَيْئًا","id":"Telah mengabarkan kepada kami [Al Walid bin Syuja'] telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Al 'Ala` bin Abdur Rahman bin Ya'qub] -bekas budaknya Al Khuraqah-, dari [ayahnya] dari [Abu Hurairah] radliallahu 'anhu. Bahwasanya Rasulullah sallallahu 'alaihi wa sallam bersabda: \"Barangsiapa yang mengajak kepada petunjuk, baginya pahala seperti pahalanya orang yang orang yang mencontohnya (mengikutinya), tanpa dikurangi pahalanya sedikitpun. Dan barangsiapa yang mengajak pada kesesatan, ia menanggung dosa sebanyak dosa orang yang mencontohnya (mengikutinya), tanpa dikurangi dosanya sedikitpun\"."},"330":{"ar":" أَخْبَرَنَا الْوَلِيدُ بْنُ شُجَاعٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ مُسْلِمٍ يَعْنِي ابْنَ صُبَيْحٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ هِلَالٍ الْعَبْسِيِّ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ قَالَ خَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَثَّ النَّاسَ عَلَى الصَّدَقَةِ فَأَبْطَئُوا حَتَّى بَانَ فِي وَجْهِهِ الْغَضَبُ ثُمَّ إِنَّ رَجُلًا مِنْ الْأَنْصَارِ جَاءَ بِصُرَّةٍ فَتَتَابَعَ النَّاسُ حَتَّى رُئِيَ فِي وَجْهِهِ السُّرُورُ فَقَالَ مَنْ سَنَّ سُنَّةً حَسَنَةً كَانَ لَهُ أَجْرُهُ وَمِثْلُ أَجْرِ مَنْ عَمِلَ بِهَا مِنْ غَيْرِ أَنْ يُنْقَصَ مِنْ أُجُورِهِمْ شَيْءٌ وَمَنْ سَنَّ سُنَّةً سَيِّئَةً كَانَ عَلَيْهِ وِزْرُهُ وَمِثْلُ وِزْرِ مَنْ عَمِلَ بِهَا مِنْ غَيْرِ أَنْ يُنْقَصَ مِنْ أَوْزَارِهِمْ شَيْءٌ","id":"Telah mengabarkan kepada kami [Al Walid bin Syuja'] telah menceritakan kepada kami [Abu mu'awiyah] telah menceritakan kepada kami [Al A'masy] dari [Muslim Ibnu Shubaih], dari [Abdur rahman bin hilal Al 'Absi] dari [Jarir bin Abdullah] ia berkata: \"Rasulullah sallallahu 'alaihi wa sallam berhutbah di hadapan kami, lalu beliau menganjurkan kami untuk bersedekah, (akan tetapi) mereka lamban hingga terlihat rona kemarahan di wajahnya. Kemudian sungguh ada seorang dari kaum Anshar datang dengan membawa kantong (tempat menyimpan uang), dan orang-orang mengikutinya hingga nampak keceriaan dari wajahnya, kemudian beliau bersabda: 'Barangsiapa memberi contoh kebaikan, baginya pahala seberat pahala orang yang mencontohnya tanpa dikurangi sedikit pun pahala orang-orang yang mencontoh. Sebaliknya barangsiapa memberi contoh keburukan, ia menanggung dosa seberat dosa orang yang mencontohnya, tanpa dikurangi sedikit pun dari dosa-dosa orang-orang yang mencontoh.\""},"331":{"ar":" أَخْبَرَنَا عَبْدُ الْوَهَّابِ بْنُ سَعِيدٍ حَدَّثَنَا شُعَيْبٌ هُوَ ابْنُ إِسْحَقَ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي حَسَّانُ بْنُ عَطِيَّةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَنَا أَعْظَمُكُمْ أَجْرًا يَوْمَ الْقِيَامَةِ لِأَنَّ لِي أَجْرِي وَمِثْلَ أَجْرِ مَنْ اتَّبَعَنِي","id":"Telah mengabarkan kepada kami [Abdul Wahab bin Sa'id] telah menceritakan kepada kami [Syu'aib Ibnu Ishak], telah menceritakan kepada kami [Al 'Auza'i] telah menceritakan kepada kami [Hassan bin 'Athiyah]: Rasulullah sallallahu 'alaihi wa sallam bersabda: \"Aku adalah orang yang paling besar pahalanya diantara kalian semua pada hari kiamat, karena aku mendapatkan pahalaku dan pahala orang -orang yang mengikutiku\"."},"332":{"ar":" أَخْبَرَنَا مَالِكُ بْنُ إِسْمَعِيلَ حَدَّثَنَا عَبْدُ السَّلَامِ عَنْ لَيْثٍ عَنْ بِشْرٍ عَنْ أَنَسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ دَعَا إِلَى أَمْرٍ وَلَوْ دَعَا رَجُلٌ رَجُلًا كَانَ يَوْمَ الْقِيَامَةِ مَوْقُوفًا بِهِ لَازِمًا بِغَارِبِهِ ثُمَّ قَرَأَ { وَقِفُوهُمْ إِنَّهُمْ مَسْئُولُونَ }","id":"Telah mengabarkan kepada kami [Malik bin Isma'il] telah menceritakan kepada kami [Abdus Salam] dari [Laits] dari [Bisyr] dari [Anas] radliallahu 'anhu ia berkata: Rasulullah sallallahu 'alaihi wa sallam bersabda: \"Barangsiapa mengajak satu perkara (meskipun seseorang hanya mengajak satu orang), pada hari kiamat ia akan ditahan (untuk mempertanggung jawabkannya), kemudian ia membaca: \"WAQIFUUHUM INNAHUM MAS`UULUUN\" (Dan tahanlah mereka (ditempat pemberhentian) karena mereka akan ditanya) -Qs. Ash Shaffat: 24-\"."},"333":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَاصِمٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَاصِمٍ عَنْ الشَّعْبِيِّ أَنَّ ابْنَ مَسْعُودٍ قَالَ أَرْبَعٌ يُعْطَاهَا الرَّجُلُ بَعْدَ مَوْتِهِ ثُلُثُ مَالِهِ إِذَا كَانَ فِيهِ قَبْلَ ذَلِكَ لِلَّهِ مُطِيعًا وَالْوَلَدُ الصَّالِحُ يَدْعُو لَهُ مِنْ بَعْدِ مَوْتِهِ وَالسُّنَّةُ الْحَسَنَةُ يَسُنُّهَا الرَّجُلُ فَيُعْمَلُ بِهَا بَعْدَ مَوْتِهِ وَالْمِائَةُ إِذَا شَفَعُوا لِلرَّجُلِ شُفِّعُوا فِيهِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ashim] telah menceritakan kepada kami [Hammad bin Salamah] dari ['Ashim] dari [As Sya'bi], bahwasanya [Ibnu Mas'ud] radliallahu 'anhu berkata: \"Ada empat hal yang akan diberikan kepada seseorang setelah wafatnya: sepertiga hartanya jika ia infakkan karena Allah subhanallahu wa ta'ala, anak shalih yang mendoakannya setelah wafatnya, keteladanan yang baik yang pernah dilakukannya dan orang lain mencontohnya, dan seratus (orang) jika mereka memberi pertolongan kepada seseorang, mereka akan ditolong (lantaran) dia\"."},"334":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ الْحَجَّاجِ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الْأَعْمَشِ قَالَ جَهَدْنَا بِإِبْرَاهِيمَ حَتَّى أَنْ نُجْلِسَهُ إِلَى سَارِيَةٍ فَأَبَى","id":"Telah mengabarkan kepada kami [Ahmad bin Al Hajjaj] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Al A'masy] ia berkata: \"Kami pernah membujuk [Ibrahim] agar mau duduk di dekat tiang namun ia menolak\". "},"335":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مُغِيرَةَ قَالَ كَانَ إِبْرَاهِيمُ لَا يَبْتَدِئُ الْحَدِيثَ حَتَّى يُسْأَلَ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah menceritakan kepada kami [Abu 'Awanah] dari [Mughirah] ia berkata: \"Dahulu [Ibrahim] tidak pernah memulai pembicaraan hingga ditanya\". "},"336":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يُونُسُ بْنُ بُكَيْرٍ حَدَّثَنَا الْأَعْمَشُ عَنْ خَيْثَمَةَ قَالَ كَانَ الْحَارِثُ بْنُ قَيْسٍ الْجُعْفِيُّ وَكَانَ مِنْ أَصْحَابِ عَبْدِ اللَّهِ وَكَانُوا مُعْجَبِينَ بِهِ فَكَانَ يَجْلِسُ إِلَيْهِ الرَّجُلُ وَالرَّجُلَانِ فَيُحَدِّثُهُمَا فَإِذَا كَثُرُوا قَامَ وَتَرَكَهُمْ","id":"Telah mengabarkan kepada kami [Abdullah bin Sa'id] telah mengabarkan kepada kami [Yunus bin Bukair] telah menceritakan kepada kami [Al A'masy] dari [Khaitsamah] ia berkata: \"Dahulu [Al Harits bin Qais Al Ju'fi] -dan ia termasuk dari sahabat Abdullah-, mereka mengaguminya, ketika ada satu atau dua orang yang duduk bersamanya, ia akan menceritakan hadits (Rasulullah sallallahu 'alaihi wa sallam) namun apabila jumlah mereka semakin banyak, ia bangkit dan meninggalkan mereka\"."},"337":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ يُونُسَ حَدَّثَنَا أَبُو شِهَابٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ قَالَ قِيلَ لَهُ حِينَ مَاتَ عَبْدُ اللَّهِ لَوْ قَعَدْتَ فَعَلَّمْتَ النَّاسَ السُّنَّةَ فَقَالَ أَتُرِيدُونَ أَنْ يُوطَأَ عَقِبِي","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah bin Yunus] telah menceritakan kepada kami [Abu Syihab] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] ia berkata: \"Seseorang berkata kepadanya ketika Abdullah wafat,: 'Ohh, sekiranya kamu duduk (menggantikannya) dan mengajari manusia tentang sunnah', ia pun berkata: 'Apakah kalian mengikutiku terus? ' \"."},"338":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ قَالَ كَانُوا يَكْرَهُونَ أَنْ تُوطَأَ أَعْقَابُهُمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Jarir] dari [manshur] dari [Ibrahim] ia berkata: \"Mereka tidak suka diikuti terus.\""},"339":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ بِسْطَامِ بْنِ مُسْلِمٍ قَالَ كَانَ مُحَمَّدُ بْنُ سِيرِينَ إِذَا مَشَى مَعَهُ الرَّجُلُ قَامَ فَقَالَ أَلَكَ حَاجَةٌ فَإِنْ كَانَتْ لَهُ حَاجَةٌ قَضَاهَا وَإِنْ عَادَ يَمْشِي مَعَهُ قَامَ فَقَالَ أَلَكَ حَاجَةٌ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [Bistham bin Muslim] ia berkata: \"Dahulu [Muhammad bin Sirin] apabila ada seseorang yang berjalan (mengikutinya) ia bertanya: 'Apakah kamu ada keperluan? ', Jika orang tersebut mempunyai keperluan dengannya, ia bereskan, dan jika ia masih mengikutinya, Muhammad bin Sirin akan bertanya kembali: 'Masihkah kamu mempunyai keperluan denganku? ' \"."},"340":{"ar":" أَخْبَرَنَا مَخْلَدُ بْنُ مَالِكٍ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ حَدَّثَنَا شُعْبَةُ عَنْ الْهَيْثَمِ عَنْ عَاصِمِ بْنِ ضَمْرَةَ أَنَّهُ رَأَى أُنَاسًا يَتْبَعُونَ سَعِيدَ بْنَ جُبَيْرٍ قَالَ فَأُرَاهُ قَالَ نَهَاهُمْ وَقَالَ إِنَّ صَنِيعَكُمْ هَذَا أَوْ مَشْيَكُمْ هَذَا مَذَلَّةٌ لِلتَّابِعِ وَفِتْنَةٌ لِلْمَتْبُوعِ","id":"Telah mengabarkan kepada kami [Makhlad bin malik] telah menceritakan kepada kami [Hajjaj bin Muhammad] telah mengabarkan kepada kami [Syu'bah] dari [Al Haitsam] dari ['Ashim bin Dlamrah], ia pernah melihat orang-orang mengikuti [Sa'id bin Jubair]. Ia berkata: \"Kemudian kulihat Sa'id melarang mereka melakukan yang demikian seraya berkata: 'Perbuatan kalian ini atau cara jalan kalian ini merupakan hal yang dapat merendahkan orang yang diikuti dan menjadi fitnah bagi orang yang mengikuti' \"."},"341":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ حَدَّثَنَا حُمَيْدُ بْنُ أَسْوَدَ عَنْ ابْنِ عَوْنٍ قَالَ شَاوَرْتُ مُحَمَّدًا فِي بِنَاءٍ أَرَدْتُ أَنْ أَبْنِيَهُ فِي الْكَلَّاءِ قَالَ فَأَشَارَ عَلَيَّ وَقَالَ إِذَا أَرَدْتَ أَسَاسَ الْبِنَاءِ فَآذِنِّي حَتَّى أَجِيءَ مَعَكَ قَالَ فَأَتَيْتُهُ قَالَ فَبَيْنَمَا نَحْنُ نَمْشِي إِذْ جَاءَ رَجُلٌ فَمَشَى مَعَهُ فَقَامَ فَقَالَ أَلَكَ حَاجَةٌ قَالَ لَا قَالَ أَمَّا لَا فَاذْهَبْ ثُمَّ أَقْبَلَ عَلَيَّ فَقَالَ أَنْتَ أَيْضًا فَاذْهَبْ قَالَ فَذَهَبْتُ حَتَّى خَالَفْتُ الطَّرِيقَ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] telah menceritakan kepada kami [Humaid bin Aswad] dari [Ibnu 'Aun] ia berkata: \"Aku pernah bermusyawarah dengan [Muhammad] tentang suatu bangunan, aku menginginkan agar aku dapat membangunnya di sebuah lahan rumput. (Ia) berkata: 'Lalu ia memberi isyarat kepadaku seraya berkata: 'Apabila kamu menginginkan pondasi bangunan, panggillah aku, aku akan mendatangimu, kemudian aku menemuinya. (Ia berkata): 'Dan tatkala kami berjalan tiba-tiba ada seseorang berjalan (mengikuti kami), lalu ia bertanya kepadanya: 'Apakah kamu ada keperluan? ', ia menjawabnya: 'Tidak', ia berkata lagi: 'Jika tidak ada keperluan, maaf pergilah', kemudian ia menghampiriku, seraya berkata: 'Juga kamu, maaf pergilah', ia (perawi) berkata: 'Lalu aku pergi hingga aku mencari jalan yang lain' \"."},"342":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ الْحَجَّاجِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ نُسَيْرٍ أَنَّ الرَّبِيعَ كَانَ إِذَا أَتَوْهُ يَقُولُ أَعُوذُ بِاللَّهِ مِنْ شَرِّكُمْ يَعْنِي أَصْحَابَهُ","id":"Telah mengabarkan kepada kami [Ahmad bin Al hajjaj] telah menceritakan kepada kami [Abdur rahman bin Mahdi] dari [Sufyan] dari [Nusair], bahwasanya [Ar rabi'] apabila ditemui oleh orang-orang (selalu) mengatakan: \"Aku berlindung kepada Allah subhanallahu wa ta'ala dari kejahatan kalian, yaitu para sahabatnya\"."},"343":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ صَالِحٍ قَالَ سَمِعْتُ الشَّعْبِيَّ قَالَ وَدِدْتُ أَنِّي نَجَوْتُ مِنْ عَمَلِي كَفَافًا لَا لِي وَلَا عَلَيَّ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Shalih] ia berkata: \"Aku pernah mendengar [As Sya'bi] berkata; 'Aku ingin selamat dari ilmuku, cukuplah tidak ada yang membelaku dan tidak ada yang mencelaku' \"."},"344":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ حَسَّانَ عَنْ أَبِي كَبْشَةَ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَمْرٍو قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بَلِّغُوا عَنِّي وَلَوْ آيَةً وَحَدِّثُوا عَنْ بَنِي إِسْرَائِيلَ وَلَا حَرَجَ وَمَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah mengabarkan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Al 'Auza'i] dari [Hassan] dari [Abu kabsyah] ia berkata: Aku pernah mendengar [Abdullah bin 'Amr] ia berkata: Aku pernah mendengar Rasulullah sallallahu 'alaihi wa sallam bersabda: \"Hendaklah kalian sampaikan (apa yang datang) dari aku sekalipun satu ayat, dan bolehlah kalian menceritakan tentang bani Isra`il, hal yang demikian tidak ada masalah, dan barangsiapa yang berdusta atas namaku dengan sengaja, hendaklah ia mempersiapkan tempat duduknya di neraka\"."},"345":{"ar":" أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ السَّعْدِيُّ أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا الْعَوَّامُ بْنُ حَوْشَبٍ أَبُو عِيسَى الشَّيْبَانِيُّ حَدَّثَنَا الْقَاسِمُ بْنُ عَوْفٍ الشَّيْبَانِيُّ عَنْ أَبِي ذَرٍّ قَالَ أَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ لَا يَغْلِبُونَا عَلَى ثَلَاثٍ أَنْ نَأْمُرَ بِالْمَعْرُوفِ وَنَنْهَى عَنْ الْمُنْكَرِ وَنُعَلِّمَ النَّاسَ السُّنَنَ","id":"Telah mengabarkan kepada kami [Ali bin Hujr As Sa'di] telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Al 'Awwam bin Hausyab Abu Isa As Syaibani] telah menceritakan kepadaku [Al Qasim bin 'Auf As Syaibani] dari [Abu Dzar] radliallahu 'anhu ia berkata: \"Rasulullah sallallahu 'alaihi wa sallam memerintahkan kami agar kami selalu melakukan tiga hal: Agar kami memerintahkan yang ma'ruf, mencegah yang mungkar, dan mengajarkan sunah kepada manusia\"."},"346":{"ar":" أَخْبَرَنَا عَبْدُ الْوَهَّابِ بْنُ سَعِيدٍ حَدَّثَنَا شُعَيْبٌ هُوَ ابْنُ إِسْحَقَ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي أَبُو كَثِيرٍ حَدَّثَنِي أَبِي قَالَ أَتَيْتُ أَبَا ذَرٍّ وَهُوَ جَالِسٌ عِنْدَ الْجَمْرَةِ الْوُسْطَى وَقَدْ اجْتَمَعَ النَّاسُ عَلَيْهِ يَسْتَفْتُونَهُ فَأَتَاهُ رَجُلٌ فَوَقَفَ عَلَيْهِ ثُمَّ قَالَ أَلَمْ تُنْهَ عَنْ الْفُتْيَا فَرَفَعَ رَأْسَهُ إِلَيْهِ فَقَالَ أَرَقِيبٌ أَنْتَ عَلَيَّ لَوْ وَضَعْتُمْ الصَّمْصَامَةَ عَلَى هَذِهِ وَأَشَارَ إِلَى قَفَاهُ ثُمَّ ظَنَنْتُ أَنِّي أُنْفِذُ كَلِمَةً سَمِعْتُهَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْلَ أَنْ تُجِيزُوا عَلَيَّ لَأَنْفَذْتُهَا","id":"Telah mengabarkan kepada kami [Abdul Wahab bin Sa'id] telah menceritakan kepada kami [Syu'aib Ibnu Ishak], telah menceritakan kepada kami [Al 'Auza'i] telah menceritakan kepadaku [Abu Katsir] ia berkata: telah menceritakan kepadaku [ayahku] ia berkata: \" Aku menemui [Abu Dzar] radliallahu 'anhu yang tengah duduk di jumrah Al Wushtha sementara banyak orang berkumpul (mengerumuninya) untuk meminta fatwa. Lalu ada seorang laki-laki datang dan berdiri di hadapannya seraya bertanya: 'Bukankah kamu telah dilarang untuk berfatwa? ', maka ia pun menengadahkan kepalanya seraya berkata: 'Apakah kamu mengawasi aku terus? Seandainya kamu semua meletakkan pedang tajam disini -seraya ia tunjukkan tengkuk lehernya- dan aku yakin bahwa aku melaksanakan kalimat yang aku dengar langsung dari Rasulullah Shallallahu Alaihi Wa Sallam, sekalipun kalian belum membolehkanku, sungguh tetap akan kulaksanakan.\""},"347":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا عَبَّادٌ هُوَ ابْنُ الْعَوَّامِ عَنْ عَوْفٍ عَنْ أَبِي الْعَالِيَةِ قَالَ سَأَلْتُ ابْنَ عَبَّاسٍ عَنْ شَيْءٍ فَقَالَ يَا أَبَا الْعَالِيَةِ أَتُرِيدُ أَنْ تَكُونَ مُفْتِيًا فَقُلْتُ لَا وَلَكِنْ لَا آمَنُ أَنْ تَذْهَبُوا وَنَبْقَى فَقَالَ صَدَقَ أَبُو الْعَالِيَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami ['Abbad Ibnu Al 'Awwam], dari ['Auf] dari [Abu Al 'Aliyah] ia berkata: \"Aku pernah bertanya kepada [Ibnu Abbas] radliallahu 'anhu tentang sesuatu, lalu ia menjawab: 'Wahai Abu Al 'Aliyah, apakah kamu menginginkan kamu menjadi seorang mufti (ahli fatwa)? ' aku menjawab: 'Tidak, tetapi aku hawatir kalian semua pergi sementara kami tetap di sini', lalu ia (ibnu Abbas radliallahu 'anhu berkata: 'Benarlah apa yang Abu Al 'Aliyah katakan' \"."},"348":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ حَدَّثَنَا غَسَّانُ هُوَ ابْنُ مُضَرَ عَنْ سَعِيدِ بْنِ يَزِيدَ قَالَ سَمِعْتُ عِكْرِمَةَ يَقُولُ مَا لَكُمْ لَا تَسْأَلُونِي أَفْلَسْتُمْ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah menceritakan kepada kami [Ghassan Ibnu Mudlar], dari [Sa'id bin Yazid] ia berkata: \"Aku pernah mendengar ['Ikrimah] berkata: 'Mengapa kalian tidak bertanya kepadaku, apakah kalian merugi? ' \"."},"349":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمٍ الْمُكْتِبُ حَدَّثَنَا عَامِرُ بْنُ صَالِحٍ حَدَّثَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ الْعِلْمُ خَزَائِنُ وَتَفْتَحُهَا الْمَسْأَلَةُ","id":"Telah mengabarkan kepada kami [Muhammad bin Hatim Al Muktib] telah menceritakan kepada kami ['Amir bin Shalih] telah menceritakan kepada kami [Yunus] dari [Ibnu Syihab] ia berkata: \"Ilmu adalah gudang, dan membukanya dengan bertanya\"."},"350":{"ar":" أَخْبَرَنَا إِبْرَاهِيمُ بْنُ إِسْحَقَ عَنْ جَرِيرٍ قَالَ قَالَ إِبْرَاهِيمُ مَنْ رَقَّ وَجْهُهُ رَقَّ عِلْمُهُ وَوَكِيعٌ عَنْ أَبِيهِ عَنْ الشَّعْبِيِّ قَالَ مَنْ رَقَّ وَجْهُهُ جَهِلَ عِلْمُهُ وَعَنْ ضَمْرَةَ عَنْ حَفْصِ بْنِ عُمَرَ قَالَ قَالَ عُمَرُ بْنُ الْخَطَّابِ مَنْ رَقَّ وَجْهُهُ رَقَّ عِلْمُهُ","id":"Telah mengabarkan kepada kami [Ibrahim bin Ishak] dari [jarir] ia berkata: [Ibrahim] pernah berkata: Barangsiapa yang lembut wajahnya (pemalu), maka lembut pula ilmunya (sedikit ilmunya) \". [Waki'] juga berkata dari [ayahnya] dari [As Sya'bi] ia berkata: \"Barangsiapa yang lembut wajahnya lembut pula ilmunya'. Diriwayatkan dari [Dlamrah] dari [Hafsh bin Umar] ia berkata; [Umar bin Khatthab] radliallahu 'anhu berkata: \"Barangsiapa yang lembut wajahnya lembut pula ilmunya\"."},"351":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْمَدَ بْنِ أَبِي خَلَفٍ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ أَنَّهُ كَانَ يَجْمَعُ بَنِيهِ فَيَقُولُ يَا بَنِيَّ تَعَلَّمُوا فَإِنْ تَكُونُوا صِغَارَ قَوْمٍ فَعَسَى أَنْ تَكُونُوا كِبَارَ آخَرِينَ وَمَا أَقْبَحَ عَلَى شَيْخٍ يُسْأَلُ لَيْسَ عِنْدَهُ عِلْمٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad bin Abu khalaf] telah menceritakan kepada kami [Anas bin 'Iyadl] dari [Hisyam bin 'Urwah] dari [ayahnya]: Bahwasanya ia mengumpulkan anak-anaknya seraya berkata: \"Wahai anakku, hendaklah kalian belajar, kalaupun sekarang kalian menjadi generasi kecil, tidak mustahil kalian akan menjadi pembesar bagi yang lainnya, dan alangkah buruknya seorang pemuka yang ditanya tetapi ia tidak memiliki ilmu\"."},"352":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ الزُّبَيْرِ بْنِ الْخِرِّيتِ عَنْ عِكْرِمَةَ قَالَ كَانَ ابْنُ عَبَّاسٍ يَضَعُ فِي رِجْلَيَّ الْكَبْلَ وَيُعَلِّمُنِي الْقُرْآنَ وَالسُّنَنَ","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari [Az Zubair bin Al Khirrit] dari ['Ikrimah] ia berkata: \"Dahulu [Ibnu Abbas] radliallahu 'anhu meletakkan tali di atas kakiku, dan ia mengajariku Al Qur`an dan sunah\". "},"353":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ عَنْ صَالِحِ بْنِ خَبَّابٍ عَنْ حُصَيْنِ بْنِ عُقْبَةَ عَنْ سَلْمَانَ قَالَ عِلْمٌ لَا يُقَالُ بِهِ كَكَنْزٍ لَا يُنْفَقُ مِنْهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Al A'masy] dari [Shalih bin Khabab] dari [Hushain bin 'Uqbah] dari [Salman] ia berkata: \"Ilmu yang tidak disampaikan bagaikan gudang harta yang tidak pernah diinfakkan\"."},"354":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ قَالَ لَقَدْ أَقَمْتُ فِي الْمَدِينَةِ ثَلَاثًا مَا لِي حَاجَةٌ إِلَّا وَقَدْ فَرَغْتُ مِنْهَا إِلَّا أَنَّ رَجُلًا كَانُوا يَتَوَقَّعُونَهُ كَانَ يَرْوِي حَدِيثًا فَأَقَمْتُ حَتَّى قَدِمَ ف��سَأَلْتُهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah] ia berkata: \"Aku pernah tinggal di kota Madinah selama tiga (hari), tidak ada keperluan di sana melainkan bisa aku selesaikan, kecuali satu hal yaitu perihal seseorang yang orang-orang meyakini kalau ia meriwayatkan hadits, oleh sebab itu aku tetap tinggal (di sana) hingga ia datang dan aku dapat bertanya kepadanya (tentang hadits tersebut) \"."},"355":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ حَدَّثَنَا الْوَلِيدُ عَنْ ابْنِ جَابِرٍ قَالَ سَمِعْتُ بُسْرَ بْنَ عُبَيْدِ اللَّهِ يَقُولُ إِنْ كُنْتُ لَأَرْكَبُ إِلَى مِصْرٍ مِنْ الْأَمْصَارِ فِي الْحَدِيثِ الْوَاحِدِ لِأَسْمَعَهُ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah mengabarkan kepada kami [Al Walid] dari [ibnu Jabir] ia berkata: \"Aku pernah mendengar [Busr bin 'Ubaidullah] berkata: 'Jika aku harus menaiki kendaraan dan pergi ke satu daerah untuk (mendengarkan) satu hadits, maka akan (kulakukan).\""},"356":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ زُرَارَةَ أَخْبَرَنَا أَبُو قَطَنٍ عَمْرُو بْنُ الْهَيْثَمِ عَنْ أَبِي خَلْدَةَ عَنْ أَبِي الْعَالِيَةِ قَالَ كُنَّا نَسْمَعُ الرِّوَايَةَ بِالْبَصْرَةِ عَنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ نَرْضَ حَتَّى رَكِبْنَا إِلَى الْمَدِينَةِ فَسَمِعْنَاهَا مِنْ أَفْوَاهِهِمْ","id":"Telah mengabarkan kepada kami ['Amr bin Zurarah] telah mengabarkan kepada kami [Abu Qathn 'Amr bin Al Haitsam], dari [Abu Khaldah] dari [Abu Al 'Aliyah] ia berkata: \"Dahulu di Bashrah, kami mendengar riwayat para sahabat Rasulullah sallallahu 'alaihi wa sallam (tentang hadits Nabi sallallahu 'alaihi wa sallam), tetapi kami belum merasa puas, hingga kami datang langsung ke kota Madinah dan mendengarkannya dari lisan mereka\"."},"357":{"ar":" أَخْبَرَنَا نُعَيْمُ بْنُ حَمَّادٍ حَدَّثَنَا بَقِيَّةُ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ التُّسْتَرِيِّ قَالَ قَالَ دَاوُدُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْ لِصَاحِبِ الْعِلْمِ يَتَّخِذْ عَصًا مِنْ حَدِيدٍ وَنَعْلَيْنِ مِنْ حَدِيدٍ وَيَطْلُبْ الْعِلْمَ حَتَّى تَنْكَسِرَ الْعَصَا وَتَنْخَرِقَ النَّعْلَانِ","id":"Telah mengabarkan kepada kami [Nu'aim bin Hammad] telah menceritakan kepada kami [Baqiyyah] dari [Abdullah bin Abdur Rahman Al Qusyairi] ia berkata: \"Nabi Daud 'alaihissalam pernah berkata: 'Katakanlah kepada para pecinta ilmu agar ia membuat sebuah tongkat dan sepasang sandal dari besi, kemudian ia menuntut ilmu hingga tongkat itu patah dan sandal tersebut hancur' \"."},"358":{"ar":" أَخْبَرَنَا مَخْلَدُ بْنُ مَالِكٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْأُمَوِيُّ حَدَّثَنَا الْحَجَّاجُ عَنْ حُصَيْنِ بْنِ عَبْدِ الرَّحْمَنِ مِنْ آلِ سَعْدِ بْنِ مُعَاذٍ قَالَ قَالَ ابْنُ عَبَّاسٍ طَلَبْتُ الْعِلْمَ فَلَمْ أَجِدْهُ أَكْثَرَ مِنْهُ فِي الْأَنْصَارِ فَكُنْتُ آتِي الرَّجُلَ فَأَسْأَلُ عَنْهُ فَيُقَالُ لِي نَائِمٌ فَأَتَوَسَّدُ رِدَائِي ثُمَّ أَضْطَجِعُ حَتَّى يَخْرُجَ إِلَى الظُّهْرِ فَيَقُولُ مَتَى كُنْتَ هَا هُنَا يَا ابْنَ عَمِّ رَسُولِ اللَّهِ فَأَقُولُ مُنْذُ زَمَنٍ طَوِيلٍ فَيَقُولُ بِئْسَ مَا صَنَعْتَ هَلَّا أَعْلَمْتَنِي فَأَقُولُ أَرَدْتُ أَنْ تَخْرُجَ إِلَيَّ وَقَدْ قَضَيْتَ حَاجَتَكَ","id":"Telah mengabarkan kepaeda kami [Makhlad bin Malik] telah menceritakan kepada kami [Yahya bin Sa'id Al `Umawi] telah menceritakan kepada kami [Al Hajjaj] dari [Hushain bin 'Abdur Rahman] -dari keluarga Sa'ad bin mu'adz-, ia berkata: [Ibnu Abbas] radliallahu 'anhu pernah berkata: \"Aku telah mencari ilmu dan aku tidak dapatkan itu sebanyak di masyarakat Anshar, suatu saat aku mendatangi seorang laki-laki, aku bertanya kepadanya, tetapi ketika diberitahu bahwa ia sedang tidur, maka aku menjadikan selendangku sebagai bantal dan berbaring hingga ia keluar untuk shalat Dhuhur, kemudian ia bertanya: 'Mulai kapan kamu menungguku wahai keponakan Rasulullah sallallahu 'alaihi wa sallam? ', aku pun menjawab: 'Sudah lama', lalu ia berkata: 'Tidak bagus kamu bersikap seperti ini, mengapa kamu tidak beritahu aku? ', aku menjawab: 'Aku ingin kamu kamu keluar menemuiku setelah kamu selesai dari semua keperluanmu' \"."},"359":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ يُونُسَ حَدَّثَنَا أَبُو بَكْرٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ ابْنِ عَبَّاسٍ قَالَ وُجِدَ أَكْثَرُ حَدِيثِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ هَذَا الْحَيِّ مِنْ الْأَنْصَارِ وَاللَّهِ إِنْ كُنْتُ لَآتِي الرَّجُلَ مِنْهُمْ فَيُقَالُ هُوَ نَائِمٌ فَلَوْ شِئْتُ أَنْ يُوقَظَ لِي فَأَدَعُهُ حَتَّى يَخْرُجَ لِأَسْتَطِيبَ بِذَلِكَ حَدِيثَهُ","id":"Telah mengabarkan kepadas kami [Ahmad bin Abdullah bin yunus] telah menceritakan kepada kami [Abu Bakar] dari [muhammad bin 'Amr] dari [Abu Salamah bin Abdur rahman] dari [Ibnu Abbas] radliallahu 'anhu ia berkata: \"Kebanyakan hadits Rasulullah sallallahui 'alaihi wa sallam didapatkan dari kampung ini dari kaum Anshar, Demi Allah subhanallahu wa ta'ala, jika saat aku datang mengunjungi salah seorang dari mereka, kemudian saya diberitahu bahwa ia sedang tidur, sekiranya aku ingin dia berkenan untuk dibangunkan untuk menemuiku, namun aku tidak mau hal itu hingga ia keluar sendiri agar aku mendapatkan haditsnya dengan cara yang baik\"."},"360":{"ar":" أَخْبَرَنَا أَبُو مَعْمَرٍ إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ سُفْيَانَ بْنِ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ قَالَ لَوْ رَفَقْتُ بِابْنِ عَبَّاسٍ لَأَصَبْتُ مِنْهُ عِلْمًا كَثِيرًا","id":"Telah mengabarkan kepoada kami [Abu Ma'mar Isma'il bin Ibrahim], dari [Sufyan bin 'uyainah] dari [Az Zuhri] dari [Abu Salamah] ia berkata: 'Kalau aku menemani Ibnu Abbas radliallahu 'anhu, niscaya aku mendapatkan ilmu yang banyak\"."},"361":{"ar":" أَخْبَرَنَا بِشْرُ بْنُ الْحَكَمِ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ قَالَ كُنْتُ آتِي بَابَ عُرْوَةَ فَأَجْلِسُ بِالْبَابِ وَلَوْ شِئْتُ أَنْ أَدْخُلَ لَدَخَلْتُ وَلَكِنْ إِجْلَالًا لَهُ","id":"Telah mengabarkan kepada kami [Bisyr bin Al hakam] telah menceritakan kepada kami [Abdur Razak] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] ia berkata: \"Dahulu aku pernah mendatangi (mengunjungi rumah) pintu 'Urwah lalu aku duduk di depan pintu, kalau waktu itu aku ingin aku bisa saja masuk, tetapi (tidak aku lakukan) karena rasa hormat kepadanya\"."},"362":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ يَعْلَى بْنِ حَكِيمٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ لَمَّا تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ لِرَجُلٍ مِنْ الْأَنْصَارِ يَا فُلَانُ هَلُمَّ فَلْنَسْأَلْ أَصْحَابَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنَّهُمْ الْيَوْمَ كَثِيرٌ فَقَالَ وَا عَجَبًا لَكَ يَا ابْنَ عَبَّاسٍ أَتَرَى النَّاسَ يَحْتَاجُونَ إِلَيْكَ وَفِي النَّاسِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَرَى فَتَرَكَ ذَلِكَ وَأَقْبَلْتُ عَلَى الْمَسْأَلَةِ فَإِنْ كَانَ لَيَبْلُغُنِي الْحَدِيثُ عَنْ الرَّجُلِ فَآتِيهِ وَهُوَ قَائِلٌ فَأَتَوَسَّدُ رِدَائِي عَلَى بَابِهِ فَتَسْفِي الرِّيحُ عَلَى وَجْهِي التُّرَابَ فَيَخْرُجُ فَيَرَانِي فَيَقُولُ يَا ابْنَ عَمِّ رَسُولِ اللَّهِ مَا جَاءَ بِكَ أَلَا أَرْسَلْتَ إِلَيَّ فَآتِيَكَ فَأَقُولُ لَا أَنَا أَحَقُّ أَنْ آتِيَكَ فَأَسْأَلُهُ عَنْ الْحَدِيثِ قَالَ فَبَقِيَ الرَّجُلُ حَتَّى رَآنِي وَقَدْ اجْتَمَعَ النَّاسُ عَلَيَّ فَقَالَ كَانَ هَذَا الْفَتَى أَعْقَلَ مِنِّي","id":"Telah mengabarkan kepada kami [yazid bin harun] telah mengabarkan kepada kami [Jarir bin Hazim] dari [ya'la bin Hakim] dari ['Ikrimah] dari [Ibnu Abbas] radliallahu 'anhu ia berkata: \"Ketika Rasulullah sallallahu 'alaihi wa sallam wafat, aku mengatakan kepada seorang kabilah Anshar: 'Wahai fulan, kemarilah, mari kita bertanya kepada para sahabat Nabi sallallahu 'alaihi wa sallam, jumlah mereka sekarang banyak.' Ia berkomentar: 'Aneh sekali kamu ini hai Ibnu Abbas radliallahu 'anhu, Tidakkah kamu tahu bahwa justru merekalah yang membutuhkan kamu, adapun para sahabat Nabi sallallahu 'alaihi wa sallam yang ada, siapa yang kamu anggap layak untuk ditanya? ', Orang itu membiarkan ucapannya, dan aku selalu bertanya dan bertanya. Jika aku peroleh informasi suatu hadits pada seseorang, segera aku temui. Kata Ibnu'Abbas: '(Suatu saat) pernah aku menjadikan selendangku untuk bantal di depan pintu rumahnya, namun angin berhembus sampai debu mengenai wajahku, kemudian ia keluar dan melihatku', ia berkata: 'Wahai keponakan Rasulullah sallallahu 'alaihi wa sallam, apa yang membuatmu datang (kesini)? Mengapa tidak kamu utus seseorang dan aku saja yang menemuimu? ', aku menjawab: 'Tidak, aku lebih layak untuk menemuimu lalu aku menanyakannya suatu hadits. Ibnu Abbas berkata: 'Orang tersebut masih hidup hingga ia melihatku dikunjungi orang banyak (utuk menggali ilmu) ', kemudian orang tersebut berkata: 'Pemuda ini memang lebih cerdas dibandingkan aku' \". "},"363":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا الْجُرَيْرِيُّ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ أَنَّ رَجُلًا مَنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَحَلَ إِلَى فَضَالَةَ بْنِ عُبَيْدٍ وَهُوَ بِمِصْرَ فَقَدِمَ عَلَيْهِ وَهُوَ يَمُدُّ لِنَاقَةٍ لَهُ فَقَالَ مَرْحَبًا قَالَ أَمَا إِنِّي لَمْ آتِكَ زَائِرًا وَلَكِنْ سَمِعْتُ أَنَا وَأَنْتَ حَدِيثًا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجَوْتُ أَنْ يَكُونَ عِنْدَكَ مِنْهُ عِلْمٌ قَالَ مَا هُوَ قَالَ كَذَا وَكَذَا","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Al Juraiji] dari [Abdullah bin Buraidah]: \" [Seorang sahabat] Nabi salallahu 'alaihi wa sallam pergi mengunjungi Khudlallah bin 'Ubaid. Setibanya dia disana dia sedang mengulurkan tangannya pada untanya seraya berkata: 'selamat datang', ia berkata: 'Aku datang menemuimu bukan (sekedar) berkunjung, tetapi aku dan kamu telah mendengar hadits dari Rasulullah shallallahu 'alaihi wasallam, aku berharap kamu mempunyai ilmu tentangnya'. Ia bertanya: 'tentang apa? ', ia menjawab: 'tentang ini dan tentang ini ' '."},"364":{"ar":" أَخْبَرَنَا الْهَيْثَمُ بْنُ جَمِيلٍ عَنْ حُسَامٍ عَنْ أَبِي مَعْشَرٍ عَنْ إِبْرَاهِيمَ أَنَّهُ كَانَ لَا يَشْتَرِي مِمَّنْ يَعْرِفُهُ","id":"Telah mengabarkan kepadakami [Al Haitsam bin Jamil] dari [Husam] dari [Abu Ma'syar] dari [Ibrahim]: \"Bahwasanya ia tidak pernah membeli dari orang yang dikenalnya\"."},"365":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ سَعِيدٍ أَخْبَرَنَا عَبْدُ السَّلَامِ عَنْ عَبْدِ اللَّهِ بْنِ الْوَلِيدِ الْمُزَنِيِّ عَنْ عُبَيْدِ بْنِ الْحَسَنِ قَالَ قَسَمَ مُصْعَبُ بْنُ الزُّبَيْرِ مَالًا فِي قُرَّاءِ أَهْلِ الْكُوفَةِ حِينَ دَخَلَ شَهْرُ رَمَضَانَ فَبَعَثَ إِلَى عَبْدِ الرَّحْمَنِ بْنِ مَعْقِلٍ بِأَلْفَيْ دِرْهَمٍ فَقَالَ لَهُ اسْتَعِنْ بِهَا فِي شَهْرِكَ هَذَا فَرَدَّهَا عَبْدُ الرَّحْمَنِ بْنُ مَعْقِلٍ وَقَالَ لَمْ نَقْرَأْ الْقُرْآنَ لِهَذَا","id":"Telah mengabarkan kepada kami [Muhammad bin Sa'id] telah mengabarkan kepada kami [Abdus Sallam] dari [Abdullah bin Al walid Al Muzani] dari ['Ubaid bin Al Hasan] ia berkata: \"Ketika memasuki bulan Ramadlan, Mush'ab bin Az Zubair membagikan hartanya kepada para qari` kota Kufah kemudian ia mengirimkan untuk Abdur Rahman bin Ma'qil sebanyak dua ribu dirham sambil berkata: 'Gunakan uang ini untuk keperluanmu sebulan ini'. Tetapi [Abdur Rahman bin Ma'qil] berkata: 'Kami tidak membaca Al qur`an untuk hal ini' \"."},"366":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْمَدَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ زَيْدٍ عَنْ عَطَاءٍ قَالَ مَا أَوَى شَيْءٌ إِلَى شَيْءٍ أَزْيَنَ مِنْ حِلْمٍ إِلَى عِلْمٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Zaid] dari ['Atha`] ia berkata: \"Tidak ada suatu hal yang jika bertemu lebih indah daripada jika sifat santun bertemu ilmu.\""},"367":{"ar":" أَخْبَرَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا عَاصِمٌ الْأَحْوَلُ عَنْ عَامِرٍ الشَّعْبِيِّ قَالَ زَيْنُ الْعِلْمِ حِلْمُ أَهْلِهِ","id":"Telah mengabarkan kepada kami [Affan] telah menceritakan kepada kami [Hammad bin Salamah] telah mengabarkan kepada kami ['Ashim Al Ahwal] dari ['Amir As Sya'bi] ia berkata: \"Hiasan ilmu adalah sikap santun sang pemiliknya'."},"368":{"ar":" أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا زَمْعَةُ بْنُ صَالِحٍ عَنْ سَلَمَةَ بْنِ وَهْرَامٍ عَنْ طَاوُسٍ قَالَ مَا حُمِلَ الْعِلْمُ فِي مِثْلِ جِرَابِ حِلْمٍ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [Abdur Rahman] telah menceritakan kepda kami [Zam'ah bin Shalih] dari [Salamah bin Wahram] dari [Thawus] ia berkata: 'Ilmu tidak dibawa seperti tempayan kesantunan.\" "},"369":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ أَخْبَرَنَا مُطَرِّفُ بْنُ مَازِنٍ عَنْ يَعْلَى بْنِ مِقْسَمٍ عَنْ وَهْبِ بْنِ مُنَبِّهٍ قَالَ إِنَّ الْحِكْمَةَ تَسْكُنُ الْقَلْبَ الْوَادِعَ السَّاكِنَ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah mengabarkan kepada kami [Mutharrif bin Mazin] dari [Ya'la bin Miqsam] dari [Wahab bin Munabbih] ia berkata: \"Hikmah itu menempati hati yang lembut dan tenang\"."},"370":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْمَدَ قَالَ سَمِعْتُ سُفْيَانَ يَقُولُ قَالَ عُبَيْدُ اللَّهِ شِنْتُمْ الْعِلْمَ وَأَذْهَبْتُمْ نُورَهُ وَلَوْ أَدْرَكَنِي وَإِيَّاكُمْ عُمَرُ لَأَوْجَعَنَا","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad] ia berkata: \"Aku pernah mendengar [Sufyan] berkata: [Ubaiadullah] berkata: 'Kalian menginginkan ilmu, tetapi kalian menghilangkan cahayanya, sekiranya Umar radliallahu 'anhu mendapatiku dan kalian, niscaya ia menghukum kita' \"."},"371":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ حُمَيْدٍ حَدَّثَنَا جَرِيرٌ عَنْ الْفُضَيْلِ بْنِ غَزْوَانَ عَنْ عَلِيِّ بْنِ حُسَيْنٍ قَالَ مَنْ ضَحِكَ ضَحْكَةً مَجَّ مَجَّةً مِنْ الْعِلْمِ","id":"Telah mengabarkan kepada kami [Muhammad bin Humaid] telah menceritakan kepada kami [Jarir] dari [Al fudlail bin Ghazwan] dari [Ali bin Husain] ia berkata: \"Barangsiapa tertawa, lepaslah satu bagian dari ilmu\"."},"372":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ أَنَّ عُمَرَ قَالَ لِكَعْبٍ مَنْ أَرْبَابُ الْعِلْمِ قَالَ الَّذِينَ يَعْمَلُونَ بِمَا يَعْلَمُونَ قَالَ فَمَا أَخْرَجَ الْعِلْمَ مِنْ قُلُوبِ الْعُلَمَاءِ قَالَ الطَّمَعُ","id":"Telah mengabarkan kepada kami [Muhammad bin yusuf] dari [Sufyan] Bahwasanya Umar berkata kepada [Ka'ab]: \"Siapakah yang disebut orang berilmu itu?, ia menjawab: 'Yaitu mereka yang mengamalkan apa yang mereka ketahui', ia bertanya: '(Kemudian) apa yang menyebabkan ilmu hengkang dari hati para ulama`? ', ia menjawab: 'Ketamakan' \"."},"373":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ حُمَيْدٍ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْوَلِيدِ عَنْ عُمَرَ بْنِ أَيُّوبَ عَنْ أَبِي إِيَاسٍ قَالَ كُنْتُ نَازِلًا عَلَى عَمْرِو بْنِ النُّعْمَانِ فَأَتَاهُ رَسُولُ مُصْعَبِ بْنِ الزُّبَيْرِ حِينَ حَضَرَهُ رَمَضَانُ بِأَلْفَيْ دِرْهَمٍ فَقَالَ إِنَّ الْأَمِيرَ يُقْرِئُكَ السَّلَامَ وَقَالَ إِنَّا لَمْ نَدَعْ قَارِئًا شَرِيفًا إِلَّا وَقَدْ وَصَلَ إِلَيْهِ مِنَّا مَعْرُوفٌ فَاسْتَعِنْ بِهَذَيْنِ عَلَى نَفَقَةِ شَهْرِكَ هَذَا فَقَالَ أَقْرِئْ الْأَمِيرَ السَّلَامَ وَقُلْ لَهُ إِنَّا وَاللَّهِ مَا قَرَأْنَا الْقُرْآنَ نُرِيدُ بِهِ الدُّنْيَا وَدِرْهَمَهَا","id":"Telah mengabarkan kepada kami [Ahmad bion Humaid] telah menceritakan kepada kami [Muhammad bin Bisyr] telah menceritakan kepada kami [Abdullah bin Al Walid] dari [Umar bin Ayyub] dari [Abu Iyas] ia berkata: \"Aku pernah tinggal (dirumah) 'Amr bin An Nu'man. Ketika tiba bulan Ramadlan, datanglah utusan Mush'ab bin Az Zubair dengan membawa dua ribu dirham, lalu ia berkata: ' Gubernur (Az Zubair) menyampaikan salam kepadamu, dan ia (Az Zubair) berkata: 'Kami tidak akan membiarkan seorang qari` yang mulia melainkan ia akan mendapatkan penghargaan dari kami, maka tolong pergunakan dua ribu dirham ini untuk keperluanmu sebulan ini', ['Amr bin Nu'man] menjawab: 'Maaf, tolong sampaikan salam kepada Gubernur, dan katakan kepadanya: Demi Allah subhanallahu wa ta'ala, kami membaca Al Qur`an tidak karena ingin peroleh dunia dan dirham' \"."},"374":{"ar":" أَخْبَرَنَا أَسَدُ بْنُ مُوسَى حَدَّثَنَا مُعَاوِيَةُ حَدَّثَنَا الْحَسَنُ بْنُ جَابِرٍ عَنْ الْمِقْدَامِ بْنِ مَعْدِي كَرِبَ الْكِنْدِيِّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرَّمَ أَشْيَاءَ يَوْمَ خَيْبَرَ الْحِمَارَ وَغَيْرَهُ ثُمَّ قَالَ لَيُوشِكُ بِالرَّجُلِ مُتَّكِئًا عَلَى أَرِيكَتِهِ يُحَدَّثُ بِحَدِيثِي فَيَقُولُ بَيْنَنَا وَبَيْنَكُمْ كِتَابُ اللَّهِ مَا وَجَدْنَا فِيهِ مِنْ حَلَالٍ اسْتَحْلَلْنَاهُ وَمَا وَجَدْنَا فِيهِ مِنْ حَرَامٍ حَرَّمْنَاهُ أَلَا وَإِنَّ مَا حَرَّمَ رَسُولُ اللَّهِ هُوَ مِثْلُ مَا حَرَّمَ اللَّهُ","id":"Telah mengabarkan kepada kami [`Asad bin musa] telah menceritakan kepada kami [Mu'awiyah] telah menceritakan kepada kami [Al Hasan bin Jabir] dari [Al Miqdam bin Ma'di Karib Al Kindi]: \"Rasulullah sallallahu 'alaihi wa sallam pada hari penaklukan Khaibar mengharamkan beberapa macam hal, diantaranya himar (keledai) dan lainnya, kemudian beliau bersabda: 'Hampir saja seseorang laki-laki yang bersandar di shafa mewah menceritakan hadits dariku, ia berkata: 'Diantara kami dan kalian ada Kitab Allah subhanallahu wa ta'ala, maka apa yang kami dapati sebagai suatu yang halal akan kami halalkan, dan apa yang kami dapatkan suatu yang haram maka kami haramkan'. Ketahuilah apa yang diharamkan oleh Rasulullah sallallahu 'alaihi wa sallam adalah seperti yang diharamkan oleh Allah subhanallahu wa ta'ala' \"."},"375":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عُيَيْنَةَ عَنْ أَبِي إِسْحَقَ الْفَزَارِيِّ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ السُّنَّةُ قَاضِيَةٌ عَلَى الْقُرْآنِ وَلَيْسَ الْقُرْآنُ بِقَاضٍ عَلَى السُّنَّةِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Uyainah] dari [Abu Ishak Al Fazari] dari [Al 'Auza'i] dari [Yahya bin Abu Katsir] ia berkata: \"Hadis adalah penjelasan yang memutuskan dalil Al Qur`an dan Al Qur`an bukan penjelas yang memutuskan dalil hadits\"."},"376":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ الْأَوْزَاعِيِّ عَنْ حَسَّانَ قَالَ كَانَ جِبْرِيلُ يَنْزِلُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالسُّنَّةِ كَمَا يَنْزِلُ عَلَيْهِ بِالْقُرْآنِ","id":"Telah mengabarkan kepada kami [Muhammad bin Katsir] dari [Al 'Auza'i] dari [Hassan] ia berkata: \"Jibril 'alaihissalam turun menemui Nabi sallallahu 'alaihi wa sallam menyampaikan sunah sebagaimana ia turun untuk menyampaikan Al Qur`an\"."},"377":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ الْأَوْزَاعِيِّ عَنْ مَكْحُولٍ قَالَ السُّنَّةُ سُنَّتَانِ سُنَّةٌ الْأَخْذُ بِهَا فَرِيضَةٌ وَتَرْكُهَا كُفْرٌ وَسُنَّةٌ الْأَخْذُ بِهَا فَضِيلَةٌ وَتَرْكُهَا إِلَى غَيْرِ حَرَجٍ","id":"Telah mengabarkan kepada kami [Muhammad bin katsir] dari [Al 'Auza'i] dari [makhul] ia berkata: \"Sunnah itu ada dua, yaitu sunnah yang wajib diambil hukumnya dan jika ditinggalkan adalah sebuah kekufuran, dan sunnah yang jika diambil adalah sebuah keutamaan dan jika ditinggalkan adalah hal bagaikan dosa\"."},"378":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ يَعْلَى بْنِ حَكِيمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ أَنَّهُ حَدَّثَ يَوْمًا بِحَدِيثٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَجُلٌ فِي كِتَابِ اللَّهِ مَا يُخَالِفُ هَذَا قَالَ أَلَا أُرَانِي أُحَدِّثُكَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَتُعَرِّضُ فِيهِ بِكِتَابِ اللَّهِ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْلَمَ بِكِتَابِ اللَّهِ مِنْكَ","id":"Telah mengabarkan kepada kami [Sulaiman bin harb] telah menceritakan kepada kami [Hammad bin Salamah] dari [Ya'la bin Hakim] dari [Sa'id bin Jubair] Bahwasanya pada suatu hari ia menceritakan hadits dari Nabi sallallahu 'alaihi wa sallam, lalu ada seorang berkata: 'Di dalam Al Qur`an bertolak belakang dengan ini (hadits yang disampaikan) ', ia berkata: 'Aku tidak paham, aku ceritakan hadits dari Rasulullah sallallahu 'alaihi wa sallam sedang kamu membandingkan dengan Kitab Allah subhanallahu wa ta'ala, Rasulullah sallallahu 'alaihi wa sallam lebih mengetahui tentang isi Kitab Allah subhanallahu wa ta'ala dibandingkan kamu' \"."},"379":{"ar":" أَخْبَرَنَا نُعَيْمُ بْنُ حَمَّادٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ ابْنِ عَجْلَانَ عَنْ عَوْنِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ مَسْعُودٍ أَنَّهُ قَالَ إِذَا حُدِّثْتُمْ بِالْحَدِيثِ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَظُنُّوا بِهِ الَّذِي هُوَ أَهْيَأُ وَالَّذِي هُوَ أَهْدَى وَالَّذِي هُوَ أَتْقَى","id":"Telah mengabarkan kepada kami [Nu'aim bin Hammad] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Ibnu 'Ajlan] dari ['Aun bin Abdullah] dari [Ibnu Mas'ud] Bahwasanya ia berkata: \"Apabila kalian menceritakan satu hadits dari Rasulullah sallallahu 'alaihi wa sallam, maka bayangkanlah (bahwa kalian sedang menceritakan) orang yang paling baik, paling mendapat petunjuk, dan paling bertakwa\"."},"380":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا مِسْعَرٌ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي الْبَخْتَرِيِّ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ عَلِيٍّ قَالَ إِذَا حُدِّثْتُمْ شَيْئًا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَظُنُّوا بِهِ الَّذِي هُوَ أَهْدَى وَالَّذِي هُوَ أَتْقَى وَالَّذِي هُوَ أَهْيَأُ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Mis'ar] dari ['Amr bin Murrah] dari [Abu Al Bakhtari] dari [Abu Abdur rahman As Sulami] dari [Ali] radliallahu 'anhu ia berkata: \"Apabila kalian diceritakan tentang hadits dari Rasulullah sallallahu 'alaihi wa sallam, bayangkanlah bahwa kalian sedang diceritakan tentang (sosok) yang paling mendapat petunjuk, paling bertakwa dan yang paling baik\"."},"381":{"ar":" أَخْبَرَنَا أَبُو مَعْمَرٍ إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ صَالِحِ بْنِ عُمَرَ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَ كَانَ إِذَا حَدَّثَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ فَكَانَ ابْنُ عَبَّاسٍ إِذَا حَدَّثَ قَالَ إِذَا سَمِعْتُمُونِي أُحَدِّثُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ تَجِدُوهُ فِي كِتَابِ اللَّهِ أَوْ حَسَنًا عِنْدَ النَّاسِ فَاعْلَمُوا أَنِّي قَدْ كَذَبْتُ عَلَيْهِ","id":"Telah mengabarkan kepada kami [Abu ma'mar Isma'il bin Ibrahim], dari [Shalih bin Umar] dari ['Ashim bin Kulaib] dari [ayahnya] dari [Abu Hurairah] radliallahu 'anhu ia berkata: \"Ayahku apabila menceritakan hadits dari Rasulullah sallallahu 'alaihi wa sallam selalu berkata: 'Rasulullah sallallahu 'alaihi wa sallam bersabda: 'Barangsiapa yang berdusta atas namaku dengan sengaja, hendaklah ia mempersiapkan tempat duduknya di neraka'. Dan Ibnu Abbas radliallahu 'anhu apabila menceritakan hadits ia selalu berkata: 'Apabila kalian mendengar aku menceritakan hadits dari Rasulullah sallallahu 'alaihi wa sallam, dan kalian tidak dapati dalam Kitab Allah subhanallahu wa ta'ala atau tidak baik menurut manusia, ketahuilah bahwa aku telah berdusta atasnya' \"."},"382":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ عِمْرَانَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ سُلَيْمَانَ الْأَحْوَلِ عَنْ عِكْرِمَةَ قَالَ إِنَّ أَزْهَدَ النَّاسِ فِي عَالِمٍ أَهْلُهُ","id":"Telah mengabarkan kepada kami [Abdullah bin Imran] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Sulaiman Al `Ahwal] dari ['ikrimah] ia berkata: \"Manusia paling zuhud adalah yang paling mengenal hakikatnya\"."},"383":{"ar":" أَخْبَرَنَا أَسَدُ بْنُ مُوسَى حَدَّثَنَا شُعْبَةُ عَنْ الْجُرَيْرِيِّ وَأَبِي مَسْلَمَةَ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ تَذَاكَرُوا الْحَدِيثَ فَإِنَّ الْحَدِيثَ يُهَيِّجُ الْحَدِيثَ","id":"Telah mengabarkan kepada kami [`Asad bin Musa] telah menceritakan kepada kami [Syu'bah] dari [Al Jurairi] dan [Abu Maslamah] dari [Abu Nadlrah] dari [Abu Sa'id Al Khudri] radliallahu 'anhu ia berkata: \"Hendaklah kalian mengulangi kembali (hadits-hadits tersebut), karena hadits itu menggerakkan (menjelaskan) hadits (lain) \"."},"384":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّث��نَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ تَذَاكَرُوا الْحَدِيثَ فَإِنَّ الْحَدِيثَ يُهَيِّجُ الْحَدِيثَ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Abu Nadlrah] dari [Abu Sa'id Al Hudri] ia berkata: \"Hendaklah kalian mengulangi kembali (hadits-hadits tersebut), karena hadits itu menggerakkan (menjelaskan) hadits (lain) \"."},"385":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْمَدَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو قَالَ قَالَ لِي طَاوُسٌ اذْهَبْ بِنَا نُجَالِسْ النَّاسَ","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad] telah menceritakan kepada kami [Sufyan] dari ['Amr] ia berkata: \" [Thawus] rahimahullahu pernah berkata kepadaku: \"Pergilah bersama kami, kita duduk bersama manusia (untuk mengulang kembali hadits Nabi sallallahu 'alaihi wa sallam) \"."},"386":{"ar":" أَخْبَرَنَا إِسْمَعِيلُ بْنُ أَبَانَ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ اللَّهِ الْقُمِّيُّ حَدَّثَنَا جَعْفَرُ بْنُ أَبِي الْمُغِيرَةِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَ تَذَاكَرُوا هَذَا الْحَدِيثَ لَا يَنْفَلِتْ مِنْكُمْ فَإِنَّهُ لَيْسَ مِثْلَ الْقُرْآنِ مَجْمُوعٌ مَحْفُوظٌ وَإِنَّكُمْ إِنْ لَمْ تَذَاكَرُوا هَذَا الْحَدِيثَ يَنْفَلِتْ مِنْكُمْ وَلَا يَقُولَنَّ أَحَدُكُمْ حَدَّثْتُ أَمْسِ فَلَا أُحَدِّثُ الْيَوْمَ بَلْ حَدِّثْ أَمْسِ وَلْتُحَدِّثْ الْيَوْمَ وَلْتُحَدِّثْ غَدًا","id":"Telah mengabarkan kepada kami [Isma'il bin Aban] telah menceritakan kepada kami [Ya'qub bin Abdullah Al Qummi] telah menceritakan kepada kami [Ja'far bin Abu Al Mughirah] dari [Sa'id bin Jubair] dari [Ibnu Abbas] radliallahu 'anhu ia berkata: \"Hendaklah kalian mengulang kembali hadits ini, maka ia tidak akan luput dari kalian, Karena hadits itu tidak seperti Al Qur`an yang terkumpul dan terjaga, dan jika kalian tidak mengulangi hadits ini, maka ia akan luput dari kalian, dan janganlah seseorang dari kalian mengatakan: 'Aku telah menceritakan kemarin dan sekarang aku tidak menceritakan (hadits tersebut), akan tetapi ceritakanlah hadits itu kemarin, hari ini, dan ceritakan pula besok' \"."},"387":{"ar":" أَخْبَرَنَا مَالِكُ بْنُ إِسْمَعِيلَ حَدَّثَنَا مِنْدَلُ بْنُ عَلِيٍّ حَدَّثَنِي جَعْفَرُ بْنُ أَبِي الْمُغِيرَةِ حَدَّثَنِي سَعِيدُ بْنُ جُبَيْرٍ قَالَ قَالَ ابْنُ عَبَّاسٍ رُدُّوا الْحَدِيثَ وَاسْتَذْكِرُوهُ فَإِنَّهُ إِنْ لَمْ تَذْكُرُوهُ ذَهَبَ وَلَا يَقُولَنَّ رَجُلٌ لِحَدِيثٍ قَدْ حَدَّثَهُ قَدْ حَدَّثْتُهُ مَرَّةً فَإِنَّهُ مَنْ كَانَ سَمِعَهُ يَزْدَادُ بِهِ عِلْمًا وَيَسْمَعُ مَنْ لَمْ يَسْمَعْ","id":"Telah mengabarkan kepada kami [Malik bin Isma'il] telah menceritakan kepada kami [Mindal bin Ali] ia berkata: telah menceritakan kepadaku [Ja'far bin Abu Al Mughirah] telah menceritakan kepadaku [Sa'id bin Jubair] ia berkata: [Ibnu Abbas] radliallahu 'anhu berkata: \"Kembalikanlah (ingatan kalian terhadap hadits) dan ulangilah kembali, karena jika kalian tidak mengulanginya kembali, ia akan lenyap, dan janganlah seseorang mengatakan: 'Aku telah menceritakan hadits tersebut sekali, karena barangsiapa yang mendengarnya maka akan bertambahlah ilmunya dan akan mendengar pula orang yang belum pernah mendengar'.\""},"388":{"ar":" أَخْبَرَنَا قَبِيصَةُ وَمُحَمَّدُ بْنُ يُوسُفَ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ قَالَ تَذَاكَرُوا الْحَدِيثَ فَإِنَّ ذِكْرَهُ حَيَاتُهُ","id":"Telah mengabarkan kepada kami [Qabishah] dan [Muhammad bin yusuf] keduanya berkata: telah mengabarkan kepada kami [Sufyan] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] ia berkata: 'Hendaklah kalian mengulang-ulang kembali hadits ini, karena mengingatnya merupakan kehidupan hadits tersebut\"."},"389":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ قُدَامَةَ عَنْ سُفْيَانَ بْنِ عُيَيْنَةَ عَنْ زِيَادِ بْنِ سَعْدٍ قَالَ كَانَ ابْنُ شِهَابٍ يُحَدِّثُ الْأَعْرَابَ","id":"Telah mengabarkan kepada kami [Muhammad bin Qudamah] dari [Sufyan bin 'uyainah] dari [Ziyad bin Sa'ad] ia berkata: 'Dahulu [Ibnu Syihab] menceritakan hadits kepada orang-orang Arab pedalaman\"."},"390":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَبِي عَبْدِ اللَّهِ الشَّقَرِيِّ عَنْ إِبْرَاهِيمَ قَالَ حَدِّثْ حَدِيثَكَ مَنْ يَشْتَهِيهِ وَمَنْ لَا يَشْتَهِيهِ فَإِنَّهُ يَصِيرُ عِنْدَكَ كَأَنَّهُ إِمَامٌ تَقْرَؤُهُ","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari [Abu Abdullah As Syaqari] dari [Ibrahim] ia berkata: \"Ceritakanlah haditsmu kepada orang yang menyukainya dan yang tidak menyukainya, karena ia di sisimu, seakan-akan imam yang sedang kamu baca\"."},"391":{"ar":" أَخْبَرَنَا أَبُو مَعْمَرٍ وَمُحَمَّدُ بْنُ سَعِيدٍ عَنْ عَبْدِ السَّلَامِ عَنْ حَجَّاجٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَ إِذَا سَمِعْتُمْ مِنَّا حَدِيثًا فَتَذَاكَرُوهُ بَيْنَكُمْ","id":"Telah mengabarkan kepada kami [Abu Ma'mar] dan [Muhammad bin Sa'id] dari [Abdus Salam] dari [Hajjaj] dari ['Atha`] dari [Ibnu Abbas] radliallahu 'anhu ia berkata: \"Apabila kalian mendengar sebuah hadits dari kami, hendaknya kalian mengulang kembali hadits tersebut diantara kalian\"."},"392":{"ar":" أَخْبَرَنَا أَبُو مَعْمَرٍ عَنْ هُشَيْمٍ أَخْبَرَنَا يُونُسُ قَالَ كُنَّا نَأْتِي الْحَسَنَ فَإِذَا خَرَجْنَا مِنْ عِنْدِهِ تَذَاكَرْنَا بَيْنَنَا","id":"Telah mengabarkan kepada kami [Abu Ma'mar] dari [Husyaim] telah mengabarkan kepada kami [Yunus] ia berkata: \"Kami pernah mendatangi (majlis) Al Hasan, tatkala kami keluar dari sisinya kami saling mengulang-ulang kembali (hadits tersebut) diantara kami\"."},"393":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ حُمَيْدٍ قَالَ قِيلَ لِعُمَرَ بْنِ عَبْدِ الْعَزِيزِ لَوْ جَمَعْتَ النَّاسَ عَلَى شَيْءٍ فَقَالَ مَا يَسُرُّنِي أَنَّهُمْ لَمْ يَخْتَلِفُوا قَالَ ثُمَّ كَتَبَ إِلَى الْآفَاقِ وَإِلَى الْأَمْصَارِ لِيَقْضِ كُلُّ قَوْمٍ بِمَا اجْتَمَعَ عَلَيْهِ فُقَهَاؤُهُمْ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] dari [hammad bin Salamah] dari [Humaid] ia berkata: Dikatakan kepada [Umar bin Abdul Aziz]: \"Seandainya kamu satukan manusia dalam satu paham\", kemudian ia berkata: \"Tidaklah menggembirakanku jika mereka tidak berselisih pendapat\". Kemudian ia menulis surat ke seluruh penjuru atau negeri-negeri agar setiap kaum berhukum dengan apa yang disepakati oleh para ahli fikih mereka."},"394":{"ar":" أَخْبَرَنَا يَزِيدُ عَنْ الْمَسْعُودِيِّ عَنْ عَوْنِ بْنِ عَبْدِ اللَّهِ قَالَ مَا أُحِبُّ أَنَّ أَصْحَابَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَخْتَلِفُوا فَإِنَّهُمْ لَوْ اجْتَمَعُوا عَلَى شَيْءٍ فَتَرَكَهُ رَجُلٌ تَرَكَ السُّنَّةَ وَلَوْ اخْتَلَفُوا فَأَخَذَ رَجُلٌ بِقَوْلِ أَحَدٍ أَخَذَ بِالسُّنَّةِ","id":"Telah mengabarkan kepada kami [Yazid] dari [Al Mas'udi] dari ['Aun bin Abdullah] ia berkata: \"Aku tidak suka bahwa para sahabat Nabi sallallahu 'alaihi wa sallam tidak berselisih pendapat, karena jika mereka berkumpul (sepakat) dalam satu paham lalu satu orang meninggalkannya, ia berarti telah meninggalkan sunnah, dan seandainya mereka berselisih pendapat, lalu seorang mengambil pendapat seorang ulama, ia telah mengambil sunnah\"."},"395":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا حَسَنٌ عَنْ لَيْثٍ عَنْ طَاوُسٍ قَالَ رُبَّمَا رَأَى ابْنُ عَبَّاسٍ الرَّأْيَ ثُمَّ تَرَكَهُ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Hasan] dari [Laits] dari [Thawus] ia berkata: \"Mungkin saja [Ibnu Abbas] radliallahu 'anhu mengeluarkan suatu pendapat, kemudian ia meninggalkan pendapatnya itu\". "},"396":{"ar":" أَخْبَرَنَا الْحَجَّاجُ بْنُ الْمِنْهَالِ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَنْبَأَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ عُرْوَةَ عَنْ مَرْوَانَ بْنِ الْحَكَمِ قَالَ قَالَ لِي عُثْمَانُ بْنُ عَفَّانَ إِنَّ عُمَرَ قَالَ لِي إِنِّي قَدْ رَأَيْتُ فِي الْجَدِّ رَأْيًا فَإِنْ رَأَيْتُمْ أَنْ تَتَّبِعُوهُ فَاتَّبِعُوهُ قَالَ عُثْمَانُ إِنْ نَتَّبِعْ رَأْيَكَ فَإِنَّهُ رَشَدٌ وَإِنْ نَتَّبِعْ رَأْيَ الشَّيْخِ قَبْلَكَ فَنِعْمَ ذُو الرَّأْيِ كَانَ قَالَ وَكَانَ أَبُو بَكْرٍ يَجْعَلُهُ أَبًا","id":"Telah mengabarkan kepada kami [Al Hajjaj bin Al minhal] telah menceritakan kepada kami [Hammad Ibnu Salamah], telah mengabarkan kepada kami [Hisyam bin 'Urwah] dari ['Urwah] dari [Marwan bin Al Hakam] ia berkata: \" [Utsman bin Affan] berkata kepadaku: Umar berkata kepadaku: 'Aku mempunyai suatu pendapat tentang kakek, jika kalian sependapat untuk mengikutinya, ikutilah ia. Utsman berkata: 'Jika kami mengikuti pendapatmu, itu benar, akan tetapi jika kami mengikuti pendapat syaikh sebelum kamu, ia pemilik sebaik-baik pendapat', ia berkata: ' [Abu Bakar] menjadikan kakek pada posisi bapak' \"."},"397":{"ar":" أَخْبَرَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ حَدَّثَنَا عَاصِمٌ الْأَحْوَلُ قَالَ عَرَضْتُ عَلَى الشَّعْبِيِّ أَحَادِيثَ الْفِقْهِ فَأَجَازَهَا لِي","id":"Telah mengabarkan kepada kami [Ibrahim bin Al Mundzir Al Hizami] telah menceritakan kepada kami [Marwan bin mu'awiyah] telah menceritakan kepada kami ['Ashim Al `Ahwal] ia berkata: \"Aku memaparkan hadits-hadits fikih kepada As Sya'bi, ia memperbolehkannya kepadaku.\""},"398":{"ar":" أَخْبَرَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ قَالَ قُلْتُ لِعَمْرِو بْنِ دِينَارٍ أَسَمِعْتَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِرَجُلٍ مَرَّ فِي الْمَسْجِدِ بِسِهَامٍ أَمْسِكْ بِنِصَالِهَا قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Ibrahim bin Al Mundzir] telah menceritakan kepada kami [Sufyan bin 'Uyainah] ia berkata: Aku pernah berkata kepada ['Amr bin Dinar]: \"Apakah kamu pernah dengar [Jabir bin Abdullah] ia berkata: Rasulullah sallallahu 'alaihi wa sallam bersabda kepada seorang laki-laki yang melintas di dalam masjid dengan membawa anak panah: 'Peganglah dengan busurnya? ', ia berkata: 'Ya' \"."},"399":{"ar":" أَخْبَرَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا سُفْيَانُ قَالَ قُلْتُ لِعَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ أَسَمِعْتَ أَبَاكَ يُحَدِّثُ عَنْ عَائِشَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُقَبِّلُهَا وَهُوَ صَائِمٌ قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Ibrahim bin Al Mundzir] telah menceritakan kepada kami [Sufyan] ia berkata: \"Aku pernah berkata kepada [Abdur Rahman bin Al Qasim]: 'Apakah kamu pernah mendengar [ayahmu] menceritakan hadits dari [Aisyah] radliallahu 'anha: ' Rasulullah sallallahu 'alaihi wa sallam menciumnya, sedang beliau dalam keadaan berpuasa? ', ia menjawab: 'Ya' \"."},"400":{"ar":" أَخْبَرَنَا الْحَسَنُ بْنُ أَحْمَدَ حَدَّثَنَا مِسْكِينُ بْنُ بُكَيْرٍ حَدَّثَنَا شُعْبَةُ قَالَ كَتَبَ إِلَيَّ مَنْصُورٌ بِحَدِيثٍ فَلَقِيتُهُ فَقُلْتُ أُحَدِّثُ بِهِ عَنْكَ قَالَ أَوَ لَيْسَ إِذَا كَتَبْتُ إِلَيْكَ فَقَدْ حَدَّثْتُكَ قَالَ وَسَأَلْتُ أَيُّوبَ السَّخْتِيَانِيَّ فَقَالَ مِثْلَ ذَلِكَ","id":"Telah mengabarkan kepada kami [Al Hasan bin Ahmad] telah menceritakan kepada kami [Miskin bin Bukair] telah menceritakan kepada kami [Syu'bah] ia berkata: ' [Manshur] pernah menulis hadits kepadaku, kemudian aku menemuinya dan bertanya: 'Apakah aku menceritakan hadits darimu? ', ia berkata: 'Bukankah apabila aku menulis kepadamu berarti sama artinya aku menceritakan hadits kepada kamu? ', ia menjawab: 'Dan sungguh aku pernah bertanya kepada [Ayyub As Sakhtiyani], dan ia berkata seperti itu pula' \"."},"401":{"ar":" أَخْبَرَنَا زَكَرِيَّا بْنُ عَدِيٍّ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ قَالَ عَرَضْتُ عَلَيْهِ كِتَابًا فَقُلْتُ أَرْوِيهِ عَنْكَ قَالَ وَمَنْ حَدَّثَكَ بِهِ غَيْرِي","id":"Telah mengabarkan kepada kami [Zakaria bin 'Adi] telah mengabarkan kepada kami [Abdullah bin al Mubarak] dari [Ma'mar] dari [Az Zuhri] ia berkata: \"Aku pernah memaparkan sebuah kitab kepadanya, aku (juga) bertanya: Apakah aku meriwayatkan darimu? ', ia menjawab: 'Siapakah yang menceritakan hadits kepadamu selainku' \"."},"402":{"ar":" أَخْبَرَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ حَدَّثَنَا دَاوُدُ بْنُ عَطَاءٍ مَوْلَى الْمُزَنِيِّينَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ قَالَ عَرْضُ الْكِتَابِ وَالْحَدِيثُ سَوَاءٌ","id":"Telah mengabarkan kepada kami [Ibrahim bin Al Mundzir Al Hizami] telah menceritakan kepada kami [Daud bin 'Atha`] -bekas budak Al Muzaniyyin-, telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [ayahnya] ia berkata: \"Pemaparan kitab dan hadits itu sama\"."},"403":{"ar":" أَخْبَرَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا دَاوُدُ بْنُ عَطَاءٍ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ قَالَ عَرْضُ الْكِتَابِ وَالْحَدِيثُ سَوَاءٌ","id":"Telah mengabarkan kepada kami [Ibrahim bin Al Mundzir] telah menceritaklan kepada kami [Daud bin 'Atha`] dari [Ja'far bin Muhammad] dari [ayahnya] ia berkata: \"Pemaparan kitab dan hadits adalah sama\"."},"404":{"ar":" أَخْبَرَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا دَاوُدُ بْنُ عَطَاءٍ قَالَ كَانَ زَيْدُ بْنُ أَسْلَمَ يَرَى عَرْضَ الْكِتَابِ وَالْحَدِيثَ سَوَاءً وَكَانَ ابْنُ أَبِي ذِئْبٍ يَرَى ذَلِكَ","id":"Telah mengabarkan kepada kami [Ibrahim bin Al Mundzir] telah menceritakan kepada kami [Daud bin 'Atha`] ia berkata: ' [Zaid bin Aslam] berpendapat bahwa pemaparan kitab dan hadits itu sama, dan [Ibnu Abu Dzi`b] juga berpendapat demikian\"."},"405":{"ar":" أَخْبَرَنَا إِبْرَاهِيمُ حَدَّثَنَا مُطَرِّفٌ عَنْ مَالِكِ بْنِ أَنَسٍ أَنَّهُ كَانَ يَرَى الْعَرْضَ وَالْحَدِيثَ سَوَاءً","id":"Telah mengabarkan kepada kami [Ibrahim] telah menceritakan kepada kami [Mutharrif] dari [Malik bin Anas]: \"Ia berpendapat kalau pemaparan kitab dan hadits itu sama\"."},"406":{"ar":" أَخْبَرَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ قَالَ كَانَ إِبْرَاهِيمُ يَقُولُ يَقُومُ عَنْ يَسَارِهِ فَحَدَّثْتُهُ عَنْ سُمَيْعٍ الزَّيَّاتِ عَنْ ابْنِ عَبَّاسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقَامَهُ عَنْ يَمِينِهِ فَأَخَذَ بِهِ","id":"Telah mengabarkan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] ia berkata: Ibrahim berkata: \"Pernah ia berdiri (shalat) di sebelah kirinya, lalu aku menceritakan sebuah hadits kepadanya (yang diriwayatkan) dari [Sumai' Az Zayyat] dari [Ibnu Abbas] radliallahu 'anhu, Nabi sallallahu 'alaihi wa sallam pernah menyuruhnya berdiri di sebelah kanannya saat shalat, dan menariknya ke sebelah kanannya ' \"."},"407":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ حُمَيْدٍ حَدَّثَنَا هَارُونُ بْنُ الْمُغِيرَةِ عَنْ عَنْبَسَةَ بْنِ سَعِيدٍ عَنْ خَالِدِ بْنِ زَيْدٍ الْأَنْصَارِيِّ عَنْ عَقَّارِ بْنِ الْمُغِيرَةِ بْنِ شُعْبَةَ عَنْ أَبِيهِ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَ نَشَدَ عُمَرُ النَّاسَ أَسَمِعَ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَدٌ مِنْكُمْ فِي الْجَنِينِ فَقَامَ الْمُغِيرَةُ بْنُ شُعْبَةَ فَقَالَ قَضَى فِيهِ عَبْدًا أَوْ أَمَةً فَنَشَدَ النَّاسَ أَيْضًا فَقَامَ الْمَقْضِيُّ لَهُ فَقَالَ قَضَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِي بِهِ عَبْدًا أَوْ أَمَةً فَنَشَدَ النَّاسَ أَيْضًا فَقَامَ الْمَقْضِيُّ عَلَيْهِ فَقَالَ قَضَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيَّ غُرَّةً عَبْدًا أَوْ أَمَةً فَقُلْتُ أَتَقْضِي عَلَيَّ فِيهِ فِيمَا لَا أَكَلَ وَلَا شَرِبَ وَلَا اسْتَهَلَّ وَلَا نَطَقَ أَنْ تُطِلَّهُ فَهُوَ أَحَقُّ مَا يُطَلُّ فَهَمَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْهِ بِشَيْءٍ مَعَهُ فَقَالَ أَشِعْرٌ فَقَالَ عُمَرُ لَوْلَا مَا بَلَغَنِي مِنْ قَضَاءِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَجَعَلْتُهُ دِيَةً بَيْنَ دِيَتَيْنِ","id":"Telah mengabarkan kepada kami [Muhammad bin Humaid] telah menceritakan kepada kami [Harun bin Al Mughirah] dari ['Anbasah bin Sa'id] dari [Khalid bin Sa'id Al Anshari] dari ['Aqqar bin Al Mughirah bin Syu'bah] dari ayahnya - [Al Mughirah bin Syu'bah] -, ia berkata: \"Umar pernah bersumpah dan bertanya kepada orang-orang, apakah ada salah seorang diantara kalian mendengar dari Nabi sallallahu 'alaihi wa sallam tentang masalah janin?, Mughirah bin Syu'bah kontan berdiri seraya berkata: 'Beliau memutuskan dalam masalah (janin) seperti seorang budak laki-laki atau budak perempuan', Umar bersumpah lagi, dan oknum yang terkenai gugatan berdiri sambil berkata: 'Nabi sallallahu 'alaihi wa sallam memutuskan untukku dalam masalah ini seperti budak laki-laki atau perempuan', kemudian Umar bersumpah lagi, dan oknum yang terkenai gugatan berdiri berkata: 'Nabi sallallahu 'alaihi wa sallam memutuskan atasku budak laki-laki atau perempuan', lantas aku (Mughirah bin Syu`bah) berkata: Apakah kamu (Umar) akan memberi keputusan terhadapku dalam masalah janin ini, yang ia belum bisa makan, belum bisa minum, belum bisa bersuara, belum bisa bicara, dengan hukuman engkau bunuh? Padahal janin itu sepertinya lebih berhak dibunuh?, Kemudian Nabi sallallahu 'alaihi wa sallam mengisyaratkan kepadanya dengan sesuatu yang ada padanya'. Mughirah bin Syu'bah kemudian bertanya 'Apakah ini sya`ir? ', Umar berkata: 'Sekiranya tidak sampai kepadaku keputusan Nabi sallallahu 'alaihi wa sallam, niscaya aku putuskan (yang mengugurkan kandungan) untuk membayar diyat diantara dua diyat' \". "},"408":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ قَالَ كَانَ سَلَّامٌ يَذْكُرُ عَنْ أَيُّوبَ قَالَ إِذَا أَرَدْتَ أَنْ تَعْرِفَ خَطَأَ مُعَلِّمِكَ فَجَالِسْ غَيْرَهُ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] ia berkata: \"Dahulu [Salam] pernah menyebutkan riwayat dari [Ayyub] ', ia berkata: 'Apabila kamu ingin mengetahui kesalahan gurumu, duduklah di majlis orang lain' \"."},"409":{"ar":" أَخْبَرَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا أَيُّوبُ قَالَ تَذَاكَرْنَا بِمَكَّةَ الرَّجُلَ يَمُوتُ فَقُلْتُ عِدَّتُهَا مِنْ يَوْمِ يَأْتِيهَا الْخَبَرُ لِقَوْلِ الْحَسَنِ وَقَتَادَةَ وَأَصْحَابِنَا قَالَ فَلَقِيَنِي طَلْقُ بْنُ حَبِيبٍ الْعَنَزِيُّ فَقَالَ إِنَّكَ عَلَيَّ كَرِيمٌ وَإِنَّكَ مِنْ أَهْلِ بَلَدٍ الْعَيْنُ إِلَيْهِمْ سَرِيعَةٌ وَإِنِّي لَسْتُ آمَنُ عَلَيْكَ وَإِنَّكَ قُلْتَ قَوْلًا هَا هُنَا خِلَافَ قَوْلِ أَهْلِ الْبَلَدِ وَلَسْتُ آمَنُ فَقُلْتُ وَفِي ذَا اخْتِلَافٌ قَالَ نَعَمْ عِدَّتُهَا مِنْ يَوْمِ يَمُوتُ فَلَقِيتُ سَعِيدَ بْنَ جُبَيْرٍ فَسَأَلْتُهُ فَقَالَ عِدَّتُهَا مِنْ يَوْمِ تُوُفِّيَ قَالَ وَسَأَلْتُ مُجَاهِدًا فَقَالَ عِدَّتُهَا مِنْ يَوْمِ تُوُفِّيَ وَسَأَلْتُ عَطَاءَ بْنَ أَبِي رَبَاحٍ فَقَالَ مِنْ يَوْمِ تُوُفِّيَ وَسَأَلْتُ أَبَا قِلَابَةَ فَقَالَ مِنْ يَوْمِ تُوُفِّيَ وَسَأَلْتُ مُحَمَّدَ بْنَ سِيرِينَ فَقَالَ مِنْ يَوْمِ تُوُفِّيَ وَحَدَّثَنِي نَافِعٌ أَنَّ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَ مِنْ يَوْمِ تُوُفِّيَ و سَمِعْت عِكْرِمَةَ يَقُولُ مِنْ يَوْمِ تُوُفِّيَ قَالَ وَقَالَ جَابِرُ بْنُ زَيْدٍ مِنْ يَوْمِ تُوُفِّيَ قَالَ وَكَانَ ابْنُ عَبَّاسٍ يَقُولُ مِنْ يَوْمِ تُوُفِّيَ قَالَ حَمَّادٌ وَسَمِعْتُ لَيْثًا حَدَّثَ عَنْ الْحَكَمِ أَنَّ عَبْدَ اللَّهِ بْنَ مَسْعُودٍ قَالَ مِنْ يَوْمِ تُوُفِّيَ قَالَ تُوُفِّيَ عَلِيٌّ مِنْ يَوْمِ يَأْتِيهَا الْخَبَرُ قَالَ عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَقُولُ مِنْ يَوْمِ تُوُفِّيَ","id":"Telah mengabarkan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Ayyub] ia berkata: \"Di Makkah, kami pernah sama-sama membicarakan perihal seorang laki-laki yang wafat (di sebuah negeri) dan meninggalkan seorang isteri di negeri lain. Aku berkata: 'Iddah (masa tunggu) nya dimulai dari hari pertama ia mendapatkan kabar tersebut sesuai pendapat [Al Hasan], [Qatadah], dan para sahabat kami. Ayyub melanjutkan bicara: 'Kemudian [Thalq bin Habib Al 'Anazi] bertemu denganku', kemudian ia berkata: 'Kamu adalah orang yang mulia di sisiku dan termasuk penduduk negeri yang cepat dalam menanggapi masalah yang terjadi pada mereka dan aku tidak tenang berkenaan denganmu', ia berkata: ' kamu telah mengatakan satu pendapat di sini yang bertentangan dengan pendapat penduduk negeri ini, dan aku juga tidak tenang dengan perselisihan (yang ada) ', aku bertanya: 'Dan dalam perbedaan pendapat yang ini ('iddah isteri)? ', ia menjawab: 'Ya benar, 'iddah nya sejak hari pertama (si suami) itu meninggal'. Maka aku bertemu [Sa'id bin Jubair] dan aku bertanya kepadanya, ia menjawab: 'iddah nya Sejak hari pertama ia meninggal'. Dan aku bertanya kepada [Mujahid], ia menjawab: 'iddah nya Sejak hari pertama ia meninggal'. Dan aku bertanya kepada ['Atha` bin Rabbah], ia menjawab: 'Sejak hari pertama ia meninggal', aku juga bertanya kepada [Abu Qilabah], lalu ia menjawab: 'Sejak hari pertama ia meninggal', aku juga bertanya kepada [Muhammad bin Sirin], ia menjawab: 'Sejak hari pertama ia meninggal'. Ia berkata: ' [Nafi'] telah menceritakan kepadaku bahwa [Ibnu Umar] radliallahu 'anhuma berkata: 'Sejak hari pertama ia meninggal' ', perawi berkata: 'Dan aku telah mendengar ['Ikrimah] berkata: 'Sejak hari pertama ia meninggal', ia berkata: [Jabir] telah berkata: 'Sejak hari pertama ia meninggal', ia berkata: [Ibnu Abbas] radliallahu 'anhu juga telah berkata: 'Sejak hari pertama ia meninggal', [Hammad] telah berkata: 'Aku telah mendengar [Laits] menceritakan dari [Al Hakam] bahwa [Abdullah bin Mas'ud] radliallahu 'anhu berkata: 'Sejak hari pertama ia meninggal', ia berkata: [Ali] berkata: 'Sejak hari pertama ia mendengar kabar', [Abdullah bin Abdur Rahman] berkata: 'Aku mengatakan: Sejak hari pertama ia meninggal' \"."},"410":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ حُمَيْدٍ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ مَعْمَرٍ عَنْ سِمَاكِ بْنِ الْفَضْلِ عَنْ وَهْبِ بْنِ مُنَبِّهٍ عَنْ الْحَكَمِ بْنِ مَسْعُودٍ قَالَ أَتَيْنَا عُمَرَ فِي الْمُشَرَّكَةِ فَلَمْ يُشَرِّكْ ثُمَّ أَتَيْنَاهُ الْعَامَ الْمُقْبِلَ فَشَرَّكَ فَقُلْنَا لَهُ فَقَالَ تِلْكَ عَلَى مَا قَضَيْنَا وَهَذِهِ عَلَى مَا قَضَيْنَا","id":"Telah mengabarkan kepada kami [Ahmad bin humaid] telah menceritaan kepada kami [Ibnu Al Mubarak] dari [Ma'mar] dari [Simak bin Al fadhl] dari [Wahab bin Munabbih] dari [Al Hakam bin mas'ud] ia berkata: \"Kami menemui [Umar] (untuk menanyakan tentang) musyarakah (dalam warits), diawalmulanya ia tidak berpendapat adanya musyarakah, kemudian kami menemuinya di tahun berikutnya dan beliau berpendapat adanya musyarakah, kami bertanya kepadanya (bagaimana dengan putusanmu tahun lalu), lalu ia menjawab: 'Itu sesuai dengan apa yang kami putuskan, dan ini sesuai dengan apa yang kami putuskan pula' \". "},"411":{"ar":" أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا رَوْحٌ حَدَّثَنَا حَجَّاجٌ الْأَسْوَدُ قَالَ قَالَ ابْنُ مُنَبِّهٍ كَانَ أَهْلُ الْعِلْمِ فِيمَا مَضَى يَضَنُّونَ بِعِلْمِهِمْ عَنْ أَهْلِ الدُّنْيَا فَيَرْغَبُ أَهْلُ الدُّنْيَا فِي عِلْمِهِمْ فَيَبْذُلُونَ لَهُمْ دُنْيَاهُمْ وَإِنَّ أَهْلَ الْعِلْمِ الْيَوْمَ بَذَلُوا عِلْمَهُمْ لِأَهْلِ الدُّنْيَا فَزَهِدَ أَهْلُ الدُّنْيَا فِي عِلْمِهِمْ فَضَنُّوا عَلَيْهِمْ بِدُنْيَاهُمْ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Hajjaj Al `Aswad] ia berkata: [Ibnu Munabbih] berkata: \"Para ulama zaman dahulu enggan mendatangi ahlud dunia (orang yang mencintai keduniaan) untuk menyampaikan ilmu mereka, sehingga orang yang mencintai keduniaan itu menjadi suka dengan ilmu mereka, sehingga mereka mau mengeluarkan harta untuk mereka (para ulama). Sedangkan para ulama zaman sekarang, mereka menyampaikan ilmu kepada orang yang mencintai keduniaan, hingga orang yang mencintai keduniaan itu menjadi tidak butuh dengan mereka, dan mereka pun enggan mengeluarkan harta untuk mereka (para ulama) ' \"."},"412":{"ar":" أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا مُحَمَّدُ بْنُ عُمَرَ بْنِ الْكُمَيْتِ حَدَّثَنَا عَلِيُّ بْنُ وَهْبٍ الْهَمْدَانِيُّ حَدَّثَنَا الضَّحَّاكُ بْنُ مُوسَى قَالَ مَرَّ سُلَيْمَانُ بْنُ عَبْدِ الْمَلِكِ بِالْمَدِينَةِ وَهُوَ يُرِيدُ مَكَّةَ فَأَقَامَ بِهَا أَيَّامًا فَقَالَ هَلْ بِالْمَدِينَةِ أَحَدٌ أَدْرَكَ أَحَدًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا لَهُ أَبُو حَازِمٍ يَا أَمِيرَ الْمُؤْمِنِينَ فَأَرْسَلَ إِلَيْهِ فَلَمَّا دَخَلَ عَلَيْهِ قَالَ لَهُ يَا أَبَا حَازِمٍ مَا هَذَا الْجَفَاءُ قَالَ أَبُو حَازِمٍ يَا أَمِيرَ الْمُؤْمِنِينَ وَأَيُّ جَفَاءٍ رَأَيْتَ مِنِّي قَالَ أَتَانِي وُجُوهُ أَهْلِ الْمَدِينَةِ وَلَمْ تَأْتِنِي قَالَ يَا أَمِيرَ الْمُؤْمِنِينَ أُعِيذُكَ بِاللَّهِ أَنْ تَقُولَ مَا لَمْ يَكُنْ مَا عَرَفْتَنِي قَبْلَ هَذَا الْيَوْمِ وَلَا أَنَا رَأَيْتُكَ قَالَ فَالْتَفَتَ سُلَيْمَانُ إِلَى مُحَمَّدِ بْنِ شِهَابٍ الزُّهْرِيِّ فَقَالَ أَصَابَ الشَّيْخُ وَأَخْطَأْتُ قَالَ سُلَيْمَانُ يَا أَبَا حَازِمٍ مَا لَنَا نَكْرَهُ الْمَوْتَ قَالَ لِأَنَّكُمْ أَخْرَبْتُمْ الْآخِرَةَ وَعَمَّرْتُمْ الدُّنْيَا فَكَرِهْتُمْ أَنْ تُنْقَلُوا مِنْ الْعُمْرَانِ إِلَى الْخَرَابِ قَالَ أَصَبْتَ يَا أَبَا حَازِمٍ فَكَيْفَ الْقُدُومُ غَدًا عَلَى اللَّهِ قَالَ أَمَّا الْمُحْسِنُ فَكَالْغَائِبِ يَقْدُمُ عَلَى أَهْلِهِ وَأَمَّا الْمُسِيءُ فَكَالْآبِقِ يَقْدُمُ عَلَى مَوْلَاهُ فَبَكَى سُلَيْمَانُ وَقَالَ لَيْتَ شِعْرِي مَا لَنَا عِنْدَ اللَّهِ قَالَ اعْرِضْ عَمَلَكَ عَلَى كِتَابِ اللَّهِ قَالَ وَأَيُّ مَكَانٍ أَجِدُهُ قَالَ { إِنَّ الْأَبْرَارَ لَفِي نَعِيمٍ وَإِنَّ الْفُجَّارَ لَفِي جَحِيمٍ } قَالَ سُلَيْمَانُ فَأَيْنَ رَحْمَةُ اللَّهِ يَا أَبَا حَازِمٍ قَالَ أَبُو حَازِمٍ { رَحْمَةَ اللَّهِ قَرِيبٌ مِنْ الْمُحْسِنِينَ } قَالَ لَهُ سُلَيْمَانُ يَا أَبَا حَازِمٍ فَأَيُّ عِبَادِ اللَّهِ أَكْرَمُ قَالَ أُولُو الْمُرُوءَةِ وَالنُّهَى قَالَ لَهُ سُلَيْمَانُ فَأَيُّ الْأَعْمَالِ أَفْضَلُ قَالَ أَبُو حَازِمٍ أَدَاءُ الْفَرَائِضِ مَعَ اجْتِنَابِ الْمَحَارِمِ قَالَ سُلَيْمَانُ فَأَيُّ الدُّعَاءِ أَسْمَعُ قَالَ أَبُو حَازِمٍ دُعَاءُ الْمُحْسَنِ إِلَيْهِ لِلْمُحْسِنِ قَالَ فَأَيُّ الصَّدَقَةِ أَفْضَلُ قَالَ لِلسَّائِلِ الْبَائِسِ وَجُهْدُ الْمُقِلِّ لَيْسَ فِيهَا مَنٌّ وَلَا أَذًى قَالَ فَأَيُّ الْقَوْلِ أَعْدَلُ قَالَ قَوْلُ الْحَقِّ عِنْدَ مَنْ تَخَافُهُ أَوْ تَرْجُوهُ قَالَ فَأَيُّ الْمُؤْمِنِينَ أَكْيَسُ قَالَ رَجُلٌ عَمِلَ بِطَاعَةِ اللَّهِ وَدَلَّ النَّاسَ عَلَيْهَا قَالَ فَأَيُّ الْمُؤْمِنِينَ أَحْمَقُ قَالَ رَجُلٌ انْحَطَّ فِي هَوَى أَخِيهِ وَهُوَ ظَالِمٌ فَبَاعَ آخِرَتَهُ بِدُنْيَا غَيْرِهِ قَالَ لَهُ سُلَيْمَانُ أَصَبْتَ فَمَا تَقُولُ فِيمَا نَحْنُ فِيهِ قَالَ يَا أَمِيرَ الْمُؤْمِنِينَ أَوَ تُعْفِينِي قَالَ لَهُ سُلَيْمَانُ لَا وَلَكِنْ نَصِيحَةٌ تُلْقِيهَا إِلَيَّ قَالَ يَا أَمِيرَ الْمُؤْمِنِينَ إِنَّ آبَاءَكَ قَهَرُوا النَّاسَ بِالسَّيْفِ وَأَخَذُوا هَذَا الْمُلْكَ عَنْوَةً عَلَى غَيْرِ مَشُورَةٍ مِنْ الْمُسْلِمِينَ وَلَا رِضَاهُمْ حَتَّى قَتَلُوا مِنْهُمْ مَقْتَلَةً عَظِيمَةً فَقَدْ ارْتَحَلُوا عَنْهَا فَلَوْ أُشْعِرْتَ مَا قَالُوا وَمَا قِيلَ لَهُمْ فَقَالَ لَهُ رَجُلٌ مِنْ جُلَسَائِهِ بِئْسَ مَا قُلْتَ يَا أَبَا حَازِمٍ قَالَ أَبُو حَازِمٍ كَذَبْتَ إِنَّ اللَّهَ أَخَذَ مِيثَاقَ الْعُلَمَاءِ لَيُبَيِّنُنَّهُ لِلنَّاسِ وَلَا يَكْتُمُونَهُ قَالَ لَهُ سُلَيْمَانُ فَكَيْفَ لَنَا أَنْ نُصْلِحَ قَالَ تَدَعُونَ الصَّلَفَ وَتَمَسَّكُونَ بِالْمُرُوءَةِ وَتَقْسِمُونَ بِالسَّوِيَّةِ قَالَ لَهُ سُلَيْمَانُ كَيْفَ لَنَا بِالْمَأْخَذِ بِهِ قَالَ أَبُو حَاَزِمٍ تَأْخُذُهُ مِنْ حِلِّهِ وَتَضَعُهُ فِي أَهْلِهِ قَالَ لَهُ سُلَيْمَانُ هَلْ لَكَ يَا أَبَا حَازِمٍ أَنْ تَصْحَبَنَا فَتُصِيبَ مِنَّا وَنُصِيبَ مِنْكَ قَالَ أَعُوذُ بِاللَّهِ قَالَ لَهُ سُلَيْمَانُ وَلِمَ ذَاكَ قَالَ أَخْشَى أَنْ أَرْكَنَ إِلَيْكُمْ شَيْئًا قَلِيلًا فَيُذِيقَنِي اللَّهُ ضِعْفَ الْحَيَاةِ وَضِعْفَ الْمَمَاتِ قَالَ لَهُ سُلَيْمَانُ ارْفَعْ إِلَيْنَا حَوَائِجَكَ قَالَ تُنْجِينِي مِنْ النَّارِ وَتُدْخِلُنِي الْجَنَّةَ قَالَ سُلَيْمَانُ لَيْسَ ذَاكَ إِلَيَّ قَالَ أَبُو حَازِمٍ فَمَا لِي إِلَيْكَ حَاجَةٌ غَيْرُهَا قَالَ فَادْعُ لِي قَالَ أَبُو حَازِمٍ اللَّهُمَّ إِنْ كَانَ سُلَيْمَانُ وَلِيَّكَ فَيَسِّرْهُ لِخَيْرِ الدُّنْيَا وَالْآخِرَةِ وَإِنْ كَانَ عَدُوَّكَ فَخُذْ بِنَاصِيَتِهِ إِلَى مَا تُحِبُّ وَتَرْضَى قَالَ لَهُ سُلَيْمَانُ قَطُّ قَالَ أَبُو حَازِمٍ قَدْ أَوْجَزْتُ وَأَكْثَرْتُ إِنْ كُنْتَ مِنْ أَهْلِهِ وَإِنْ لَمْ تَكُنْ مِنْ أَهْلِهِ فَمَا يَنْفَعُنِي أَنْ أَرْمِيَ عَنْ قَوْسٍ لَيْسَ لَهَا وَتَرٌ قَالَ لَهُ سُلَيْمَانُ أَوْصِنِي قَالَ سَأُوصِيكَ وَأُوجِزُ عَظِّمْ رَبَّكَ وَنَزِّهْهُ أَنْ يَرَاكَ حَيْثُ نَهَاكَ أَوْ يَفْقِدَكَ حَيْثُ أَمَرَكَ فَلَمَّا خَرَجَ مِنْ عِنْدِهِ بَعَثَ إِلَيْهِ بِمِائَةِ دِينَارٍ وَكَتَبَ إِلَيْهِ أَنْ أَنْفِقْهَا وَلَكَ عِنْدِي مِثْلُهَا كَثِيرٌ قَالَ فَرَدَّهَا عَلَيْهِ وَكَتَبَ إِلَيْهِ يَا أَمِيرَ الْمُؤْمِنِينَ أُعِيذُكَ بِاللَّهِ أَنْ يَكُونَ سُؤَالُكَ إِيَّايَ هَزْلًا أَوْ رَدِّي عَلَيْكَ بَذْلًا وَمَا أَرْضَاهَا لَكَ فَكَيْفَ أَرْضَاهَا لِنَفْسِي وَكَتَبَ إِلَيْهِ إِنَّ مُوسَى بْنَ عِمْرَانَ لَمَّا وَرَدَ مَاءَ مَدْيَنَ وَجَدَ عَلَيْهَا رِعَاءً يَسْقُونَ وَوَجَدَ مِنْ دُونِهِمْ جَارِيَتَيْنِ تَذُودَانِ فَسَأَلَهُمَا فَقَالَتَا { لَا نَسْقِي حَتَّى يُصْدِرَ الرِّعَاءُ وَأَبُونَا شَيْخٌ كَبِيرٌ فَسَقَى لَهُمَا ثُمَّ تَوَلَّى إِلَى الظِّلِّ فَقَالَ رَبِّ إِنِّي لِمَا أَنْزَلْتَ إِلَيَّ مِنْ خَيْرٍ فَقِيرٌ } وَذَلِكَ أَنَّهُ كَانَ جَائِعًا خَائِفًا لَا يَأْمَنُ فَسَأَلَ رَبَّهُ وَلَمْ يَسْأَلْ النَّاسَ فَلَمْ يَفْطِنْ الرِّعَاءُ وَفَطِنَتْ الْجَارِيتَانِ فَلَمَّا رَجَعَتَا إِلَى أَبِيهِمَا أَخْبَرَتَاهُ بِالْقِصَّةِ وَبِقَوْلِهِ فَقَالَ أَبُوهُمَا وَهُوَ شُعَيْبٌ هَذَا رَجُلٌ جَائِعٌ فَقَالَ لِإِحْدَاهُمَا اذْهَبِي فَادْعِيهِ فَلَمَّا أَتَتْهُ عَظَّمَتْهُ وَغَطَّتْ وَجْهَهَا وَقَالَتْ { إِنَّ أَبِي يَدْعُوكَ لِيَجْزِيَكَ أَجْرَ مَا سَقَيْتَ لَنَا } فَشَقَّ عَلَى مُوسَى حِينَ ذَكَرَتْ { أَجْرَ مَا سَقَيْتَ لَنَا } وَلَمْ يَجِدْ بُدًّا مِنْ أَنْ يَتْبَعَهَا إِنَّهُ كَانَ بَيْنَ الْجِبَالِ جَائِعًا مُسْتَوْحِشًا فَلَمَّا تَبِعَهَا هَبَّتْ الرِّيحُ فَجَعَلَتْ تَصْفِقُ ثِيَابَهَا عَلَى ظَهْرِهَا فَتَصِفُ لَهُ عَجِيزَتَهَا وَكَانَتْ ذَاتَ عَجُزٍ وَجَعَلَ مُوسَى يُعْرِضُ مَرَّةً وَيَغُضُّ أُخْرَى فَلَمَّا عِيلَ صَبْرُهُ نَادَاهَا يَا أَمَةَ اللَّهِ كُونِي خَلْفِي وَأَرِينِي السَّمْتَ بِقَوْلِكِ ذَا فَلَمَّا دَخَلَ عَلَى شُعَيْبٍ إِذَا هُوَ بِالْعَشَاءِ مُهَيَّأً فَقَالَ لَهُ شُعَيْبٌ اجْلِسْ يَا شَابُّ فَتَعَشَّ فَقَالَ لَهُ مُوسَى أَعُوذُ بِاللَّهِ فَقَالَ لَهُ شُعَيْبٌ لِمَ أَمَا أَنْتَ جَائِعٌ قَالَ بَلَى وَلَكِنِّي أَخَافُ أَنْ يَكُونَ هَذَا عِوَضًا لِمَا سَقَيْتُ لَهُمَا وَإِنَّا مِنْ أَهْلِ بَيْتٍ لَا نَبِيعُ شَيْئًا مِنْ دِينِنَا بِمِلْءِ الْأَرْضِ ذَهَبًا فَقَالَ لَهُ شُعَيْبٌ لَا يَا شَابُّ وَلَكِنَّهَا عَادَتِي وَعَادَةُ آبَائِي نُقْرِي الضَّيْفَ وَنُطْعِمُ الطَّعَامَ فَجَلَسَ مُوسَى فَأَكَلَ فَإِنْ كَانَتْ هَذِهِ الْمِائَةُ دِينَارٍ عِوَضًا لِمَا حَدَّثْتُ فَالْمَيْتَةُ وَالدَّمُ وَلَحْمُ الْخِنْزِيرِ فِي حَالِ الِاضْطِرَارِ أَحَلُّ مِنْ هَذِهِ وَإِنْ كَانَ لِحَقٍّ لِي فِي بَيْتِ الْمَالِ فَلِي فِيهَا نُظَرَاءُ فَإِنْ سَاوَيْتَ بَيْنَنَا وَإِلَّا فَلَيْسَ لِي فِيهَا حَاجَةٌ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [Muhammad bin Umar bin Al Kumait] telah menceritakan kepada kami [Ali bin Wahab Al Hamdani] telah menceritakan kepada kami [Adl Dlahak bin Musa] ia berkata: \"Sulaiman bin 'Abdul Malik melewati kota Madinah dan ingin menuju kota Makkah, lalu ia tinggal di Madinah beberapa hari, kemudian ia berkata: 'Apakah di Madinah ada seorang yang pernah bertemu salah seorang sahabat Nabi sallallahu 'alaihi wa sallam? ', mereka menjawab: 'Ada, Abu Hazim wahai amirul mukminin.\" Lalu ia mengutus seseorang untuk menjemput Abu Hazim. Tatkala Abu Hazim sampai ke Sulaiman bin'Abdul Malik. Sulaiman bertanya: 'Wahai Abu Hazim, Apa maksud sikap ketusmu ini? ', [Abu Hazim] menjawab: 'Wahai amirul mu`minin, sikap ketus seperti apa yang kamu lihat dariku? ', ia menjawab: 'Begini, kulihat para penduduk Madinah menemui aku, tetapi kamu tidak mau menemui diriku.' Lalu ia menjawab: 'Wahai amirul mu`minin, aku berdo`a semoga Allah subhanallahu wa ta'ala melindungi kamu untuk tidak mengatakan apa yang tidak terjadi sebenarnya, kamu tidak mengenal sebelum hari ini dan aku pun tidak pernah melihatmu (sebelumnya) '. Dhahak bin Musa mengatakan: 'Lalu Sulaiman menoleh kepada Muhammad bin Syihab Az Zuhri', seraya berkata: 'Syaikh ini, -Abu Hazim-, ia benar dan aku yang salah', Sulaiman berkata: 'Wahai Abu Hazim, Mengapa kita membenci kematian? ', Ia menjawab: 'Karena kita menghancurkan akhirat dan membangun dunia, sehingga kalian membenci untuk berpindah dari pembangunan menuju penghancuran'. Sulaiman menjawab: 'Kamu benar, wahai Abu hazim, bagaimana kita besok menghadap Allah subhanallahu wa ta'ala,? ', ia menjawab: 'Adapun orang yang baik, ia mendatangi Allah subhanallahu wa ta'ala seperti orang yang sekian lama tidak bertemu keluarganya, sedangkan orang yang jahat, ia seperti budak yang lari mendatangi tuannya', Mendengar perkataan ini Sulaiman menangis, ia bertanya: 'Aku bersumpah, apa bekal kita di sisi Allah subhanallahu wa ta'ala? ', Ia menjawab: 'Sesuaikan amal perbuatanmu dengan Kitab Allah subhanallahu wa ta'ala. Lalu ia bertanya: 'Di ayat manakah aku dapat mendapatinya? ', ia menjawab: \"INNAL `ABRARA LAFII NA'IM, WA INNAL FUJJARA LAFII JAHIIM\" (orang-orang yang banyak berbakti benar-benar berada dalam surga yang penuh dengan kenikmatan, dan orang-orang yang durhaka benar-benar berada dalam neraka) -Qs. Al Infithar: 13, 14-. Sulaiman bertanya lagi: 'Dimanakah rahmat Allah subhanallahu wa ta'ala? ', ia menjawab: 'Rahmat Allah subhanallahu wa ta'ala lebih dekat kepada orang-orang yang berbakti', Sulaiman bertanya: 'Wahai Abu hazim, siapakah hamba Allah subhanallahu wa ta'ala yang paling mulia? ', ia menjawab: 'Orang-orang yang memiliki rasa kemanusiaan dan memiliki akal', Sulaiman bertanya: 'Amal perbuatan apa yang paling utama? ', Abu Hazim menjawab: 'Melaksanakan kewajiban dibarengi meninggalkan semua hal yang diharamkan', Sulaiman terus bertanya: 'Do`a apa yang paling didengar? ', Abu Hazim menjawab: 'Do`a orang yang diberi kebajikan untuk orang yang memberikan kebajikan', ia bertanya lagi: 'Sedekah apa yang paling utama? ', ia menjawab: 'Sedekah untuk peminta-minta yang sangat membutuhkan dan pemberian orang yang sangat sedikit hartanya tanpa mengungkit-ungkit kebajikannya dan tanpa kata yang menyakitkan', ia bertanya lagi: 'Perkataan apa yang paling adil? ', ia menjawab: 'Berkata benar terhadap orang yang kamu takuti atau terhadap orang yang kamu harapkan', ia bertanya lagi: 'Siapakah orang beriman yang cerdik? ', ia menjawab: 'Seorang yang melakukan ketaatan kepada Allah subhanallahu wa ta'ala dan menunjukkan manusia kepada ketaatan itu', ia bertanya: 'Siapakah orang beriman yang bodoh? ', ia menjawab: 'Seorang yang jatuh (tunduk) pada nafsu saudaranya yang dzalim, ia menjual akhiratnya dengan dunia orang lain'. Sulaiman berkata kepadanya: 'kamu benar, bagaimana pendapatmu tentang kondisi kami sekarang ini? ', ia menjawab: 'Wahai amirul mu`minin, apakah engkau memaafkan aku? ', Sulaiman menjawab: 'Tidak, tapi itu betul-betul nasehat yang kau campakkan kepadaku! ', Abu Hazim berkata: 'Wahai amirul mu`minin, para leluhurmu telah menindas manusia dengan pedang, dan mengambil kekuasaan secara paksa tanpa bermusyawarah kepada kaum muslimin dan tanpa meminta kerelaan mereka, hingga mereka (leluhurmu) membunuh mereka dengan pembunuhan besar-besaran (masal) dan sungguh mereka telah pergi meninggalkannya, Ohhh,,,,, seandainya kamu merasakan apa yang mereka katakan dan kritikan untuk mereka itu! \"'. Salah seorang dari anggota majelis khalifah berkata kepadanya: 'Alangkah buruknya perkataanmu, wahai Abu Hazim', Abu Hazim menjawab: 'Kamu telah berdusta, Allah subhanallahu wa ta'ala telah mengambil perjanjian dari para ulama`agar mereka menjelaskannya kepada manusia dan tidak menyembunyikannya sedikitpun', Sulaiman berkata kepadanya: 'Bagaimana cara kami memperbaikinya? ', ia menjawabnya: 'Menjauhkan sikap berpura-pura dan berpedoman dengan sikap kemanusiaan serta tidak ada lagi diskriminasi', Sulaiman bertanya lagi: 'Bagaimana cara kami memperaktekkannya? ', Abu Hazim menjawab: 'Kamu mengambilnya dari hal yang halal dan meletakkannya pada mereka yang berhak menerimanya'. Sulaiman berkata kepadanya: 'Wahai Abu Hazim, apakah kamu berkenan menyertai kami, hingga kamu dapat membenarkan kesalahan kami dan kami dapat membenarkan kesalahanmu? ', ia berkata: 'Aku berlindung kepada Allah subhanallahu wa ta'ala', Sulaiman bertanya: 'Mengapa harus demikian? ', ia menjawab: 'Karena aku takut cenderung berpihak kepadamu walau sedikit saja, niscaya Allah subhanallahu wa ta'ala akan menimpakan kepadaku kelemahan hidup dan kelemahan (diri dalam menghadapi) kematian', Sulaiman berkata kepadanya: 'Katakanlah kepada kami (apa saja) keperluan kamu? ', ia menjawab: 'Kamu selamatkan aku dari neraka dan masukkanlah aku ke dalam surga', Sulaiman menjawab: 'Itu bukanlah permohonan kepadaku', Abu Hazim berkata: 'Jika demikian, aku tidak memiliki keperluan darimu', Sulaiman berkata: 'Wahai Abu hazim, doakanlah aku! ', Abu Hazim lantas berdo`a: 'Ya Allah jika Sulaiman adalah waliMu, mudahkan ia untuk kebaikan dunia akhirat, dan jika ia adalah musuhMu, tariklah ubun-ubunnya ke jalan yang Engkau cintai dan ridlai'. Sulaiman bertanya: 'Hanya itu saja' Abu Hazim menjawab: 'Maaf aja,,,, telah kuperingkas nasehat ini dan aku telah banyak bicara, kiranya kamu termasuk orang yang insyaf terhadap nasehatku ini, kalaulah tidak, apa manfaatku melontar panah dari busur yang tidak memiliki tali senar'. Sulaiman berkata kepadaku: 'Nasehatilah aku! ', ia menjawab: 'Aku mau menasehati kamu dengan nasehat yang ringkas: Agungkanlah Tuhanmu, dan sucikanlah Dia, karena Dia melihatmu di tempat tinggal-Nya yang Dia pergunakan untuk melarangmu, dan Dia bisa mengintaimu ditempat Dia memerintahkanmu'. Ketika itu Sualiman bin Abdul Malik keluar dari sisinya Abu Hazim), ia mengirim kepadanya seratus dinar dan menuliskan surat yang isinya: 'Infaklah uang itu dan kamu masih mendapatkan tambahan yang sama di sisiku', perawi berkata: 'Abu Hazim mengembalikan uang itu dan menulis surat yang isinya: 'Wahai amirul mu`minin, aku mohon perlindungan kepada Allah subhanallahu wa ta'ala untukmu jika permintaanmu kepadaku hanyalah sekedar dagelan (lelucon) atau jawabanku adalah pengorbanan. Suatu hal yang aku tidak merelakannya untukmu, bagaimana mungkin aku merelakannya untuk diriku sendiri?\"', dan ia menulis surat kepadanya: 'Bahwa Musa bin Imran 'alaihissalam ketika sampai di mata air negeri Madyan, di sana ia menjumpai sekumpulan orang yang sedang memberi minum ternak mereka, ia dapati di belakang orang banyak itu dua orang wanita sedang menambatkan ternaknya, lalu ia menanyakan keduanya, keduanya menjawab: 'Kami tidak dapat memberi minum ternak kami sebelum pengembala-pengembala itu membawa pulang ternak mereka, sedangkan ayah kami adalah orang tua yang sudah lanjut usia', Musa 'alaihissalam membari minum pada ternak (keduanya) dengan niyatan menolong. Ia pergi berteduh seraya berdo`a: 'Ya Tuhanku, aku sangat memerlukan sesuatu kebaikan yang Engkau turunkan kepadaku', hal itu karena ia lapar dan dalam keadaan takut serta tidak merasa aman, ia berdo`a kepada Tuhannya dan tidak meminta kepada manusia. Para pengembala tidak memperhatikannya tapi kedua wanita itu justru memperhatikannya', ketika keduanya kembali kepada ayahnya, keduanya mengabarkan kisah dan perkataannya, lalu bapaknya (Syu'aib) berkata: 'Ini orang lapar', lalu ia berkata kepada salah seorang dari kedua putrinya: 'Panggilah orang itu! ', ketika ia (Musa) menemuinya, ia menghormati Musa dan menutup wajahnya, dan berkata: 'Ayahku memanggilmu untuk memberi upah terhadap kebaikanmu memberi minum ternak kami'. Berat terasa bagi Musa 'alaihissalam ketika wanita itu menyebut upah memberi minum ternak, akan tetapi ia tidak menemukan jalan lain kecuali mengikutinya, karena dalam kondisi lapar sekali diantara barisan gunung. Ketika ia mengikutinya, angin kencang menerpa sehingga melekatkan pakaiannya pada punggungnya, lalu nampak oleh Musa 'alaihissalam lekukan pantatnya dan ia adalah seorang wanita yang memiliki pantat besar, sehingga Musa 'alaihissalam sekali berpaling dan sekali menundukkan pandangan ketika kesabarannya melemah, ia memanggilnya: 'Wahai hamba Allah subhanallahu wa ta'ala, berjalanlah kamu di belakangku dan tunjukkanlah aku jalan dengan ucapan ini', Ketika ia sampai dan bertemu Syu'aib dan telah dipersiapkan baginya makan malam, Syu'aib berkata kepadanya: 'Niscaya kamu akan aman'. Musa 'alaihissalam berkata kepadanya: 'Aku berlindung kepada Allah subhanallahu wa ta'ala', Syu'aib bertanya: 'Kenapa?, bukankah kamu lapar? ', ia menjawab: 'Ya, tapi aku takut kalau ini merupakan imbalan memberi minum ternak keduanya, dan aku anggota keluarga yang tidak menjual sedikitpun dari agama kami dengan emas seisi bumi pun', Syu'aib berkata kepadanya: 'Tidak, wahai pemuda! Tetapi ini adalah kebiasaanku dan nenek moyangku, kami menyuguhkan tamu dan memberi makan, lalu Musa 'alaihissalam duduk dan makan. Jika seratus dinar ini sebagai imbalan apa yang telah terjadi, bangkai, darah dan daging babi dalam kondiksi terpaksa lebih halal dari pada uang ini, dan jika uang itu dimasukkan ke baitulmaal, aku memiliki para pengatur di dalamnya. Ini jika kamu mau membereskan persoalan diantara kita, dan jika tidak, aku juga tidak membutuhkan uang itu' \"."},"413":{"ar":" أَخْبَرَنَا أَبُو عُثْمَانَ الْبَصْرِيُّ عَنْ عَبْدِ الْعَزِيزِ بْنِ مُسْلِمٍ الْقَسْمَلِيِّ أَخْبَرَنَا زَيْدٌ الْعَمِّيُّ عَنْ بَعْضِ الْفُقَهَاءِ أَنَّهُ قَالَ يَا صَاحِبَ الْعِلْمِ اعْمَلْ بِعِلْمِكَ وَأَعْطِ فَضْلَ مَالِكَ وَاحْبِسْ الْفَضْلَ مِنْ قَوْلِكَ إِلَّا بِشَيْءٍ مِنْ الْحَدِيثِ يَنْفَعُكَ عِنْدَ رَبِّكَ يَا صَاحِبَ الْعِلْمِ إِنَّ الَّذِي عَلِمْتَ ثُمَّ لَمْ تَعْمَلْ بِهِ قَاطِعٌ حُجَّتَكَ وَمَعْذِرَتَكَ عِنْدِ رَبِّكَ إِذَا لَقِيتَهُ يَا صَاحِبَ الْعِلْمِ إِنَّ الَّذِي أُمِرْتَ بِهِ مِنْ طَاعَةِ اللَّهِ لَيَشْغَلُكَ عَمَّا نُهِيتَ عَنْهُ مِنْ مَعْصِيَةِ اللَّهِ يَا صَاحِبَ الْعِلْمِ لَا تَكُونَنَّ قَوِيًّا فِي عَمَلِ غَيْرِكَ ضَعِيفًا فِي عَمَلِ نَفْسِكَ يَا صَاحِبَ الْعِلْمِ لَا يَشْغَلَنَّكَ الَّذِي لِغَيْرِكَ عَنْ الَّذِي لَكَ يَا صَاحِبَ الْعِلْمِ جَالِسْ الْعُلَمَاءَ وَزَاحِمْهُمْ وَاسْتَمِعْ مِنْهُمْ وَدَعْ مُنَازَعَتَهُمْ يَا صَاحِبَ الْعِلْمِ عَظِّمْ الْعُلَمَاءَ لِعِلْمِهِمْ وَصَغِّرْ الْجُهَّالَ لِجَهْلِهِمْ وَلَا تُبَاعِدْهُمْ وَقَرِّبْهُمْ وَعَلِّمْهُمْ يَا صَاحِبَ الْعِلْمِ لَا تُحَدِّثْ بِحَدِيثٍ فِي مَجْلِسٍ حَتَّى تَفْهَمَهُ وَلَا تُجِبْ امْرَأً فِي قَوْلِهِ حَتَّى تَعْلَمَ مَا قَالَ لَكَ يَا صَاحِبَ الْعِلْمِ لَا تَغْتَرَّ بِاللَّهِ وَلَا تَغْتَرَّ بِالنَّاسِ فَإِنَّ الْغِرَّةَ بِاللَّهِ تَرْكُ أَمْرِهِ وَالْغِرَّةَ بِالنَّاسِ اتِّبَاعُ أَهْوَائِهِمْ وَاحْذَرْ مِنْ اللَّهِ مَا حَذَّرَكَ مِنْ نَفْسِهِ وَاحْذَرْ مِنْ النَّاسِ فِتْنَتَهُمْ يَا صَاحِبَ الْعِلْمِ إِنَّهُ لَا يَكْمُلُ ضَوْءُ النَّهَارِ إِلَّا بِالشَّمْسِ كَذَلِكَ لَا تَكْمُلُ الْحِكْمَةُ إِلَّا بِطَاعَةِ اللَّهِ يَا صَاحِبَ الْعِلْمِ إِنَّهُ لَا يَصْلُحُ الزَّرْعُ إِلَّا بِالْمَاءِ وَالتُّرَابِ كَذَلِكَ لَا يَصْلُحُ الْإِيمَانُ إِلَّا بِالْعِلْمِ وَالْعَمَلِ يَا صَاحِبَ الْعِلْمِ كُلُّ مُسَافِرٍ مُتَزَوِّدٌ وَسَيَجِدُ إِذَا احْتَاجَ إِلَى زَادِهِ مَا تَزَوَّدَ وَكَذَلِكَ سَيَجِدُ كُلُّ عَامِلٍ إِذَا احْتَاجَ إِلَى عَمَلِهِ فِي الْآخِرَةِ مَا عَمِلَ فِي الدُّنْيَا يَا صَاحِبَ الْعِلْمِ إِذَا أَرَادَ اللَّهُ أَنْ يَحُضَّكَ عَلَى عِبَادَتِهِ فَاعْلَمْ أَنَّهُ إِنَّمَا أَرَادَ أَنْ يُبَيِّنَ لَكَ كَرَامَتَكَ عَلَيْهِ فَلَا تَحَوَّلَنَّ إِلَى غَيْرِهِ فَتَرْجِعَ مِنْ كَرَامَتِهِ إِلَى هَوَانِهِ يَا صَاحِبَ الْعِلْمِ إِنَّكَ إِنْ تَنْقُلْ الْحِجَارَةَ وَالْحَدِيدَ أَهْوَنُ عَلَيْكَ مِنْ أَنْ تُحَدِّثَ مَنْ لَا يَعْقِلُ حَدِيثَكَ وَمَثَلُ الَّذِي يُحَدِّثُ مَنْ لَا يَعْقِلُ حَدِيثَهُ كَمَثَلِ الَّذِي يُنَادِي الْمَيِّتَ وَيَضَعُ الْمَائِدَةَ لِأَهْلِ الْقُبُورِ","id":"Telah mengabarkan kepada kami [Abu Utsman Al Bashri] dari [Abdul Aziz bin Muslim Al Qasmali] telah mengabarkan kepada kami [Zaid Al 'Ammi] dari [beberapa ulama fikih], ia berkata: 'Wahai orang berilmu, amalkan ilmumu, berikan kelebihan hartamu, dan tahanlah kelebihan perkataanmu kecuali sedikit pembicaraan, akan bermanfaat bagimu di sisi Tuhanmu. Wahai orang berilmu, sesuatu yang kamu ketahui tetapi tidak kamu amalkan adalah pemotong argumentasi dan alasanmu di sisi Tuhanmu ketika kamu menemui-Nya. Wahai orang berilmu, taat kepada Allah yang diperintahkan kepadamu sebenarnya telah menyibukkanmu dari maksiat kepada Allah yang dilarang untukmu. Wahai orang berilmu, janganlah kamu menjadi orang kuat yang meneropong perbuatan orang lain, namun kamu sendiri manusia lemah dalam mengerjakan (suatu amal) untuk dirimu sendiri. Wahai orang berilmu, janganlah apa yang dimiliki orang lain, membuatmu lupa terhadap apa yang kamu miliki. Wahai orang berilmu, ajaklah bicara para `ulama, bergaulah dengan mereka dan dengarkanlah perkataan mereka dan janganlah kamu menentangnya. Wahai orang berilmu, agungkanlah ulama karena ilmu mereka dan janganlah kamu menghormati orang-orang bodoh karena kebodohan mereka, namun jangan menjauhi mereka, tetapi dekatilah dan ajarilah mereka. Wahai orang berilmu, janganlah kamu membicarakan suatu hadits di suatu majelis sehingga kamu betul-betul memahaminya, dan janganlah menjawab pertanyaan orang hingga engkau tahu persis apa yang diucapkannya kepadamu. Wahai orang berilmu, janganlah kamu tertipu oleh Allah dan jangan pula kamu tertipu oleh manusia. Tertipu oleh Allah maksudnya meninggalkan perintah-Nya, dan tertipu oleh manusia maksudnya mengikuti hawa nafsu mereka. Takutlah kepada Allah dalam semua hal yang Dia mengajakmu takut terhadap diri-Nya, dan hindarilah manusia karena fitnah mereka. Wahai orang berilmu, cahaya siang tidaklah sempurna kecuali dengan matahari, begitu pula hikmah tidak sempurna kecuali dengan menaati Allah subhanallahu wa ta'ala. Wahai orang berilmu, tanaman tidak baik kecuali dengan air dan tanah, begitu pula dengan iman tidak baik kecuali dengan ilmu dan amal. Wahai orang berilmu, setiap musafir haruslah berbekal, dan ia dapatkan bekalnya apabila ia dibutuhkannya, begitu pula dengan setiap orang yang beramal, di akhirat akan ia dapatkan apa yang telah diperbuatnya di dunia apabila ia butuhkan amal perbuatannya. Wahai orang berilmu, Apabila Allah subhanallahu wa ta'ala berkehendak mendorongmu dalam beribadah kepadaNya, ketahuilah bahwa Dia ingin menampakkan karamah-Nya terhadapmu, maka janganlah kamu mengalihkannya kepada selainNya, sehingga kamu tinggalkan kemuliaanNya dan malah kamu dapatkan kehinaan hidup. Wahai orang berilmu, Jika kamu memindahkan batu atau besi, itu lebih ringan bagimu daripada berbicara kepada orang yang tidak menerima pembicaraanmu, perumpamaan orang yang berbicara kepada orang yang tidak menerima pembicaraannya adalah seperti orang yang memanggil orang mati dan meletakkan hidangan untuk penghuni kubur\". "},"414":{"ar":" أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ سُلَيْمَانَ أَبُو عَبْدِ الرَّحْمَنِ الْأَنْطَاكِيُّ عَنْ عَبَّادِ بْنِ عَبَّادٍ الْخَوَّاصِ الشَّامِيِّ أَبِي عُتْبَةَ قَالَ أَمَّا بَعْدُ اعْقِلُوا وَالْعَقْلُ نِعْمَةٌ فَرُبَّ ذِي عَقْلٍ قَدْ شُغِلَ قَلْبُهُ بِالتَّعَمُّقِ عَمَّا هُوَ عَلَيْهِ ضَرَرٌ عَنْ الِانْتِفَاعِ بِمَا يَحْتَاجُ إِلَيْهِ حَتَّى صَارَ عَنْ ذَلِكَ سَاهِيًا وَمِنْ فَضْلِ عَقْلِ الْمَرْءِ تَرْكُ النَّظَرِ فِيمَا لَا نَظَرَ فِيهِ حَتَّى لَا يَكُونَ فَضْلُ عَقْلِهِ وَبَالًا عَلَيْهِ فِي تَرْكِ مُنَافَسَةِ مَنْ هُوَ دُونَهُ فِي الْأَعْمَالِ الصَّالِحَةِ أَوْ رَجُلٍ شُغِلَ قَلْبُهُ بِبِدْعَةٍ قَلَّدَ فِيهَا دِينَهُ رِجَالًا دُونَ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ اكْتَفَى بِرَأْيِهِ فِيمَا لَا يَرَى الْهُدَى إِلَّا فِيهَا وَلَا يَرَى الضَّلَالَةَ إِلَّا بِتَرْكِهَا يَزْعُمُ أَنَّهُ أَخَذَهَا مِنْ الْقُرْآنِ وَهُوَ يَدْعُو إِلَى فِرَاقِ الْقُرْآنِ أَفَمَا كَانَ لِلْقُرْآنِ حَمَلَةٌ قَبْلَهُ وَقَبْلَ أَصْحَابِهِ يَعْمَلُونَ بِمُحْكَمِهِ وَيُؤْمِنُونَ بِمُتَشَابِهِهِ وَكَانُوا مِنْهُ عَلَى مَنَارٍ كَوَضَحِ الطَّرِيقِ فَكَانَ الْقُرْآنُ إِمَامَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ رَسُولُ اللَّهِ إِمَامًا لِأَصْحَابِهِ وَكَانَ أَصْحَابُهُ أَئِمَّةً لِمَنْ بَعْدَهُمْ رِجَالٌ مَعْرُوفُونَ مَنْسُوبُونَ فِي الْبُلْدَانِ مُتَّفِقُونَ فِي الرَّدِّ عَلَى أَصْحَابِ الْأَهْوَاءِ مَعَ مَا كَانَ بَيْنَهُمْ مِنْ الِاخْتِلَافِ وَتَسَكَّعَ أَصْحَابُ الْأَهْوَاءِ بِرَأْيِهِمْ فِي سُبُلٍ مُخْتَلِفَةٍ جَائِرَةٍ عَنْ الْقَصْدِ مُفَارِقَةٍ لِلصِّرَاطِ الْمُسْتَقِيمِ فَتَوَّهَتْ بِهِمْ أَدِلَّاؤُهُمْ فِي مَهَامِهَ مُضِلَّةٍ فَأَمْعَنُوا فِيهَا مُتَعَسِّفِينَ فِي تِيهِهِمْ كُلَّمَا أَحْدَثَ لَهُمْ الشَّيْطَانُ بِدْعَةً فِي ضَلَالَتِهِمْ انْتَقَلُوا مِنْهَا إِلَى غَيْرِهَا لِأَنَّهُمْ لَمْ يَطْلُبُوا أَثَرَ السَّالِفِينَ وَلَمْ يَقْتَدُوا بِالْمُهَاجِرِينَ وَقَدْ ذُكِرَ عَنْ عُمَرَ أَنَّهُ قَالَ لِزِيَادٍ هَلْ تَدْرِي مَا يَهْدِمُ الْإِسْلَامَ زَلَّةُ عَالِمٍ وَجِدَالُ مُنَافِقٍ بِالْقُرْآنِ وَأَئِمَّةٌ مُضِلُّونَ اتَّقُوا اللَّهَ وَمَا حَدَثَ فِي قُرَّائِكُمْ وَأَهْلِ مَسَاجِدِكُمْ مِنْ الْغِيبَةِ وَالنَّمِيمَةِ وَالْمَشْيِ بَيْنَ النَّاسِ بِوَجْهَيْنِ وَلِسَانَيْنِ وَقَدْ ذُكِرَ أَنَّ مَنْ كَانَ ذَا وَجْهَيْنِ فِي الدُّنْيَا كَانَ ذَا وَجْهَيْنِ فِي النَّارِ يَلْقَاكَ صَاحِبُ الْغِيبَةِ فَيَغْتَابُ عِنْدَكَ مَنْ يَرَى أَنَّكَ تُحِبُّ غِيبَتَهُ وَيُخَالِفُكَ إِلَى صَاحِبِكَ فَيَأْتِيهِ عَنْكَ بِمِثْلِهِ فَإِذَا هُوَ قَدْ أَصَابَ عِنْدَ كُلِّ وَاحِدٍ مِنْكُمَا حَاجَتَهُ وَخَفِيَ عَلَى كُلِّ وَاحِدٍ مِنْكُمَا مَا أُتِيَ بِهِ عِنْدَ صَاحِبِهِ حُضُورُهُ عِنْدَ مَنْ حَضَرَهُ حُضُورُ الْإِخْوَانِ وَغَيْبَتُهُ عَلَى مَنْ غَابَ عَنْهُ غَيْبَةُ الْأَعْدَاءِ مَنْ حَضَرَ مِنْهُمْ كَانَتْ لَهُ الْأَثَرَةُ وَمَنْ غَابَ مِنْهُمْ لَمْ تَكُنْ لَهُ حُرْمَةٌ يَفْتِنُ مَنْ حَضَرَهُ بِالتَّزْكِيَةِ وَيَغْتَابُ مَنْ غَابَ عَنْهُ بِالْغِيبَةِ فَيَا لَعِبَادَ اللَّهِ أَمَا فِي الْقَوْمِ مِنْ رَشِيدٍ وَلَا مُصْلِحٍ يَقْمَعُ هَذَا عَنْ مَكِيدَتِهِ وَيَرُدُّهُ عَنْ عِرْضِ أَخِيهِ الْمُسْلِمِ بَلْ عَرَفَ هَوَاهُمْ فِيمَا مَشَى بِهِ إِلَيْهِمْ فَاسْتَمْكَنَ مِنْهُمْ وَأَمْكَنُوهُ مِنْ حَاجَتِهِ فَأَكَلَ بِدِينِهِ مَعَ أَدْيَانِهِمْ فَاللَّهَ اللَّهَ ذُبُّوا عَنْ حُرَمِ أَغْيَابِكُمْ وَكُفُّوا أَلْسِنَتَكُمْ عَنْهُمْ إِلَّا مِنْ خَيْرٍ وَنَاصِحُوا اللَّهَ فِي أُمَّتِكُمْ إِذْ كُنْتُمْ حَمَلَةَ الْكِتَابِ وَالسُّنَّةِ فَإِنَّ الْكِتَابَ لَا يَنْطِقُ حَتَّى يُنْطَقَ بِهِ وَإِنَّ السُّنَّةَ لَا تَعْمَلُ حَتَّى يُعْمَلَ بِهَا فَمَتَى يَتَعَلَّمُ الْجَاهِلُ إِذَا سَكَتَ الْعَالِمُ فَلَمْ يُنْكِرْ مَا ظَهَرَ وَلَمْ يَأْمُرْ بِمَا تُرِكَ وَقَدْ { أَخَذَ اللَّهُ مِيثَاقَ الَّذِينَ أُوتُوا الْكِتَابَ لَتُبَيِّنُنَّهُ لِلنَّاسِ وَلَا تَكْتُمُونَهُ } اتَّقُوا اللَّهَ فَإِنَّكُمْ فِي زَمَانٍ رَقَّ فِيهِ الْوَرَعُ وَقَلَّ فِيهِ الْخُشُوعُ وَحَمَلَ الْعِلْمَ مُفْسِدُوهُ فَأَحَبُّوا أَنْ يُعْرَفُوا بِحَمْلِهِ وَكَرِهُوا أَنْ يُعْرَفُوا بِإِضَاعَتِهِ فَنَطَقُوا فِيهِ بِالْهَوَى لَمَّا أَدْخَلُوا فِيهِ مِنْ الْخَطَإِ وَحَرَّفُوا الْكَلِمَ عَمَّا تَرَكُوا مِنْ الْحَقِّ إِلَى مَا عَمِلُوا بِهِ مِنْ بَاطِلٍ فَذُنُوبُهُمْ ذُنُوبٌ لَا يُسْتَغْفَرُ مِنْهَا وَتَقْصِيرُهُمْ تَقْصِيرٌ لَا يُعْتَرَفُ بِهِ كَيْفَ يَهْتَدِي الْمُسْتَدِلُّ الْمُسْتَرْشِدُ إِذَا كَانَ الدَّلِيلُ حَائِرًا أَحَبُّوا الدُّنْيَا وَكَرِهُوا مَنْزِلَةَ أَهْلِهَا فَشَارَكُوهُمْ فِي الْعَيْشِ وَزَايَلُوهُمْ بِالْقَوْلِ وَدَافَعُوا بِالْقَوْلِ عَنْ أَنْفُسِهِمْ أَنْ يُنْسَبُوا إِلَى عَمَلِهِمْ فَلَمْ يَتَبَرَّءُوا مِمَّا انْتَفَوْا مِنْهُ وَلَمْ يَدْخُلُوا فِيمَا نَسَبُوا إِلَيْهِ أَنْفُسَهُمْ لِأَنَّ الْعَامِلَ بِالْحَقِّ مُتَكَلِّمٌ وَإِنْ سَكَتَ وَقَدْ ذُكِرَ أَنَّ اللَّهَ تَعَالَى يَقُولُ إِنِّي لَسْتُ كُلَّ كَلَامِ الْحَكِيمِ أَتَقَبَّلُ وَلَكِنِّي أَنْظُرُ إِلَى هَمِّهِ وَهَوَاهُ فَإِنْ كَانَ هَمُّهُ وَهَوَاهُ لِي جَعَلْتُ صَمْتَهُ حَمْدًا وَوَقَارًا لِي وَإِنْ لَمْ يَتَكَلَّمْ وَقَالَ اللَّهُ تَعَالَى { مَثَلُ الَّذِينَ حُمِّلُوا التَّوْرَاةَ ثُمَّ لَمْ يَحْمِلُوهَا } لَمْ يَعْمَلُوا بِهَا { كَمَثَلِ الْحِمَارِ يَحْمِلُ أَسْفَارًا } كُتُبًا وَقَالَ { خُذُوا مَا آتَيْنَاكُمْ بِقُوَّةٍ } قَالَ الْعَمَلُ بِمَا فِيهِ وَلَا تَكْتَفُوا مِنْ السُّنَّةِ بِانْتِحَالِهَا بِالْقَوْلِ دُونَ الْعَمَلِ بِهَا فَإِنَّ انْتِحَالَ السُّنَّةِ دُونَ الْعَمَلِ بِهَا كَذِبٌ بِالْقَوْلِ مَعَ إِضَاعَةِ الْعَمَلِ وَلَا تَعِيبُوا بِالْبِدَعِ تَزَيُّنًا بِعَيْبِهَا فَإِنَّ فَسَادَ أَهْلِ الْبِدَعِ لَيْسَ بِزَائِدٍ فِي صَلَاحِكُمْ وَلَا تَعِيبُوهَا بَغْيًا عَلَى أَهْلِهَا فَإِنَّ الْبَغْيَ مِنْ فَسَادِ أَنْفُسِكُمْ وَلَيْسَ يَنْبَغِي لِلطَّبِيبِ أَنْ يُدَاوِيَ الْمَرْضَى بِمَا يُبَرِّئُهُمْ وَيُمْرِضُهُ فَإِنَّهُ إِذَا مَرِضَ اشْتَغَلَ بِمَرَضِهِ عَنْ مُدَاوَاتِهِمْ وَلَكِنْ يَنْبَغِي أَنْ يَلْتَمِسَ لِنَفْسِهِ الصِّحَّةَ لِيَقْوَى بِهِ عَلَى عِلَاجِ الْمَرْضَى فَلْيَكُنْ أَمْرُكُمْ فِيمَا تُنْكِرُونَ عَلَى إِخْوَانِكُمْ نَظَرًا مِنْكُمْ لِأَنْفُسِكُمْ وَنَصِيحَةً مِنْكُمْ لِرَبِّكُمْ وَشَفَقَةً مِنْكُمْ عَلَى إِخْوَانِكُمْ وَأَنْ تَكُونُوا مَعَ ذَلِكَ بِعُيُوبِ أَنْفُسِكُمْ أَعْنَى مِنْكُمْ بِعُيُوبِ غَيْرِكُمْ وَأَنْ يَسْتَطْعِمَ بَعْضُكُمْ بَعْضًا النَّصِيحَةَ وَأَنْ يَحْظَى عِنْدَكُمْ مَنْ بَذَلَهَا لَكُمْ وَقَبِلَهَا مِنْكُمْ وَقَدْ قَالَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ رَحِمَ اللَّهُ مَنْ أَهْدَى إِلَيَّ عُيُوبِي تُحِبُّونَ أَنْ تَقُولُوا فَيُحْتَمَلَ لَكُمْ وَإِنْ قِيلَ لَكُمْ مِثْلُ الَّذِي قُلْتُمْ غَضِبْتُمْ تَجِدُونَ عَلَى النَّاسِ فِيمَا تُنْكِرُونَ مِنْ ��ُمُورِهِمْ وَتَأْتُونَ مِثْلَ ذَلِكَ فَلَا تُحِبُّونَ أَنْ يُوجَدَ عَلَيْكُمْ اتَّهِمُوا رَأْيَكُمْ وَرَأْيَ أَهْلِ زَمَانِكُمْ وَتَثَبَّتُوا قَبْلَ أَنْ تَكَلَّمُوا وَتَعَلَّمُوا قَبْلَ أَنْ تَعْمَلُوا فَإِنَّهُ يَأْتِي زَمَانٌ يَشْتَبِهُ فِيهِ الْحَقُّ وَالْبَاطِلُ وَيَكُونُ الْمَعْرُوفُ فِيهِ مُنْكَرًا وَالْمُنْكَرُ فِيهِ مَعْرُوفًا فَكَمْ مِنْ مُتَقَرِّبٍ إِلَى اللَّهِ بِمَا يُبَاعِدُهُ وَمُتَحَبِّبٍ إِلَيْهِ بِمَا يُغْضِبُهُ عَلَيْهِ قَالَ اللَّهُ تَعَالَى { أَفَمَنْ زُيِّنَ لَهُ سُوءُ عَمَلِهِ فَرَآهُ حَسَنًا } الْآيَةَ فَعَلَيْكُمْ بِالْوُقُوفِ عِنْدَ الشُّبُهَاتِ حَتَّى يَبْرُزَ لَكُمْ وَاضِحُ الْحَقِّ بِالْبَيِّنَةِ فَإِنَّ الدَّاخِلَ فِيمَا لَا يَعْلَمُ بِغَيْرِ عِلْمٍ آثِمٌ وَمَنْ نَظَرَ لِلَّهِ نَظَرَ اللَّهُ لَهُ عَلَيْكُمْ بِالْقُرْآنِ فَأْتَمُّوا بِهِ وَأُمُّوا بِهِ وَعَلَيْكُمْ بِطَلَبِ أَثَرِ الْمَاضِينَ فِيهِ وَلَوْ أَنَّ الْأَحْبَارَ وَالرُّهْبَانَ لَمْ يَتَّقُوا زَوَالَ مَرَاتِبِهِمْ وَفَسَادَ مَنْزِلَتِهِمْ بِإِقَامَةِ الْكِتَابِ وَتِبْيَانِهِ مَا حَرَّفُوهُ وَلَا كَتَمُوهُ وَلَكِنَّهُمْ لَمَّا خَالَفُوا الْكِتَابَ بِأَعْمَالِهِمْ الْتَمَسُوا أَنْ يَخْدَعُوا قَوْمَهُمْ عَمَّا صَنَعُوا مَخَافَةَ أَنْ تَفْسُدَ مَنَازِلُهُمْ وَأَنْ يَتَبَيَّنَ لِلنَّاسِ فَسَادُهُمْ فَحَرَّفُوا الْكِتَابَ بِالتَّفْسِيرِ وَمَا لَمْ يَسْتَطِيعُوا تَحْرِيفَهُ كَتَمُوهُ فَسَكَتُوا عَنْ صَنِيعِ أَنْفُسِهِمْ إِبْقَاءً عَلَى مَنَازِلِهِمْ وَسَكَتُوا عَمَّا صَنَعَ قَوْمُهُمْ مُصَانَعَةً لَهُمْ وَقَدْ { أَخَذَ اللَّهُ مِيثَاقَ الَّذِينَ أُوتُوا الْكِتَابَ لَتُبَيِّنُنَّهُ لِلنَّاسِ وَلَا تَكْتُمُونَهُ } بَلْ مَالَئُوا عَلَيْهِ وَرَقَّقُوا لَهُمْ فِيهِ","id":"Telah mengabarkan kepada kami [Abdul Malik bin Sulaiman Abu Abdur Rahman Al `Anthaki] dari ['Abbad bin 'Abbad Al Khawwash As Syami Abu 'Utbah] ia berkata: \"Perhatian, gunakanlah akal, karena akal sebuah nikmat. Berapa banyak orang berakal menyibukkan hatinya untuk memperdalam hal-hal yang membahayakan dirinya daripada memanfaatkan apa yang dibutuhkannya, sehingga ia lupa hal itu. Diantara keutamaan akal seseorang adalah meninggalkan perhatian terhadap hal-hal yang tidak perlu sehingga keutamaan akalnya tidak menjadi bencana baginya, yaitu ia meninggalkan persaingan dengan orang yang lebih rendah amal shalihnya, atau seseorang yang menyibukkan hatinya dengan bid'ah, yang ia sekedar mengikuti orang dalam urusan agamanya tanpa mengikuti para sahabat Rasulullah shalallahu 'alahi wa sallam, atau ia hanya merasa cukup dengan pendapatnya sendiri, yang ia tidak melihat petunjuk kecuali kepada akalnya, dan tidak melihat kesesatan kecuali meninggalkannya dengan anggapan bahwa ia mengambilnya dari Al qur`an, padahal ia menyerukan untuk meninggalkan Al qur`an. Bukankah Al qur`an mempunyai pengemban-pengemban sebelumnya, yaitu para pembelanya yang mengamalkan ayat-ayat yang muhkam dan mengimani ayat-ayat yang mutasyabih? Mereka berada di menara layaknya cahaya jalan, Al Quran imam Rasulullah shalallahu'alahi wa sallam, sedang Rasulullah shallahu 'alaihi wa sallam imam para sahabatnya, dan para sahabat adalah imam orang-orang setelah mereka, yaitu orang-orang yang sudah dikenal kebaikannya, mereka menjadi barometer di negeri-negeri mereka yang sepakat menolak para pengagung hawa nafsu walaupun diantara mereka terdapat perselisihan pendapat. Para pengagum hawa nafsu meraba-raba dengan pendapat mereka, yaitu dengan cara yang bermacam-macam, yang melenceng dari tujuan karena memisahkan diri dari jalan yang lurus. Petunjuk mereka menyesatkan mereka sendiri dalam misteri padang pasir yang menyesatkan. Mereka konsentrasi melihat petunjuk jalan dengan penuh kebingungan dalam kesesatannya. Setiap kali setan membuat satu bid'ah dalam kesesatan, mereka berpindah dari satu bid'ah ke bid'ah lain, karena mereka tidak mencari petunjuk para pendahulu dan juga tidak mengikuti jejak kaum muhajirin. Telah disebutkan dalam satu riwayat dari Umar radliallahu 'anhu bahwa ia berkata kepada Ziad: 'Tahukah kamu apa yang (menyebabkan) kehancuran Islam? ', Jawabnya karena kesalahan orang berilmu, perdebatan orang munafik terhadap Al Qur`an dan para imam yang sesat'. Takutlah kamu kepada Allah subhanallahu wa ta'ala, dan waspadailah apa yang terjadi pada ulama kamu dan pengisi masjid-masjid kamu dari perbuatan ghibah, namimah dan berjalan diantara manusia dengan dua wajah dan dua lisan. Dalam satu riwayat disebutkan barangsiapa mempunyai dua wajah di dunia, ia mempunyai dua wajah di neraka. Jika tukang ghibah menemuimu, ia menggunjing orang yang kamu senangi untuk di gunjing, lalu ia berpaling darimu untuk mendatangi temanmu dan melakukan hal yang sama. Jika ia telah memperoleh apa yang ia butuhkan dari setiap kalian, dan menyembunyikan sesuatu dari salah satu (dari) kalian, ia tidak memberi kabar kepada sahabatmu yang lain. Kedatangannya kepada orang yang didatanginya adalah seperti datangnya seorang teman, namun kepergiannya dari teman yang ditinggalkan bagaikan kepergian dari seorang musuh. Siapa saja yang menemuinya, ia dapatkan kemuliaan, sebaliknya siapa yang tidak ditemuinya, tidak ia dapatkan kehormatan, ia menipu orang yang didatanginya dengan penghargaan-penghargaan, dan menggunjing orang yang tidak ditemuinya dengan ghibah mematikan. Wahai hamba-hamba Allah subhanallahu wa ta'ala, tidakkah suatu kaum muncul penunjuk jalan dan reformis, yang ia sanggup mengekang orang seperti ini dari tipu dayanya, dan mengajaknya untuk mempertahankan kehormatan saudaranya semuslim?, bahkan kalau bisa memberitahu mereka niyat orang seperti ini saat datang menemui mereka, yang ia bertindak sekedar ingin memperoleh keperluannya sehingga mereka mempersilahkan, yang ujungnya ia mencaplok agamanya sekaligus agama mereka? Ya Allah, Ya Allah! Pertahankanlah kehormatan kamu, hentikanlah lisanmu (dari menggunjing) mereka kecuali kebaikan semata. Tolong kalian saling mengingatkan untuk berbakti kepada Allah khususnya terhadap umatmu, karena kamu adalah pengemban Al Kitab (Al Qur`an) dan sunah,. Al Kitab tidak berbicara hingga ia dibicarakan, dan sunnah tidak sanggup mengejawantahkan hingga ia diejawantahkan. Bilamana orang bodoh belajar, namun orang alim diam tidak memungkiri apa yang nampak dan tidak memerintahkan apa yang ditinggalkan', bukankah Allah subhanallahu wa ta'ala telah mengambil perjanjian dari orang-orang yang diberikan Al Kitab kepada mereka untuk menjelaskannya kepada manusia dan tidak menyembunyikannya?. Bertakwalah kepada Allah subhanallahu wa ta'ala, karena kamu berada pada zaman menipisnya sifat wara' dan kurangnya kekhusyu'an, dan para pengemban ilmu adalah para perusaknya. Mereka begitu marah jika dikenal sebagai orang-orang yang menghilangkannya, mereka membicarakannya dengan hawa nafsu ketika mengikutsertakan kesalahan dalam ilmu, dan memutarbalikkan perkataan dari kebenaran yang mereka tinggalkan, lantas mereka belokkan menuju kebatilan yang mereka kerjakan. Dosa mereka adalah dosa yang tidak diampuni dan kelalaian mereka adalah kelalaian yang tidak bisa dibenarkan, bagaimana orang yang mencari petunjuk dan tuntunan mendapatkan petunjuk apabila petunjuknya sendiri membingungkan, mereka cinta dunia dan benci terhadap kebahagiaan penduduknya yang memperoleh kedudukan tinggi, lantas mereka menyertai dalam kehidupan dan menyelisihi mereka dengan perkataan, dan mempertahankan diri mereka dengan perkataan, agar mereka dihubung-hubungkan dengan kebaikan mereka. Mereka sama sekali tidak bersih dari kotoran yang mereka hilangkan, dan belum memenuhi kriteria untuk dihargai amal mereka, sebab orang yang benar-benar beramal shalih secara tidak langsung ia ia telah bicara sekalipun dia diam. Dan telah diberitakan bahwa Allah Ta'ala berfirman; Aku tidak menerima semua semua perkataan orang bijak, akan tetapi Aku melihat kepada kecenderungan dan niyat baiknya untuk-Ku. Sebab siapa yang hasrat dan niyatnya untuk-Ku, Aku jadikan diamnya terpuji dan berwibawa, walaupun ia tidak berbicara. Allah subhanallahu wa ta'ala berfirman: \"MATSALULLADZINA HUMMILUT TAURATA TSUMMA LAM YAHMILUUHA KAMATSALIL HIMARI YAHMILUL ASFARA\" (Perumpamaan orang-orang yang dipikulkan kepadanya Taurat, kemudian mereka tidak memikulnya (tidak mengerjakannya) adalah seperti keledai yang membawa kitab-kitab yang tebal) -Qs. Al Jumu'ah: 5-, Allah subhanallahu wa ta'ala juga berfirman: \"KHUDZU MAA ATAINAAKUM BI QUWWAH\" (Peganglah teguh-teguh apa yang telah kami berikan kepadamu) -Qs. Al Baqarah: 63, 93, 171-, ia berkata: 'Maksudnya mengerjakan isi yang terkandung padanya, dan tidak mencukupkan sunnah hanya dengan ucapan tanpa pengalaman. Karena pensifatan sunnah dengan perkataan tanpa perbuatan adalah dusta dengan perkataan, yang sekaligus menghilangkan ilmu. Dan janganlah kamu mencela bid`ah sekedar untuk bungkus keindahanmu dengan meneropong aib-aibnya, karena kerusakan penganut bid`ah tidak menambah kesalehanmu, dan janganlah kamu mencelanya karena dorongan diskriminatif terhadap penganutnya, karena diskriminasi adalah kerusakan dirimu sendiri, sebab tidak selayaknya dokter mengobati pasien dengan obat yang berpotensi menyembuhkan penyakit namun obat itu juga berpotensi mendatangkan penyakit baru. Karena apabila dokter itu sakit, ia sibuk dengan penyakitnya dan lupa mengobati mereka. Akan tetapi selayaknya ia mencari kesehatan untuk dirinya agar ia dapat mengobati para pasien. Hendaklah saat engkau melihat masalah yang menimpa saudara-saudaramu dan hatimu \"kurang sreg\", sebagaimana engkau melihat jika terjadi pada dirimu sendiri dan sebagai \"peringatan\" Tuhanmu terhadapmu, serta rasa kasihanmu kepada saudara-saudara kamu. Walaupun dalam hal itu lebih baik kamu lebih peduli terhadap aib diri kamu sendiri dari pada aib orang lain, dan lakukan saling menasehati satu sama lain diantara kamu, dan hendaklah yang mengorbankan nasehat itu merasa beruntung dan kamu menerimanya. Umar bin Al Khatthab radliallahu 'anhu berkata: 'Semoga Allah subhanallahu wa ta'ala melimpahkan rahmat kepada orang yang menunjukkan aib-aibku kepadaku'. Kamu suka berkata dan orang yang mendengarmu menahan diri demi kebaikanmu, padahal jika dikatakan kepada kamu perkataan yang sama seperti yang kamu katakan, kamu jengkel. Kamu mendapatkan hal-hal yang menjengkelkanmu, sebaliknya kamu mengerjakan apa yang mereka kerjakan, apakah kamu tidak suka dipersalahkan? ', Pikir ulanglah pendapatmu dan pendapat orang-orang yang sezaman denganmu, Selidikilah dahulu sebuah berita sebelum kalian berbicara dan belajarlah sebelum kalian beramal. Karena nanti akan datang suatu zaman yang saat itu yang benar bercampur dengan yang batil, dan yang ma'ruf (baik) menjadi mungkar dan yang mungkar menjadi ma'ruf. Betapa banyak orang yang mendekatkan diri kepada Allah subhanallahu w ta'ala namun dengan hal-hal yang justru menjauhkan dariNya, dan mencari cintaNya dengan hal-hal yang membuatNya murka. Allah subhanallahu wa ta'ala berfirman: \"AFAMAN ZUYYINA LAHU SUU`U 'MALIHI FA RA`AHU HASANA\" (Maka apabila orang yang dijadikan (syaitan) menganggap baik pekerjaannya yang buruk lalu ia meyakini pekerjaan itu baik (sama dengan orang yang tidak ditipu syaitan)? -Qs. Al Fathir: 8-, hendaklah kamu berhenti dari hal-hal yang syubhat sehingga nampak bagi kamu kebenaran yang jelas disertai keterangan, karena orang yang mengintervensi perkara yang ia tidak tahu tanpa ilmu, ia berdosa, dan barangsiapa yang menyelidiki dengan niat ikhlash karena Allah, Allah subhanallahu wa ta'ala akan melihatnya. Hendaklah kamu berpegang teguh dengan Al Qur`an, jadikanlah ia imam dan ajaklah (manusia) untuk menjadikan Al Qur`an sebagai imam. Hendaknya kamu mencari jejak-jejak para pendahulu padanya. Seandainya para ahbar (pendeta yahudi) dan para rahib (pendeta Nashrani) tidak takut kehilangan martabat mereka dan kerusakan kedudukannya dengan menegakkan Al Kitab dan penjelasannya, niscaya mereka tidak akan menyelewengkan dan menyembunyikannya, akan tetapi mereka ketika menentang Al Kitab dengan perbuatan mereka, mereka berusaha mencari cara menipu kaumnya karena perbuatan yang mereka lakukan sendiri, karena mereka khawatir kedudukan mereka dirobohkan, dan manusia memperoleh kejelasan kerusakan mereka, lalu mereka selewengkan Al Kitab dengan tafsir menyeleweng, dan apa yang mereka tidak bisa selewengkan, mereka sembunyikan, lalu mereka diam terhadap perbuatan mereka sendiri karena dorongan untuk mempertahankan kedudukan mereka, dan diam terhadap apa yang diperbuat oleh kaumnya sambil berpura-pura. Sedang Allah subhanallahu wa ta'ala telah mengambil perjanjian dengan orang-orang yang di berikan Al Kitab agar mereka menjelaskannya kepada manusia dan tidak menyembunyikannya, akan tetapi mereka justru cenderung kepadanya dan mengajak manusia menganggap enteng masalah itu. "},"415":{"ar":" أَخْبَرَنَا عَلِيُّ بْنُ عَبْدِ الْحَمِيدِ حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ لَمَّا نُهِينَا أَنْ نَبْتَدِئَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُعْجِبُنَا أَنْ يَقْدُمَ الْبَدَوِيُّ وَالْأَعْرَابِيُّ الْعَاقِلُ فَيَسْأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ عِنْدَهُ فَبَيْنَا نَحْنُ كَذَلِكَ إِذْ جَاءَ أَعْرَابِيٌّ فَجَثَا بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا مُحَمَّدُ إِنَّ رَسُولَكَ أَتَانَا فَزَعَمَ لَنَا أَنَّكَ تَزْعُمُ أَنَّ اللَّهَ أَرْسَلَكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَ قَالَ فَبِالَّذِي رَفَعَ السَّمَاءَ وَبَسَطَ الْأَرْضَ وَنَصَبَ الْجِبَالَ آللَّهُ أَرْسَلَكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ قَالَ فَإِنَّ رَسُولَكَ زَعَمَ لَنَا أَنَّكَ تَزْعُمُ أَنَّ عَلَيْنَا خَمْسَ صَلَوَاتٍ فِي الْيَوْمِ وَاللَّيْلَةِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَ قَالَ فَبِالَّذِي أَرْسَلَكَ آللَّهُ أَمَرَكَ بِهَذَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ قَالَ فَإِنَّ رَسُولَكَ زَعَمَ لَنَا أَنَّكَ تَزْعُمُ أَنَّ عَلَيْنَا صَوْمَ شَهْرٍ فِي السَّنَةِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَ قَالَ فَبِالَّذِي أَرْسَلَكَ آللَّهُ أَمَرَكَ بِهَذَا قَالَ نَعَمْ قَالَ فَإِنَّ رَسُولَكَ زَعَمَ لَنَا أَنَّكَ تَزْعُمُ أَنَّ عَلَيْنَا فِي أَمْوَالِنَا الزَّكَاةَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَ قَالَ فَبِالَّذِي أَرْسَلَكَ آللَّهُ أَمَرَكَ بِهَذَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ قَالَ فَإِنَّ رَسُولَكَ زَعَمَ لَنَا أَنَّكَ تَزْعُمُ أَنَّ عَلَيْنَا الْحَجَّ إِلَى الْبَيْتِ مَنْ اسْتَطَاعَ إِلَيْهِ سَبِيلًا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَ قَالَ فَبِالَّذِي أَرْسَلَكَ آللَّهُ أَمَرَكَ بِهَذَا قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ قَالَ فَوَالَّذِي بَعَثَكَ بِالْحَقِّ لَا أَدَعُ مِنْهُنَّ شَيْئًا وَلَا أُجَاوِزُهُنَّ قَالَ ثُمَّ وَثَبَ الْأَعْرَابِيُّ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ صَدَقَ الْأَعْرَابِيُّ دَخَلَ الْجَنَّةَ","id":"Telah mengabarkan kepada kami [Ali bin Abdul hamid] telah menceritakan kepada kami [Sulaiman bin Al Mughirah] dari [Tsabit] dari [Anas bin malik] radliallahu 'anhu ia berkata: \"Ketika kami dilarang mendahului bertanya Nabi sallallahu 'alaihi wa sallam, kami merasa senang sekali jika ada seorang arab badui dan orang arab dusun yang cerdas datang dan bertanya kepada Nabi sallallahu 'alaihi wa sallam. Saat kami dan nabi berkumpul seperti itu, tiba-tiba seorang arab dusun datang dan berdiri di hadapan Rasulullah sallallahu 'alaihi wa sallam seraya berkata: 'Ya Muhammad, utusan kamu mendatangi kami, lalu ia meyakinkan kami bahwa kamu mengaku kalau Allah subhanallahu wa ta'ala mengutusmu, lalu Nabi sallallahu 'alaihi wa salam berkata: 'ia benar. Laki-laki pedalaman itu berkata: 'Demi Dzat yang meninggikan langit dan membentangkan bumi, dan yang menancapkan gunung, Apakah Allah subhanallahu wa ta'ala yang mengutusmu? ', lalu Nabi sallallahu 'alaihi wa sallam menjawab: 'Ya, benar'. Ia bertanya lagi: 'Utusanmu meyakinkan kami bahwa kamu mengaku kalau (diwajibkan) atas kami shalat lima waktu dalam sehari semalam? ', nabi sallalahu 'alaihi wa sallam menjawab: 'Ia benar', ia bertanya lagi: 'Demi Dzat yang telah mengutusmu, apakah Allah subhanallahu wa ta'ala memerintahkan kamu hal ini? ', Nabi sallallahu 'alaihi wa sallam menjawab: 'Ya, benar', ia berkata: 'Utusanmu meyakinkan kami bahwa kamu mewajibkan atas kami puasa satu bulan dalam satu tahun? ', Nabi sallallahu 'alaihi wa sallam menjawab: 'Ia benar', ia berkata lagi: 'Demi Dzat yang mengutusmu, apakah Allah subhanallahu wa ta'ala yang memerintahkanmu hal ini? ', beliau menjawab: 'Ya, benar', ia berkata lagi: 'Utusanmu meyakinkan kami kalau kamu mewajibkan atas harta-harta kami (dikeluarkan) zakatnya? ', Nabi salalahu 'alaihi wa sallam menjawab: 'Ia benar', ia bertanya lagi: 'Demi Dzat yang mengutusmu, apakah Allah subhanallahu wa ta'ala yang memerintahkanmu hal ini? ', Nabi sallallahu 'alaihi wa sallam menjawab: 'Ya, benar', ia berkata lagi: 'Utusanmu meyakinkan kami kalau kamu mewajibkan atas kami (menunaikan) ibadah haji ke Baitul Haram bagi yang mampu menunaikan? ', beliau menjawab: 'Ia benar', ia bertanya: 'demi Dzat yang mengutusmu, apakah Allah subhanallahu wa ta'ala yang memerintahkanmu hal ini? ', Nabi sallallahu 'alaihi wa sallam menjawab: 'Ya, benar', ia berkata: 'Demi dzat yang mengutusmu dengan benar, aku tidak akan tinggalkan itu semua sedikit pun namun aku juga tidak akan menambahnya', perawi berkata: 'Kemudian orang Arab dusun itu melompat (pergi), dan Nabi sallallahu 'alaihi wa sallam berkomentar: 'Jika orang Arab dusun itu benar, ia masuk surga' \"."},"416":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يَزِيدَ حَدَّثَنَا ابْنُ فُضَيْلٍ حَدَّثَنَا عَطَاءُ بْنُ السَّائِبِ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ ابْنِ عَبَّاسٍ قَالَ جَاءَ أَعْرَابِيٌّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ السَّلَامُ عَلَيْكَ يَا غُلَامَ بَنِي عَبْدِ الْمُطَّلِبِ فَقَالَ وَعَلَيْكَ وَقَالَ إِنِّي رَجُلٌ مِنْ أَخْوَالِكَ مِنْ بَنِي سَعْدِ بْنِ بَكْرٍ وَأَنَا رَسُولُ قَوْمِي إِلَيْكَ وَوَافِدُهُمْ وَإِنِّي سَائِلُكَ فَمُشَدِّدٌ مَسْأَلَتِي إِلَيْكَ وَمُنَاشِدُكَ فَمُشَدِّدٌ مُنَاشَدَتِي إِيَّاكَ قَالَ خُذْ عَنْكَ يَا أَخَا بَنِي سَعْدٍ قَالَ مَنْ خَلَقَكَ وَخَلَقَ مَنْ قَبْلَكَ وَمَنْ هُوَ خَالِقُ مَنْ بَعْدَكَ قَالَ اللَّهُ قَالَ فَنَشَدْتُكَ بِذَلِكَ أَهُوَ أَرْسَلَكَ قَالَ نَعَمْ قَالَ مَنْ خَلَقَ السَّمَوَاتِ السَّبْعَ وَالْأَرَضِينَ السَّبْعَ وَأَجْرَى بَيْنَهُنَّ الرِّزْقَ قَالَ اللَّهُ قَالَ فَنَشَدْتُكَ بِذَلِكَ أَهُوَ أَرْسَلَكَ قَالَ نَعَمْ قَالَ إِنَّا وَجَدْنَا فِي كِتَابِكَ وَأَمَرَتْنَا رُسُلُكَ أَنْ نُصَلِّيَ فِي الْيَوْمِ وَاللَّيْلَةِ خَمْسَ صَلَوَاتٍ لِمَوَاقِيتِهَا فَنَشَدْتُكَ بِذَلِكَ أَهُوَ أَمَرَكَ قَالَ نَعَمْ قَالَ فَإِنَّا وَجَدْنَا فِي كِتَابِكَ وَأَمَرَتْنَا رُسُلُكَ أَنْ نَأْخُذَ مِنْ حَوَاشِي أَمْوَالِنَا فَنَرُدَّهَا عَلَى فُقَرَائِنَا فَنَشَدْتُكَ بِذَلِكَ أَهُوَ أَمَرَكَ بِذَلِكَ قَالَ نَعَمْ ثُمَّ قَالَ أَمَّا الْخَامِسَةُ فَلَسْتُ بِسَائِلِكَ عَنْهَا وَلَا أَرَبَ لِي فِيهَا ثُمَّ قَالَ أَمَا وَالَّذِي بَعَثَكَ بِالْحَقِّ لَأَعْمَلَنَّ بِهَا وَمَنْ أَطَاعَنِي مِنْ قَوْمِي ثُمَّ رَجَعَ فَضَحِكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى بَدَتْ نَوَاجِذُهُ ثُمَّ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَئِنْ صَدَقَ لَيَدْخُلَنَّ الْجَنَّةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yazid] telah menceritakan kepada kami [Ibnu Fudlail] telah menceritakan kepada kami ['Atha` bin As sa`ib] dari [Salim bin Abu Al Ja'd] dari [Ibnu Abbas] radliallahu 'anhu ia berkata: \"Seorang Arab dusun datang kepada Nabi sallallahu 'alaihi wa sallam dan berkata: 'ASSALAMU 'ALAIKA (semoga keselamatan selalu terlimpahkan atas kamu) wahai anak Bani Abdul Muthallib', beliau menjawab: 'WA 'ALAIKA (atasmu juga) ', Ia berkata lagi: 'Aku seorang dari pamanmu dari Bani Sa'ad bin Bakar, dan aku utusan kaumku yang diutus untuk menemuimu, dan aku betul-betul serius menanyakan permasalahanku'. Beliau berkata: 'Silahkan wahai saudara bani Sa'ad', ia bertanya: 'Siapakah yang menciptakan kamu dan orang-orang sebelum kamu?, dan siapa yang menciptakan orang-orang setelah kamu? ' beliau menjawab: 'Allah subhanallahu wa ta'ala', ia berkata: 'Aku tegaskan apakah Dia yang mengutusmu? ', beliau menjawab: 'Ya, benar', ia bertanya lagi: 'Siapakah yang menciptakan langit dan bumi yang tujuh dan mengatur rizki (untuk mahluk) diantara keduanya? ', beliau menjawab: 'Allah subhanallahu wa ta'ala', ia berkata lagi: Aku tegaskan lagi apakah Dia yang mengutusmu? ', beliau menjawab: 'Ya, benar', ia berkata: Kami dapati dalam kitabmu, dan para utusanmu memerintahkan kami agar kami menunaikan shalat dalam sehari semalam sebanyak lima waktu, aku tegaskan apakah Dia yang mengutusmu? ', beliau menjawab: 'Ya, benar', ia berkata: ' kami dapati dalam kitabmu, dan para utusanmu memerintahkan kami untuk mengeluarkan sebagian dari harta-harta kami (untuk diberikan kepada) orang fakir kami?, aku tegaskan apakah Dia yang mengutusmu? ', beliau menjawab: 'Ya, benar', ia berkata: 'Adapun (pertanyaan) yang kelima, aku tidak menanyakannya padamu dan aku tidak ragu padanya, kemudian ia berkata: 'Demi Dzat yang mengutusmu dengan benar, aku dan orang yang menaatiku dari kaumku akan mengamalkan itu semua', kemudian ia pulang, lalu Nabi sallallahu 'alaihi wa sallam tertawa, hingga terlihat gigi gerahamnya, kemudian beliau berkata: 'Demi Dzat yang jiwaku berada dalam genggamannya, jika ia benar, niscaya ia masuk surga' \"."},"417":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ حُمَيْدٍ حَدَّثَنَا سَلَمَةُ حَدَّثَنِي مُحَمَّدُ بْنُ إِسْحَقَ حَدَّثَنِي سَلَمَةُ بْنُ كُهَيْلٍ وَمُحَمَّدُ بْنُ الْوَلِيدِ بْنِ نُوَيْفِعٍ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍ قَالَ بَعَثَ بَنُو سَعْدِ بْنِ بَكْرٍ ضِمَامَ بْنَ ثَعْلَبَةَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَدِمَ عَلَيْهِ فَأَنَاخَ بَعِيرَهُ عَلَى بَابِ الْمَسْجِدِ ثُمَّ عَقَلَهُ ثُمَّ دَخَلَ الْمَسْجِدَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسٌ فِي أَصْحَابِهِ وَكَانَ ضِمَامٌ رَجُلًا جَلْدًا أَشْعَرَ ذَا غَدِيرَتَيْنِ حَتَّى وَقَفَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَيُّكُمْ ابْنُ عَبْدِ الْمُطَّلِبِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا ابْنُ عَبْدِ الْمُطَّلِبِ قَالَ مُحَمَّدٌ قَالَ نَعَمْ قَالَ يَا ابْنَ عَبْدِ الْمُطَّلِبِ إِنِّي سَائِلُكَ وَمُغَلِّظٌ فِي الْمَسْأَلَةِ فَلَا تَجِدَنَّ فِي نَفْسِكَ قَالَ لَا أَجِدُ فِي نَفْسِي فَسَلْ عَمَّا بَدَا لَكَ قَالَ إِنِّي أَنْشُدُكَ بِاللَّهِ إِلَهِكَ وَإِلَهِ مَنْ كَانَ قَبْلَكَ وَإِلَهِ مَنْ هُوَ كَائِنٌ بَعْدَكَ آللَّهُ بَعَثَكَ إِلَيْنَا رَسُولًا قَالَ اللَّهُمَّ نَعَمْ قَالَ فَأَنْشُدُكَ بِاللَّهِ إِلَهِكَ وَإِلَهِ مَنْ كَانَ قَبْلَكَ وَإِلَهِ مَنْ هُوَ كَائِنٌ بَعْدَكَ آللَّهُ أَمَرَكَ أَنْ نَعْبُدَهُ وَحْدَهُ لَا نُشْرِكُ بِهِ شَيْئًا وَأَنْ نَخْلَعَ هَذِهِ الْأَنْدَادَ الَّتِي كَانَتْ آبَاؤُنَا تَعْبُدُهَا مِنْ دُونِهِ قَالَ اللَّهُمَّ نَعَمْ قَالَ فَأَنْشُدُكَ بِاللَّهِ إِلَهِكَ وَإِلَهِ مَنْ كَانَ قَبْلَكَ وَإِلَهِ مَنْ هُوَ كَائِنٌ بَعْدَكَ آللَّهُ أَمَرَكَ أَنْ نُصَلِّيَ هَذِهِ الصَّلَوَاتِ الْخَمْسَ قَالَ اللَّهُمَّ نَعَمْ قَالَ ثُمَّ جَعَلَ يَذْكُرُ فَرَائِضَ الْإِسْلَامِ فَرِيضَةً فَرِيضَةً الزَّكَاةَ وَالصِّيَامَ وَالْحَجَّ وَشَرَائِعَ الْإِسْلَامِ كُلَّهَا وَيُنَاشِدُهُ عِنْدَ كُلِّ فَرِيضَةٍ كَمَا نَاشَدَهُ فِي الَّتِي قَبْلَهَا حَتَّى إِذَا فَرَغَ قَالَ فَإِنِّي أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ وَسَأُؤَدِّي هَذِهِ الْفَرِيضَةَ وَأَجْتَنِبُ مَا نَهَيْتَنِي عَنْهُ ثُمَّ قَالَ لَا أَزِيدُ وَلَا أُنْقِصُ ثُمَّ انْصَرَفَ إِلَى بَعِيرِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ وَلَّى إِنْ يَصْدُقْ ذُو الْعَقِيصَتَيْنِ يَدْخُلْ الْجَنَّةَ فَأَتَى إِلَى بَعِيرِهِ فَأَطْلَقَ عِقَالَهُ ثُمَّ خَرَجَ حَتَّى قَدِمَ عَلَى قَوْمِهِ فَاجْتَمَعُوا إِلَيْهِ فَكَانَ أَوَّلَ مَا تَكَلَّمَ أَنْ قَالَ بِاسْتِ اللَّاتِ وَالْعُزَّى قَالُوا مَهْ يَا ضِمَامُ اتَّقِ الْبَرَصَ وَاتَّقِ الْجُنُونَ وَاتَّقِ الْجُذَامَ قَالَ وَيْلَكُمْ إِنَّهُمَا وَاللَّهِ مَا يَضُرَّانِ وَلَا يَنْفَعَانِ إِنَّ اللَّهَ قَدْ بَعَثَ رَسُولًا وَأَنْزَلَ عَلَيْهِ كِتَابًا اسْتَنْقَذَكُمْ بِهِ مِمَّا كُنْتُمْ فِيهِ وَإِنِّي أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ وَقَدْ جِئْتُكُمْ مِنْ عِنْدِهِ بِمَا أَمَرَكُمْ بِهِ وَنَهَاكُمْ عَنْهُ قَالَ فَوَاللَّهِ مَا أَمْسَى مِنْ ذَلِكَ الْيَوْمِ وَفِي حَاضِرِهِ رَجُلٌ وَلَا امْرَأَةٌ إِلَّا مُسْلِمًا قَالَ يَقُولُ ابْنُ عَبَّاسٍ فَمَا سَمِعْنَا بِوَافِدِ قَوْمٍ كَانَ أَفْضَلَ مِنْ ضِمَامِ بْنِ ثَعْلَبَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Humaid] telah menceritkan kepada kami [Salamah] ia berkata: Telah menceritakan kepadaku [Muhammad bin Ishak] ia berkata: Telah menceritakan kepadaku [Salamah bin Kuhail] dan [Muhammad bin Al Walid bin Nuwaifi'] dari [Kuraib] -bekas budak Ibnu Abbas radiallahu 'anhu- dari [Ibnu Abbas] radliallahu 'anhu ia berkata: \"Bani Sa'ad bin Bakar mengutus Dhimam bin Tsa'labah kepada Rasulullah shallallahu 'alaihi wasallam, ia datang menemui beliau, ia dudukkan untanya di depan pintu masjid kemudian ia ikat, selanjutnya ia masuk ke masjid dan Rasulullah shallallahu 'alaihi wasallam sedang duduk dengan para sahabatnya. Dhimam adalah seorang yang kuat, mempunyai dua kepang pada rambutnya, hingga ia berdiri di hadapan Rasulullah shallallahu 'alaihi wasallam, lalu bertanya: 'Manakah diantara kalian yang Ibnu Abdul Muthallib? ', Rasulullah shallallahu 'alaihi wasallam menjawab: 'Saya Ibnu Abdul Muthallib', ia bertanya: '(namamu) Muhammad? ', beliau menjawab: 'Ya, benar', ia berkata: 'Wahai Ibnu Abdul muthallib, aku bertanya kepadamu dengan pertanyaan yang berat, jangan ada ganjalan dalam hatimu', beliau menjawab: 'Tidak ada ganjalan dalam hatiku, silahkan bertanyalah apa yang kamu ingin tanyakan', ia berkata: 'Aku bersumpah kepada Allah subhanallahu wa ta'ala, Tuhanmu dan Tuhan orang-orang sebelum kamu dan tuhan orang-orang sesudah kamu, apakah Allah subhanallahu wa ta'ala yang mengutusmu sebagai Rasul kepada kami? ', ia berkata: 'Ya Allah, Ya', ia bekata: 'Aku bersumpah kepada Allah subhanallahu wa ta'ala, Tuhanmu tuhan orang-orang sebelum kamu dan Tuhan orang-orang setelah kamu, apakah Allah subhanallahu wa ta'ala memerintahkan kamu (untuk menyeru) agar kami menyembah-Nya semata dan tidak menyekutukan-Nya dengan sesuatu apapun, dan agar kami melepaskan semua tandingan (sekutu ini) yang dahulu nenek moyang kami menyembahnya? ', beliau menjawab: 'Ya, benar', ia berkata: 'Aku bersumpah dengan nama Allah Tuhan kamu, dan tuhan orang-orang setelah kamu dan Tuhan orang-orang sebelum kamu, apakah Allah subhanallahu wa ta'ala yang memerintahkanmu (untuk menyeru) agar kami menunaikan shalat yang lima waktu ini? ', beliau menjawab: 'Ya, benar', kemudian ia menyebutkan kewajiban syariat Islam lain, seperti: zakat, puasa, haji, dan syariat-syariat Islam semuanya, dan ia bersumpah dalam setiap kewajiban (yang disebutkan) sebagaimana ia bersumpah pada (penyebutan) kewajiban sebelumnya, hingga setelah selesai ia berkata: ' aku bersaksi bahwa tidak ada tuhan (yang berhak disembah) kecuali Allah subhanallahu wa ta'ala, dan aku bersaksi bahwa Muhammad hamba dan utusanNya, dan aku akan laksanakan kewajiban ini dan akan kuhindari apa saja yang kamu larang', kemudian ia berkata lagi: 'Aku tidak akan menambah atau menguranginya', lalu ia berpaling menuju ke untanya, Rasulullah shallallahu 'alaihi wasallam berkata (saat ia pergi): 'Jika orang berkepang itu benar, ia masuk surga'. Kemudia ia datang menuju untanya dan melepaskan ikatannya lalu ia pulang hingga sampai di kaumnya, lalu mereka berkumpul di sekelilingnya, dan perkataan yang pertama kali ia ucapkan adalah: 'Alangkah jeleknya Latta dan Uzza', mereka berkata: 'Ada apa Dhimam, hati-hatilah nanti kamu terkena penyakit kusta, hati-hati juga nanti kamu gila atau terkena penyakit lepra, ia berkata: 'Celakalah kalian, Demi Allah subhanallahu wa ta'ala keduanya (Latta dan Uzza) tidaklah memberikan madharat atau manfaat, Allah subhanallahu wa ta'ala telah mengutus seorang Rasul dan menurunkan sebuah kitab kepadanya yang dengannya ia selamatkan kalian dari apa yang selama ini kamu jalani, dan aku bersaksi bahwa tidak ada Tuhan (yang berhak disembah) kecuali Allah, dan aku juga bersaksi bahwa Muhammad adalah hamba dan utusanNya, sungguh aku datang dari sisinya kepada kalian (membawa) apa yang ia perintahkan dan ia larang atas kalian. Ia berkata: 'Demi Allah subhanallahu wa ta'ala sore hari itu tidak ada seorang laki-laki atau perempuanpun melainkan ia masuk Islam, perawi berkata: Ibnu Abbas radliallahu 'anhu berkata: 'Kami tidak pernah mendengar seorang utusan pun yang lebih mulia dari Dhimam bin Tsa'labah' \"."},"418":{"ar":" أَخْبَرَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبَانُ هُوَ ابْنُ يَزِيدَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ زَيْدٍ عَنْ أَبِي سَلَّامٍ عَنْ أَبِي مَالِكٍ الْأَشْعَرِيِّ أَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الطُّهُورُ شَطْرُ الْإِيمَانِ وَالْحَمْدُ لِلَّهِ يَمْلَأُ الْمِيزَانَ وَلَا إِلَهَ إِلَّا اللَّهُ وَاللَّهُ أَكْبَرُ يَمْلَآَنِ مَا بَيْنَ السَّمَاوَاتِ وَالْأَرْضِ وَالصَّلَاةُ نُورٌ وَالصَّدَقَةُ بُرْهَانٌ وَالْوُضُوءُ ضِيَاءٌ وَالْقُرْآنُ حُجَّةٌ لَكَ أَوْ عَلَيْكَ وَكُلُّ النَّاسِ يَغْدُو فَبَائِعٌ نَفْسَهُ فَمُعْتِقُهَا أَوْ مُوبِقُهَا","id":"Telah mengabarkan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Aban Ibnu Yazid], telah menceriytakan kepada kami [Yahya bin Abu katsir] dari [Zaid] dari [Abu Salam] dari [Abu Malik Al Asy'ari] Nabi shallallahu 'alaihi wasallam bersabda: \"Kebersihan adalah setengah keimanan, dan (ucapan) ALHAMDULILLAH memenuhi timbangan, dan (kalimat) LAA ILAAHA ILLALLAHU WA ALLAHU AKBAR keduanya memenuhi langit dan bumi, shalat adalah cahaya, sedekah bukti, wudhu itu sinar, dan Al Qur`an dapat menjadi hujjah yang membelamu atau hujjah yang menuntutmu, seluruh manusia berpagi hari, lantas menjual dirinya, hingga ia memerdekakan dirinya atau membinasakannya\". "},"419":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ أَبِي إِسْحَقَ عَنْ جُرَيٍّ النَّهْدِيِّ عَنْ رَجُلٍ مِنْ بَنِي سُلَيْمٍ قَالَ عَقَدَهُنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي يَدِي أَوْ قَالَ عَقَدَهُنَّ فِي يَدِهِ وَيَدُهُ فِي يَدِي سُبْحَانَ اللَّهِ نِصْفُ الْإِيمَانِ وَالْحَمْدُ لِلَّهِ يَمْلَأُ الْمِيزَانَ وَاللَّهُ أَكْبَرُ يَمْلَأُ مَا بَيْنَ السَّمَاءِ وَالْأَرْضِ وَالْوُضُوءُ نِصْفُ الْإِيمَانِ وَالصَّوْمُ نِصْفُ الصَّبْرِ","id":"Telah menceritakan kepada kami [Sa'id bin 'Amir] dari [Syu'bah] dari [Abu Ishak] dari [jurai An Nahdi] dari [seseorang dari bani Sulaim] ia berkata: \"Rasulullah shallallahu 'alaihi wasallam menghitung beberapa kalimat dengan tangannya -atau sepertinya mengatakan menghitung dengan jari tangannya yang saat itu tangannya diatas tanganku- (yaitu kalimat): SUBHANALLAHU setengah timbangan, ALHAMDULILLAH memenuhi timbangan, dan ALLAHU AKBAR memenuhi ruang langit dan bumi, wudhu setengah keimanan, dan puasa setengah kesabaran\"."},"420":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ وَالْأَعْمَشِ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ ثَوْبَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَقِيمُوا وَلَنْ تُحْصُوا وَاعْلَمُوا أَنَّ خَيْرَ أَعْمَالِكُمْ الصَّلَاةُ وَقَالَ الْآخَرُ إِنَّ مِنْ خَيْرِ أَعْمَالِكُمْ الصَّلَاةَ وَلَنْ يُحَافِظَ عَلَى الْوُضُوءِ إِلَّا مُؤْمِنٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Manshur] dan [Al A'masy] dari [Salim bin Abu Al Ja'd] dari [tsauban] -bekas budak Rasulullah shallallahu 'alaihi wasallam-, ia berkata: Rasulullah shallallahu 'alaihi wasallam bersabda: 'Beristiqamah lah kalian semua dan janganlah kalian menghitung-hitung, ketahuilah bahwa amal kalian yang paling baik adalah shalat', (dan beliau bersabda di lain waktu): ' sebaik-baik amalan kalian adalah shalat, dan tidaklah seorang yang selalu menjaga wudhunya melainkan ia seorang yang beriman\". "},"421":{"ar":" حَدَّثَنَا يَحْيَى بْنُ بِشْرٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا ابْنُ ثَوْبَانَ قَالَ حَدَّثَنِي حَسَّانُ بْنُ عَطِيَّةَ أَنَّ أَبَا كَبْشَةَ السَّلُولِيَّ حَدَّثَهُ أَنَّهُ سَمِعَ ثَوْبَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَدِّدُوا وَقَارِبُوا وَخَيْرُ أَعْمَالِكُمْ الصَّلَاةُ وَلَنْ يُحَافِظَ عَلَى الْوُضُوءِ إِلَّا مُؤْمِنٌ","id":"Telah menceritakan kepada kami [Yahya bin Bisyr] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Ibnu Tsauban] ia berkata: Telah menceritakan kepadaku [Hassan bin 'Athiyyah] Bahwa [Abu Kabsyah As Saluli] menceritakan kepadanya, ia pernah mendengar [Tsauban] (bekas budak Rasulullah shallallahu 'alaihi wasallam) berkata: Rasulullah shallallahu 'alaihi wasallam bersabda: \"Usahakanlah untuk menetapi kebenaran dan usahakanlah untuk mendekatinya, dan sebaik-baik amalan kalian adalah shalat, dan tidaklah seorang selalu menjaga wudhu melainkan ia seorang yang beriman\"."},"422":{"ar":" حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا مَسْعُودُ بْنُ عَلِيٍّ عَنْ عِكْرِمَةَ أَنَّ سَعْدًا كَانَ يُصَلِّي الصَّلَوَاتِ كُلَّهَا بِوُضُوءٍ وَاحِدٍ وَأَنَّ عَلِيًّا كَانَ يَتَوَضَّأُ لِكُلِّ صَلَاةٍ وَتَلَا هَذِهِ الْآيَةَ { إِذَا قُمْتُمْ إِلَى الصَّلَاةِ فَاغْسِلُوا وُجُوهَكُمْ وَأَيْدِيَكُمْ } الْآيَةَ","id":"Telah menceritakan kepada kami [Abdus Shamad bin Abdul Warits] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Mas'ud bin Ali] dari ['Ikrimah]. Bahwasanya [Sa'ad] menunaikan beberapa shalat dengan satu wudhu, sedangkan [Ali] selalu berwudhu untuk setiap shalat, dan ia membaca ayat ini: \"IDZAA QUMTUM ILAS SHALATI FAGHSILUU WUJUUHAKUM WA AIDIYAKUM...\" (Apabila kalian hendak menunaikan shalat basuhlah wajah dan kedua tanganmu...) -Qs. Al Ma`idah: 6-\"."},"423":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدٌ هُوَ ابْنُ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَ قُلْتُ أَرَأَيْتَ تَوَضُّؤَ ابْنِ عُمَرَ لِكُلِّ صَلَاةٍ طَاهِرًا أَوْ غَيْرَ طَاهِرٍ عَمَّ ذَلِكَ قَالَ حَدَّثَتْهُ أَسْمَاءُ بِنْتُ زَيْدِ بْنِ الْخَطَّابِ أَنَّ عَبْدَ اللَّهِ بْنَ حَنْظَلَةَ بْنِ أَبِي عَامِرٍ حَدَّثَهَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمِرَ بِالْوُضُوءِ لِكُلِّ صَلَاةٍ طَاهِرًا أَوْ غَيْرَ طَاهِرٍ فَلَمَّا شَقَّ ذَلِكَ عَلَيْهِ أُمِرَ بِالسِّوَاكِ لِكُلِّ صَلَاةٍ وَكَانَ ابْنُ عُمَرَ يَرَى أَنَّ بِهِ عَلَى ذَلِكَ قُوَّةً فَكَانَ لَا يَدَعُ الْوُضُوءَ لِكُلِّ صَلَاةٍ","id":"Telah mengabarkan kepada kami [Ahmad bin Khalid] telah menceritakan kepada kami [Muhamad Ibnu Ishak], dari [Muhammad bin Yahya bin Habban] dari [Abdillah bin Abdullah bin Umar] ia berkata: Aku berkata: \"Apakah kamu melihat wudhunya Ibnu Umar radliallahu 'anhu untuk setiap shalatnya baik dalam kondisi suci mengapa demikian? ', ia berkata: telah menceritakan kepadanya [`Asma` binti Zaid bin Al Khttahab] bahwasanya [Abdullah bin Hanzhalah bin Abu 'Amir] menceritakan kepadanya (`Asma`) Rasulullah shallallahu 'alaihi wasallam diperintahkan untuk berwudhu pada setiap shalat baik dalam kondisi suci atau tidak suci, ketika hal itu memberatkannya ia diperintah untuk bersiwak pada setiap shalat, dan Ibnu Umar radliallahu 'anhu berpendapat bahwa hal itu (riwayat berwudhu untuk setiap shalat) kuat, ia tidak meninggalkan wudhu untuk setiap shalat (nya) ' \". "},"424":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ سُفْيَانَ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ لِكُلِّ صَلَاةٍ حَتَّى كَانَ يَوْمُ فَتْحِ مَكَّةَ صَلَّى الصَّلَوَاتِ بِوُضُوءٍ وَاحِدٍ وَمَسَحَ عَلَى خُفَّيْهِ فَقَالَ لَهُ عُمَرُ رَأَيْتُكَ صَنَعْتَ شَيْئًا لَمْ تَكُنْ تَصْنَعُهُ قَالَ إِنِّي عَمْدًا صَنَعْتُ يَا عُمَرُ قَالَ أَبُو مُحَمَّد فَدَلَّ فِعْلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ مَعْنَى قَوْلِ اللَّهِ تَعَالَى { إِذَا قُمْتُمْ إِلَى الصَّلَاةِ فَاغْسِلُوا وُجُوهَكُمْ } الْآيَةَ لِكُلِّ مُحْدِثٍ لَيْسَ لِلطَّاهِرِ وَمِنْهُ قَوْلُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا وُضُوءَ إِلَّا مِنْ حَدَثٍ وَاللَّهُ أَعْلَمُ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Musa] dari [Sufyan] dari ['Alqamah bin Martsad] dari [Ibnu Buraidah] dari [ayahnya] ia berkata: \"Rasulullah shallallahu 'alaihi wasallam selalu berwudhu untuk setiap shalatnya hingga hari fathu Makkah (penaklukan kota Makkah), beliau shalat beberapa waktu shalat dengan satu wudhu, dan beliau (cukup) mengusap kedua khufnya, lalu Umar bertanya kepada beliau: 'Aku melihat kamu melakukan sesuatu yang belum pernah kamu lakukan sebelumnya? ', beliau menjawab: 'Aku melakukan itu dengan sengaja wahai Umar', Abu Muhammad berkata: 'Perbuatan Rasulullah shallallahu 'alaihi wasallam ini (menunjukkan) bahwa makna firman Allah subhanallahu wa ta'aa: \"IDZAA QUMTUM ILASSHALATI FAGHSILUU WUJUHAKUM\" (Apabila kalian hendak menunaikan shalat, hendaklah ia membasuh wajah kalian) -Qs. Al Ma`idah: 6- itu untuk setiap orang yang berhadats dan bukan untuk orang yang masih suci, (yang semakna) diantaranya sabdanya: 'Tidaklah wajib wudhu itu melainkan untuk orang yang berhadats.\""},"425":{"ar":" أَخْبَرَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَ كُنْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَعْضِ أَسْفَارِهِ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا ذَهَبَ إِلَى الْحَاجَةِ أَبْعَدَ","id":"Telah mengabarkan kepada kami [Ya'la bin Ubaid] telah menceritakan kepada kami [Muhammad bin 'Amr] dari [Abu Salamah] dari [Al Mughirah bin Syu'bah] ia berkata: \"Aku dahulu bersama Rasulullah shallallahu 'alaihi wasallam di beberapa perjalanan jauhnya, dan Rasulullah shallallahu 'alaihi wasallam apabila hendak buang hajat beliau menjauh\"."},"426":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ ابْنِ سِيرِينَ عَنْ عَمْرِو بْنِ وَهْبٍ ��َنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَبَرَّزَ تَبَاعَدَ قَالَ أَبُو مُحَمَّد هُوَ الْأَدَبُ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Jarir bin hazim] dari [Ibnu Sirin] dari ['Amr bin Wahab] dari [Al Mughirah bin Syu'bah] ia berkata: \"Dahulu Nabi shallallahu 'alaihi wasallam setiap kali hendak buang hajat beliau menjauh\". Abu Muhammad berkata: \"Itulah adab (buang hajat) \"."},"427":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ حَدَّثَنَا ثَوْرُ بْنُ يَزِيدَ حَدَّثَنَا حُصَيْنٌ الْحِمْيَرِيُّ أَخْبَرَنَا أَبُو سَعِيدٍ الْخَيْرُ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اكْتَحَلَ فَلْيُوتِرْ مَنْ فَعَلَ ذَلِكَ فَقَدْ أَحْسَنَ وَمَنْ لَا فَلَا حَرَجَ مَنْ اسْتَجْمَرَ فَلْيُوتِرْ مَنْ فَعَلَ فَقَدْ أَحْسَنَ وَمَنْ لَا فَلَا حَرَجَ مَنْ أَكَلَ فَلْيَتَخَلَّلْ فَمَا تَخَلَّلَ فَلْيَلْفِظْ وَمَا لَاكَ بِلِسَانِهِ فَلْيَبْتَلِعْ مَنْ أَتَى الْغَائِطَ فَلْيَسْتَتِرْ فَإِنْ لَمْ يَجِدْ إِلَّا كَثِيبَ رَمْلٍ فَلْيَسْتَدْبِرْهُ فَإِنَّ الشَّيَاطِينَ يَتَلَاعَبُونَ بِمَقَاعِدِ بَنِي آدَمَ مَنْ فَعَلَ فَقَدْ أَحْسَنَ وَمَنْ لَا فَلَا حَرَجَ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] telah menceritakan kepada kami [Tsaur bin Yazid] telah menceritakan kepada kami [Hushain Al Himyari] telah mengabarkan kepada kami [Abu Sa'id Al Khair] dari [Abu Hurairah] radliallahu 'anhu ia berkata: Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bercelak hendaklah mengganjilkannya, siapa yang mengerjakan hal itu, hal itu adalah lebih baik, dan barangsiapa tidak mengerjakan tidak apa-apa. Barangsiapa yang ber-istijmar (bersuci dengan batu) hendaklah dia mengganjilkannya, barangsiapa yang mengerjakan hal itu, hal itu baik dan siapa yang tidak mengerjakannya, tidak apa-apa. Barangsiapa yang makan hendaklah ia membersihkannya dari sela-sela giginya, kemudian sisa makanan itu ia keluarkan dari mulut, dan barangsiapa yang mengambilnya dengan lidahnya, hendaknya ia menelannya. Barangsiapa yang pergi ke tempat buang hajat hendaknya ia menutup auratnya, barangsiapa yang tidak mendapatkan penutupnya kecuali gundukan pasir, hendaknya ia menghadap ke belakang, karena setan bermain-main di tempat duduk manusia, barangsiapa yang mengerjakan hal ini, hal itu baik, tetapi barangsiapa yang tidak mengerjakannya, tidak apa-apa\"."},"428":{"ar":" أَخْبَرَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا مَهْدِيٌّ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي يَعْقُوبَ عَنْ الْحَسَنِ بْنِ سَعْدٍ مَوْلَى الْحَسَنِ بْنِ عَلِيٍّ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ قَالَ كَانَ أَحَبَّ مَا اسْتَتَرَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِحَاجَتِهِ هَدَفٌ أَوْ حَائِشُ نَخْلٍ","id":"Telah mengabarkan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Mahdi] telah menceritakan kepada kami [Muhammad bin Abdullah bin Abu ya'qub] dari [Al Hasan bin Sa'ad] -bekas budak Al Hasan bin Ali-, dari [Abdullah bin Ja'far] ia berkata: \"Yang paling disukai Nabi shallallahu 'alaihi wasallam untuk dijadikan penutup ketika beliau buang hajat adalah segala benda yang tinggi atau pohon kurma\"."},"429":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَبْدِ الْكَرِيمِ عَنْ الْوَلِيدِ بْنِ مَالِكٍ مِنْ عَبْدِ الْقَيْسِ عَنْ مُحَمَّدِ بْنِ قَيْسٍ مَوْلَى سَهْلِ بْنِ حُنَيْفٍ عَنْ سَهْلِ بْنِ حُنَيْفٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ أَنْتَ رَسُولِي إِلَى أَهْلِ مَكَّةَ فَقُلْ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ عَلَيْكُمْ السَّلَامَ وَيَأْمُرُكُمْ إِذَا خَرَجْتُمْ فَلَا تَسْتَقْبِلُوا الْقِبْلَةَ وَلَا تَسْتَدْبِرُوهَا","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [ibnu Juraij] dari [Abdul Karim] dari [Al Walid bin Malik bin Abdul Qais] dari [muhammad bin Qais] -bekas budak Sahl bin Hunaif-, dari [Sahl bin Hunaif] Nabi shallallahu 'alaihi wasallam bersabda: 'Kamu utusanku untuk penduduk Makkah, katakanlah: ' Rasulullah shallallahu 'alaihi wasallam menyampaikan salam kepada kalian, dan beliau memerintahkan apabila kalian keluar (untuk buang hajat), janganlah menghadap kiblat atau membelakanginya.\""},"430":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ عَنْ أَبِي أَيُّوبَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَتَيْتُمْ الْغَائِطَ فَلَا تَسْتَقْبِلُوا الْقِبْلَةَ بِغَائِطٍ وَلَا بَوْلٍ وَلَا تَسْتَدْبِرُوهَا قَالَ ثُمَّ قَالَ أَبُو أَيُّوبَ فَقَدِمْنَا الشَّامَ فَوَجَدْنَا مَرَاحِيضَ قَدْ بُنِيَتْ عِنْدَ الْقِبْلَةِ فَنَنْحَرِفُ وَنَسْتَغْفِرُ اللَّهَ قَالَ أَبُو مُحَمَّد وَهَذَا أَصَحُّ مِنْ حَدِيثِ عَبْدِ الْكَرِيمِ وَعَبْدُ الْكَرِيمِ شِبْهُ الْمَتْرُوكِ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [ibnu 'Uyainah] dari [Az zuhri] dari ['Atha` bin Yazid] dari [Abu Ayyub] dari Nabi shallallahu 'alaihi wasallam beliau bersabda; \"Apabila kamu datang untuk buang hajat, janganlah kalian menghadap atau membelakangi kiblat\". Lalu ia berkata: Abu Ayyub berkata: \"Kami datang ke negeri Syam, dan kami dapati toilet disana dibangun menghadap kiblat, lalu kami ubah dan kami memohon ampun kepada Allah subhanallahu wa ta'ala\". Abu Muhammad berkata: \"Hadits ini lebih shahih daripada hadits riwayat Abdul Karim, dan Abdul Karim hampir sederajat dengan para perawi yang riwayatnya tidak diterima\"."},"431":{"ar":" حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ عَنْ عَبْدِ السَّلَامِ بْنِ حَرْبٍ عَنْ الْأَعْمَشِ عَنْ أَنَسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَا يَرْفَعُ ثَوْبَهُ حَتَّى يَدْنُوَ مِنْ الْأَرْضِ قَالَ أَبُو مُحَمَّد هُوَ أَدَبٌ وَهُوَ أَشْبَهُ مِنْ حَدِيثِ الْمُغِيرَةِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] dari [Abdus salam bin Harb] dari [Al A'masy] dari [Anas] radliallahu 'anhu: \"Nabi shallallahu 'alahi wa sallam tidak mengangkat bajunya hingga saat beliau sudah dekat dengan tanah (dekat dengan tempat buang hajat) \". Abu Muhammad berkata: \"Ini adalah adab dan ini serupa dengan hadits Al Mughirah."},"432":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ أَنَّ مُحَمَّدَ بْنَ يَحْيَى بْنِ حَبَّانَ أَخْبَرَهُ أَنَّ عَمَّهُ وَاسِعَ بْنَ حَبَّانَ أَخْبَرَهُ عَنْ ابْنِ عُمَرَ قَالَ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى ظَهْرِ بَيْتِنَا فَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسًا عَلَى لَبِنَتَيْنِ مُسْتَقْبِلَ بَيْتِ الْمَقْدِسِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Yahya bin Sa'id] bahwa [Muhammad bin Yahya bin Habban] telah mengabarkan kepadanya bahwa pamannya - [Wasi' bin Habban] - telah mengabarkan kepadanya dari [Ibnu Umar], ia berkata: aku melihat Nabi shallallallahu'alaihiwasallam dari atas rumah kami, aku melihat Nabi shallallahu 'alaihi wasallam duduk di atas dua batu bata menghadap Baitul Maqdis (untuk buang hajat) \"."},"433":{"ar":" أَخْبَرَنَا جَعْفَرُ بْنُ عَوْنٍ أَخْبَرَنَا الْأَعْمَشُ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَ قَالَ جَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى سُبَاطَةِ قَوْمٍ فَبَالَ وَهُوَ قَائِمٌ قَالَ أَبُو مُحَمَّد لَا أَعْلَمُ فِيهِ كَرَاهِيَةً","id":"Telah mengabarkan kepada kami [Ja'far bin 'Aun] telah memberitakan kepada kami [Al A'masy] dari [Abu Wa`il] dari [Hudzaifah] ia berkata: \"Rasulullah shallallahu 'alaihi wasallam berjalan ke sebuah lorong (kosong) suatu kaum, lalu beliau buang air kecil sambil berdiri\". Abu Muhammad berkata: \"Aku tidak mengetahui adanya hukum makruh dalam hal demikian\"."},"434":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ الْخَلَاءَ قَالَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْخُبْثِ وَالْخَبَائِثِ","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah meneritakan kepada kami [Hammad bin zaid] dari [Abdul aziz bin Shuhaib] dari [Anas bin malik] radliallahu 'anhu ia berkata: \"Rasulullah shallallahu 'alaihi wasallam apabila hendak masuk ke tempat buang hajat beliau berdo`a: ALLAHUMMA INNI `A'UUDZU BIKA MINAL KHUBUTSI WAL KHABAA`ITS\" (Ya Allah, aku berlindung kepadaMu dari gangguan setan laki-laki dan perempuan) \"."},"435":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي حَازِمٍ عَنْ مُسْلِمِ بْنِ قُرْطٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا ذَهَبَ أَحَدُكُمْ إِلَى الْغَائِطِ فَلْيَذْهَبْ مَعَهُ بِثَلَاثَةِ أَحْجَارٍ يَسْتَطِيبُ بِهِنَّ فَإِنَّهَا تُجْزِئُ عَنْهُ","id":"Telah meneritakan kepda kami [Sa'id bin manshur] telah menceritakan kepada kami [Ya'qub bin Abdur Rahman] dari [Abu Hazim] dari [muslim bin Qurth] dari ['Urwah] dari [Aisyah] radliallahu 'anha ia berkata: \"Rasulullah shallallahu 'alaihi wasallam bersabda; Hendaklah ia membawa tiga tiga batu untuk bersuci dengannya, itu cukup \"."},"436":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عُيَيْنَةَ أَخْبَرَنَا عَلِيٌّ هُوَ ابْنُ مُسْهِرٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ عَمْرِو بْنِ خُزَيْمَةَ عَنْ عُمَارَةَ بْنِ خُزَيْمَةَ بْنِ ثَابِتٍ الْأَنْصَارِيِّ عَنْ أَبِيهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةُ أَحْجَارٍ لَيْسَ مِنْهُنَّ رَجِيعٌ يَعْنِي الِاسْتِطَابَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Uyainah] telah memberitakan kepada kami [Ali bin Mushir] dari [Hisyam bin 'Urwah] dari ['Amr bin Khuzaimah] dari ['Umarah bin Khuzaimah bin Tsabit Al Anshari] dari [ayahnya] ia berkata: Rasulullah salallahu 'alahi wa sallam: \"Dengan tiga batu tidak terdapat kotoran atau tinja padanya \". Maksudnya untuk bersuci."},"437":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَبْدِ الْكَرِيمِ هُوَ ابْنُ أَبِي الْمُخَارِقِ عَنْ الْوَلِيدِ بْنِ مَالِكٍ مِنْ عَبْدِ الْقَيْسِ عَنْ مُحَمَّدِ بْنِ قَيْسٍ مَوْلَى سَهْلِ بْنِ حُنَيْفٍ عَنْ سَهْلِ بْنِ حُنَيْفٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ أَنْتَ رَسُولِي إِلَى أَهْلِ مَكَّةَ فَقُلْ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ عَلَيْكُمْ السَّلَامَ وَيَأْمُرُكُمْ أَنْ لَا تَسْتَنْجُوا بِعَظْمٍ وَلَا بِبَعْرَةٍ قَالَ أَبُو عَاصِمٍ مَرَّةً وَيَنْهَاكُمْ أَوْ يَأْمُرُكُمْ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Abdul Karim Ibnu Abu Al Mukhariq], dari [Al Walid bin Malik bin Abdul Qais] dari [Muhammad bin Qais] -bekas budak Sahl bin Hunaif-, dari [Sahl bin Hunaif] Nabi shalallahu 'alahi wa sallam beliau berkata kepadanya: \"Kamu adalah utusanku untuk penduduk Makkah, maka katakanlah Rasulullah shalallahu 'alaihi wa sallam menitipkan salam kepada kalian dan memerintahkan kalian untuk tidak beristinja` (bersuci) dengan tulang atau kotoran hewan \". Abu 'Ashim mengatakan dalam kesempatan yang lain dengan susunan redaksi: \"Dan beliau melarang atau memerintahkan kepada kalian \"."},"438":{"ar":" أَخْبَرَنَا وَهْبُ بْنُ جَرِيرٍ وَيَزِيدُ بْنُ هَارُونَ وَأَبُو نُعَيْمٍ عَنْ هِشَامٍ عَنْ يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَمَسَّ أَحَدُكُمْ ذَكَرَهُ بِيَمِينِهِ وَلَا يَتَمَسَّحْ بِيَمِينِهِ","id":"Telah mengabarkan kepada kami [Wahab bin Jarir] dan [Yazid bin harun] serta [Abu Nu'aim] dari [Hisyam] dari [yahya] dari [Abdullah bin Abu Qatadah] dari [ayahnya] Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah seorang diantara kalian menyentuh kemaluannya dengan tangannya dan jangan pula melakukan istinja`dengan menggunakan tangan kanan.\"` "},"439":{"ar":" حَدَّثَنَا زَكَرِيَّا بْنُ عَدِيٍّ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ ابْنِ عَجْلَانَ عَنْ الْقَعْقَاعِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا أَنَا لَكُمْ مِثْلُ الْوَالِدِ لِلْوَلَدِ أُعَلِّمُكُمْ فَلَا تَسْتَقْبِلُوا الْقِبْلَةَ وَلَا تَسْتَدْبِرُوهَا وَإِذَا اسْتَطَبْتَ فَلَا تَسْتَطِبْ بِيَمِينِكَ وَكَانَ يَأْمُرُنَا بِثَلَاثَةِ أَحْجَارٍ وَيَنْهَى عَنْ الرَّوْثِ وَالرِّمَّةِ قَالَ زَكَرِيَّا يَعْنِي الْعِظَامَ الْبَالِيَةَ","id":"Telah menceritakan kepada kami [Zakaria bin 'Adi] telah menceritakan kepada kami [Ibnu Al Mubarak] dari [Ibnu Al 'Ajlan] dari [Al Qa'qa'] dari [Abu Shalih] dari [Abu Hurairah] radliallahu 'anhu ia berkata: Rasulullah shallallahu 'alaihi wasallam bersabda: \"Keberadaanku bagi kalian laksana seorang ayah bagi anaknya, yang aku adalah mengajari kalian, janganlah kalian menghadap kiblat dan jangan pula kalian membelakanginya (ketika buang hajat), dan apabila kalian hendak bersuci, janganlah kamu menggunakan tangan kananmu\". Dan Rasulullah shallallahu 'alaihi wasallam memerintahkan kami untuk menggunakan tiga buah batu, dan beliau melarang (untuk bersuci dengan menggunakan) kotoran dan rimmah. Zakaria berkata: \"Maksud (rimmah) adalah tulang rapuh\"."},"440":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ عَنْ شُعْبَةَ عَنْ عَطَاءِ بْنِ أَبِي مَيْمُونَةَ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا ذَهَبَ لِحَاجَتِهِ أَتَيْتُهُ أَنَا وَغُلَامٌ بِعَنَزَةٍ وَإِدَاوَةٍ فَيَتَوَضَّأُ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] dari [Syu'bah] dari ['Atha` bin Abu Maimunah] dari [Anas bin malik] radliallahu 'anhu \"Nabi shallallahu 'alaihi wasallam apabila hendak pergi untuk buang hajat, aku dengan seorang pembantu (nya) mendatanginya sambil membawa tongkat dan bejana, lalu beliau berwudhu\"."},"441":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي مُعَاذٍ عَنْ أَنَسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا خَرَجَ مِنْ الْخَلَاءِ جَاءَ الْغُلَامُ بِإِدَاوَةٍ مِنْ مَاءٍ كَانَ يَسْتَنْجِي بِهِ قَالَ أَبُو مُحَمَّد أَبُو مُعَاذٍ اسْمُهُ عَطَاءُ بْنُ مَنِيعٍ أَبِي مَيْمُونَةٍ","id":"Telah mengabarkan kepada kami [Abu Al Walid At Thayalisi] telah menceritakan kepada kami [Syu'bah] dari [Abi Mu'adz] dari [Anas]. Nabi shalallahu 'alaihi wa sallam Jika keluar dari WC, seorang pembantu medatanginya dengan membawa bejana air yang digunakan beliau untuk beristinja` \". Abu Muhammad mengatakan: \"Abu Muadz, namanya 'Atha` bin mani' Abu Maimunah \"."},"442":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ سُلَيْمَانَ عَنْ عَبَّادِ بْنِ الْعَوَّامِ عَنْ حُصَيْنِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ ذَرٍّ عَنْ الْمُسَيَّبِ بْنِ نَجَبَةَ قَالَ حَدَّثَتْنِي عَمَّتِي وَكَانَتْ تَحْتَ حُذَيْفَةَ أَنَّ حُذَيْفَةَ كَانَ يَسْتَنْجِي بِالْمَاءِ ","id":"Telah mengabarkan kepada kami [Said bin Sulaiman] dari ['Abbad bin Al 'Awwam] dari [hushain bin Abdur Rahman] dari [Dzar] dari [Al Musayyib bin Najabah] ia berkata: telah menceritakan kepadaku [bibiku] -saat itu masih menjadi budak bagi Hudzaifah-, \" [Hudzaifah] apabila beristinja` ia menggunakan air\". "},"443":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ أَبَانَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي حَازِمٍ عَنْ مَوْلًى لِأَبِي هُرَيْرَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ائْتِنِي بِوَضُوءٍ ثُمَّ دَخَلَ غَيْضَةً فَأَتَيْتُهُ بِمَاءٍ فَاسْتَنْجَى ثُمَّ مَسَحَ يَدَهُ بِالتُّرَابِ ثُمَّ غَسَلَ يَدَيْهِ أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا أَبَانُ بْنُ عَبْدِ اللَّهِ حَدَّثَنِي إِبْرَاهِيمُ بْنُ جَرِيرِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Aban bin Abdullah bin Abu hazim] dari [bekas budaknya Abu Hurairah] dari [Abu Hurairah] radliallahu 'anhu ia berkata: Nabi shallallahu 'alaihi wasallam pernah berkata: \"Tolong bawakan aku air untuk wudhu\", beliau masuk ke rerimbunan pohon, setelah itu aku membawakan air, dan beliau menggunakanya untuk istinja`, beliau mengusapkan tangannya ke tanah dan setelah itu beliau mencuci kedua tangannya (dengan air) \". Telah mengabarkan kepada kami [Muhammad bin yusuf] telah menceritakan kepada kami [Aban bin bin Abdullah] telah menceritakan kepadaku [Ibrahim bin jarir bin Abdullah] dari [ayahnya] dari Nabi shallallahu 'alahi wa sallam dengan hadits semisal.\""},"444":{"ar":" أَخْبَرَنَا مَالِكُ بْنُ إِسْمَعِيلَ حَدَّثَنَا إِسْرَائِيلُ عَنْ يُوسُفَ بْنِ أَبِي بُرْدَةَ عَنْ أَبِيهِ أَنَّ عَائِشَةَ حَدَّثَتْهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا خَرَجَ مِنْ الْخَلَاءِ قَالَ غُفْرَانَكَ","id":"Telah mengabarkan kepada kami [Malik bin Isma'il] telah menceritakan kepada kami [Isra`il] dari [Yusuf bin Abu Burdah] dari [ayahnya], bahwasanya [Aisyah] radliallahu 'anha menceritakan kepadanya: \" Nabi shallallahu 'alaihi wasallam apabila keluar dari tempat buang hajat, beliau membaca: GHUFRAANAKA (Aku memohon ampunan-Mu ya Allah) \"."},"445":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا سَعِيدُ بْنُ زَيْدٍ عَنْ شُعَيْبِ بْنِ الْحَبْحَابِ عَنْ أَنَسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَكْثَرْتُ عَلَيْكُمْ فِي السِّوَاكِ","id":"Telah mengabarkan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Sa'id bin Zaid] dari [Syu'aib bin Al Habhab] dari [Anas] radliallahu 'anhu. Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Aku sering memerintahkan kalian untuk bersiwak\"."},"446":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ شُعَيْبِ بْنِ الْحَبْحَابِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْثَرْتُ عَلَيْكُمْ فِي السِّوَاكِ","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Abdul Warits] dari [Syu'aib bin Al Habhab] dari [Anas bin Malik] radliallahu 'anhu ia berkata: Rasululah shallalahu 'alaihi wa sallam pernah bersabda: \"Aku sering memerintahkan kalian banyak bersiwak\"."},"447":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْمَدَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي لَأَمَرْتُهُمْ بِهِ عِنْدَ كُلِّ صَلَاةٍ قَالَ أَبُو مُحَمَّد يَعْنِي السِّوَاكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad] telah menceritakan kepada kami [Sufyan] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sekiranya aku tidak memberatkan umatku, niscaya kuperintahkan mereka melakukannya setiap kali hendak shalat.\" Abu Muhammad berkata: \"Yaitu bersiwak\"."},"448":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ هُوَ الْقَطْوَانِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ إِسْمَعِيلَ بْنِ أَبِي حَبِيبَةَ أَخْبَرَنِي دَاوُدُ بْنُ الْحُصَيْنِ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ قَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السِّوَاكُ مَطْهَرَةٌ لِلْفَمِ مَرْضَاةٌ لِلرَّبِّ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad Al Qathawani], telah menceritakan kepada kami [Ibrahim bin Isma'il bin Abu Habibah] ia berkata: telah mengabarkan kepadaku [Daud bin Al Hushain] dari [Al Qasim bin Muhammad] dari [Aisyah] radliallahu 'anha ia berkata: Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Siwak itu (berfungsi untuk) membersihkan mulut (gigi) dan mendatangkan keridhaan Rabb subhanallahu wa ta'ala\"."},"449":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ الرَّبِيعِ حَدَّثَنَا شُعْبَةُ عَنْ حُصَيْنٍ قَالَ سَمِعْتُ أَبَا وَائِلٍ عَنْ حُذَيْفَةَ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ إِلَى التَّهَجُّدِ يَشُوصُ فَاهُ بِالسِّوَاكِ","id":"Telah mengabarkan kepada kami [Sa'id bin Ar Rabi'] telah menceritakan kepada kami [Syu'bah] dari [hushain] ia berkata: \"Aku pernah mendengar [Abu Wa`il] dari [Hudzaifah] ia berkata: 'Rasulullah shallallahu 'alaihi wasallam apabila bangun untuk melaksanakan shalat tahajjud, beliau menggosok giginya dengan siwak\"."},"450":{"ar":" أَخْبَرَنَا سَهْلُ بْنُ حَمَّادٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَبِي الْمَلِيحِ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَقْبَلُ اللَّهُ صَلَاةً بِغَيْرِ طُهُورٍ وَلَا صَدَقَةً مِنْ غُلُولٍ","id":"Telah mengabarkan kepada kami [Sahl bin Hammad] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Abu Al Malih] dari [ayahnya] dari Nabi shallallahu 'alahi wa sallam, beliau bersabda; \"Allah subhanalahu wa ta'ala tidak menerima shalat (seorang hamba yang dilakukan) tanpa bersuci, dan (Allah subhanallahu wa ta'ala tidak menerima) sedekah dari ghulul (mengambil harta rampasan perang sebelum di bagikan) \"."},"451":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ مُحَمَّدِ بْنِ الْحَنَفِيَّةِ عَنْ عَلِيٍّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِفْتَاحُ الصَّلَاةِ الطُّهُورُ وَتَحْرِيمُهَا التَّكْبِيرُ وَتَحْلِيلُهَا التَّسْلِيمُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Abdullah bin Muhammad bin 'Aqil] dari [Muhammad Ibnu Al Hanafiyah] dari [Ali] radhialahu 'anhu ia berkata: Rasulullah shallalahu 'alaihi wa sallam bersabda: \"Kunci shalat adalah bersuci, tanda mengharamkan (segala aktivitas diluar shalat) adalah takbir, dan tanda menghalalkan (segala aktivitas diluar shalat) adalah salam\". "},"452":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا ابْنُ عُلَيَّةَ حَدَّثَنَا أَبُو رَيْحَانَةَ عَنْ سَفِينَةَ قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ بِالْمُدِّ وَيَغْتَسِلُ بِالصَّاعِ","id":"Telah mengabarkan kepada kami [Muhammad bin isa] telah menceritakan kepada kami [Ibnu 'Ulayyah] telah meneritakan kepada kami [Abu Raihanah] dari [Safinah] ia berkata: \"Nabi shallallahu 'alaihi wasallam berwudhu dengan (air sebanyak satu ukuran) mudd, dan beliau mandi dengan (air sebanyak satu ukuran) sha' \"."},"453":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ جَبْرٍ قَالَ سَمِعْتُ أَنَسًا يَقُولُ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ بِالْمَكُّوكِ وَيَغْتَسِلُ بِخَمْسِ مَكَاكِي","id":"Telah mengabarkan kepada kami [Abu Al walid At Thayalisi] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepadaku [Abdullah bin Abdullah bin jabr] ia berkata: \"Aku pernah mendengar [Anas] radliallahu 'anhu berkata: Rasulullah shallallahu 'alaihi wasallam pernah berwudhu dengan (air sebanyak) satu makkuk, dan mandi dengan (air sebanyak) lima makkuk.\" "},"454":{"ar":" أَخْبَرَنَا زَكَرِيَّا بْنُ عَدِيٍّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ الرُّبَيِّعِ بِنْتِ مُعَوِّذِ بْنِ عَفْرَاءَ قَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْتِينَا فِي مَنْزِلِنَا فَآخُذُ مِيضَأَةً لَنَا تَكُونُ مُدًّا وَثُلُثَ مُدٍّ أَوْ رُبُعَ مُدٍّ فَأَسْكُبُ عَلَيْهِ فَيَتَوَضَّأُ ثَلَاثًا ثَلَاثًا","id":"Telah mengabarkan kepada kami [Zakaria bin 'Adi] telah menceritakan kepada kami [Ubaidullah bin 'Amr] dari [Abdullah bin Muhammad bin 'Aqil] dari [Ar Rubai' binti Mu'awwidz bin 'Afra`] ia berkata: \"Rasulullah shallalahu 'alaihi wa sallam mendatangi rumah kami, lalu aku mengambil tempat air untuk wudhu kira-kira seukuran satu sepertiga atau seperempat mudd, lalu aku menuangkan ke beliau, dan beliau berwudhu tiga kali-tiga kali\"."},"455":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو عَامِرٍ الْعَقَدِيُّ حَدَّثَنَا كَثِيرُ بْنُ زَيْدٍ حَدَّثَنِي رُبَيْحُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سَعِيدٍ الْخُدْرِيُّ عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا وُضُوءَ لِمَنْ لَمْ يَذْكُرْ اسْمَ اللَّهِ عَلَيْهِ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'id] telah menceritakan kepada kami [Abu 'Amir Al 'Aqadi] telah menceritakan kepada kami [Katsir bin Zaid] telah menceritakan kepadaku [Rubaih bin Abdur Rahman bin Abu Sa'id Al Khudri] dari [ayahnya] dari [kakeknya] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Tidak (sah) wudhu seseorang yang tidak membaca basmallah\". "},"456":{"ar":" أَخْبَرَنَا هَاشِمُ بْنُ الْقَاسِمِ أَخْبَرَنَا شُعْبَةُ أَخْبَرَنِي النُّعْمَانُ بْنُ سَالِمٍ قَالَ سَمِعْتُ ابْنَ عَمْرِو بْنِ أَوْسٍ يُحَدِّثُ عَنْ جَدِّهِ أَوْسِ بْنِ أَبِي أَوْسٍ أَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ فَاسْتَوْكَفَ ثَلَاثًا فَقُلْتُ أَنَا لَهُ أَيُّ شَيْءٍ اسْتَوْكَفَ ثَلَاثًا قَالَ غَسَلَ يَدَيْهِ ثَلَاثًا","id":"Telah mengabarkan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepadaku [An nu'man bin Salim] ia berkata: \" Aku pernah mendengar [Ibnu 'Amr bin `Aus] menceritakan dari kakeknya - [`Aus bin Abu `Aus] -, ia pernah melihat Rasulullah shallallahu 'alaihi wasallam berwudhu, beliau meminta untuk dikucuri sebanyak tiga kali, lalu aku bertanya kepadanya: 'Anggota mana saja (yang) beliau meminta dikucuri sebanyak tiga kali? ', ia menjawab: 'Beliau membasuh tangannya sebanyak tiga kali' \"."},"457":{"ar":" أَخْبَرَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ عَنْ حُمْرَانَ بْنِ أَبَانَ مَوْلَى عُثْمَانَ بْنِ عَفَّانَ أَنَّ عُثْمَانَ تَوَضَّأَ فَمَضْمَضَ وَاسْتَنْشَقَ وَغَسَلَ وَجْهَهُ ثَلَاثًا وَيَدَيْهِ ثَلَاثًا وَمَسَحَ بِرَأْسِهِ وَغَسَلَ رِجْلَيْهِ ثَلَاثًا ثُمَّ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ كَمَا تَوَضَّأْتُ ثُمَّ قَالَ مَنْ تَوَضَّأَ وُضُوئِي هَذَا ثُمَّ صَلَّى رَكْعَتَيْنِ لَا يُحَدِّثُ فِيهِمَا نَفْسَهُ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengabarkan kepada kami [Nashr bin Ali Al Jahdhami] telah menceritakan kepada kami [Abdul A'la] dari [Ma'mar] dari [Az Zuhri] dari ['Atha` bin Yazid] dari [Humran bin Aban] -bekas budaknya Utsman bin Affan-. Bahwasanya [Utsman] radliallahu 'anhu berwudhu, ia berkumur-kumur, memasukkan air ke dalam hidung, membasuh wajahnya sebanyak tiga kali, mencuci kedua tangannya tiga kali, mengusap kepalanya, dan mencuci kedua kakinya sebanyak tiga kali, kemudian dia berkata: \"Aku melihat Rasulullah shallallahu 'alaihi wasallam berwudhu sebagaimana (baru saja) aku berwudhu, kemudian beliau bersabda: 'Barangsiapa berwudhu seperti wudhuku ini kemudian shalat dua rakaat dan tidak memikirkan sesuatu apapun dalam hatinya (ketika shalat), ia diampuni dari dosanya yang lewat' \"."},"458":{"ar":" حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ وَخَالِدُ بْنُ عَبْدِ اللَّهِ عَنْ عَمْرِو بْنِ يَحْيَى الْمَازِنِيِّ عَنْ أَبِيهِ أَنَّ عَبْدَ اللَّهِ بْنَ زَيْدٍ دَعَا بِتَوْرٍ مِنْ مَاءٍ فَأَكْفَأَ عَلَى يَدَيْهِ فَغَسَلَهُمَا ثَلَاثَ مَرَّاتٍ وَغَسَلَ وَجْهَهُ ثَلَاثًا وَيَدَيْهِ إِلَى الْمِرْفَقَيْنِ مَرَّتَيْنِ مَرَّتَيْنِ ثُمَّ قَالَ هَكَذَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ أَخْبَرَنَا يَحْيَى حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي سَلَمَةَ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوًا مِنْهُ","id":"Telah menceritakan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dan [Khalid bin Abdullah] dari ['Amr bin Yahya Al Mazini] dari [ayahnya]; [Abdullah bin Zaid] meminta diambilkan sebuah bejana yang berisi air, kemudian menuangkan ke kedua tangannya, lalu ia mencuci keduanya sebanyak tiga kali, dan ia membasuh wajahnya sebanyak tiga kali, dan mencuci kedua tangannya hingga kedua sikunya sebanyak dua kali-dua kali, kemudian ia berkata: 'Beginilah, aku melihat Rasulullah shallallahu 'alaihi wasallam berwudhu' \". Telah mengabarkan kepada kami [Yahya Ibnu hassan], telah menceritakan kepada kami [Abdul Aziz bin Abu Salamah] dari ['Amr bin Yahya] dari [ayahnya] dari [Abdullah bin Zaid] dari Nabi shalallahu 'alaihi wa sallam dengan hadits yang serupa."},"459":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ حَدَّثَنَا سُفْيَانُ الثَّوْرِيُّ حَدَّثَنَا زَيْدُ بْنُ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍ قَالَ أَلَا أُنَبِّئُكُمْ أَوْ أَلَا أُخْبِرُكُمْ بِوُضُوءِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَوَضَّأَ مَرَّةً مَرَّةً أَوْ قَالَ مَرَّةً مَرَّةً","id":"Telah mengabarkan kepada kami [Abu 'Ashim] telah menceritakan kepada kami [Sufyan Ats Tsauri] telah menceritakan kepada kami [Zaid bin Aslam] dari ['Atha` bin Yasar] dari [Ibnu Abbas] radliallahu 'anhu ia berkata: \"Maukah kuberitahu atau maukah aku kabarkan kepada kalian tentang wudhu Rasulullah shallallahu 'alaihi wasallam?, kemudian beliau berwudhu sebanyak sekali-sekali atau ia berkata: 'sekali-sekali' \". "},"460":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنِي عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ الدَّرَاوَرْدِيُّ حَدَّثَنَا زَيْدُ بْنُ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ مَرَّةً مَرَّةً جَمَعَ بَيْنَ الْمَضْمَضَةِ وَالِاسْتِنْشَاقِ","id":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepadaku [Abdul Aziz bin Muhammad Ad Darawardi] telah menceritakan kepada kami [Zaid bin Aslam] dari ['Atha` bin Yasar] dari [Ibnu Abbas] radliallahu 'anhu Nabi shallallahu 'alaihi wasallam pernah berwudhu sekali-sekali, dan beliau menggabungkan antara berkumur-kumur dan memasukkan air ke hidung\"."},"461":{"ar":" حَدَّثَنَا زَكَرِيَّا بْنُ عَدِيٍّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو عَنْ ابْنِ عَقِيلٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ سَمِعَهُ يَقُولُ أَلَا أَدُلُّكُمْ عَلَى مَا يُكَفِّرُ اللَّهُ بِهِ الْخَطَايَا وَيَزِيدُ بِهِ فِي الْحَسَنَاتِ قَالُوا بَلَى قَالَ إِسْبَاغُ الْوُضُوءِ عَلَى الْمَكْرُوهَاتِ وَكَثْرَةُ الْخُطَا إِلَى الْمَسَاجِدِ وَانْتِظَارُ الصَّلَاةِ بَعْدَ الصَّلَاةِ حَدَّثَنَا مُوسَى بْنُ مَسْعُودٍ حَدَّثَنَا زُهَيْرُ بْنُ مُحَمَّدٍ عَنْ عَبْدِ اللَّهِ هُوَ ابْنُ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ بِنَحْوِهِ","id":"Telah mengabarkan kepada kami [Zakaria bin 'Adi] telah menceritakan kepada kami [Ubaidullah bin 'Amr] dari [Ibnu 'Aqil] dari [Sa'id bin Al Musayyib] dari [Abu Sa'id Al Khudri] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam ia mendengar beliau bersabda: \"Maukah kutunjukkan kepada kalian satu hal yang dapat menghapus dosa-dosa, dan dapat menambah nilai kebaikan?\", mereka menjawab: \"Tentu\", beliau bersabda: \"Hendaklah kalian menyempurnakan wudhu saat tidak suka, memperbanyak langkah kaki menuju masjid, dan menanti waktu shalat secara rutin\". Telah menceritakan kepada kami [Musa bin Mas'ud] telah menceritakan kepada kami [Zuhair bin Muhammad] dari [Abdullah Ibnu Muhammad bin 'Aqil], dari [Sa'id bin Al Musayyab] dari [Abu Sa'id Al Khudri] radliallahu 'anhu ia telah mendengar Rasulullah shallallahu 'alaihi wasallam, kemudian ia menyebutkan hadits yang serupa dengannya\". "},"462":{"ar":" حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَبِي الْجَهْضَمِ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُمِرْنَا بِإِسْبَاغِ الْوُضُوءِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Hammad bin Zaid] dari [Abu Al jahdham] dari [Ubaidullah bin Abdullah] dari [Ibnu Abbas] radliallahu 'anhu dari Nabi shallallahu 'alahi wa sallam pernah bersabda: \"Kami diperintahkan menyempurnakan wudhu\"."},"463":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا زَائِدَةُ حَدَّثَنَا خَالِدُ بْنُ عَلْقَمَةَ الْهَمْدَانِيُّ حَدَّثَنِي عَبْدُ خَيْرٍ قَالَ دَخَلَ عَلِيٌّ الرَّحَبَةَ بَعْدَمَا صَلَّى الْفَجْرَ قَالَ فَجَلَسَ فِي الرَّحَبَةِ ثُمَّ قَالَ لِغُلَامٍ لَهُ ائْتِنِي بِطَهُورٍ قَالَ فَأَتَاهُ الْغُلَامُ بِإِنَاءٍ فِيهِ مَاءٌ وَطَسْتٍ قَالَ عَبْدُ خَيْرٍ وَنَحْنُ جُلُوسٌ نَنْظُرُ إِلَيْهِ فَأَدْخَلَ يَدَهُ الْيُمْنَى فَمَلَأَ فَمَهُ فَمَضْمَضَ وَاسْتَنْشَقَ وَنَثَرَ بِيَدِهِ الْيُسْرَى فَعَلَ هَذَا ثَلَاثَ مَرَّاتٍ ثُمَّ قَالَ مَنْ سَرَّهُ أَنْ يَنْظُرَ إِلَى طُهُورِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهَذَا طُهُورُهُ أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا حَسَنُ بْنُ عُقْبَةَ الْمُرَادِيُّ أَخْبَرَنِي عَبْدُ خَيْرٍ بِإِسْنَادِهِ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Za`idah] telah menceritakan kepada kami [Khalid bin 'Alqamah Al Hamdani] telah menceritakan kepadaku ['Abdu khair] ia berkata: \"(Suatu hari) setelah shalat fajr [Ali] pernah masuk ke beranda, lalu ia duduk di beranda', dan berkata kepada pembantunya: 'Tolong ambilkan aku (air untuk) bersuci', ia berkata: 'Pembantunya datang dengan membawa bejana yang berisi air', 'Abdu Khair berkata: 'Dan kami waktu itu duduk sambil melihatnya', kemudian ia memasukkan tangan kanannya dan memenuhi mulutnya dengan air untuk berkumur-kumur dan memasukkan air ke hidungnya, kemudian ia keluarkan (air dari hidungnya) dengan tangan kirinya, ia melakukan hal ini sebanyak tiga kali-tiga kali, kemudian ia berkata: 'Barangsiapa ingin melihat cara berwudhu Rasulullah shallallahu 'alaihi wasallam, seperti inilah cara wudhu yang pernah dilakukan oleh Nabi shallallahu 'alaihi wasallam' \". Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Hasan bin Uqbah Al Muradi] ia berkata: 'Telah mengabarkan kepadaku ['Abdu] Khair dengan sanad yang serupa dengannya\"."},"464":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ عَائِذِ اللَّهِ بْنِ عَبْدِ اللَّهِ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ اسْتَنْشَقَ فَلْيَسْتَنْثِرْ وَمَنْ اسْتَجْمَرَ فَلْيُوتِرْ","id":"Telah mengabarkan kepada kami [Ahmad bin Khalid] telah menceritakan kepada kami [Muhammad bin Ishak] dari [Az Zuhri] dari ['A`idzullah bin Abdullah] ia berkata: Aku pernah mendengar [Abu Hurairah] radliallahu 'anhu berkata: \"Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Barangsiapa memasukkan air ke hidung dan mengeluarkannya, dan barangsiapa beristinja` dengan batu hendaknya ia (melakukannya) dengan bilangan ganjil' \"."},"465":{"ar":" أَخْبَرَنَا مَالِكُ بْنُ إِسْمَعِيلَ حَدَّثَنَا إِسْرَائِيلُ عَنْ عَامِرِ بْنِ شَقِيقٍ عَنْ شَقِيقِ بْنِ سَلَمَةَ قَالَ رَأَيْتُ عُثْمَانَ تَوَضَّأَ فَخَلَّلَ لِحْيَتَهُ وَقَالَ هَكَذَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ","id":"Telah mengabarkan kepada kami [Malik bin Isma'il] telah menceritakan kepada kami [Isra`il] dari ['Amir bin Syaqiq] dari [Syaqiq bin Salamah] ia berkata: \"Aku pernah melihat [Utsman] radliallahu 'anhu berwudhu, beliau menyela-nyela jenggotnya, dan ia berkata: 'Beginilah aku melihat Rasulullah shallallahu 'alaihi wasallam berwudhu\"."},"466":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي إِسْمَعِيلُ بْنُ كَثِيرٍ عَنْ عَاصِمِ بْنِ لَقِيطِ بْنِ صَبِرَةَ عَنْ أَبِيهِ وَافِدِ بَنِي الْمُنْتَفِقِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا تَوَضَّأْتَ فَأَسْبِغْ وُضُوءَكَ وَخَلِّلْ بَيْنَ أَصَابِعِكَ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] telah memberitakan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Isma'il bin Katsir] dari ['Ashim bin Laqith bin Shabrah] dari [ayahnya] -utusan Bani Al Muntafiq-, dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Apabila kamu berwudhu, hendaknya kamu menyempurnakan wudhumu, dan hendaknya kamu menyela-nyela jari-jemarimu\"."},"467":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا جَعْفَرٌ هُوَ ابْنُ الْحَارِثِ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ أَبِي يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيْلٌ لِلْأَعْقَابِ مِنْ النَّارِ أَسْبِغُوا الْوُضُوءَ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Ja'far Ibnu Al Harits], dari [Manshur] dari [Hilal bin Yasaf] dari [Abu yahya] dari [Abdullah bin 'Amr] ia berkata: Rasulullah shallallahu 'alaihi wasallam bersabda: \"Celakalah tumit-tumit (yang tidak terkena air wudhu, akan terkena oleh) api neraka, hendaklah kalian menyempurnakan wudhu.\""},"468":{"ar":" أَخْبَرَنَا هَاشِمُ بْنُ الْقَاسِمِ أَخْبَرَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ زِيَادٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ قَالَ كَانَ يَمُرُّ بِنَا وَالنَّاسُ يَتَوَضَّئُونَ مِنْ الْمِطْهَرَةِ وَيَقُولُ أَسْبِغُوا الْوُضُوءَ قَالَ أَبُو الْقَاسِمِ وَيْلٌ لِلْأَعْقَابِ مِنْ النَّارِ قَالَ أَبُو مُحَمَّد هَذَا أَعْجَبُ إِلَيَّ مِنْ حَدِيثِ عَبْدِ اللَّهِ بْنِ عَمْرٍو","id":"Telah mengabarkan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin Ziyad] ia berkata: \"Aku pernah mendengar [Abu Hurairah] radliallahu 'anhu ia bercerita: 'Dia pernah melewati kami dan orang-orang berwudhu dari tempat berwudhu, lalu ia berkata: 'Sempurnakanlah wudhu kalian, Abu Al Qasim shallallahu 'alaihi wasallam bersabda: 'Celakalah tumit-tumit (yang tidak terkena air wudhu, akan terkena) api neraka' \". Abu Muhammad berkata: \"Hadits ini lebih membuatku kagum dibandingkan dengan hadits Abdullah bin 'Amr\". "},"469":{"ar":" أَخْبَرَنَا مَالِكُ بْنُ إِسْمَعِيلَ حَدَّثَنَا إِسْرَائِيلُ عَنْ عَامِرِ بْنِ شَقِيقٍ عَنْ شَقِيقِ بْنِ سَلَمَةَ قَالَ رَأَيْتُ عُثْمَانَ تَوَضَّأَ فَمَسَحَ بِرَأْسِهِ وَأُذُنَيْهِ ظَاهِرِهِمَا وَبَاطِنِهِمَا ثُمَّ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَنَعَ كَمَا صَنَعْتُ أَوْ كَالَّذِي صَنَعْتُ","id":"Telah mengabarkan kepada kami [Malik bin Isma'il telah menceritakan kepada kami [Isra`il] dari ['Amir bin Syaqiq] dari [Syaqiq bin Salamah] ia berkata: \"Aku pernah melihat [Utsman] berwudhu, lalu ia mengusap kepalanya (rambutnya) dan kedua telinganya, baik bagian luar atau dalam, kemudian ia berkata: 'Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam melakukan (berwudhu) yang kulakukan atau seperti yang kulakukan' \". "},"470":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا حَبَّانُ بْنُ وَاسِعٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدِ بْنِ عَاصِمٍ الْمَازِنِيِّ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ بِالْجُحْفَةِ فَمَضْمَضَ وَاسْتَنْشَقَ ثُمَّ غَسَلَ وَجْهَهُ ثَلَاثًا ثُمَّ غَسَلَ يَدَيْهِ ثَلَاثًا ثُمَّ مَسَحَ رَأْسَهُ وَغَسَلَ رِجْلَيْهِ حَتَّى أَنْقَاهُمَا ثُمَّ مَسَحَ رَأْسَهُ بِمَاءٍ غَيْرِ فَضْلِ يَدَيْهِ قَالَ أَبُو مُحَمَّد يُرِيدُ بِهِ تَفْسِيرَ مَسْحِ الْأَوَّلِ","id":"Telah mengabarkan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Ibnu Lahi'ah] telah menceritakan kepada kami [Habban bin Wasi'] dari [ayahnya] dari [Abdullah bin Zaid 'Ashim Al Mazini] ia berkata: \"Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam berwudhu sewaktu di Al juhfah, beliau berkumur-kumur dan memasukkan air ke hidung, kemudian membasuh wajahnya tiga kali, lalu beliau mengusap kepalanya (rambutnya), lalu mencuci kedua kakinya hingga bersih, kemudian beliau membasuh kepalanya dengan air baru (bukan air sisa basuhan tangan) \". Abu Muhammad berkata: \"(Pernyataan akhir ini) ia maksudkan untuk menjelaskan basuhan (kepala) yang pertama\". "},"471":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ جَعْفَرِ بْنِ عَمْرِو بْنِ أُمَيَّةَ الضَّمْرِيِّ عَنْ أَبِيهِ أَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَسَحَ عَلَى الْخُفَّيْنِ وَالْعِمَامَةِ قِيلَ لِأَبِي مُحَمَّدٍ تَأْخُذُ بِهِ قَالَ إِي وَاللَّهِ","id":"Telah mengabarkan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Al 'Auza'i] dari [Yahya] dari [Abu Salamah] dari [Ja'far bin 'Amr bin Umayyah Adh Dhamri] dari [ayahnya]: \" Ia pernah melihat Rasulullah shallallahu 'alaihi wasallam membasuh kedua khufnya dan sorbannya\". Ditanyakan kepada Abu Muhammad: \"Apakah kamu menjadikannya sebagai hujjah?\", ia menjawab: \"Ya, Demi Allah subhanallahu wa ta'ala\"."},"472":{"ar":" أَخْبَرَنَا قَبِيصَةُ أَخْبَرَنَا سُفْيَانُ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ مَرَّةً مَرَّةً وَنَضَحَ فَرْجَهُ","id":"Telah mengabarkan kepada kami [Qabishah] telah memberitakan kepada kami [Sufyan] dari [Zaid bin Aslam] dari ['Atha` bin Yasar] dari [Ibnu Abbas] radliallahu 'anhu: Nabi shallallahu 'alaihi wasallam berwudhu sekali-sekali, dan beliau memercikkan air pada kemaluan beliau (setelah beristinja`) \"."},"473":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ ابْنِ أَبِي لَيْلَى عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ قَالَ سَأَلْتُ مَيْمُونَةَ خَالَتِي عَنْ غُسْلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْجَنَابَةِ فَقَالَتْ كَانَ يُؤْتَى بِالْإِنَاءِ فَيُفْرِغُ بِيَمِينِهِ عَلَى شِمَالِهِ فَيَغْسِلُ فَرْجَهُ وَمَا أَصَابَهُ ثُمَّ يَتَوَضَّأُ وُضُوءَهُ لِلصَّلَاةِ ثُمَّ يَغْسِلُ رَأْسَهُ وَسَائِرَ جَسَدِهِ ثُمَّ يَتَحَوَّلُ فَيَغْسِلُ رِجْلَيْهِ ثُمَّ يُؤْتَى بِالْمِنْدِيلِ فَيَضَعُهُ بَيْنَ يَدَيْهِ فَيَنْفُضُ أَصَابِعَهُ وَلَا يَمَسُّهُ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Musa] dari [Ibnu Abu Laila] dari [Salamah bin Kuhail] dari [Kuraib] dari [Ibnu Abbas] radliallahu 'anhu ia berkata: \"Aku pernah bertanya kepada [Maimunah] radliallahu 'anha bibiku, tentang (cara) mandi junub Nabi shallallahu 'alaihi wasallam, ia menjawab: 'Beliau dibawakan bejana air, lalu beliau menyiramkan air dengan telapak kanannya ke telapak kirinya, lalu beliau mencuci kemaluannya dan bagian yang kotor, kemudian beliau berwudhu sebagaimana wudhu untuk shalat, lalu beliau mencuci kepalanya dan seluruh tubuhnya, kemudian berpindah dan membasuh kedua kakinya, kemudian beliau diberi sapu tangan dan beliau letakkan di depan beliau, kemudian jemari beliau mengibaskannya tanpa memegangnya\". "},"474":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زَكَرِيَّا هُوَ ابْنُ أَبِي زَائِدَةَ عَنْ عَامِرٍ عَنْ عُرْوَةَ بْنِ الْمُغِيرَةِ عَنْ أَبِيهِ قَالَ كُنْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فِي سَفَرٍ فَقَالَ أَمَعَكَ مَاءٌ فَقُلْتُ نَعَمْ فَنَزَلَ عَنْ رَاحِلَتِهِ فَمَشَى حَتَّى تَوَارَى عَنِّي فِي سَوَادِ اللَّيْلِ ثُمَّ جَاءَ فَأَفْرَغْتُ عَلَيْهِ مِنْ الْإِدَاوَةِ فَغَسَلَ يَدَيْهِ وَوَجْهَهُ وَعَلَيْهِ جُبَّةٌ مِنْ صُوفٍ فَلَمْ يَسْتَطِعْ أَنْ يُخْرِجَ ذِرَاعَيْهِ مِنْهَا حَتَّى أَخْرَجَهُمَا مِنْ أَسْفَلِ الْجُبَّةِ فَغَسَلَ ذِرَاعَيْهِ وَمَسَحَ بِرَأْسِهِ ثُمَّ أَهْوَيْتُ لِأَنْزِعَ خُفَّيْهِ فَقَالَ دَعْهُمَا فَإِنِّي أَدْخَلْتُهُمَا طَاهِرَتَيْنِ فَمَسَحَ عَلَيْهِمَا","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zakaria Ibnu Abu Za`idah], dari ['Amir] dari ['Urwah bin Al Mughirah] dari [ayahnya] ia berkata: \"Aku pernah bersama Rasulullah shallallahu 'alaihi wasallam pada suatu malam dalam sebuah perjalanan, lalu beliau bertanya: 'Apakah kamu membawa air? ', Aku menjawab: 'Ya, ada', lalu beliau turun dari tunggangannya dan berjalan hingga tidak terlihat dariku dalam gelapnya malam, kemudian beliau datang dan aku tuangkan air kepadanya dari ember, lalu beliau mencuci kedua tangannya dan membasuh wajahnya, dan beliau (saat itu) mengenakan jubah dari bulu domba, beliau tidak bisa mengeluarkan sebagian lengannya, hingga beliau mengeluarkan keduanya dari arah bawah jubah, lalu beliau mencuci dua lengannya dan mengusap kepadanya, kemudian aku menunduk untuk melepas kedua khufnya, tetapi beliau berkata: 'Biarkan keduanya, karena aku memasukkannya dalam keadaan suci', lalu beliau mengusap bagian atasnya' \". "},"475":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ قَيْسٍ عَنْ الْحَكَمِ بْنِ عُتَيْبَةَ عَنْ الْقَاسِمِ بْنِ مُخَيْمِرَةَ عَنْ شُرَيْحِ بْنِ هَانِئٍ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَ جَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةَ أَيَّامٍ وَلَيَالِيَهُنَّ لِلْمُسَافِرِ وَيَوْمًا وَلَيْلَةً لِلْمُقِيمِ يَعْنِي الْمَسْحَ عَلَى الْخُفَّيْنِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari ['Amr bin Qais] dari [Al Hakam bin 'Utaibah] dari [Al Qasim bin Mukhaimirah] dari [syuraih bin hani`] dari [Ali bin Abu Thalib] radliallahu 'anhu ia berkata: \"Rasulullah shallallahu 'alaihi wasallam menetapkan (batasan), tiga hari tiga malam bagi mereka yang sedang bepergian (dalam perjalanan jauh), dan sehari semalam untuk orang yang tidak sedang bepergian\". Maksudnya batas waktu dibolehkan mengusap kedua khuf."},"476":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا يُونُسُ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ خَيْرٍ قَالَ رَأَيْتُ عَلِيًّا تَوَضَّأَ وَمَسَحَ عَلَى النَّعْلَيْنِ فَوَسَّعَ ثُمَّ قَالَ لَوْلَا أَنِّي رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَلَ كَمَا رَأَيْتُمُونِي فَعَلْتُ لَرَأَيْتُ أَنَّ بَاطِنَ الْقَدَمَيْنِ أَحَقُّ بِالْمَسْحِ مِنْ ظَاهِرِهِمَا قَالَ أَبُو مُحَمَّد هَذَا الْحَدِيثُ مَنْسُوخٌ بِقَوْلِهِ تَعَالَى { وَامْسَحُوا بِرُءُوسِكُمْ وَأَرْجُلَكُمْ إِلَى الْكَعْبَيْنِ }","id":"Telah mengabarkan kepada kami [Abu nu'aim] telah menceritakan kepada kami [Yunus] dari [Abu Ishak] dari [Abdu Khair] ia berkata: \"Aku pernah melihat [Ali] radliallahu 'anhu berwudhu dan mengusap bagian atas kedua sandalnya, lalu ia melonggarkannya, kemudian ia berkata: 'Kalau saja aku tidak melihat Rasulullah shallallahu 'alaihi wasallam mengerjakan seperti yang kalian lihat kukerjakan, niscaya aku (lebih) berpendapat bahwa bagian bawah kaki itu lebih pantas untuk diusap dibandingkan bagian atasnya' \". Abu Muhammad berkata: \"Hadits ini mansukh (dihapus keberlakuan hukumnya), lalu ditanyakan kepadanya: 'Apa yang menghapusnya? ', ia menjawab: 'Firman Allah subhanallahu wa ta'ala \"IMSAHUU BI RU`UUSIKUM WA ARJULAKUM ILAL KA'BAIN\" (Maka usaplah kepala kalian, dan kaki-kaki kalian hingga mata kaki) -Qs. Al Ankabut: 6-."},"477":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا حَيْوَةُ أَخْبَرَنَا أَبُو عَقِيلٍ زُهْرَةُ بْنُ مَعْبَدٍ عَنْ ابْنِ عَمِّهِ عَنْ عُقْبَةَ بْنِ عَامِرٍ أَنَّهُ خَرَجَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ تَبُوكَ فَجَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا يُحَدِّثُ أَصْحَابَهُ فَقَالَ مَنْ قَامَ إِذَا اسْتَقَلَّتْ الشَّمْسُ فَتَوَضَّأَ فَأَحْسَنَ الْوُضُوءَ ثُمَّ صَلَّى رَكْعَتَيْنِ خَرَجَ مِنْ ذُنُوبِهِ كَيَوْمِ وَلَدَتْهُ أُمُّهُ فَقَالَ عُقْبَةُ فَقُلْتُ الْحَمْدُ لِلَّهِ الَّذِي رَزَقَنِي أَنْ أَسْمَعَ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عُمَرُ بْنُ الْخَطَّابِ وَكَانَ تُجَاهِي جَالِسًا أَتَعْجَبُ مِنْ هَذَا فَقَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْجَبَ مِنْ هَذَا قَبْلَ أَنْ تَأْتِيَ فَقُلْتُ وَمَا ذَلِكَ بِأَبِي أَنْتَ وَأُمِّي فَقَالَ عُمَرُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَوَضَّأَ فَأَحْسَنَ الْوُضُوءَ ثُمَّ رَفَعَ بَصَرَهُ إِلَى السَّمَاءِ أَوْ قَالَ نَظَرَهُ إِلَى السَّمَاءِ فَقَالَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ فُتِحَتْ لَهُ ثَمَانِيَةُ أَبْوَابِ الْجَنَّةِ يَدْخُلُ مِنْ أَيِّهِنَّ شَاءَ","id":"Telah mengabarkan kepada kami [Abdullah bin Yazid] telah menceritakan kepada kami [Haiwah] telah memberitakan kepada kami [Abu 'Aqil Zuhra bin Ma'bad] dari [sepupunya] dari ['Uqbah bin 'Amir] ia pergi bersama Rasulullah shallallahu 'alaii wa sallam pada peperangan Tabuk. Pada suatu hari Rasulullah shallallahu 'alaihi wasallam duduk menyampaikan sebuah hadits kepada para sahabatnya, beliau bersabda: 'Barangsiapa yang bangun dan matahari sudah mulai berlalu, lalu ia berwudhu dan membaguskan wudhunya, kemudian ia shalat dua rakaat, ia keluar dari dosa-dosanya sebagaimana saat ia dilahirkan ibunya'. 'Uqbah berkata: 'Segala puji bagi Allah subhanallahu wa ta'ala yang menganugerahkan kepadaku mendengar hadits dari Rasulullah shallallahu 'alaihi wasallam, lalu Umar bin Al Khatthab radliallahu 'anhu yang pada waktu itu sedang duduk di depanku berkata: 'Apakah kamu heran dengan hal ini?, padahal Rasulullah shallalahu 'alaihi wa sallam sebelumnya menyampaikan sabda yang lebih membuat kalian heran dibandingkan yang ini, sebelum kamu datang', aku bertanya: 'Apa itu', lalu Umar radliallahu 'anhu bersabda: 'Barangsiapa yang berwudhu dan membaguskan wudhunya, kemudian ia menengadahkan pandangannya (atau ia bersabda: 'melihat') ke langit dan mengucap: 'ASY HADU ANLAA ILAAHA ILLALLAHU WAHDAHU LAA SYARIKA LAHU WA ASYHADU ANNA MUHAMMADAN 'ABDUHU WA RASULUHU' (Aku bersaksi bahwa tidak ada Tuhan (yang berhak di sembah) kecuali Allah yang esa, tidak ada sekutu bagiNya, dan aku bersaksi bahwa Muhammad adalah hamba dan utusanNya), niscaya dibukakan untuknya delapan pintu surga, dan ia bebas masuk melewati pintu mana saja' \"."},"478":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ عَنْ أَبِي الزُّبَيْرِ عَنْ سُفْيَانَ بْنِ عَبْدِ اللَّهِ عَنْ عَاصِمِ بْنِ سُفْيَانَ أَنَّهُمْ غَزَوْا غَزْوَةَ السَّلَاسِلِ فَرَجَعُوا إِلَى مُعَاوِيَةَ وَعِنْدَهُ أَبُو أَيُّوبَ وَعُقْبَةُ بْنُ عَامِرٍ فَقَالَ أَبُو أَيُّوبَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ تَوَضَّأَ كَمَا أُمِرَ وَصَلَّى كَمَا أُمِرَ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ عَمَلٍ أَكَذَاكَ يَا عُقْبَةُ قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Laits bin Sa'ad] dari [Abu Az Zubair] dari [Sufyan bin Abdullah] dari ['Ashim bin Sufyan]: \"Mereka pergi melakukan perjalanan perang Salasil, kemudian kembali kepada Mu'awiyah dan di sisinya ada Abu Ayyub dan 'Uqbah bin 'Amir radliallahu 'anhum. Kemudian [Abu Ayyub] radliallahu 'anhu berkata: 'Aku pernah mendengar Rasulullah shallallahu 'alahi wa sallam bersabda: 'Barangsiapa berwudhu seperti yang diperintahkan, kemudian shalat seperti yang diperintahkan, ia diampuni segala yang telah lalu, bukankah demikian wahai ['Uqbah]? ', ia menjawab: 'Ya, benar' \"."},"479":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ حَدَّثَنَا مَالِكٌ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا تَوَضَّأَ الْعَبْدُ الْمُسْلِمُ أَوْ الْمُؤْمِنُ فَغَسَلَ وَجْهَهُ خَرَجَتْ مِنْ وَجْهِهِ كُلُّ خَطِيئَةٍ نَظَرَ إِلَيْهَا بِعَيْنِهِ مَعَ الْمَاءِ أَوْ مَعَ آخِرِ قَطْرِ الْمَاءِ فَإِذَا غَسَلَ يَدَيْهِ خَرَجَتْ مِنْ يَدَيْهِ كُلُّ خَطِيئَةٍ بَطَشَتْهَا يَدَاهُ مَعَ الْمَاءِ أَوْ مَعَ آخِرِ قَطْرِ الْمَاءِ حَتَّى يَخْرُجَ نَقِيًّا مِنْ الذُّنُوبِ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah menceritakan kepada kami [Malik] dari [Suhail bin Abu Shalih] dari [ayahnya] dari [Abu Hurairah] radliallahu 'anhu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila seorang hamba muslim atau mu`min berwudhu, dengan membasuh wajahnya, keluarlah dari wajahnya setiap dosa yang disebabkan oleh penglihatan kedua matanya, bersama air atau bersama tetesan air terahir, dan apabila ia membasuh kedua tangannya, keluarlah dari kedua tangannya setiap dosa yang dilakukan oleh tangannya, bersama air atau tetesan air terahir, hingga ia keluar bersih dari segala dosa\"."},"480":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ أَبِي عُثْمَانَ قَالَ كُنْتُ مَعَ سَلْمَانَ تَحْتَ شَجَرَةٍ فَأَخَذَ مِنْهَا غُصْنًا يَابِسًا فَهَزَّهُ حَتَّى تَحَاتَّ وَرَقُهُ قَالَ أَمَا تَسْأَلُنِي لِمَ أَفْعَلُ هَذَا قُلْتُ لَهُ لِمَ فَعَلْتَهُ قَالَ هَكَذَا فَعَلَ بِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ إِنَّ الْمُسْلِمَ إِذَا تَوَضَّأَ فَأَحْسَنَ الْوُضُوءَ وَصَلَّى الْخَمْسَ تَحَاتَّتْ ذُنُوبُهُ كَمَا تَحَاتَّ هَذَا الْوَرَقُ ثُمَّ قَالَ { وَأَقِمْ الصَّلَاةَ طَرَفَيْ النَّهَارِ وَزُلَفًا مِنْ اللَّيْلِ - إِلَى قَوْلِهِ - ذَلِكَ ذِكْرَى لِلذَّاكِرِينَ }","id":"Telah mengabarkan kepada kami [Yahya bin hassan] telah menceritakan kepada kami [Hammad bin Salamah] dari [Ali bin Zaid] dari [Abu Utsman] ia berkata: \"Dahulu aku pernah bersama [Salman] di bawah sebuah pohon, ia memetik ranting yang kering, ia mengguncangnya hingga rontoklah daunnya, dan bertanya: 'Mengapa kamu tidak menanyakan apa yang aku lakukan ini? ', Aku bertanya kepadanya: 'Mengapa kamu melakukan ini? ', Ia menjawab: 'Demikianlah Rasulullah shallallahu 'alaihi wasallam'pernah melakukan hal seperti ini, kemudian beliau bersabda: 'Jika seorang muslim berwudhu dan membaguskan wudhunya kemudian shalat lima waktu, niscaya rontoklah dosanya sebagaimana rontoknya dedaunan ini'. Kemudian beliau membaca: \"WA AQIMISSHALATA THARAFAYINNAHARI WA ZULAFAN MINAL LAIL\" (Dan dirikanlah shalat itu di ujung siang (pagi dan petang) dan pada bagian permulaan malam. perbuatan yang baik itu menghapuskan perbuatan yang buruk. Itulah peringatan bagi orang-orang yang mengingat) -Qs. Huud: 114-' \". "},"481":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ عَمْرِو بْنِ عَامِرٍ الْأَنْصَارِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ لِكُلِّ صَلَاةٍ وَكَانَ أَحَدُنَا يَكْفِيهِ الْوُضُوءُ مَا لَمْ يُحْدِثْ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari ['Amr bin 'Amir Al Anshari] dari [Anas bin Malik] radliallahu 'anhu ia berkata: \"Rasulullah shallallahu 'alaihi wasallam berwudhu untuk setiap kali hendak shalat, namun salah satu dari kami cukup dengan berwudhu sekali saja selama belum berhadats (batal wudhunya) \"."},"482":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا وَجَدَ أَحَدُكُمْ فِي صَلَاتِهِ حَرَكَةً فِي دُبُرِهِ فَأَشْكَلَ عَلَيْهِ أَحْدَثَ أَوْ لَمْ يُحْدِثْ فَلَا يَنْصَرِفَنَّ حَتَّى يَسْمَعَ صَوْتًا أَوْ يَجِدَ رِيحًا","id":"Telah mengabarkan kepada kami [Yahya bin hassan] telah menceritakan kepada kami [Hammad bin Salamah] dari [Suhail bin Abu Shalih] dari [ayahnya] dari [Abu Hurairah] radliallahu 'anhu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila seseorang diantara kalian shalat dan mendapatkan (merasakan) sesuatu bergerak, kemudian ia ragu, apakah ia berhadats (batal wudhunya) atau tidak, jangan ia berpaling hingga mendengar suara atau mencium baunya\"."},"483":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُبَارَكِ أَخْبَرَنَا بَقِيَّةُ بْنُ الْوَلِيدِ عَنْ أَبِي بَكْرِ بْنِ أَبِي مَرْيَمَ حَدَّثَنِي عَطِيَّةُ بْنُ قَيْسٍ الْكَلَاعِيُّ عَنْ مُعَاوِيَةَ بْنِ أَبِي سُفْيَانَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا الْعَيْنَانِ وِكَاءُ السَّهِ فَإِذَا نَامَتْ الْعَيْنُ اسْتَطْلَقَ الْوِكَاءُ قِيلَ لِأَبِي مُحَمَّدٍ عَبْدِ اللَّهِ تَقُولُ بِهِ قَالَ لَا إِذَا نَامَ قَائِمًا لَيْسَ عَلَيْهِ الْوُضُوءُ","id":"Telah mengabarkan kepaa kami [Muhammad bin Al Mubarak] telah memberitakan kepada kami [Baqiyyah bin Al Walid] dari [Abu Bakar bin Abu Maryam] telah menceritakan kepadaku ['Athiyyah bin Qais Al Kalaa'i] dari [Mu'awiyyah bin Abu Sufyan] radliallahu 'anhu Nabi shallallahu 'alaihi wasallam bersabda: \"Kedua mata adalah pengikat kesadaran, apabila mata itu tertidur pudarlah tali pengikat itu\". Lalu ditanyakan kepada Abu Muhammad Abdullah: \"Kamu mengatakan itu (apakah kamu menjadikannya sebagai hujjah)? ', ia menjawab: 'Tidak', ia berkata: 'Apabila ia tidur dengan berdiri, ia tidak harus berwudhu\"."},"484":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ سَعِيدِ بْنِ عُبَيْدِ بْنِ السَّبَّاقِ عَنْ أَبِيهِ عَنْ سَهْلِ بْنِ حُنَيْفٍ قَالَ كُنْتُ أَلْقَى مِنْ الْمَذْيِ شِدَّةً فَكُنْتُ أُكْثِرُ الْغُسْلَ مِنْهُ فَذَكَرْتُ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَأَلْتُهُ عَنْهُ فَقَالَ إِنَّمَا يُجْزِئُكَ مِنْ ذَلِكَ الْوُضُوءُ قَالَ قُلْتُ فَكَيْفَ بِمَا يُصِيبُ ثَوْبِي مِنْهُ قَالَ خُذْ كَفًّا مِنْ مَاءٍ فَانْضَحْهُ حَيْثُ تَرَى أَنَّهُ أَصَابَهُ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah memberitakan kepada kami [Muhammad bin Ishak] dari [Sa'id bin 'Ubaid bin As Sabbaq] dari [ayahnya] dari [Sahl bin Hunaif] ia berkata: \"Aku termasuk orang yang sering keluar madzi, (karena itu) aku sering mandi karenanya, lalu aku ceritakan hal itu kepada Nabi shallallahu 'alaihiwa sallam dan aku bertanya hal itu, dan beliau bersabda: ' Cukup bagimu wudhu untuk hal itu', ia berkata: (Aku bertanya) 'Terus bagaimana dengan (madzi) yang mengenai bajuku? ', beliau menjawab: 'Ambilah segenggam air dan percikkanlah ke bagian yang kamu lihat terkena olehnya.\" "},"485":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ الزُّهْرِيِّ حَدَّثَنِي ابْنُ حَزْمٍ عَنْ عُرْوَةَ عَنْ بُسْرَةَ بِنْتِ صَفْوَانَ أَنَّهَا سَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَتَوَضَّأُ الرَّجُلُ مِنْ مَسِّ الذَّكَرِ","id":"Telah mengahabarkan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Al 'Auza'i] dari [Az Zuhri] telah menceritakan kepadaku [Ibnu Hazm] dari ['Urwah] dari [Busrah binti Shafwan] ia pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang laki-laki (wajib) berwudhu apabila menyentuh kemaluan\". "},"486":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ خَالِدٍ الْوَهْبِيُّ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ عُرْوَةَ عَنْ مَرْوَانَ بْنِ الْحَكَمِ عَنْ بُسْرَةَ بِنْتِ صَفْوَانَ أَنَّهَا سَمِعَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ مَسَّ فَرْجَهُ فَلْيَتَوَضَّأْ قَالَ أَبُو مُحَمَّد هَذَا أَوْثَقُ فِي مَسِّ الْفَرْجِ وَقَالَ الْوُضُوءُ أَثْبَتُ ","id":"Telah mengabarkan kepada kami [Ahmad bin Khalid Al Wahbi] dari [Muhammad bin Ishak] dari [Abdullah bin Abu Bakar] dari ['Urwah] dari [Marwan bin Al Hakam] dari [Busrah binti Shafwan] ia pernah mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menyentuh kemaluannya hendaklah berwudhu\". Abu Muhammad berkata: \"Hadits ini paling kuat (dalam permasalahan kewajiban berwudhu) ketika memegang kemaluan\"."},"487":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عَبْدُ الْمَلِكِ بْنُ أَبِي بَكْرِ بْنِ الْحَارِثِ بْنِ هِشَامٍ أَنَّ خَارِجَةَ بْنَ زَيْدٍ الْأَنْصَارِيَّ أَخْبَرَهُ أَنَّ أَبَاهُ زَيْدَ بْنَ ثَابِتٍ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْوُضُوءُ مِمَّا مَسَّتْ النَّارُ قِيلَ لِأَبِي مُحَمَّدٍ تَأْخُذُ بِهِ قَالَ لَا","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] ia berkata: Telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab] ia berkata: Telah mengabarkan kepadaku [Abdul Malik bin Abu Bakar bin Al Harits bin Hisyam], [Kharijah bin Zaid Al Anshari] telah mengabarkan kepadanya, bahwasanya ayahnya, yaitu [Zaid bin tsabit] berkata: \"Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Berwudhulah dari setiap sesuatu yang terkena api (yang dibakar) ' \". Ditanyakan kepada Abu Muhammad: \"Apakah kamu mengambilnya (sebagai hujjah)? ', ia menjawab: 'Tidak' \"."},"488":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي جَعْفَرُ بْنُ عَمْرِو بْنِ أُمَيَّةَ أَنَّ أَبَاهُ عَمْرَو بْنَ أُمَيَّةَ أَخْبَرَهُ أَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحْتَزُّ مِنْ كَتِفِ شَاةٍ فِي يَدِهِ ثُمَّ دُعِيَ إِلَى الصَّلَاةِ فَأَلْقَى السِّكِّينَ الَّتِي كَانَ يَحْتَزُّ بِهَا ثُمَّ قَامَ فَصَلَّى وَلَمْ يَتَوَضَّأْ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] ia berkata: Telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab] telah menceritakan kepadaku [Ja'far bin 'Amr bin `Umayyah], bahwasanya ayahnya - ['Amr bin `Umayyah] - pernah melihat Rasulullah shallallahu 'alaihi wasallam memotong kecil-kecil daging kambing di tangan beliau, kemudian ada panggilan shalat, maka beliau letakkan pisau yang ia gunakan untuk memotong kambing tersebut, kemudian beliau berdiri dan shalat, tanpa berwudhu (lagi) \"."},"489":{"ar":" أَخْبَرَنَا الْحَسَنُ بْنُ أَحْمَدَ الْحَرَّانِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ الْجُلَاحِ عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدٍ الْمَخْزُومِيِّ عَنْ الْمُغِيرَةِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَ أَتَى رِجَالٌ مِنْ بَنِي مُدْلِجٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّا أَصْحَابُ هَذَا الْبَحْرِ نُعَالِجُ الصَّيْدَ عَلَى رَمَثٍ فَنَعْزُبُ فِيهِ اللَّيْلَةَ وَاللَّيْلَتَيْنِ وَالثَّلَاثَ وَالْأَرْبَعَ وَنَحْمِلُ مَعَنَا مِنْ الْعَذْبِ لِشِفَاهِنَا فَإِنْ نَحْنُ تَوَضَّأْنَا بِهِ خَشِينَا عَلَى أَنْفُسِنَا وَإِنْ نَحْنُ آثَرْنَا بِأَنْفُسِنَا وَتَوَضَّأْنَا مِنْ الْبَحْرِ وَجَدْنَا فِي أَنْفُسِنَا مِنْ ذَلِكَ فَخَشِينَا أَنْ لَا يَكُونَ طَهُورًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّئُوا مِنْهُ فَإِنَّهُ الطَّاهِرُ مَاؤُهُ الْحَلَالُ مَيْتَتُهُ","id":"Telah mengabarkan kepada kami [Al Hasan bin Ahmad Al Harrani] telah menceritakan kepada kami [Muhammad bin Salamah] dari [Muhammad bin Ishak] dari [Yazid bin Abu Habib] dari [Al Julah] dari [Abdullah bin Sa'id Al Makhzumi] dari [Al Mughirah bin Abu Burdah] dari [ayahnya] dari [Abu Hurairah] radliallahu 'anhu ia berkata: \"Orang-oramg dari Bani Mudlij mendatangi Rasulullah shallallahu 'alaihi wasallam dan bertanya: 'Wahai Rasulullah shallallahu 'alaihi wasallam, kami para pelaut, yang bekerja mencari ikan di atas rakit, terkadang kami mencari ikan semalam, dua malam, tiga malam, bahkan empat malam. Dan kami membawa bekal air tawar guna (menyegarkan) mulut-mulut kami, dan jika kami berwudhu dengan (air tawar), kami khawatir diri kami (kehausan), namun jika kami berwudhu dengan air laut, kami khawatir kalau air laut itu tidak mensucikan. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: 'Berwudhulah dengannya (air laut), karena (laut) itu suci airnya dan halal bangkainya'."},"490":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُبَارَكِ عَنْ مَالِكٍ قِرَاءَةً عَنْ صَفْوَانَ بْنِ سُلَيْمٍ عَنْ سَعِيدِ بْنِ سَلَمَةَ مِنْ آلِ الْأَزْرَقِ أَنَّ الْمُغِيرَةَ بْنَ أَبِي بُرْدَةَ وَهُوَ رَجُلٌ مِنْ بَنِي عَبْدِ الدَّارِ أَخْبَرَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُ سَأَلَ رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّا نَرْكَبُ الْبَحْرَ وَمَعَنَا الْقَلِيلُ مِنْ الْمَاءِ فَإِنْ تَوَضَّأْنَا بِهِ عَطِشْنَا أَفَنَتَوَضَّأُ مِنْ مَاءِ الْبَحْرِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ الطَّهُورُ مَاؤُهُ الْحِلُّ مَيْتَتُهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mubarak] dari [Malik] -dengan bacaan-, dari [Shafwan bin Sulaim] dari [Sa'id bin Salamah] -dari keluarga Al `Azraq-, Al [Mughirah bin Burdah] (dia adalah seorang dari Bani Abdud Daar) mengabarkan kepadanya, ia mendengar [Abu Hurairah] radliallahu 'anhu ia berkata: \"Seseorang pernah bertanya Rasulullah shallallahu 'alaihi wasallam, ia berkata: ' Kami naik (perahu) di laut, dan bersama kami hanya ada sedikit air, jika kami pergunakan untuk berwudhu tentu kami kehausan, apakah kami boleh berwudhu dengan air laut? ', Rasulullah shallallahu 'alaihi wasallam menjawab: ' (laut) itu suci airnya dan halal bangkainya' \"."},"491":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا زَائِدَةُ عَنْ هِشَامٍ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَبُولُ أَحَدُكُمْ فِي الْمَاءِ الدَّائِمِ ثُمَّ يَغْتَسِلُ مِنْهُ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Za`idah] dari [Hisyam] dari [Muhammad] dari [Abu Hurairah] radliallahu 'anhu dari Nabi shallallahu 'alahi wa sallam bersabda: \"Janganlah seseorang diantara kalian buang air kecil di air tergenang kemudian ia mandi dari air tersebut\"."},"492":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ جَعْفَرِ بْنِ الزُّبَيْرِ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُسْأَلُ عَنْ الْمَاءِ يَكُونُ بِالْفَلَاةِ مِنْ الْأَرْضِ وَمَا يَنُوبُهُ مِنْ الدَّوَابِّ وَالسِّبَاعِ فَقَالَ إِذَا بَلَغَ الْمَاءُ قُلَّتَيْنِ لَمْ يُنَجِّسْهُ شَيْءٌ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Muhammad bin Ishak] dari [Muhammad bin Ja'far Az Zubair] dari [Ubaidullah bin Abdullah bin Umar] dari [ayahnya] ia berkata: \"Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam ditanya tentang air yang ada di tanah lapang dan sering didatangi oleh binatang buas, beliau menjawab: 'Apabila kadar air mencapai dua qullah, tidak ada sesuatupun yang dapat membuatnya najis' \". "},"493":{"ar":" حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ الْوَلِيدِ بْنِ كَثِيرٍ عَنْ مُحَمَّدِ بْنِ جَعْفَرِ بْنِ الزُّبَيْرِ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ الْمَاءِ وَمَا يَنُوبُهُ مِنْ الدَّوَابِّ وَالسِّبَاعِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ الْمَاءُ قُلَّتَيْنِ لَمْ يَحْمِلْ الْخَبَثَ","id":"Telah menceritakan kepada kami [Yahya bin Hassan] telah menceritakan kepaa kami [Abu Usamah] dari [Al Walid bin Katsir] dari [Muhammad bin Ja'far Az Zubair] dari [Ubaidullah bin Abdullah] dari [Ibnu Umar] radliallahu 'anhu Rasulullah shallallahu 'alaihi wasallam ditanya tentang air yang sering di datangi binatang ternak dan binatang buas, Rasulullah shallallahu 'alaihi wasallam menjawab: \"Apabila air itu dua qullah, ia tidak mengandung najis\". "},"494":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ وَأَبُو زَيْدٍ سَعِيدُ بْنُ الرَّبِيعِ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ قَالَ سَمِعْتُ جَابِرًا يَقُولُ جَاءَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُنِي وَأَنَا مَرِيضٌ لَا أَعْقِلُ فَتَوَضَّأَ وَصَبَّ مِنْ وَضُوئِهِ عَلَيَّ فَعَقَلْتُ","id":"Telah mengabarkan kepada kami [Abu Al Walid At Thayalisi] dan [Abu Zaid Sa'id bin Ar Rubai'], keduanya berkata: Telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin Al Munkadir] ia berkata: \"Aku pernah mendengar [Jabir] radliallahu 'anhu ia berkata: 'Nabi shallallahu 'alaihi wasallam datang menjengukku sedang aku dalam keadaan sakit tidak sadarkan diri, lalu beliau berwudhu dan menuangkan dari air wudhunya di atas badanku lalu aku menjadi sadar' \"."},"495":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا يَزِيدُ بْنُ عَطَاءٍ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ قَامَتْ امْرَأَةٌ مِنْ نِسَاءِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاغْتَسَلَتْ فِي جَفْنَةٍ مِنْ جَنَابَةٍ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى فَضْلِهَا يَسْتَحِمُّ فَقَالَتْ إِنِّي قَدْ اغْتَسَلْتُ فِيهِ قَبْلَكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ لَيْسَ عَلَى الْمَاءِ جَنَابَةٌ أَخْبَرَنَا عَبْدُ اللَّهِ عَنْ سُفْيَانَ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Yazid bin 'Atha`] dari [Simak] dari ['Ikrimah] dari [Ibnu Abbas] radliallahu 'anhu ia berkata: \"Pernah seorang dari isteri-isteri Nabi shallallahu 'alaihi wasallam mandi junub di sebuah bak mandi, kemudian Nabi shallallahu 'alaihi wasallam beranjak dan mandi dengan sisa airnya (isteri beliau), lalu isteri nabi berkata: 'Sebelummu aku mandi di bak itu', maka Nabi shallallahu 'alaihi wasallam berkata: ' air itu tidak terkena hukum junub' \". \"Telah mengabarkan kepada kami [Ubaidullah] dari [Sufyan] dari [Simak bin Harb] dari ['Ikrimah] dari [Ibnu Abbas] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam dengan redaksi yang sama.\""},"496":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ أَخْبَرَنَا مَالِكٌ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ حُمَيْدَةَ بِنْتِ عُبَيْدِ بْنِ رِفَاعَةَ عَنْ كَبْشَةَ بِنْتِ كَعْبِ بْنِ مَالِكٍ وَكَانَتْ تَحْتَ ابْنِ أَبِي قَتَادَةَ أَنَّ أَبَا قَتَادَةَ دَخَلَ عَلَيْهَا فَسَكَبَتْ لَهُ وَضُوءًا فَجَاءَتْ هِرَّةٌ تَشْرَبُ مِنْهُ فَأَصْغَى لَهَا أَبُو قَتَادَةَ الْإِنَاءَ حَتَّى شَرِبَتْ قَالَتْ كَبْشَةُ فَرَآنِي أَنْظُرُ فَقَالَ أَتَعْجَبِينَ يَا بِنْتَ أَخِي قُلْتُ نَعَمْ قَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّهَا لَيْسَتْ بِنَجَسٍ إِنَّمَا هِيَ مِنْ الطَّوَّافِينَ عَلَيْكُمْ وَالطَّوَّافَاتِ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah mengabarkan kepada kami [Malik] dari [Ishak bin Abdullah bin Abu Thalhah] dari [Humaidah binti 'Ubaid bin Rifa'ah] dari [Kabsyah binti Ka'ab bin Malik] -dan waktu itu ia masih menjadi isteri Ibnu Abu Qatadah-, [Abu Qatadah] pernah masuk menemuinya, lalu ia (Kabsyah binti Ka'ab) menuangkan air untuk wudhu, lalu datanglah seekor kucing meminumnya (air wudhu), maka Abu Qatadah memiringkan bejana tersebut agar kucing itu bisa minum (dengan leluasa), Kabsyah berkata: 'Abu Qatadah melihatku yang tengah memperhatikan dengan penuh keheranan', lalu ia bertanya: 'Apakah kamu heran wahai anak saudaraku? ', aku menjawab: 'Ya, benar', ia berkata lagi: ' Rasulullah shallallahu 'alaihi wasallam pernah bersabda: ' (kucing) tidaklah najis, hanya ia hewan yang seringkali berkeliaran dan mengelilingi (berada di dekat) kalian' \"."},"497":{"ar":" أَخْبَرَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي التَّيَّاحِ عَنْ مُطَرِّفٍ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا وَلَغَ الْكَلْبُ فِي الْإِنَاءِ فَاغْسِلُوهُ سَبْعَ مِرَارٍ وَالثَّامِنَةَ عَفِّرُوهُ فِي التُّرَابِ","id":"Telah mengabarkan kepada kami [Wahab bin jarir] telah menceritakan kepada kami [Syu'bah] dari [Abu At Tayyah] dari [Mutharrif] dari [Abdullah bin Mughaffal] Nabi shallallahu 'alaihi wasallam pernah bersabda: \"Apabila seekor anjing menjilat sebuah bejana, hendaklah kalian mencucinya sebanyak tujuh kali, dan untuk basuhan ke delapan gunakanlah debu\"."},"498":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ ابْنِ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَ أَنَّ فَأْرَةً وَقَعَتْ فِي سَمْنٍ فَمَاتَتْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلْقُوهَا وَمَا حَوْلَهَا وَكُلُوهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Ibnu 'Uyainah] dari [Az Zuhri] dari [Ubaidullah] dari [Ibnu Abbas] radliallahu 'anhu dari [Maimunah] radliallahu 'anha ada seekor tikus jatuh ke dalam minyak samin, kemudian tikus itu mati, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Buanglah (tikus) dan minyak di sekitarnya, dan makanlah (sisa) nya\"."},"499":{"ar":" أَخْبَرَنَا الْمُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا الْأَعْمَشُ عَنْ مُجَاهِدٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَ مَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَبْرَيْنِ فَقَالَ إِنَّهُمَا لَيُعَذَّبَانِ فِي قُبُورِهِمَا وَمَا يُعَذَّبَانِ فِي كَبِيرٍ كَانَ أَحَدُهُمَا يَمْشِي بِالنَّمِيمَةِ وَكَانَ الْآخَرُ لَا يَسْتَنْزِهُ عَنْ الْبَوْلِ أَوْ مِنْ الْبَوْلِ قَالَ ثُمَّ أَخَذَ جَرِيدَةً رَطْبَةً فَكَسَرَهَا فَغَرَزَ عِنْدَ رَأْسِ كُلِّ قَبْرٍ مِنْهُمَا قِطْعَةً ثُمَّ قَالَ عَسَى أَنْ يُخَفَّفَ عَنْهُمَا حَتَّى تَيْبَسَا","id":"Telah mengabarkan kepada kami [Al Mu'alla bin `Asad] telah menceritakan kepada kami [Abdul Wahid bin Ziyad] telah menceritakan kepada kami [Al A'masy] dari [Mujahid] dari [Thawus] dari [Ibnu Abbas] radliallahu 'anhu ia berkata: \"Rasulullah shallallahu 'alaihi wasallam pernah melewati dua kuburan, lalu beliau berkata: ' keduanya sedang diadzab dalam kubur, dan keduanya tidaklah diadzab karena dosa besar, salah satunya (diadzab) karena namimah (sering mengadu domba), dan yang satunya lagi (diadzab) karena tidak bersuci ketika buang air kecil'. Ia (Ibnu Abbas radliallahu 'anhu) berkata: 'Kemudian Rasulullah shallahu 'alaihi wa sallam mengambil pelepah kurma yang masih basah, lalu membelahnya dan menancapkan tiap belahan di atas kepala kuburan, kemudian beliau berdo`a: 'Semoga keduanya diringankan siksanya hingga kedua pelepah ini kering' ' \". "},"500":{"ar":" حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ أَخْبَرَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ أَنَسٍ قَالَ جَاءَ أَعْرَابِيٌّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا قَامَ بَالَ فِي نَاحِيَةِ الْمَسْجِدِ قَالَ فَصَاحَ بِهِ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَفَّهُمْ عَنْهُ ثُمَّ دَعَا بِدَلْوٍ مِنْ مَاءٍ فَصَبَّهُ عَلَى بَوْلِهِ","id":"Telah menceritakan kepada kami [Ja'far bin 'Aun] telah memberitakan kepada kami [Yahya bin Sa'id] dari [Anas] radliallahu 'anhuia berkata: \"Ada seorang Arab dusun datang menemui Nabi shallallahu 'alaihi wasallam, kemudian orang tersebut buang air kecil di sudut masjid, ia berkata: 'Para sahabat Nabi shallallahu 'alaihi wasallam berteriak agar ia menghentikan kencingnya, namun beliau justru melarang menghentikannya, beliau hanya meminta seember air dan beliau siramkan ke atas kencing orang tersebut' \"."}};
